pub fn app() -> Router {
    app_with_state(AppState::demo())
}

pub fn app_with_state(state: AppState) -> Router {
    Router::new()
        .merge(common_routes())
        .merge(setup_routes())
        .nest("/api/v1", api_v1_routes(state.clone()))
        .merge(gateway_routes())
        .layer(TraceLayer::new_for_http())
        .with_state(state)
}

fn common_routes() -> Router<AppState> {
    Router::new()
        .route("/health", get(health))
        .route("/api/event_logging/batch", post(event_logging_batch))
}

fn setup_routes() -> Router<AppState> {
    Router::new()
        .route("/setup/status", get(setup_status))
        .route("/setup/test-db", post(test_database))
        .route("/setup/test-redis", post(test_redis))
        .route("/setup/install", post(install))
}

fn api_v1_routes(state: AppState) -> Router<AppState> {
    Router::new()
        .merge(auth_routes())
        .merge(public_settings_routes())
        .merge(page_routes())
        .merge(backup_public_routes())
        .merge(user_routes())
        .merge(payment_routes())
        .merge(admin_routes(state))
}

fn backup_public_routes() -> Router<AppState> {
    Router::new().route("/admin/backups/:id/download", get(admin_backup_download))
}

fn gateway_routes() -> Router<AppState> {
    Router::new()
        .route(
            "/v1/responses",
            get(gateway_websocket_endpoint).post(gateway_endpoint),
        )
        .route(
            "/v1/responses/*subpath",
            get(gateway_websocket_endpoint).post(gateway_endpoint),
        )
        .route(
            "/responses",
            get(gateway_websocket_endpoint).post(gateway_endpoint),
        )
        .route(
            "/responses/*subpath",
            get(gateway_websocket_endpoint).post(gateway_endpoint),
        )
        .route(
            "/backend-api/codex/responses",
            get(gateway_websocket_endpoint).post(gateway_endpoint),
        )
        .route(
            "/backend-api/codex/responses/*subpath",
            get(gateway_websocket_endpoint).post(gateway_endpoint),
        )
        .route("/v1/chat/completions", post(gateway_endpoint))
        .route("/chat/completions", post(gateway_endpoint))
        .route("/v1/messages", post(gateway_endpoint))
        .route("/v1/messages/count_tokens", post(gateway_endpoint))
        .route("/v1/embeddings", post(gateway_endpoint))
        .route("/embeddings", post(gateway_endpoint))
        .route("/v1/images/generations", post(gateway_endpoint))
        .route("/images/generations", post(gateway_endpoint))
        .route("/v1/images/edits", post(gateway_endpoint))
        .route("/images/edits", post(gateway_endpoint))
        .route("/v1/models", get(gateway_endpoint))
        .route("/v1/usage", get(gateway_endpoint))
        .route("/v1beta/models", get(gateway_endpoint))
        .route(
            "/v1beta/models/:model_action",
            get(gateway_endpoint).post(gateway_endpoint),
        )
        .route("/antigravity/v1/messages", post(gateway_endpoint))
        .route(
            "/antigravity/v1/messages/count_tokens",
            post(gateway_endpoint),
        )
        .route("/antigravity/v1/models", get(gateway_endpoint))
        .route("/antigravity/models", get(gateway_endpoint))
        .route("/antigravity/v1/usage", get(gateway_endpoint))
        .route("/antigravity/v1beta/models", get(gateway_endpoint))
        .route(
            "/antigravity/v1beta/models/:model_action",
            get(gateway_endpoint).post(gateway_endpoint),
        )
}

