async fn health() -> Json<Value> {
    Json(json!({
        "status": "ok",
        "service": "sub2api-backend-next"
    }))
}

async fn event_logging_batch(
    State(state): State<AppState>,
    body: Bytes,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    let payload = parse_json_body(&body)?;
    Ok(success(state.payment_portal.record_event_batch(payload)))
}

async fn payment_webhook(
    State(state): State<AppState>,
    OriginalUri(uri): OriginalUri,
    method: Method,
    headers: HeaderMap,
    Query(query): Query<HashMap<String, String>>,
    body: Bytes,
) -> Result<Response, ApiError> {
    let provider = payment_webhook_provider(uri.path());
    let mut payload = parse_payment_webhook_payload(method.as_str(), uri.query(), &body)?;
    if let Value::Object(object) = &mut payload {
        for (key, value) in query {
            object.entry(key).or_insert(json!(value));
        }
    }
    let result = state
        .payment_portal
        .handle_webhook(
            &provider,
            method.as_str(),
            payload,
            &payment_webhook_headers(&headers),
            &repository_payment_provider_instances(&state).await?,
        )
        .await?;
    sync_payment_audits_from_webhook_result(&state, &result.audits).await?;
    let record = payment_webhook_result_with_repository_order(&state, result.record).await?;
    sync_payment_order_from_webhook_result(&state, &record).await?;
    fulfill_payment_order_from_webhook_result(&state, &record).await?;
    Ok(payment_webhook_ack_response(&result.provider))
}

fn payment_webhook_ack_response(provider: &str) -> Response {
    match provider {
        "wxpay" => (
            StatusCode::OK,
            [(CONTENT_TYPE, "application/json")],
            Json(json!({ "code": "SUCCESS", "message": "\u{6210}\u{529f}" })),
        )
            .into_response(),
        "stripe" | "airwallex" => StatusCode::OK.into_response(),
        _ => (
            StatusCode::OK,
            [(CONTENT_TYPE, "text/plain; charset=utf-8")],
            "success",
        )
            .into_response(),
    }
}

async fn require_admin(
    State(state): State<AppState>,
    headers: HeaderMap,
    request: axum::extract::Request,
    next: Next,
) -> Result<Response, ApiError> {
    if let Some(admin_api_key) = headers
        .get("x-api-key")
        .and_then(|value| value.to_str().ok())
        .map(str::trim)
        .filter(|value| !value.is_empty())
    {
        if !validate_admin_api_key(&state, admin_api_key).await? {
            return Err(ApiError::unauthorized("Invalid admin API key"));
        }
    } else {
        state.auth.admin_user_from_headers(&headers)?;
    }
    Ok(next.run(request).await)
}

