async fn validate_promo_code(
    State(state): State<AppState>,
    Json(request): Json<ValidateCodeRequest>,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    let code = validate_code_value(&request.code)?;
    let settings = admin_settings_with_payment_config(&state).await?;
    if !bool_setting(&settings, "promo_code_enabled", true) {
        return Ok(success(json!({
            "valid": false,
            "error_code": "PROMO_CODE_DISABLED"
        })));
    }
    let Some(code_item) = find_admin_collection_item_by_code(&state, "promo-codes", code).await?
    else {
        return Ok(success(json!({
            "valid": false,
            "error_code": "PROMO_CODE_NOT_FOUND"
        })));
    };
    if promo_code_is_expired(&code_item) {
        return Ok(success(json!({
            "valid": false,
            "error_code": "PROMO_CODE_EXPIRED"
        })));
    }
    if !string_field_eq_any(&code_item, "status", &["active"]) {
        return Ok(success(json!({
            "valid": false,
            "error_code": "PROMO_CODE_DISABLED"
        })));
    }
    if promo_code_max_used(&code_item) {
        return Ok(success(json!({
            "valid": false,
            "error_code": "PROMO_CODE_MAX_USED"
        })));
    }
    Ok(success(json!({
        "valid": true,
        "bonus_amount": f64_from_value(&code_item, "bonus_amount").unwrap_or(0.0)
    })))
}

async fn validate_invitation_code(
    State(state): State<AppState>,
    Json(request): Json<ValidateCodeRequest>,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    let code = validate_code_value(&request.code)?;
    let settings = admin_settings_with_payment_config(&state).await?;
    if !bool_setting(&settings, "invitation_code_enabled", false) {
        return Ok(success(json!({
            "valid": false,
            "error_code": "INVITATION_CODE_DISABLED"
        })));
    }
    let Some(code_item) = find_admin_collection_item_by_code(&state, "redeem-codes", code).await?
    else {
        return Ok(success(json!({
            "valid": false,
            "error_code": "INVITATION_CODE_NOT_FOUND"
        })));
    };
    if !string_field_eq_any(&code_item, "type", &["invitation"]) {
        return Ok(success(json!({
            "valid": false,
            "error_code": "INVITATION_CODE_INVALID"
        })));
    }
    if !string_field_eq_any(&code_item, "status", &["unused"]) {
        return Ok(success(json!({
            "valid": false,
            "error_code": "INVITATION_CODE_USED"
        })));
    }
    Ok(success(json!({ "valid": true })))
}

async fn register(
    State(state): State<AppState>,
    Json(request): Json<RegisterRequest>,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    let credential_email = request.email.trim().to_ascii_lowercase();
    let credential_password_hash = hash_password_for_repository(&request.password)?;
    let affiliate_code = request
        .aff_code
        .as_deref()
        .or(request.affiliate_code.as_deref())
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_owned);
    let (tokens, user) = state.auth.register(request)?;
    sync_auth_user_to_repository(&state, &user).await?;
    let user_id = user
        .get("id")
        .and_then(Value::as_i64)
        .ok_or_else(|| ApiError::internal_server_error("registered user id is missing"))?;
    persist_auth_credential(
        &state,
        user_id,
        credential_email,
        credential_password_hash,
        "active",
    )
    .await?;
    if let Some(code) = affiliate_code {
        let _ = bind_affiliate_inviter_by_code(&state, user_id, &code).await;
    }
    persist_auth_session(&state, &tokens, user_id, "register").await?;
    Ok(success(auth_response(tokens, user)))
}

async fn login(
    State(state): State<AppState>,
    Json(request): Json<LoginRequest>,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    let (tokens, user) = match state.auth.login(request.clone()) {
        Ok(authenticated) => authenticated,
        Err(error) if error.status() == StatusCode::UNAUTHORIZED => {
            login_with_repository_credential(&state, &request).await?
        }
        Err(error) => return Err(error),
    };
    let user_id = user
        .get("id")
        .and_then(Value::as_i64)
        .ok_or_else(|| ApiError::internal_server_error("login user id is missing"))?;
    if totp_enabled_for_user(&state, user_id).await? {
        state.auth.revoke_tokens(&tokens);
        let temp_token = create_2fa_login_session(&state, user_id).await?;
        return Ok(success(json!({
            "requires_2fa": true,
            "temp_token": temp_token,
            "user_email_masked": mask_email(user.get("email").and_then(Value::as_str).unwrap_or_default())
        })));
    }
    persist_auth_session(&state, &tokens, user_id, "login").await?;
    Ok(success(auth_response(tokens, user)))
}

async fn login_2fa(
    State(state): State<AppState>,
    Json(request): Json<Login2FARequest>,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    let temp_token = request
        .temp_token
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .ok_or_else(|| ApiError::bad_request("temp_token is required"))?;
    let code = request
        .totp_code
        .or(request.code)
        .ok_or_else(|| ApiError::bad_request("2fa code is required"))?;
    let user_id = validate_2fa_login_session(&state, temp_token).await?;
    let totp_state = load_totp_state(&state, user_id).await?;
    if !totp_state
        .get("enabled")
        .and_then(Value::as_bool)
        .unwrap_or(false)
    {
        return Err(ApiError::bad_request("totp is not enabled"));
    }
    let secret = decrypt_totp_secret(&state, &totp_state)?;
    if !crate::totp::verify_code(&secret, &code) {
        return Err(ApiError::bad_request("invalid totp code"));
    }
    delete_2fa_login_session(&state, temp_token).await?;
    let (tokens, user) = state.auth.issue_tokens_for_user(user_id)?;
    persist_auth_session(&state, &tokens, user_id, "login_2fa").await?;
    Ok(success(auth_response(tokens, user)))
}

async fn send_verify_code(
    State(state): State<AppState>,
    Json(request): Json<EmailCodeRequest>,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    let prepared = state.auth.prepare_email_binding_code(1, request.email)?;
    state
        .email_dispatch
        .send_verification_code(
            &prepared.target,
            &prepared.code,
            VerificationEmailKind::Auth,
        )
        .await?;
    Ok(success(
        state.auth.commit_prepared_verification_code(&prepared)?,
    ))
}

async fn refresh_token(
    State(state): State<AppState>,
    Json(request): Json<RefreshRequest>,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    let requested_refresh_token = request.refresh_token.clone();
    let tokens = match state.auth.refresh(request) {
        Ok(tokens) => {
            match state
                .repository
                .get_auth_session_by_refresh_token(&requested_refresh_token)
                .await
            {
                Ok(old_session) => {
                    if let Err(error) = ensure_repository_auth_session_active(&old_session, true) {
                        state.auth.revoke_tokens(&tokens);
                        return Err(error);
                    }
                    state
                        .repository
                        .revoke_auth_session_by_refresh_token(
                            &requested_refresh_token,
                            current_unix_time(),
                        )
                        .await
                        .map_err(repository_api_error)?;
                    persist_auth_session(&state, &tokens, old_session.user_id, "refresh").await?;
                }
                Err(repository::RepositoryError::NotFound { .. }) => {}
                Err(repository::RepositoryError::InvalidInput(_)) => {
                    state.auth.revoke_tokens(&tokens);
                    return Err(ApiError::unauthorized("invalid refresh token"));
                }
                Err(error) => {
                    state.auth.revoke_tokens(&tokens);
                    return Err(repository_api_error(error));
                }
            }
            tokens
        }
        Err(error) if error.status() == StatusCode::UNAUTHORIZED => {
            let old_session =
                active_repository_auth_session_by_refresh_token(&state, &requested_refresh_token)
                    .await?;
            state
                .repository
                .get_user(old_session.user_id)
                .await
                .map_err(repository_api_error)?;
            let tokens = state
                .auth
                .issue_tokens_for_repository_user(old_session.user_id);
            state
                .repository
                .revoke_auth_session_by_refresh_token(&requested_refresh_token, current_unix_time())
                .await
                .map_err(repository_api_error)?;
            persist_auth_session(&state, &tokens, old_session.user_id, "refresh").await?;
            tokens
        }
        Err(error) => return Err(error),
    };
    Ok(success(json!({
        "access_token": tokens.access_token,
        "refresh_token": tokens.refresh_token,
        "expires_in": tokens.expires_in,
        "token_type": tokens.token_type
    })))
}

async fn logout(
    State(state): State<AppState>,
    Json(request): Json<LogoutRequest>,
) -> Json<crate::response::ApiEnvelope<Value>> {
    if let Some(refresh_token) = request.refresh_token.clone() {
        let _ = state
            .repository
            .revoke_auth_session_by_refresh_token(&refresh_token, current_unix_time())
            .await;
    }
    state.auth.logout(request);
    empty_success()
}

async fn forgot_password(
    State(state): State<AppState>,
    Json(request): Json<EmailCodeRequest>,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    state.email_dispatch.ensure_password_reset_config().await?;
    let Some(prepared) = prepare_password_reset_with_repository(&state, request).await? else {
        return Ok(success(AuthService::password_reset_requested_response()));
    };
    match state
        .email_dispatch
        .send_password_reset_link(&prepared.email, &prepared.token)
        .await
    {
        Ok(()) => Ok(success(
            state.auth.commit_prepared_password_reset(&prepared)?,
        )),
        Err(error) if error.status().is_server_error() => Err(error),
        Err(_) => Ok(success(AuthService::password_reset_requested_response())),
    }
}

async fn reset_password(
    State(state): State<AppState>,
    Json(request): Json<ResetPasswordRequest>,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    state.email_dispatch.ensure_password_reset_config().await?;
    let email = request.email.trim().to_ascii_lowercase();
    match state.repository.get_auth_credential_by_email(&email).await {
        Ok(mut credential) => {
            let password_hash = state.auth.reset_repository_password_token(
                &email,
                &request.token,
                &request.new_password,
            )?;
            credential.password_hash = password_hash.clone();
            credential.updated_at_unix = current_unix_time().max(1);
            let user_id = credential.user_id;
            state
                .repository
                .upsert_auth_credential(credential)
                .await
                .map_err(repository_api_error)?;
            state
                .auth
                .replace_memory_password_hash_if_present(&email, &password_hash);
            state.auth.revoke_all_user_sessions(user_id);
            state
                .repository
                .revoke_auth_sessions_by_user(user_id, current_unix_time())
                .await
                .map_err(repository_api_error)?;
            return Ok(success(json!({
                "message": "Your password has been reset successfully. You can now log in with your new password."
            })));
        }
        Err(repository::RepositoryError::NotFound { .. })
        | Err(repository::RepositoryError::InvalidInput(_)) => {}
        Err(error) => return Err(repository_api_error(error)),
    }
    let response = state.auth.reset_password(request)?;
    Ok(success(response))
}

async fn current_user(
    State(state): State<AppState>,
    headers: HeaderMap,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    let mut user = match state.auth.current_user_from_headers(&headers) {
        Ok(user) => user,
        Err(error) if error.status() == StatusCode::UNAUTHORIZED => {
            repository_current_user_from_headers(&state, &headers).await?
        }
        Err(error) => return Err(error),
    };
    merge_repository_balance_into_user(&state, &mut user).await?;
    Ok(success(user))
}

async fn revoke_all_sessions(
    State(state): State<AppState>,
    headers: HeaderMap,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    let user_id = current_user_id_from_headers_or_repository(&state, &headers).await?;
    let response = state.auth.revoke_all_sessions_from_headers(&headers)?;
    state
        .repository
        .revoke_auth_sessions_by_user(user_id, current_unix_time())
        .await
        .map_err(repository_api_error)?;
    Ok(success(response))
}

async fn oauth_bind_token(
    State(state): State<AppState>,
    headers: HeaderMap,
) -> Result<Response, ApiError> {
    let bind = state.auth.prepare_oauth_bind_token(&headers)?;
    let token = bind
        .get("bind_token")
        .and_then(Value::as_str)
        .ok_or_else(|| ApiError::internal_server_error("failed to prepare oauth bind token"))?;
    Ok(Response::builder()
        .status(StatusCode::NO_CONTENT)
        .header(
            SET_COOKIE,
            header_value_or_root(&oauth_cookie_at_path(
                "oauth_bind_access_token",
                token,
                600,
                "/api/v1/auth/oauth",
            )),
        )
        .body(axum::body::Body::empty())
        .unwrap())
}

