async fn oauth_complete_registration(
    State(state): State<AppState>,
    OriginalUri(uri): OriginalUri,
    Json(request): Json<OAuthCompletionRequest>,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    let provider = oauth_provider_from_path(uri.path());
    let (tokens, user) = state.auth.complete_oauth_registration(&provider, request)?;
    sync_auth_user_to_repository(&state, &user).await?;
    let user_id = user
        .get("id")
        .and_then(Value::as_i64)
        .ok_or_else(|| ApiError::internal_server_error("oauth user id is missing"))?;
    let email = user
        .get("email")
        .and_then(Value::as_str)
        .unwrap_or("")
        .to_owned();
    persist_auth_credential(
        &state,
        user_id,
        email,
        hash_password_for_repository("oauth-password")?,
        "active",
    )
    .await?;
    persist_auth_session(&state, &tokens, user_id, "oauth_complete_registration").await?;
    Ok(success(auth_response(tokens, user)))
}

async fn oauth_bind_login(
    State(state): State<AppState>,
    OriginalUri(uri): OriginalUri,
    headers: HeaderMap,
    Json(mut request): Json<OAuthCompletionRequest>,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    fill_pending_token_from_cookie(&mut request, &headers);
    let browser_session_key = oauth_browser_session_from_headers(&headers);
    let session = state
        .auth
        .oauth_session_from_completion_request(&request, browser_session_key.as_deref())?;
    let email = request
        .email
        .as_deref()
        .ok_or_else(|| ApiError::bad_request("email is required"))?;
    let password = request
        .password
        .as_deref()
        .ok_or_else(|| ApiError::bad_request("password is required"))?;
    let user_id = verify_login_user_id_with_repository(&state, email, password).await?;
    ensure_repository_oauth_identity_available(&state, &session, Some(user_id)).await?;
    let (tokens, user) = state.auth.oauth_bind_login_with_session(
        &oauth_provider_from_path(uri.path()),
        request,
        browser_session_key.as_deref(),
    )?;
    persist_oauth_identity_from_session(&state, &session, user_id, &user).await?;
    persist_auth_session(&state, &tokens, user_id, "oauth_bind_login").await?;
    Ok(success(auth_response(tokens, user)))
}

async fn oauth_pending_exchange(
    State(state): State<AppState>,
    headers: HeaderMap,
    Json(request): Json<PendingOAuthExchangeRequest>,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    let session_token = oauth_pending_session_from_headers(&headers);
    let browser_session_key = oauth_browser_session_from_headers(&headers);
    let session = state.auth.oauth_session_from_exchange_request(
        &request,
        session_token.as_deref(),
        browser_session_key.as_deref(),
    )?;
    if let Some(user_id) = session.target_user_id {
        ensure_repository_oauth_identity_available(&state, &session, Some(user_id)).await?;
    }
    let response = state.auth.pending_oauth_exchange_with_session(
        request,
        session_token.as_deref(),
        browser_session_key.as_deref(),
    )?;
    if let Some(user_id) = session.target_user_id {
        if response.get("auth_result").and_then(Value::as_str) == Some("login") {
            let user = response.get("user").cloned().unwrap_or(Value::Null);
            persist_oauth_identity_from_session(&state, &session, user_id, &user).await?;
            if let (Some(access_token), Some(refresh_token), Some(expires_in)) = (
                response.get("access_token").and_then(Value::as_str),
                response.get("refresh_token").and_then(Value::as_str),
                response.get("expires_in").and_then(Value::as_u64),
            ) {
                let tokens = crate::auth::AuthTokens {
                    access_token: access_token.to_owned(),
                    refresh_token: refresh_token.to_owned(),
                    expires_in,
                    token_type: "Bearer",
                };
                persist_auth_session(&state, &tokens, user_id, "oauth_pending_exchange").await?;
            }
        }
    }
    Ok(success(response))
}

async fn oauth_pending_send_verify_code(
    State(state): State<AppState>,
    headers: HeaderMap,
    Json(request): Json<EmailCodeRequest>,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    let session_token = oauth_pending_session_from_headers(&headers)
        .ok_or_else(|| ApiError::bad_request("pending auth token is required"))?;
    let browser_session_key = oauth_browser_session_from_headers(&headers);
    let session = state
        .auth
        .pending_oauth_session(&session_token, browser_session_key.as_deref())?;
    if session.intent != "login" || session.target_user_id.is_some() {
        return Err(ApiError::bad_request(
            "pending auth session cannot send registration verification code",
        ));
    }
    let prepared = state.auth.prepare_email_binding_code(1, request.email)?;
    state
        .email_dispatch
        .send_verification_code(
            &prepared.target,
            &prepared.code,
            VerificationEmailKind::Auth,
        )
        .await?;
    let mut response = state.auth.commit_prepared_verification_code(&prepared)?;
    response["auth_result"] = json!("verify_code_sent");
    response["provider"] = json!("pending");
    response["redirect"] = json!("/dashboard");
    Ok(success(response))
}

async fn oauth_pending_create_account(
    State(state): State<AppState>,
    OriginalUri(uri): OriginalUri,
    headers: HeaderMap,
    Json(mut request): Json<OAuthCompletionRequest>,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    fill_pending_token_from_cookie(&mut request, &headers);
    let credential_password_hash = hash_password_for_repository(
        request
            .password
            .as_deref()
            .ok_or_else(|| ApiError::bad_request("password is required"))?,
    )?;
    let browser_session_key = oauth_browser_session_from_headers(&headers);
    let session = state
        .auth
        .oauth_session_from_completion_request(&request, browser_session_key.as_deref())?;
    ensure_repository_oauth_identity_available(&state, &session, None).await?;
    let (tokens, user) = state.auth.create_pending_oauth_account_with_session(
        &oauth_provider_from_path(uri.path()),
        request,
        browser_session_key.as_deref(),
    )?;
    let user_id = user
        .get("id")
        .and_then(Value::as_i64)
        .ok_or_else(|| ApiError::internal_server_error("oauth user id is missing"))?;
    let email = user
        .get("email")
        .and_then(Value::as_str)
        .unwrap_or("")
        .to_owned();
    persist_auth_credential(&state, user_id, email, credential_password_hash, "active").await?;
    persist_oauth_identity_from_session(&state, &session, user_id, &user).await?;
    persist_auth_session(&state, &tokens, user_id, "oauth_create_account").await?;
    Ok(success(auth_response(tokens, user)))
}

