async fn change_password(
    State(state): State<AppState>,
    headers: HeaderMap,
    Json(request): Json<ChangePasswordRequest>,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    let request_for_repository = request.clone();
    match state.auth.change_password_from_headers(&headers, request) {
        Ok(response) => {
            if let Ok(user_id) = current_user_id_from_headers_or_repository(&state, &headers).await
            {
                if let Ok(user) = state.repository.get_user(user_id).await {
                    persist_auth_credential(
                        &state,
                        user_id,
                        user.email,
                        hash_password_for_repository(&request_for_repository.new_password)?,
                        "active",
                    )
                    .await?;
                }
            }
            Ok(success(response))
        }
        Err(error) if error.status() == StatusCode::UNAUTHORIZED => {
            change_repository_password_from_headers(&state, &headers, request_for_repository).await
        }
        Err(error) => Err(error),
    }
}

