async fn transfer_affiliate_quota(
    State(state): State<AppState>,
    headers: HeaderMap,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    let user_id = authenticated_user_id(&state, &headers)?;
    ensure_repository_user(&state, user_id).await?;
    let (claim, mut profile) = claim_affiliate_quota_with_repository(&state, user_id).await?;
    let now = Utc::now().to_rfc3339();
    let transaction = match state
        .repository
        .apply_balance_transaction(repository::BalanceTransactionRecord {
            id: 0,
            user_id,
            order_id: format!(
                "affiliate-transfer-{user_id}-{}",
                uuid::Uuid::new_v4().simple()
            ),
            transaction_type: "affiliate_transfer".to_owned(),
            amount: claim.amount,
            balance_after: 0.0,
            created_at: now,
            metadata: json!({
                "available_quota_after": claim.available_quota_after,
                "frozen_quota_after": claim.frozen_quota_after,
                "history_quota_after": claim.history_quota_after,
                "snapshot_available": true,
                "source": "affiliate"
            }),
        })
        .await
    {
        Ok(transaction) => transaction,
        Err(error) => {
            rollback_affiliate_quota_claim_with_repository(&state, user_id, &mut profile, &claim)
                .await?;
            return Err(repository_api_error(error));
        }
    };
    store_affiliate_profile(&state, user_id, profile).await?;
    store_affiliate_transfer_record(&state, user_id, &claim, transaction.balance_after).await?;
    Ok(success(state.user_portal.commit_affiliate_transfer(
        user_id,
        &claim,
        transaction.balance_after,
    )))
}

async fn send_email_binding_code(
    State(state): State<AppState>,
    headers: HeaderMap,
    Json(request): Json<EmailRequest>,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    let user_id = authenticated_user_id(&state, &headers)?;
    if request.email.trim().is_empty() {
        return Err(ApiError::bad_request("email is required"));
    }
    let prepared = state
        .auth
        .prepare_email_binding_code(user_id, request.email)?;
    state
        .email_dispatch
        .send_verification_code(
            &prepared.target,
            &prepared.code,
            VerificationEmailKind::Auth,
        )
        .await?;
    Ok(success(
        state.auth.commit_prepared_verification_code(&prepared)?,
    ))
}

async fn bind_email_identity(
    State(state): State<AppState>,
    headers: HeaderMap,
    Json(request): Json<BindEmailIdentityRequest>,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    let user_id = authenticated_user_id(&state, &headers)?;
    let user = state.auth.bind_email_identity(
        user_id,
        request.email,
        request.verify_code,
        request.password,
    )?;
    sync_auth_user_to_repository(&state, &user).await?;
    if let Ok(mut credential) = state
        .repository
        .get_auth_credential_by_user_id(user_id)
        .await
    {
        credential.email = user
            .get("email")
            .and_then(Value::as_str)
            .unwrap_or("")
            .to_owned();
        credential.updated_at_unix = current_unix_time().max(1);
        state
            .repository
            .upsert_auth_credential(credential)
            .await
            .map_err(repository_api_error)?;
    }
    Ok(success(user))
}

