async fn totp_setup(
    State(state): State<AppState>,
    headers: HeaderMap,
    Json(request): Json<TotpSetupRequest>,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    let user_id = authenticated_user_id(&state, &headers)?;
    verify_totp_identity(
        &state,
        user_id,
        request.email_code.as_deref(),
        request.password.as_deref(),
    )?;
    let secret = crate::totp::generate_secret();
    let setup_token = format!("totp-setup-{}", uuid::Uuid::new_v4());
    let secret_encrypted = encrypt_totp_secret(&state, &secret)?;
    store_totp_state(
        &state,
        user_id,
        json!({
            "enabled": false,
            "enabled_at": Value::Null,
            "secret_encrypted": secret_encrypted,
            "setup_token": setup_token,
            "setup_started_at": current_unix_time()
        }),
    )
    .await?;
    Ok(success(json!({
        "secret": secret,
        "qr_code_url": format!("otpauth://totp/sub2api:user-{user_id}?secret={secret}&issuer=sub2api"),
        "setup_token": setup_token,
        "countdown": 300
    })))
}

async fn totp_enable(
    State(state): State<AppState>,
    headers: HeaderMap,
    Json(request): Json<TotpEnableRequest>,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    let user_id = authenticated_user_id(&state, &headers)?;
    if request.totp_code.trim().len() != 6 {
        return Err(ApiError::bad_request("totp_code must be 6 digits"));
    }
    let mut totp_state = load_totp_state(&state, user_id).await?;
    let setup_token = totp_state
        .get("setup_token")
        .and_then(Value::as_str)
        .ok_or_else(|| ApiError::bad_request("totp setup is required"))?;
    if setup_token != request.setup_token {
        return Err(ApiError::bad_request("invalid setup token"));
    }
    let secret = decrypt_totp_secret(&state, &totp_state)?;
    if !crate::totp::verify_code(&secret, &request.totp_code) {
        return Err(ApiError::bad_request("invalid totp code"));
    }
    let enabled_at = current_unix_time();
    totp_state["enabled"] = json!(true);
    totp_state["enabled_at"] = json!(enabled_at);
    totp_state["setup_token"] = Value::Null;
    store_totp_state(&state, user_id, totp_state).await?;
    Ok(success(json!({ "success": true })))
}

async fn totp_disable(
    State(state): State<AppState>,
    headers: HeaderMap,
    Json(request): Json<TotpDisableRequest>,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    let user_id = authenticated_user_id(&state, &headers)?;
    verify_totp_identity(
        &state,
        user_id,
        request.email_code.as_deref(),
        request.password.as_deref(),
    )?;
    let mut totp_state = load_totp_state(&state, user_id).await.unwrap_or_else(|_| {
        json!({
            "enabled": false,
            "enabled_at": Value::Null,
            "secret_encrypted": Value::Null,
            "secret": Value::Null,
            "setup_token": Value::Null
        })
    });
    totp_state["enabled"] = json!(false);
    totp_state["enabled_at"] = Value::Null;
    totp_state["setup_token"] = Value::Null;
    store_totp_state(&state, user_id, totp_state).await?;
    Ok(success(json!({ "success": true })))
}

fn verify_totp_identity(
    state: &AppState,
    user_id: i64,
    email_code: Option<&str>,
    password: Option<&str>,
) -> Result<(), ApiError> {
    if let Some(email_code) = email_code.map(str::trim).filter(|value| !value.is_empty()) {
        return state.auth.verify_totp_email_code(user_id, email_code);
    }
    state
        .auth
        .verify_user_password(user_id, password.unwrap_or_default())
}

async fn totp_status_value(state: &AppState, user_id: i64) -> Result<Value, ApiError> {
    let totp_state = load_totp_state(state, user_id).await.unwrap_or_else(|_| {
        json!({
            "enabled": false,
            "enabled_at": Value::Null
        })
    });
    Ok(json!({
        "enabled": totp_state.get("enabled").and_then(Value::as_bool).unwrap_or(false),
        "enabled_at": totp_state.get("enabled_at").cloned().unwrap_or(Value::Null),
        "feature_enabled": true
    }))
}

fn encrypt_totp_secret(state: &AppState, secret: &str) -> Result<String, ApiError> {
    state
        .totp_secret
        .encrypt(secret)
        .map_err(|error| ApiError::internal_server_error(error.to_string()))
}

fn decrypt_totp_secret(state: &AppState, totp_state: &Value) -> Result<String, ApiError> {
    let ciphertext = totp_state
        .get("secret_encrypted")
        .and_then(Value::as_str)
        .filter(|value| !value.trim().is_empty())
        .ok_or_else(|| {
            ApiError::internal_server_error(
                "totp secret is not encrypted; reconfigure totp for this user",
            )
        })?;
    state
        .totp_secret
        .decrypt(ciphertext)
        .map_err(|error| ApiError::internal_server_error(error.to_string()))
}

