async fn redeem_code_from_repository(
    state: &AppState,
    user_id: i64,
    request: RedeemRequest,
) -> Result<Value, ApiError> {
    let code = request.code.trim();
    if code.is_empty() {
        return Err(ApiError::bad_request("code is required"));
    }
    ensure_repository_user(state, user_id).await?;
    let redeem_item = repository_redeem_code_by_code(state, code).await?;
    ensure_redeem_code_can_use(&redeem_item)?;
    let redeem_type = string_field(&redeem_item, "type")
        .unwrap_or_else(|| "balance".to_owned())
        .to_ascii_lowercase();
    match redeem_type.as_str() {
        "balance" => redeem_balance_code(state, user_id, code, redeem_item).await,
        "subscription" => redeem_subscription_code(state, user_id, code, redeem_item).await,
        other => Err(ApiError::bad_request(format!(
            "unsupported redeem code type: {other}"
        ))),
    }
}

async fn repository_redeem_code_by_code(state: &AppState, code: &str) -> Result<Value, ApiError> {
    repository_redeem_code_items(state)
        .await?
        .into_iter()
        .find(|item| {
            item.get("code")
                .and_then(Value::as_str)
                .map(|value| value.eq_ignore_ascii_case(code))
                .unwrap_or(false)
        })
        .ok_or_else(|| ApiError::not_found("redeem code not found"))
}

async fn repository_redeem_code_items(state: &AppState) -> Result<Vec<Value>, ApiError> {
    let mut items = state
        .repository
        .list_admin_collection_items("redeem-codes")
        .await
        .map_err(repository_api_error)?
        .into_iter()
        .map(|record| record.item)
        .collect::<Vec<_>>();
    sort_admin_items_by_id(&mut items);
    Ok(items)
}

fn redeem_code_stats_from_items(items: &[Value]) -> Value {
    let mut used = 0;
    let mut unused = 0;
    let mut expired = 0;
    for item in items {
        match redeem_code_status(item).as_str() {
            "used" => used += 1,
            "expired" => expired += 1,
            _ => unused += 1,
        }
    }
    json!({
        "total": items.len(),
        "used": used,
        "unused": unused,
        "expired": expired
    })
}

fn redeem_code_csv_from_items(items: &[Value]) -> String {
    let mut content = "code,type,value,status\n".to_owned();
    for item in items {
        let code = csv_escape(string_field(item, "code").unwrap_or_default());
        let redeem_type =
            csv_escape(string_field(item, "type").unwrap_or_else(|| "balance".to_owned()));
        let value = item
            .get("value")
            .or_else(|| item.get("amount"))
            .map(csv_value)
            .unwrap_or_default();
        let status = csv_escape(redeem_code_status(item));
        content.push_str(&format!("{code},{redeem_type},{value},{status}\n"));
    }
    content
}

fn redeem_code_status(item: &Value) -> String {
    string_field(item, "status").unwrap_or_else(|| "unused".to_owned())
}

fn csv_value(value: &Value) -> String {
    match value {
        Value::String(value) => csv_escape(value.clone()),
        Value::Null => String::new(),
        other => csv_escape(other.to_string()),
    }
}

fn csv_escape(value: String) -> String {
    if value.contains([',', '"', '\n', '\r']) {
        format!("\"{}\"", value.replace('"', "\"\""))
    } else {
        value
    }
}

fn ensure_redeem_code_can_use(item: &Value) -> Result<(), ApiError> {
    let status = item
        .get("status")
        .and_then(Value::as_str)
        .unwrap_or("unused")
        .to_ascii_lowercase();
    match status.as_str() {
        "unused" | "active" => Ok(()),
        "expired" => Err(ApiError::conflict("redeem code expired")),
        _ => Err(ApiError::conflict("redeem code already used")),
    }
}

async fn redeem_balance_code(
    state: &AppState,
    user_id: i64,
    requested_code: &str,
    mut redeem_item: Value,
) -> Result<Value, ApiError> {
    let id = value_id(&redeem_item)
        .ok_or_else(|| ApiError::internal_server_error("redeem code id is missing"))?;
    let amount = redeem_item
        .get("value")
        .or_else(|| redeem_item.get("amount"))
        .and_then(Value::as_f64)
        .unwrap_or(0.0);
    let code = string_field(&redeem_item, "code").unwrap_or_else(|| requested_code.to_owned());
    let now = Utc::now().to_rfc3339();
    let transaction = state
        .repository
        .apply_balance_transaction(repository::BalanceTransactionRecord {
            id: 0,
            user_id,
            order_id: code.clone(),
            transaction_type: "redeem_balance".to_owned(),
            amount,
            balance_after: 0.0,
            created_at: now.clone(),
            metadata: json!({
                "redeem_code_id": id,
                "notes": redeem_item.get("notes").cloned().unwrap_or(Value::Null)
            }),
        })
        .await
        .map_err(repository_api_error)?;
    redeem_item["status"] = json!("used");
    redeem_item["used_by"] = json!(user_id);
    redeem_item["used_at"] = json!(now);
    state
        .repository
        .upsert_admin_collection_item(repository::AdminCollectionItemRecord {
            collection: "redeem-codes".to_owned(),
            id,
            item: redeem_item,
        })
        .await
        .map_err(repository_api_error)?;
    let _ = accrue_affiliate_rebate_for_redeem(state, user_id, amount, &code, id).await;
    Ok(json!({
        "id": id,
        "code": code,
        "message": "ok",
        "type": "balance",
        "value": amount,
        "new_balance": transaction.balance_after,
        "status": "used",
        "used_at": transaction.created_at
    }))
}

async fn redeem_subscription_code(
    state: &AppState,
    user_id: i64,
    requested_code: &str,
    mut redeem_item: Value,
) -> Result<Value, ApiError> {
    let id = value_id(&redeem_item)
        .ok_or_else(|| ApiError::internal_server_error("redeem code id is missing"))?;
    let group_id = redeem_item
        .get("group_id")
        .and_then(Value::as_i64)
        .ok_or_else(|| {
            ApiError::bad_request("invalid subscription redeem code: missing group_id")
        })?;
    ensure_repository_user(state, user_id).await?;
    let group = state
        .repository
        .get_group(GroupId(group_id))
        .await
        .or_else(|error| match error {
            repository::RepositoryError::NotFound { .. } => {
                group_from_admin_collection(state, group_id)
            }
            other => Err(other),
        })
        .map_err(repository_api_error)?;
    if group.status != domain::GroupStatus::Active {
        return Err(ApiError::bad_request("target group is not active"));
    }
    let validity_days = redeem_item
        .get("validity_days")
        .or_else(|| redeem_item.get("value"))
        .and_then(Value::as_i64)
        .unwrap_or(30)
        .clamp(1, 36500);
    let code = string_field(&redeem_item, "code").unwrap_or_else(|| requested_code.to_owned());
    let now = Utc::now();
    let subscription = state
        .repository
        .upsert_user_subscription(repository::UserSubscriptionRecord {
            id: 0,
            user_id,
            group_id,
            plan_id: redeem_item.get("plan_id").and_then(Value::as_i64),
            status: "active".to_owned(),
            starts_at: now.to_rfc3339(),
            expires_at: (now + Duration::days(validity_days)).to_rfc3339(),
            daily_usage_usd: 0.0,
            weekly_usage_usd: 0.0,
            monthly_usage_usd: 0.0,
            daily_window_start: None,
            weekly_window_start: None,
            monthly_window_start: None,
            source_order_id: format!("redeem-{code}"),
            created_at: now.to_rfc3339(),
            metadata: json!({
                "source": "redeem",
                "redeem_code_id": id,
                "redeem_code": code,
                "validity_days": validity_days,
                "notes": redeem_item.get("notes").cloned().unwrap_or(Value::Null)
            }),
        })
        .await
        .map_err(repository_api_error)?;
    let used_at = now.to_rfc3339();
    redeem_item["status"] = json!("used");
    redeem_item["used_by"] = json!(user_id);
    redeem_item["used_at"] = json!(used_at);
    state
        .repository
        .upsert_admin_collection_item(repository::AdminCollectionItemRecord {
            collection: "redeem-codes".to_owned(),
            id,
            item: redeem_item,
        })
        .await
        .map_err(repository_api_error)?;
    Ok(json!({
        "id": id,
        "code": code,
        "message": "ok",
        "type": "subscription",
        "value": validity_days,
        "group_id": group_id,
        "validity_days": validity_days,
        "subscription_id": subscription.id,
        "expires_at": subscription.expires_at,
        "status": "used",
        "used_at": used_at
    }))
}

async fn repository_announcements_for_user(
    state: &AppState,
    user_id: i64,
    unread_only: bool,
) -> Result<Value, ApiError> {
    let mut announcements = state
        .repository
        .list_admin_collection_items("announcements")
        .await
        .map_err(repository_api_error)?
        .into_iter()
        .filter_map(|record| user_announcement_from_repository_item(record.item, user_id))
        .filter(|item| {
            if unread_only {
                item.get("read_at").map(Value::is_null).unwrap_or(true)
            } else {
                true
            }
        })
        .collect::<Vec<_>>();
    announcements.sort_by(|left, right| {
        let left_read = left.get("read_at").map(Value::is_null) == Some(false);
        let right_read = right.get("read_at").map(Value::is_null) == Some(false);
        left_read
            .cmp(&right_read)
            .then_with(|| value_id(right).cmp(&value_id(left)))
    });
    Ok(Value::Array(announcements))
}

async fn repository_visible_announcement(
    state: &AppState,
    _user_id: i64,
    id: i64,
) -> Result<Value, ApiError> {
    let record = state
        .repository
        .get_admin_collection_item("announcements", id)
        .await
        .map_err(|error| match error {
            repository::RepositoryError::NotFound { .. } => {
                ApiError::not_found("announcement not found")
            }
            other => repository_api_error(other),
        })?;
    user_announcement_from_repository_item(record.item, 0)
        .ok_or_else(|| ApiError::not_found("announcement not found"))
}

fn user_announcement_from_repository_item(mut item: Value, _user_id: i64) -> Option<Value> {
    if !item
        .get("status")
        .and_then(Value::as_str)
        .map(|status| status.eq_ignore_ascii_case("active"))
        .unwrap_or(false)
    {
        return None;
    }
    let object = item.as_object_mut()?;
    if !object.contains_key("notify_mode") {
        object.insert("notify_mode".to_owned(), json!("none"));
    }
    if !object.contains_key("starts_at") {
        object.insert("starts_at".to_owned(), Value::Null);
    }
    if !object.contains_key("ends_at") {
        object.insert("ends_at".to_owned(), Value::Null);
    }
    if !object.contains_key("read_at") {
        object.insert("read_at".to_owned(), Value::Null);
    }
    if !object.contains_key("created_at") {
        object.insert("created_at".to_owned(), json!("2026-06-06T00:00:00Z"));
    }
    if !object.contains_key("updated_at") {
        object.insert("updated_at".to_owned(), json!("2026-06-06T00:00:00Z"));
    }
    object.remove("status");
    object.remove("targeting");
    object.remove("created_by");
    object.remove("updated_by");
    Some(item)
}

