async fn active_channel_items(state: &AppState) -> Result<Value, ApiError> {
    let mut channels = state
        .repository
        .list_admin_collection_items("channels")
        .await
        .map_err(repository_api_error)?
        .into_iter()
        .map(|record| record.item)
        .filter(|item| {
            item.get("status")
                .and_then(Value::as_str)
                .map(|status| status.eq_ignore_ascii_case("active"))
                .unwrap_or(false)
        })
        .collect::<Vec<_>>();
    channels.sort_by_key(|item| value_id(item).unwrap_or(i64::MAX));
    Ok(Value::Array(channels))
}

