async fn create_payment_order(
    State(state): State<AppState>,
    headers: HeaderMap,
    Json(request): Json<CreateOrderRequest>,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    let user_id = authenticated_user_id(&state, &headers)?;
    ensure_repository_user(&state, user_id).await?;
    let resolved_plan = resolve_payment_order_plan(&state, &request).await?;
    let request = request_with_resolved_plan(request, resolved_plan.as_ref());
    let provider_instances = repository_payment_provider_instances(&state).await?;
    let mut order = state
        .payment_portal
        .create_order(user_id, request, &provider_instances)
        .await?;
    enrich_payment_order_response_with_plan(&mut order, resolved_plan.as_ref());
    let mut persisted_order = order.clone();
    if let Value::Object(object) = &mut persisted_order {
        object.entry("user_id").or_insert(json!(user_id));
    }
    sync_payment_order_from_json(&state, &persisted_order).await?;
    Ok(success(order))
}

