async fn admin_dashboard_backfill(
    State(state): State<AppState>,
    Json(payload): Json<Value>,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    let (start, end) = parse_dashboard_backfill_payload(&payload)?;
    if end <= start {
        return Err(ApiError::bad_request("Invalid backfill time range"));
    }
    if end - start > Duration::days(31) {
        return Err(ApiError::bad_request("Backfill range too large"));
    }

    state.admin_portal.dashboard_backfill(json!({
        "start": start.to_rfc3339_opts(chrono::SecondsFormat::Secs, true),
        "end": end.to_rfc3339_opts(chrono::SecondsFormat::Secs, true)
    }))?;

    Ok(success(json!({ "status": "accepted" })))
}

