async fn admin_group_api_keys(
    State(state): State<AppState>,
    Path(id): Path<i64>,
    Query(query): Query<HashMap<String, String>>,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    let page = query_i64(&query, "page", 1).max(1);
    let page_size = query_i64(&query, "page_size", 20).clamp(1, 200);
    state
        .repository
        .get_group(GroupId(id))
        .await
        .or_else(|error| match error {
            repository::RepositoryError::NotFound { .. } => group_from_admin_collection(&state, id),
            other => Err(other),
        })
        .map_err(repository_api_error)?;
    let mut items = state
        .repository
        .list_api_keys_by_group(GroupId(id))
        .await
        .map_err(repository_api_error)?
        .into_iter()
        .filter(is_public_repository_api_key)
        .map(api_key_to_admin_json)
        .collect::<Vec<_>>();
    items.sort_by_key(|item| item["id"].as_i64().unwrap_or_default());
    let total = items.len() as i64;
    let start = ((page - 1) * page_size) as usize;
    let page_items = items
        .into_iter()
        .skip(start)
        .take(page_size as usize)
        .collect::<Vec<_>>();
    let total_pages = if total == 0 {
        0
    } else {
        ((total as f64) / (page_size as f64)).ceil() as i64
    };
    Ok(success(json!({
        "items": page_items,
        "total": total,
        "page": page,
        "page_size": page_size,
        "pages": total_pages,
        "total_pages": total_pages
    })))
}

