async fn ensure_group_exists_for_overrides(
    state: &AppState,
    group_id: i64,
) -> Result<(), ApiError> {
    match state.repository.get_group(GroupId(group_id)).await {
        Ok(_) => Ok(()),
        Err(repository::RepositoryError::NotFound { .. }) => state
            .admin_portal
            .get_collection_item("groups", group_id)
            .map(|_| ()),
        Err(error) => Err(repository_api_error(error)),
    }
}

fn user_group_rate_records_from_payload(
    group_id: i64,
    payload: &Value,
    rate_mode: bool,
) -> Result<Vec<repository::UserGroupRateRecord>, ApiError> {
    let entries = payload
        .get("entries")
        .and_then(Value::as_array)
        .ok_or_else(|| ApiError::bad_request("entries is required"))?;
    let now = Utc::now().to_rfc3339();
    entries
        .iter()
        .map(|entry| {
            let user_id = entry
                .get("user_id")
                .and_then(Value::as_i64)
                .filter(|value| *value > 0)
                .ok_or_else(|| ApiError::bad_request("user_id is required"))?;
            let rate_multiplier = if rate_mode {
                Some(
                    entry
                        .get("rate_multiplier")
                        .and_then(Value::as_f64)
                        .filter(|value| value.is_finite() && *value > 0.0)
                        .ok_or_else(|| {
                            ApiError::bad_request("rate_multiplier must be greater than zero")
                        })?,
                )
            } else {
                None
            };
            let rpm_override =
                if rate_mode {
                    None
                } else {
                    let value = entry
                        .get("rpm_override")
                        .or_else(|| entry.get("rpm_limit"))
                        .and_then(Value::as_i64)
                        .filter(|value| *value >= 0)
                        .ok_or_else(|| ApiError::bad_request("rpm_override must be >= 0"))?;
                    Some(i32::try_from(value).map_err(|_| {
                        ApiError::bad_request("rpm_override exceeds supported range")
                    })?)
                };
            Ok(repository::UserGroupRateRecord {
                user_id,
                group_id,
                rate_multiplier,
                rpm_override,
                updated_at: now.clone(),
            })
        })
        .collect()
}

async fn user_group_rate_records_json(
    state: &AppState,
    records: Vec<repository::UserGroupRateRecord>,
) -> Result<Value, ApiError> {
    let users = state
        .repository
        .list_users()
        .await
        .map_err(repository_api_error)?
        .into_iter()
        .map(|user| (user.id, user))
        .collect::<HashMap<_, _>>();
    Ok(Value::Array(
        records
            .into_iter()
            .map(|record| {
                let user = users.get(&record.user_id);
                json!({
                    "user_id": record.user_id,
                    "user_name": user.map(|user| user.username.clone()).unwrap_or_default(),
                    "user_email": user.map(|user| user.email.clone()).unwrap_or_default(),
                    "user_notes": "",
                    "user_status": user.map(|user| user.status.clone()).unwrap_or_default(),
                    "rate_multiplier": record.rate_multiplier,
                    "rpm_override": record.rpm_override
                })
            })
            .collect::<Vec<_>>(),
    ))
}

