fn user_attribute_value_records_json(
    user_id: i64,
    records: Vec<repository::UserAttributeValueRecord>,
) -> Value {
    Value::Array(
        records
            .into_iter()
            .map(|record| {
                let id = if record.attribute_id > 0 {
                    record.attribute_id
                } else {
                    user_id
                };
                let created_at = if record.created_at.trim().is_empty() {
                    "2026-06-06T00:00:00Z".to_owned()
                } else {
                    record.created_at
                };
                let updated_at = if record.updated_at.trim().is_empty() {
                    "2026-06-06T00:00:00Z".to_owned()
                } else {
                    record.updated_at
                };
                json!({
                    "id": id,
                    "user_id": user_id,
                    "attribute_id": record.attribute_id,
                    "value": record.value,
                    "created_at": created_at,
                    "updated_at": updated_at
                })
            })
            .collect::<Vec<_>>(),
    )
}

fn user_attribute_value_records_from_payload(
    user_id: i64,
    payload: &Value,
) -> Result<Vec<repository::UserAttributeValueRecord>, ApiError> {
    let values = payload
        .get("values")
        .and_then(Value::as_object)
        .ok_or_else(|| ApiError::bad_request("values is required"))?;
    let now = Utc::now().to_rfc3339();
    values
        .iter()
        .map(|(attribute_id, value)| {
            let attribute_id = attribute_id
                .parse::<i64>()
                .map_err(|_| ApiError::bad_request("attribute id must be an integer"))?;
            Ok(repository::UserAttributeValueRecord {
                user_id,
                attribute_id,
                value: value
                    .as_str()
                    .map(ToOwned::to_owned)
                    .unwrap_or_else(|| value.to_string()),
                created_at: now.clone(),
                updated_at: now.clone(),
            })
        })
        .collect()
}

fn user_attribute_value_map(records: Vec<repository::UserAttributeValueRecord>) -> Value {
    json!(records
        .into_iter()
        .map(|record| (record.attribute_id.to_string(), json!(record.value)))
        .collect::<Map<_, _>>())
}

