async fn admin_user_platform_quotas(
    State(state): State<AppState>,
    Path(id): Path<i64>,
    method: Method,
    body: Bytes,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    ensure_repository_user(&state, id).await?;
    match method {
        Method::GET => {
            let quotas = state
                .repository
                .list_user_platform_quotas(id)
                .await
                .map_err(repository_api_error)?;
            if quotas.is_empty() {
                return Ok(success(state.admin_portal.user_platform_quotas(id)?));
            }
            Ok(success(user_views::platform_quota_response(&quotas, true)))
        }
        Method::PUT => {
            let payload = parse_json_body(&body)?;
            let mut quotas = user_platform_quota_records_from_payload(id, &payload)?;
            let existing = state
                .repository
                .list_user_platform_quotas(id)
                .await
                .map_err(repository_api_error)?;
            let existing_by_platform = existing
                .into_iter()
                .map(|record| (record.platform.clone(), record))
                .collect::<HashMap<_, _>>();
            for quota in &mut quotas {
                if let Some(existing) = existing_by_platform.get(&quota.platform) {
                    quota.id = existing.id;
                    quota.daily_usage_usd = existing.daily_usage_usd;
                    quota.weekly_usage_usd = existing.weekly_usage_usd;
                    quota.monthly_usage_usd = existing.monthly_usage_usd;
                    quota.daily_window_start = existing.daily_window_start.clone();
                    quota.weekly_window_start = existing.weekly_window_start.clone();
                    quota.monthly_window_start = existing.monthly_window_start.clone();
                }
            }
            let saved = state
                .repository
                .replace_user_platform_quotas(id, quotas)
                .await
                .map_err(repository_api_error)?;
            Ok(success(user_views::platform_quota_response(&saved, true)))
        }
        Method::POST => {
            let payload = parse_json_body(&body)?;
            let platform = payload
                .get("platform")
                .and_then(Value::as_str)
                .ok_or_else(|| ApiError::bad_request("platform is required"))?;
            let window = payload
                .get("window")
                .and_then(Value::as_str)
                .unwrap_or("daily");
            let mut quotas = state
                .repository
                .list_user_platform_quotas(id)
                .await
                .map_err(repository_api_error)?;
            let mut matched = false;
            let now = Utc::now();
            for quota in &mut quotas {
                if quota.platform != platform {
                    continue;
                }
                matched = true;
                crate::quota_window::reset_quota_window(quota, window, now)
                    .map_err(ApiError::bad_request)?;
            }
            if !matched {
                return Err(ApiError::not_found("user platform quota not found"));
            }
            let saved = state
                .repository
                .replace_user_platform_quotas(id, quotas)
                .await
                .map_err(repository_api_error)?;
            Ok(success(user_views::platform_quota_response(&saved, true)))
        }
        _ => Err(ApiError::bad_request("unsupported platform quota method")),
    }
}

