async fn admin_update_user_balance(
    State(state): State<AppState>,
    Path(id): Path<i64>,
    Json(payload): Json<Value>,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    ensure_repository_user(&state, id).await?;
    seed_repository_balance_from_admin_user(&state, id).await?;
    let amount = payload
        .get("balance")
        .and_then(Value::as_f64)
        .ok_or_else(|| ApiError::bad_request("balance is required"))?;
    if amount <= 0.0 {
        return Err(ApiError::bad_request("balance must be greater than 0"));
    }
    let operation = payload
        .get("operation")
        .and_then(Value::as_str)
        .unwrap_or("set");
    let current = state
        .repository
        .get_user_balance(id)
        .await
        .map_err(repository_api_error)?
        .balance;
    let delta = match operation {
        "set" => amount - current,
        "add" => amount,
        "subtract" => -amount,
        _ => {
            return Err(ApiError::bad_request(
                "operation must be one of set, add, subtract",
            ))
        }
    };
    let next = current + delta;
    if next < 0.0 {
        return Err(ApiError::bad_request(format!(
            "balance cannot be negative, current balance: {current:.2}, requested operation would result in: {next:.2}"
        )));
    }

    if delta.abs() > f64::EPSILON {
        state
            .repository
            .apply_balance_transaction(repository::BalanceTransactionRecord {
                id: 0,
                user_id: id,
                order_id: format!("admin-balance-{id}-{}", uuid::Uuid::new_v4().simple()),
                transaction_type: "admin_balance".to_owned(),
                amount: delta,
                balance_after: 0.0,
                created_at: "2026-06-06T00:00:00Z".to_owned(),
                metadata: json!({
                    "operation": operation,
                    "requested_balance": amount,
                    "old_balance": current,
                    "notes": payload.get("notes").and_then(Value::as_str).unwrap_or("")
                }),
            })
            .await
            .map_err(repository_api_error)?;
    }

    let updated =
        state
            .admin_portal
            .update_collection_item("users", id, json!({ "balance": next }))?;
    Ok(success(updated))
}

async fn admin_replace_user_group(
    State(state): State<AppState>,
    Path(id): Path<i64>,
    Json(payload): Json<Value>,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    state.admin_portal.get_collection_item("users", id)?;
    let old_group_id = payload
        .get("old_group_id")
        .and_then(Value::as_i64)
        .ok_or_else(|| ApiError::bad_request("old_group_id is required"))?;
    let new_group_id = payload
        .get("new_group_id")
        .and_then(Value::as_i64)
        .ok_or_else(|| ApiError::bad_request("new_group_id is required"))?;
    state
        .admin_portal
        .get_collection_item("groups", old_group_id)?;
    state
        .admin_portal
        .get_collection_item("groups", new_group_id)?;
    let migrated_keys = state
        .auth
        .replace_user_group_keys(id, old_group_id, new_group_id);
    let mut repository_migrated_keys = 0;
    for mut api_key in public_repository_api_keys_by_user(&state, id).await? {
        if api_key.group_id == Some(GroupId(old_group_id)) {
            api_key.group_id = Some(GroupId(new_group_id));
            state
                .repository
                .upsert_api_key(api_key)
                .await
                .map_err(repository_api_error)?;
            repository_migrated_keys += 1;
        }
    }
    Ok(success(json!({
        "migrated_keys": migrated_keys.max(repository_migrated_keys)
    })))
}

