async fn admin_account_apply_oauth_credentials(
    State(state): State<AppState>,
    Path(id): Path<i64>,
    Json(payload): Json<Value>,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    let existing = state.admin_portal.get_collection_item("accounts", id)?;
    if !admin_account_is_oauth(&existing) {
        return Err(ApiError::bad_request(
            "cannot apply oauth credentials to non-OAuth account",
        ));
    }

    let credentials = payload
        .get("credentials")
        .cloned()
        .filter(Value::is_object)
        .ok_or_else(|| ApiError::bad_request("credentials is required"))?;
    let account_type = payload
        .get("type")
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| matches!(*value, "oauth" | "setup-token"))
        .ok_or_else(|| ApiError::bad_request("type must be oauth or setup-token"))?;
    let extra = merge_account_extra(
        existing.get("extra").cloned().unwrap_or_else(|| json!({})),
        payload.get("extra").cloned().unwrap_or_else(|| json!({})),
        &credentials,
        account_type,
    );
    let api_key = credentials
        .get("access_token")
        .or_else(|| credentials.get("api_key"))
        .and_then(Value::as_str)
        .map(str::trim)
        .unwrap_or("");

    let updated = state.admin_portal.update_collection_item(
        "accounts",
        id,
        json!({
            "type": account_type,
            "credentials": credentials,
            "extra": extra,
            "api_key": api_key,
            "error_message": "",
            "oauth": payload
        }),
    )?;
    sync_admin_collection_item_to_repository(&state, "accounts", &updated).await?;

    Ok(success(account_response_with_redacted_credentials(updated)))
}

