async fn admin_proxy_stats(
    State(state): State<AppState>,
    Path(id): Path<i64>,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    let proxy = state.admin_portal.get_collection_item("proxies", id)?;
    let accounts = proxy_accounts_for_stats(&state, id);
    let active_accounts = accounts
        .iter()
        .filter(|account| {
            account
                .get("status")
                .and_then(Value::as_str)
                .map(|status| matches!(status, "active" | "enabled"))
                .unwrap_or(true)
        })
        .count() as i64;
    let account_ids = accounts
        .iter()
        .filter_map(|account| account.get("id").and_then(Value::as_i64))
        .collect::<Vec<_>>();
    let mut usage_records = Vec::new();
    for account_id in &account_ids {
        usage_records.extend(
            repository_usage_records(
                &state,
                repository::UsageFilter {
                    account_id: Some(AccountId(*account_id)),
                    ..repository::UsageFilter::all()
                },
            )
            .await?,
        );
    }
    let total_requests = usage_records.len() as i64;
    let failed_requests = usage_records
        .iter()
        .filter(|record| matches!(record.status.as_str(), "failed" | "error"))
        .count() as i64;
    let success_requests = total_requests - failed_requests;
    let duration_sum = usage_records
        .iter()
        .filter_map(|record| record.metadata.get("duration_ms").and_then(Value::as_i64))
        .sum::<i64>();
    let duration_count = usage_records
        .iter()
        .filter(|record| {
            record
                .metadata
                .get("duration_ms")
                .and_then(Value::as_i64)
                .is_some()
        })
        .count() as i64;
    let average_latency_ms = if duration_count > 0 {
        duration_sum / duration_count
    } else {
        proxy.get("latency_ms").and_then(Value::as_i64).unwrap_or(0)
    };
    let success_rate = if total_requests > 0 {
        success_requests as f64 * 100.0 / total_requests as f64
    } else if proxy
        .get("last_test_success")
        .and_then(Value::as_bool)
        .unwrap_or(false)
    {
        100.0
    } else {
        0.0
    };
    Ok(success(json!({
        "id": id,
        "total_accounts": account_ids.len() as i64,
        "active_accounts": active_accounts,
        "total_requests": total_requests,
        "success_requests": success_requests,
        "failed_requests": failed_requests,
        "success_rate": success_rate,
        "average_latency": average_latency_ms,
        "average_latency_ms": average_latency_ms,
        "last_tested_at": proxy.get("last_tested_at").cloned().unwrap_or(Value::Null),
        "last_test_success": proxy.get("last_test_success").cloned().unwrap_or(Value::Null),
        "latency_status": proxy.get("latency_status").cloned().unwrap_or(Value::Null),
        "latency_message": proxy.get("latency_message").cloned().unwrap_or(Value::Null),
        "quality_status": proxy.get("quality_status").cloned().unwrap_or(Value::Null),
        "quality_score": proxy.get("quality_score").cloned().unwrap_or(Value::Null),
        "quality_grade": proxy.get("quality_grade").cloned().unwrap_or(Value::Null),
        "quality_summary": proxy.get("quality_summary").cloned().unwrap_or(Value::Null),
    })))
}

