async fn admin_bulk_assign_subscriptions(
    State(state): State<AppState>,
    Json(payload): Json<Value>,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    let user_ids = payload
        .get("user_ids")
        .and_then(Value::as_array)
        .ok_or_else(|| ApiError::bad_request("user_ids is required"))?;
    if user_ids.is_empty() {
        return Err(ApiError::bad_request("user_ids must not be empty"));
    }
    let mut created = Vec::with_capacity(user_ids.len());
    for user_id in user_ids {
        let user_id = user_id
            .as_i64()
            .ok_or_else(|| ApiError::bad_request("user_ids must be numbers"))?;
        let mut item_payload = payload.clone();
        if let Some(object) = item_payload.as_object_mut() {
            object.insert("user_id".to_owned(), json!(user_id));
        }
        let subscription = assign_repository_subscription(&state, &item_payload).await?;
        created.push(admin_subscription_json(&state, &subscription).await);
    }
    Ok(success(json!(created)))
}

