async fn admin_extend_subscription(
    State(state): State<AppState>,
    Path(id): Path<i64>,
    Json(payload): Json<Value>,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    let days = payload
        .get("days")
        .and_then(Value::as_i64)
        .ok_or_else(|| ApiError::bad_request("days is required"))?;
    if !(-36500..=36500).contains(&days) || days == 0 {
        return Err(ApiError::bad_request(
            "days must be between -36500 and 36500",
        ));
    }
    let mut subscription = state
        .repository
        .get_user_subscription(id)
        .await
        .map_err(repository_api_error)?;
    let now = Utc::now();
    let expires_at = parse_rfc3339_utc(&subscription.expires_at)
        .ok_or_else(|| ApiError::bad_request("subscription expires_at is invalid"))?;
    let base = if expires_at > now { expires_at } else { now };
    let new_expires_at = base + Duration::days(days);
    if new_expires_at <= now {
        return Err(ApiError::bad_request(
            "adjustment would result in expired subscription",
        ));
    }
    subscription.expires_at = new_expires_at.to_rfc3339();
    if subscription.status.eq_ignore_ascii_case("expired") {
        subscription.status = "active".to_owned();
    }
    let subscription = state
        .repository
        .update_user_subscription(subscription)
        .await
        .map_err(repository_api_error)?;
    Ok(success(
        admin_subscription_json(&state, &subscription).await,
    ))
}

async fn admin_reset_subscription_quota(
    State(state): State<AppState>,
    Path(id): Path<i64>,
    Json(payload): Json<Value>,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    let reset_daily = payload
        .get("daily")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let reset_weekly = payload
        .get("weekly")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let reset_monthly = payload
        .get("monthly")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    if !reset_daily && !reset_weekly && !reset_monthly {
        return Err(ApiError::bad_request(
            "At least one of daily, weekly, or monthly must be true",
        ));
    }
    let mut subscription = state
        .repository
        .get_user_subscription(id)
        .await
        .map_err(repository_api_error)?;
    let window_start = Utc::now().to_rfc3339();
    if reset_daily {
        subscription.daily_usage_usd = 0.0;
        subscription.daily_window_start = Some(window_start.clone());
    }
    if reset_weekly {
        subscription.weekly_usage_usd = 0.0;
        subscription.weekly_window_start = Some(window_start.clone());
    }
    if reset_monthly {
        subscription.monthly_usage_usd = 0.0;
        subscription.monthly_window_start = Some(window_start);
    }
    let subscription = state
        .repository
        .update_user_subscription(subscription)
        .await
        .map_err(repository_api_error)?;
    Ok(success(
        admin_subscription_json(&state, &subscription).await,
    ))
}

