async fn admin_channel_monitor_run(
    State(state): State<AppState>,
    Path(id): Path<i64>,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    let config = state.admin_portal.channel_monitor_config(id)?;
    let results = crate::channel_monitor_probe::run_monitor(&config).await?;
    let checked_at = Utc::now().to_rfc3339();
    let mut saved_results = Vec::with_capacity(results.len());
    for result in results {
        let record = state
            .repository
            .insert_channel_monitor_history(repository::ChannelMonitorHistoryRecord {
                id: 0,
                monitor_id: id,
                model: result.model,
                status: result.status.to_owned(),
                latency_ms: result.latency_ms,
                ping_latency_ms: result.ping_latency_ms,
                message: result.message,
                checked_at: checked_at.clone(),
                metadata: json!({}),
            })
            .await
            .map_err(repository_api_error)?;
        saved_results.push(channel_monitor_history_record_json(record));
    }

    let primary = saved_results.first();
    state.admin_portal.update_collection_item(
        "channel-monitors",
        id,
        json!({
            "last_checked_at": checked_at,
            "primary_status": primary
                .and_then(|result| result.get("status"))
                .cloned()
                .unwrap_or_else(|| json!("unknown")),
            "primary_latency_ms": primary
                .and_then(|result| result.get("latency_ms"))
                .cloned()
                .unwrap_or(Value::Null),
            "primary_model": primary
                .and_then(|result| result.get("model"))
                .cloned()
                .unwrap_or_else(|| json!("gpt-5.4"))
        }),
    )?;
    Ok(success(json!({ "results": saved_results })))
}

async fn admin_channel_monitor_history(
    State(state): State<AppState>,
    Path(id): Path<i64>,
    Query(query): Query<HashMap<String, String>>,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    state
        .admin_portal
        .get_collection_item("channel-monitors", id)?;
    let page = query_i64(&query, "page", 1).max(1);
    let page_size = query_i64(&query, "page_size", 20).clamp(1, 100);
    let history = state
        .repository
        .list_channel_monitor_history(id, repository::Pagination::new(page, page_size))
        .await
        .map_err(repository_api_error)?;
    Ok(success(channel_monitor_history_page_json(history)))
}

