const AFFILIATE_PROFILES_COLLECTION: &str = "affiliate-profiles";
const AFFILIATE_INVITES_COLLECTION: &str = "affiliate-invites";
const AFFILIATE_REBATES_COLLECTION: &str = "affiliate-rebates";
const AFFILIATE_TRANSFERS_COLLECTION: &str = "affiliate-transfers";

async fn affiliate_detail_with_repository(
    state: &AppState,
    user_id: i64,
) -> Result<Value, ApiError> {
    thaw_affiliate_frozen_quota(state, user_id).await?;
    let profile = affiliate_profile_or_default(state, user_id).await?;
    let invitees = affiliate_invitee_items(state, user_id).await?;
    Ok(json!({
        "user_id": user_id,
        "aff_code": profile_string(&profile, "aff_code", &default_aff_code(user_id)),
        "inviter_id": profile.get("inviter_id").cloned().unwrap_or(Value::Null),
        "aff_count": profile_i64(&profile, "aff_count"),
        "aff_quota": profile_f64_any(&profile, &["aff_quota", "available_quota"]),
        "aff_frozen_quota": profile_f64_any(&profile, &["aff_frozen_quota", "frozen_quota"]),
        "aff_history_quota": profile_f64_any(&profile, &["aff_history_quota", "history_quota"]),
        "effective_rebate_rate_percent": affiliate_effective_rebate_rate(
            &profile,
            &repository_setting_or_default(state, "admin", "settings", default_admin_settings()).await?
        ),
        "invitees": invitees
    }))
}

async fn claim_affiliate_quota_with_repository(
    state: &AppState,
    user_id: i64,
) -> Result<(AffiliateTransferClaim, Value), ApiError> {
    thaw_affiliate_frozen_quota(state, user_id).await?;
    let mut profile = affiliate_profile_or_default(state, user_id).await?;
    let amount = profile_f64_any(&profile, &["aff_quota", "available_quota"]);
    if amount <= f64::EPSILON {
        return Err(ApiError::bad_request(
            "no affiliate quota available to transfer",
        ));
    }
    let frozen = profile_f64_any(&profile, &["aff_frozen_quota", "frozen_quota"]);
    let history = profile_f64_any(&profile, &["aff_history_quota", "history_quota"]);
    set_affiliate_quota_fields(&mut profile, 0.0, frozen, history);
    profile["updated_at"] = json!(Utc::now().to_rfc3339());
    Ok((
        AffiliateTransferClaim {
            amount,
            available_quota_after: 0.0,
            frozen_quota_after: frozen,
            history_quota_after: history,
        },
        profile,
    ))
}

async fn rollback_affiliate_quota_claim_with_repository(
    state: &AppState,
    user_id: i64,
    profile: &mut Value,
    claim: &AffiliateTransferClaim,
) -> Result<(), ApiError> {
    let available = profile_f64_any(profile, &["aff_quota", "available_quota"]) + claim.amount;
    set_affiliate_quota_fields(
        profile,
        available,
        claim.frozen_quota_after,
        claim.history_quota_after,
    );
    profile["updated_at"] = json!(Utc::now().to_rfc3339());
    store_affiliate_profile(state, user_id, profile.clone()).await
}

async fn affiliate_profile_or_default(state: &AppState, user_id: i64) -> Result<Value, ApiError> {
    match state
        .repository
        .get_admin_collection_item(AFFILIATE_PROFILES_COLLECTION, user_id)
        .await
    {
        Ok(record) => Ok(normalize_affiliate_profile(user_id, record.item)),
        Err(repository::RepositoryError::NotFound { .. }) => {
            let fallback = state.user_portal.affiliate_detail(user_id);
            let profile = normalize_affiliate_profile(user_id, fallback);
            store_affiliate_profile(state, user_id, profile.clone()).await?;
            Ok(profile)
        }
        Err(error) => Err(repository_api_error(error)),
    }
}

async fn thaw_affiliate_frozen_quota(state: &AppState, user_id: i64) -> Result<f64, ApiError> {
    let records = state
        .repository
        .list_admin_collection_items(AFFILIATE_REBATES_COLLECTION)
        .await
        .map_err(repository_api_error)?;
    let now = Utc::now();
    let mut thawed = 0.0;
    let mut matured_records = Vec::new();
    for record in records {
        let mut rebate = record.item;
        let rebate_user_id = rebate
            .get("inviter_id")
            .or_else(|| rebate.get("inviter_user_id"))
            .and_then(Value::as_i64);
        if rebate_user_id != Some(user_id) || !affiliate_rebate_is_frozen(&rebate) {
            continue;
        }
        let Some(available_at) = affiliate_rebate_available_at(&rebate)? else {
            continue;
        };
        if available_at > now {
            continue;
        }
        let amount = profile_f64_any(&rebate, &["rebate_quota", "rebate_amount"]);
        if amount <= f64::EPSILON {
            continue;
        }
        thawed += amount;
        rebate["status"] = json!("available");
        rebate["frozen_until"] = Value::Null;
        rebate["thawed_at"] = json!(now.to_rfc3339());
        matured_records.push(repository::AdminCollectionItemRecord {
            collection: AFFILIATE_REBATES_COLLECTION.to_owned(),
            id: record.id,
            item: rebate,
        });
    }
    if thawed <= f64::EPSILON {
        return Ok(0.0);
    }

    let mut profile = affiliate_profile_or_default(state, user_id).await?;
    let available = profile_f64_any(&profile, &["aff_quota", "available_quota"]) + thawed;
    let frozen =
        (profile_f64_any(&profile, &["aff_frozen_quota", "frozen_quota"]) - thawed).max(0.0);
    let history = profile_f64_any(&profile, &["aff_history_quota", "history_quota"]);
    set_affiliate_quota_fields(&mut profile, available, frozen, history);
    profile["updated_at"] = json!(now.to_rfc3339());
    store_affiliate_profile(state, user_id, profile).await?;
    for record in matured_records {
        state
            .repository
            .upsert_admin_collection_item(record)
            .await
            .map_err(repository_api_error)?;
    }
    Ok(round_money(thawed))
}

fn affiliate_rebate_is_frozen(rebate: &Value) -> bool {
    rebate
        .get("status")
        .and_then(Value::as_str)
        .is_some_and(|status| status.eq_ignore_ascii_case("frozen"))
        || rebate
            .get("frozen_until")
            .is_some_and(|value| !value.is_null())
}

fn affiliate_rebate_available_at(rebate: &Value) -> Result<Option<DateTime<Utc>>, ApiError> {
    let value = rebate
        .get("available_at")
        .or_else(|| rebate.get("frozen_until"));
    let Some(value) = value else {
        return Ok(None);
    };
    if value.is_null() {
        return Ok(None);
    }
    let Some(text) = value
        .as_str()
        .map(str::trim)
        .filter(|text| !text.is_empty())
    else {
        return Ok(None);
    };
    parse_rfc3339_utc(text)
        .map(Some)
        .ok_or_else(|| ApiError::internal_server_error("invalid affiliate rebate available_at"))
}

async fn store_affiliate_profile(
    state: &AppState,
    user_id: i64,
    profile: Value,
) -> Result<(), ApiError> {
    state
        .repository
        .upsert_admin_collection_item(repository::AdminCollectionItemRecord {
            collection: AFFILIATE_PROFILES_COLLECTION.to_owned(),
            id: user_id,
            item: normalize_affiliate_profile(user_id, profile),
        })
        .await
        .map_err(repository_api_error)?;
    Ok(())
}

async fn store_affiliate_transfer_record(
    state: &AppState,
    user_id: i64,
    claim: &AffiliateTransferClaim,
    balance_after: f64,
) -> Result<(), ApiError> {
    let user = repository_user_or_admin_fallback(state, user_id).await?;
    let id = string_storage_id(
        &format!(
            "affiliate-transfer-{user_id}-{}",
            uuid::Uuid::new_v4().simple()
        ),
        "affiliate transfer id",
    )?;
    state
        .repository
        .upsert_admin_collection_item(repository::AdminCollectionItemRecord {
            collection: AFFILIATE_TRANSFERS_COLLECTION.to_owned(),
            id,
            item: json!({
                "id": id,
                "ledger_id": id,
                "user_id": user_id,
                "email": user.email,
                "user_email": user.email,
                "username": user.username,
                "quota_amount": claim.amount,
                "balance_amount": claim.amount,
                "amount": claim.amount,
                "balance_after": balance_after,
                "available_quota_after": claim.available_quota_after,
                "frozen_quota_after": claim.frozen_quota_after,
                "history_quota_after": claim.history_quota_after,
                "snapshot_available": true,
                "created_at": Utc::now().to_rfc3339()
            }),
        })
        .await
        .map_err(repository_api_error)?;
    Ok(())
}

async fn bind_affiliate_inviter_by_code(
    state: &AppState,
    user_id: i64,
    raw_code: &str,
) -> Result<(), ApiError> {
    let settings =
        repository_setting_or_default(state, "admin", "settings", default_admin_settings()).await?;
    if !bool_setting(&settings, "affiliate_enabled", false) {
        return Ok(());
    }
    let code = normalize_affiliate_code(raw_code)?;
    let inviter = affiliate_profile_by_code(state, &code)
        .await?
        .ok_or_else(|| ApiError::bad_request("invalid affiliate code"))?;
    let inviter_id = inviter
        .get("user_id")
        .and_then(Value::as_i64)
        .ok_or_else(|| ApiError::bad_request("invalid affiliate code"))?;
    if inviter_id == user_id {
        return Err(ApiError::bad_request("invalid affiliate code"));
    }
    let mut invitee = affiliate_profile_or_default(state, user_id).await?;
    if invitee
        .get("inviter_id")
        .and_then(Value::as_i64)
        .is_some_and(|existing| existing > 0)
    {
        return Ok(());
    }
    invitee["inviter_id"] = json!(inviter_id);
    invitee["updated_at"] = json!(Utc::now().to_rfc3339());
    store_affiliate_profile(state, user_id, invitee).await?;

    let mut inviter_profile = normalize_affiliate_profile(inviter_id, inviter);
    inviter_profile["aff_count"] = json!(profile_i64(&inviter_profile, "aff_count") + 1);
    inviter_profile["updated_at"] = json!(Utc::now().to_rfc3339());
    store_affiliate_profile(state, inviter_id, inviter_profile.clone()).await?;

    let invitee_user = repository_user_or_admin_fallback(state, user_id).await?;
    let inviter_user = repository_user_or_admin_fallback(state, inviter_id).await?;
    let id = string_storage_id(
        &format!("affiliate-invite-{inviter_id}-{user_id}"),
        "affiliate invite id",
    )?;
    match state
        .repository
        .get_admin_collection_item(AFFILIATE_INVITES_COLLECTION, id)
        .await
    {
        Ok(_) => Ok(()),
        Err(repository::RepositoryError::NotFound { .. }) => {
            state
                .repository
                .upsert_admin_collection_item(repository::AdminCollectionItemRecord {
                    collection: AFFILIATE_INVITES_COLLECTION.to_owned(),
                    id,
                    item: json!({
                        "id": id,
                        "inviter_id": inviter_id,
                        "inviter_user_id": inviter_id,
                        "inviter_email": inviter_user.email,
                        "inviter_username": inviter_user.username,
                        "invitee_id": user_id,
                        "invitee_user_id": user_id,
                        "invitee_email": invitee_user.email,
                        "invitee_username": invitee_user.username,
                        "aff_code": code,
                        "total_rebate": 0.0,
                        "created_at": Utc::now().to_rfc3339()
                    }),
                })
                .await
                .map_err(repository_api_error)?;
            Ok(())
        }
        Err(error) => Err(repository_api_error(error)),
    }
}

async fn accrue_affiliate_rebate_for_order(
    state: &AppState,
    order: &repository::PaymentOrderRecord,
) -> Result<(), ApiError> {
    let settings =
        repository_setting_or_default(state, "admin", "settings", default_admin_settings()).await?;
    if !bool_setting(&settings, "affiliate_enabled", false) {
        return Ok(());
    }
    if order.amount <= 0.0 || !order.status.eq_ignore_ascii_case("COMPLETED") {
        return Ok(());
    }
    let invitee = affiliate_profile_or_default(state, order.user_id).await?;
    let Some(inviter_id) = invitee.get("inviter_id").and_then(Value::as_i64) else {
        return Ok(());
    };
    if inviter_id <= 0 || inviter_id == order.user_id {
        return Ok(());
    }
    if !affiliate_rebate_within_duration(&settings, &invitee) {
        return Ok(());
    }
    let rebate_id = string_storage_id(&order.out_trade_no, "affiliate rebate id")?;
    if state
        .repository
        .get_admin_collection_item(AFFILIATE_REBATES_COLLECTION, rebate_id)
        .await
        .is_ok()
    {
        return Ok(());
    }
    let mut inviter = affiliate_profile_or_default(state, inviter_id).await?;
    let rate = affiliate_effective_rebate_rate(&inviter, &settings);
    let existing_rebate =
        affiliate_rebate_total_for_invitee(state, inviter_id, order.user_id).await?;
    let mut rebate = round_money(order.amount * rate / 100.0);
    let per_invitee_cap = settings
        .get("affiliate_rebate_per_invitee_cap")
        .and_then(Value::as_f64)
        .unwrap_or(0.0)
        .max(0.0);
    if per_invitee_cap > 0.0 {
        if existing_rebate >= per_invitee_cap {
            return Ok(());
        }
        rebate = rebate.min(round_money(per_invitee_cap - existing_rebate));
    }
    if rebate <= f64::EPSILON {
        return Ok(());
    }
    let freeze_hours = settings
        .get("affiliate_rebate_freeze_hours")
        .and_then(Value::as_i64)
        .unwrap_or(0)
        .max(0);
    let mut available = profile_f64_any(&inviter, &["aff_quota", "available_quota"]);
    let mut frozen = profile_f64_any(&inviter, &["aff_frozen_quota", "frozen_quota"]);
    if freeze_hours > 0 {
        frozen += rebate;
    } else {
        available += rebate;
    }
    let history = profile_f64_any(&inviter, &["aff_history_quota", "history_quota"]) + rebate;
    set_affiliate_quota_fields(&mut inviter, available, frozen, history);
    inviter["rebated_invitee_count"] =
        json!(profile_i64(&inviter, "rebated_invitee_count").max(0) + 1);
    inviter["updated_at"] = json!(Utc::now().to_rfc3339());
    store_affiliate_profile(state, inviter_id, inviter).await?;

    let inviter_user = repository_user_or_admin_fallback(state, inviter_id).await?;
    let invitee_user = repository_user_or_admin_fallback(state, order.user_id).await?;
    state
        .repository
        .upsert_admin_collection_item(repository::AdminCollectionItemRecord {
            collection: AFFILIATE_REBATES_COLLECTION.to_owned(),
            id: rebate_id,
            item: json!({
                "id": rebate_id,
                "order_id": order.id,
                "out_trade_no": order.out_trade_no,
                "inviter_id": inviter_id,
                "inviter_user_id": inviter_id,
                "inviter_email": inviter_user.email,
                "inviter_username": inviter_user.username,
                "invitee_id": order.user_id,
                "invitee_user_id": order.user_id,
                "invitee_email": invitee_user.email,
                "invitee_username": invitee_user.username,
                "order_amount": order.amount,
                "pay_amount": order.pay_amount,
                "base_amount": order.amount,
                "rebate_rate_percent": rate,
                "rebate_quota": rebate,
                "rebate_amount": rebate,
                "payment_type": order.payment_type,
                "order_status": order.status,
                "status": if freeze_hours > 0 { "frozen" } else { "available" },
                "available_at": if freeze_hours > 0 {
                    json!((Utc::now() + Duration::hours(freeze_hours)).to_rfc3339())
                } else {
                    json!(Utc::now().to_rfc3339())
                },
                "frozen_until": if freeze_hours > 0 {
                    json!((Utc::now() + Duration::hours(freeze_hours)).to_rfc3339())
                } else {
                    Value::Null
                },
                "created_at": Utc::now().to_rfc3339()
            }),
        })
        .await
        .map_err(repository_api_error)?;
    insert_payment_audit_once(
        state,
        &order.out_trade_no,
        "AFFILIATE_REBATE_ACCRUED",
        json!({
            "inviter_id": inviter_id,
            "invitee_id": order.user_id,
            "rebate_amount": rebate,
            "rebate_rate_percent": rate
        }),
    )
    .await
}

async fn accrue_affiliate_rebate_for_redeem(
    state: &AppState,
    user_id: i64,
    amount: f64,
    code: &str,
    redeem_code_id: i64,
) -> Result<(), ApiError> {
    if amount <= 0.0 {
        return Ok(());
    }
    let safe_code = code
        .trim()
        .replace(|ch: char| !ch.is_ascii_alphanumeric(), "-");
    let now = Utc::now().to_rfc3339();
    let order = repository::PaymentOrderRecord {
        id: redeem_code_id,
        user_id,
        amount,
        pay_amount: amount,
        currency: "USD".to_owned(),
        fee_rate: 0.0,
        payment_type: "redeem".to_owned(),
        out_trade_no: format!("redeem-{safe_code}-{redeem_code_id}"),
        status: "COMPLETED".to_owned(),
        order_type: "balance".to_owned(),
        refund_amount: 0.0,
        refund_reason: None,
        refund_request_reason: None,
        plan_id: None,
        provider_instance_id: None,
        created_at: now.clone(),
        expires_at: now.clone(),
        paid_at: Some(now.clone()),
        completed_at: Some(now),
        cancelled_at: None,
        refund_requested_at: None,
        refunded_at: None,
        webhook_count: 0,
        metadata: json!({
            "source": "redeem",
            "redeem_code_id": redeem_code_id,
            "redeem_code": code
        }),
    };
    accrue_affiliate_rebate_for_order(state, &order).await
}

fn affiliate_rebate_within_duration(settings: &Value, invitee: &Value) -> bool {
    let duration_days = settings
        .get("affiliate_rebate_duration_days")
        .and_then(Value::as_i64)
        .unwrap_or(0)
        .max(0);
    if duration_days <= 0 {
        return true;
    }
    let Some(created_at) = invitee.get("created_at").and_then(Value::as_str) else {
        return true;
    };
    parse_rfc3339_utc(created_at)
        .map(|created_at| Utc::now() <= created_at + Duration::days(duration_days))
        .unwrap_or(true)
}

async fn affiliate_profile_by_code(
    state: &AppState,
    code: &str,
) -> Result<Option<Value>, ApiError> {
    for record in state
        .repository
        .list_admin_collection_items(AFFILIATE_PROFILES_COLLECTION)
        .await
        .map_err(repository_api_error)?
    {
        if record
            .item
            .get("aff_code")
            .and_then(Value::as_str)
            .map(|existing| existing.eq_ignore_ascii_case(code))
            .unwrap_or(false)
        {
            let user_id = record
                .item
                .get("user_id")
                .and_then(Value::as_i64)
                .unwrap_or(record.id);
            return Ok(Some(normalize_affiliate_profile(user_id, record.item)));
        }
    }
    if let Some(user_id) = default_affiliate_user_id_from_code(code) {
        if state.repository.get_user(user_id).await.is_ok()
            || state
                .admin_portal
                .get_collection_item("users", user_id)
                .is_ok()
        {
            let profile = affiliate_profile_or_default(state, user_id).await?;
            return Ok(Some(profile));
        }
    }
    Ok(None)
}

async fn affiliate_rebate_total_for_invitee(
    state: &AppState,
    inviter_id: i64,
    invitee_id: i64,
) -> Result<f64, ApiError> {
    Ok(state
        .repository
        .list_admin_collection_items(AFFILIATE_REBATES_COLLECTION)
        .await
        .map_err(repository_api_error)?
        .into_iter()
        .map(|record| record.item)
        .filter(|rebate| {
            rebate
                .get("inviter_id")
                .or_else(|| rebate.get("inviter_user_id"))
                .and_then(Value::as_i64)
                == Some(inviter_id)
                && rebate
                    .get("invitee_id")
                    .or_else(|| rebate.get("invitee_user_id"))
                    .and_then(Value::as_i64)
                    == Some(invitee_id)
        })
        .map(|rebate| profile_f64_any(&rebate, &["rebate_quota", "rebate_amount"]))
        .sum())
}

async fn affiliate_records_with_repository(
    state: &AppState,
    kind: &str,
    query: &HashMap<String, String>,
) -> Result<Value, ApiError> {
    let collection = match kind {
        "invites" => AFFILIATE_INVITES_COLLECTION,
        "rebates" => AFFILIATE_REBATES_COLLECTION,
        "transfers" => AFFILIATE_TRANSFERS_COLLECTION,
        _ => return Ok(paginate_json_values(Vec::new(), query, 20, 200)),
    };
    let records = state
        .repository
        .list_admin_collection_items(collection)
        .await
        .map_err(repository_api_error)?;
    if records.is_empty() {
        return Ok(state.admin_portal.affiliate_records(kind, query));
    }
    let mut items = records
        .into_iter()
        .map(|record| record.item)
        .collect::<Vec<_>>();
    filter_affiliate_records_by_time(&mut items, query);
    sort_affiliate_records(&mut items, kind, query);
    Ok(paginate_json_values(items, query, 20, 100))
}

async fn affiliate_users_with_repository(
    state: &AppState,
    query: &HashMap<String, String>,
) -> Result<Value, ApiError> {
    let profiles = state
        .repository
        .list_admin_collection_items(AFFILIATE_PROFILES_COLLECTION)
        .await
        .map_err(repository_api_error)?;
    if profiles.is_empty() {
        return Ok(state.admin_portal.affiliate_users(query));
    }
    let users = repository_users_by_id(state).await?;
    let mut items = profiles
        .into_iter()
        .map(|record| {
            let user_id = record
                .item
                .get("user_id")
                .and_then(Value::as_i64)
                .unwrap_or(record.id);
            let profile = normalize_affiliate_profile(user_id, record.item);
            let user = users.get(&user_id);
            json!({
                "user_id": user_id,
                "email": user.map(|user| user.email.clone()).unwrap_or_default(),
                "username": user.map(|user| user.username.clone()).unwrap_or_default(),
                "aff_code": profile_string(&profile, "aff_code", &default_aff_code(user_id)),
                "aff_code_custom": profile_bool(&profile, "aff_code_custom"),
                "aff_rebate_rate_percent": profile.get("aff_rebate_rate_percent").cloned().unwrap_or(Value::Null),
                "aff_count": profile_i64(&profile, "aff_count")
            })
        })
        .collect::<Vec<_>>();
    items.sort_by_key(|item| {
        item.get("user_id")
            .and_then(Value::as_i64)
            .unwrap_or_default()
    });
    Ok(paginate_json_values(items, query, 20, 200))
}

fn filter_affiliate_records_by_time(items: &mut Vec<Value>, query: &HashMap<String, String>) {
    let start = parse_affiliate_record_time_query(query, "start_at", false);
    let end = parse_affiliate_record_time_query(query, "end_at", true);
    if start.is_none() && end.is_none() {
        return;
    }
    items.retain(|item| {
        let created_at = item
            .get("created_at")
            .and_then(Value::as_str)
            .and_then(parse_rfc3339_utc);
        let Some(created_at) = created_at else {
            return false;
        };
        start.map(|start| created_at >= start).unwrap_or(true)
            && end.map(|end| created_at <= end).unwrap_or(true)
    });
}

fn parse_affiliate_record_time_query(
    query: &HashMap<String, String>,
    key: &str,
    end_of_day: bool,
) -> Option<DateTime<Utc>> {
    let raw = query.get(key)?.trim();
    if raw.is_empty() {
        return None;
    }
    if let Some(parsed) = parse_rfc3339_utc(raw) {
        return Some(parsed);
    }
    let date = NaiveDate::parse_from_str(raw, "%Y-%m-%d").ok()?;
    let timezone = query_timezone(query);
    let local = if end_of_day {
        date.and_hms_opt(23, 59, 59)?
    } else {
        date.and_hms_opt(0, 0, 0)?
    };
    match timezone.from_local_datetime(&local) {
        LocalResult::Single(value) => Some(value.with_timezone(&Utc)),
        LocalResult::Ambiguous(value, _) => Some(value.with_timezone(&Utc)),
        LocalResult::None => None,
    }
}

fn sort_affiliate_records(items: &mut [Value], kind: &str, query: &HashMap<String, String>) {
    let sort_by = query
        .get("sort_by")
        .map(|value| value.trim())
        .filter(|value| !value.is_empty())
        .unwrap_or("created_at");
    let descending = !query
        .get("sort_order")
        .map(|value| value.trim().eq_ignore_ascii_case("asc"))
        .unwrap_or(false);
    items.sort_by(|left, right| {
        let ordering = affiliate_sort_value(left, kind, sort_by)
            .cmp(&affiliate_sort_value(right, kind, sort_by))
            .then_with(|| value_id(left).cmp(&value_id(right)));
        if descending {
            ordering.reverse()
        } else {
            ordering
        }
    });
}

fn affiliate_sort_value(item: &Value, kind: &str, sort_by: &str) -> AffiliateSortValue {
    let number_keys: &[&str] = match (kind, sort_by) {
        ("invites", "inviter") => &["inviter_id", "inviter_user_id"],
        ("invites", "invitee") => &["invitee_id", "invitee_user_id"],
        ("invites", "total_rebate") => &["total_rebate"],
        ("rebates", "order") => &["order_id"],
        ("rebates", "inviter") => &["inviter_id", "inviter_user_id"],
        ("rebates", "invitee") => &["invitee_id", "invitee_user_id"],
        ("rebates", "order_amount") => &["order_amount", "base_amount"],
        ("rebates", "pay_amount") => &["pay_amount"],
        ("rebates", "rebate_amount") => &["rebate_amount", "rebate_quota"],
        ("transfers", "user") => &["user_id"],
        ("transfers", "amount") => &["amount", "balance_amount"],
        ("transfers", "balance_after") => &["balance_after"],
        ("transfers", "available_quota_after") => &["available_quota_after"],
        ("transfers", "frozen_quota_after") => &["frozen_quota_after"],
        ("transfers", "history_quota_after") => &["history_quota_after"],
        _ => &[],
    };
    if let Some(number) = number_keys
        .iter()
        .find_map(|key| item.get(*key).and_then(Value::as_f64))
    {
        return AffiliateSortValue::Number(number);
    }
    let text_keys: &[&str] = match (kind, sort_by) {
        ("invites", "aff_code") => &["aff_code"],
        ("rebates", "payment_type") => &["payment_type"],
        ("rebates", "order_status") => &["order_status", "status"],
        _ => &["created_at"],
    };
    AffiliateSortValue::Text(
        text_keys
            .iter()
            .find_map(|key| item.get(*key).and_then(Value::as_str))
            .unwrap_or("")
            .to_owned(),
    )
}

#[derive(Debug, Clone, PartialEq)]
enum AffiliateSortValue {
    Number(f64),
    Text(String),
}

impl Eq for AffiliateSortValue {}

impl Ord for AffiliateSortValue {
    fn cmp(&self, other: &Self) -> std::cmp::Ordering {
        use std::cmp::Ordering;
        match (self, other) {
            (Self::Number(left), Self::Number(right)) => {
                left.partial_cmp(right).unwrap_or(Ordering::Equal)
            }
            (Self::Text(left), Self::Text(right)) => left.cmp(right),
            (Self::Number(_), Self::Text(_)) => Ordering::Greater,
            (Self::Text(_), Self::Number(_)) => Ordering::Less,
        }
    }
}

impl PartialOrd for AffiliateSortValue {
    fn partial_cmp(&self, other: &Self) -> Option<std::cmp::Ordering> {
        Some(self.cmp(other))
    }
}

async fn affiliate_user_overview_with_repository(
    state: &AppState,
    user_id: i64,
) -> Result<Value, ApiError> {
    ensure_repository_user(state, user_id).await?;
    thaw_affiliate_frozen_quota(state, user_id).await?;
    let user = repository_user_or_admin_fallback(state, user_id).await?;
    let profile = affiliate_profile_or_default(state, user_id).await?;
    Ok(json!({
        "user_id": user_id,
        "email": user.email,
        "username": user.username,
        "aff_code": profile_string(&profile, "aff_code", &default_aff_code(user_id)),
        "rebate_rate_percent": affiliate_effective_rebate_rate(
            &profile,
            &repository_setting_or_default(state, "admin", "settings", default_admin_settings()).await?
        ),
        "invited_count": profile_i64(&profile, "aff_count"),
        "rebated_invitee_count": profile_i64(&profile, "rebated_invitee_count"),
        "available_quota": profile_f64_any(&profile, &["available_quota", "aff_quota"]),
        "history_quota": profile_f64_any(&profile, &["history_quota", "aff_history_quota"])
    }))
}

async fn update_affiliate_user_with_repository(
    state: &AppState,
    user_id: i64,
    payload: Value,
) -> Result<Value, ApiError> {
    ensure_repository_user(state, user_id).await?;
    let mut profile = affiliate_profile_or_default(state, user_id).await?;
    if let Some(code) = payload.get("aff_code").and_then(Value::as_str) {
        let code = normalize_affiliate_code(code)?;
        ensure_affiliate_code_available(state, user_id, &code).await?;
        profile["aff_code"] = json!(code);
        profile["aff_code_custom"] = json!(true);
    }
    if payload
        .get("clear_rebate_rate")
        .and_then(Value::as_bool)
        .unwrap_or(false)
    {
        profile["aff_rebate_rate_percent"] = Value::Null;
    } else if payload.get("aff_rebate_rate_percent").is_some() {
        profile["aff_rebate_rate_percent"] = json!(affiliate_rate_from_payload(
            &payload,
            "aff_rebate_rate_percent",
        )?);
    }
    profile["updated_at"] = json!(Utc::now().to_rfc3339());
    store_affiliate_profile(state, user_id, profile).await?;
    Ok(json!({ "user_id": user_id }))
}

async fn batch_affiliate_rate_with_repository(
    state: &AppState,
    payload: Value,
) -> Result<Value, ApiError> {
    let user_ids = payload
        .get("user_ids")
        .and_then(Value::as_array)
        .ok_or_else(|| ApiError::bad_request("user_ids is required"))?
        .iter()
        .filter_map(Value::as_i64)
        .filter(|id| *id > 0)
        .collect::<Vec<_>>();
    let clear = payload
        .get("clear")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let rate = if !clear && payload.get("aff_rebate_rate_percent").is_some() {
        Some(affiliate_rate_from_payload(
            &payload,
            "aff_rebate_rate_percent",
        )?)
    } else {
        None
    };
    if user_ids.is_empty() {
        return Err(ApiError::bad_request("user_ids cannot be empty"));
    }
    if !clear && rate.is_none() {
        return Err(ApiError::bad_request(
            "aff_rebate_rate_percent is required unless clear=true",
        ));
    }
    let mut affected = 0;
    for user_id in user_ids {
        if ensure_repository_user(state, user_id).await.is_err() {
            continue;
        }
        let mut profile = affiliate_profile_or_default(state, user_id).await?;
        if clear {
            profile["aff_rebate_rate_percent"] = Value::Null;
        } else if let Some(rate) = rate {
            profile["aff_rebate_rate_percent"] = json!(rate);
        }
        profile["updated_at"] = json!(Utc::now().to_rfc3339());
        store_affiliate_profile(state, user_id, profile).await?;
        affected += 1;
    }
    Ok(json!({ "affected": affected }))
}

fn affiliate_rate_from_payload(payload: &Value, key: &str) -> Result<f64, ApiError> {
    let rate = payload
        .get(key)
        .and_then(Value::as_f64)
        .ok_or_else(|| ApiError::bad_request("invalid rebate rate"))?;
    if !rate.is_finite() {
        return Err(ApiError::bad_request("invalid rebate rate"));
    }
    if !(0.0..=100.0).contains(&rate) {
        return Err(ApiError::bad_request("rebate rate out of range"));
    }
    Ok(rate)
}

async fn reset_affiliate_user_with_repository(
    state: &AppState,
    user_id: i64,
) -> Result<Value, ApiError> {
    ensure_repository_user(state, user_id).await?;
    let mut profile = affiliate_profile_or_default(state, user_id).await?;
    profile["aff_code"] = json!(default_aff_code(user_id));
    profile["aff_code_custom"] = json!(false);
    profile["aff_rebate_rate_percent"] = Value::Null;
    profile["updated_at"] = json!(Utc::now().to_rfc3339());
    store_affiliate_profile(state, user_id, profile).await?;
    Ok(json!({ "user_id": user_id }))
}

async fn affiliate_invitee_items(
    state: &AppState,
    inviter_id: i64,
) -> Result<Vec<Value>, ApiError> {
    let users = repository_users_by_id(state).await?;
    let rebates = state
        .repository
        .list_admin_collection_items(AFFILIATE_REBATES_COLLECTION)
        .await
        .map_err(repository_api_error)?
        .into_iter()
        .map(|record| record.item)
        .collect::<Vec<_>>();
    let mut invitees = state
        .repository
        .list_admin_collection_items(AFFILIATE_INVITES_COLLECTION)
        .await
        .map_err(repository_api_error)?
        .into_iter()
        .filter_map(|record| {
            let item = record.item;
            let item_inviter_id = item
                .get("inviter_id")
                .or_else(|| item.get("inviter_user_id"))
                .and_then(Value::as_i64)?;
            if item_inviter_id != inviter_id {
                return None;
            }
            let invitee_id = item
                .get("invitee_id")
                .or_else(|| item.get("invitee_user_id"))
                .and_then(Value::as_i64)?;
            let user = users.get(&invitee_id);
            let total_rebate = rebates
                .iter()
                .filter(|rebate| {
                    rebate
                        .get("inviter_id")
                        .or_else(|| rebate.get("inviter_user_id"))
                        .and_then(Value::as_i64)
                        == Some(inviter_id)
                        && rebate
                            .get("invitee_id")
                            .or_else(|| rebate.get("invitee_user_id"))
                            .and_then(Value::as_i64)
                            == Some(invitee_id)
                })
                .map(|rebate| profile_f64_any(rebate, &["rebate_quota", "rebate_amount"]))
                .sum::<f64>();
            Some(json!({
                "user_id": invitee_id,
                "email": user.map(|user| mask_email_for_affiliate(&user.email)).unwrap_or_default(),
                "username": user.map(|user| user.username.clone()).unwrap_or_default(),
                "created_at": item.get("created_at").cloned().unwrap_or(Value::Null),
                "total_rebate": total_rebate
            }))
        })
        .collect::<Vec<_>>();
    invitees.sort_by_key(|item| {
        item.get("user_id")
            .and_then(Value::as_i64)
            .unwrap_or_default()
    });
    Ok(invitees)
}

async fn ensure_affiliate_code_available(
    state: &AppState,
    user_id: i64,
    code: &str,
) -> Result<(), ApiError> {
    for record in state
        .repository
        .list_admin_collection_items(AFFILIATE_PROFILES_COLLECTION)
        .await
        .map_err(repository_api_error)?
    {
        if record.id != user_id
            && record
                .item
                .get("aff_code")
                .and_then(Value::as_str)
                .map(|existing| existing.eq_ignore_ascii_case(code))
                .unwrap_or(false)
        {
            return Err(ApiError::conflict("affiliate code already in use"));
        }
    }
    Ok(())
}

