async fn repository_user_or_admin_fallback(
    state: &AppState,
    user_id: i64,
) -> Result<repository::UserRecord, ApiError> {
    match state.repository.get_user(user_id).await {
        Ok(user) => Ok(user),
        Err(repository::RepositoryError::NotFound { .. }) => {
            ensure_repository_user(state, user_id).await?;
            state
                .repository
                .get_user(user_id)
                .await
                .map_err(repository_api_error)
        }
        Err(error) => Err(repository_api_error(error)),
    }
}

fn normalize_affiliate_profile(user_id: i64, mut profile: Value) -> Value {
    profile["user_id"] = json!(user_id);
    if profile.get("aff_code").and_then(Value::as_str).is_none() {
        profile["aff_code"] = json!(default_aff_code(user_id));
    }
    if profile.get("aff_code_custom").is_none() {
        profile["aff_code_custom"] = json!(false);
    }
    let available = profile_f64_any(&profile, &["aff_quota", "available_quota"]);
    let frozen = profile_f64_any(&profile, &["aff_frozen_quota", "frozen_quota"]);
    let history = profile_f64_any(&profile, &["aff_history_quota", "history_quota"]);
    set_affiliate_quota_fields(&mut profile, available, frozen, history);
    if profile.get("aff_count").and_then(Value::as_i64).is_none() {
        profile["aff_count"] = json!(0);
    }
    if profile
        .get("rebated_invitee_count")
        .and_then(Value::as_i64)
        .is_none()
    {
        profile["rebated_invitee_count"] = json!(0);
    }
    if profile.get("created_at").is_none() {
        profile["created_at"] = json!(Utc::now().to_rfc3339());
    }
    if profile.get("updated_at").is_none() {
        profile["updated_at"] = json!(Utc::now().to_rfc3339());
    }
    profile
}

fn set_affiliate_quota_fields(profile: &mut Value, available: f64, frozen: f64, history: f64) {
    profile["aff_quota"] = json!(available);
    profile["available_quota"] = json!(available);
    profile["aff_frozen_quota"] = json!(frozen);
    profile["frozen_quota"] = json!(frozen);
    profile["aff_history_quota"] = json!(history);
    profile["history_quota"] = json!(history);
}

fn affiliate_effective_rebate_rate(profile: &Value, settings: &Value) -> f64 {
    profile
        .get("aff_rebate_rate_percent")
        .and_then(Value::as_f64)
        .or_else(|| {
            settings
                .get("affiliate_rebate_rate")
                .and_then(Value::as_f64)
        })
        .unwrap_or(20.0)
        .clamp(0.0, 100.0)
}

fn profile_string(profile: &Value, key: &str, default: &str) -> String {
    profile
        .get(key)
        .and_then(Value::as_str)
        .unwrap_or(default)
        .to_owned()
}

fn profile_bool(profile: &Value, key: &str) -> bool {
    profile.get(key).and_then(Value::as_bool).unwrap_or(false)
}

fn profile_i64(profile: &Value, key: &str) -> i64 {
    profile.get(key).and_then(Value::as_i64).unwrap_or(0)
}

fn profile_f64_any(profile: &Value, keys: &[&str]) -> f64 {
    keys.iter()
        .find_map(|key| profile.get(*key).and_then(Value::as_f64))
        .unwrap_or(0.0)
}

fn default_aff_code(user_id: i64) -> String {
    format!("AFF{user_id:04}")
}

fn default_affiliate_user_id_from_code(code: &str) -> Option<i64> {
    let digits = code.strip_prefix("AFF")?;
    if digits.len() != 4 || !digits.chars().all(|ch| ch.is_ascii_digit()) {
        return None;
    }
    digits.parse::<i64>().ok().filter(|id| *id > 0)
}

fn normalize_affiliate_code(raw: &str) -> Result<String, ApiError> {
    let code = raw.trim().to_uppercase();
    let valid_len = (4..=32).contains(&code.len());
    let valid_chars = code
        .chars()
        .all(|ch| ch.is_ascii_uppercase() || ch.is_ascii_digit() || ch == '_' || ch == '-');
    if !valid_len || !valid_chars {
        return Err(ApiError::bad_request("invalid affiliate code"));
    }
    Ok(code)
}

fn round_money(value: f64) -> f64 {
    (value * 100_000_000.0).round() / 100_000_000.0
}

fn mask_email_for_affiliate(email: &str) -> String {
    let email = email.trim();
    let Some((local, domain)) = email.split_once('@') else {
        return "***".to_owned();
    };
    if local.is_empty() || domain.is_empty() {
        return "***".to_owned();
    }
    let prefix = local.chars().next().unwrap_or('*');
    format!("{prefix}***@{domain}")
}

fn paginate_json_values(
    items: Vec<Value>,
    query: &HashMap<String, String>,
    default_page_size: i64,
    max_page_size: i64,
) -> Value {
    let page = query_i64(query, "page", 1).max(1);
    let page_size = query_i64(query, "page_size", default_page_size).clamp(1, max_page_size);
    let search = query
        .get("search")
        .or_else(|| query.get("q"))
        .map(|value| value.to_lowercase());
    let filtered = items
        .into_iter()
        .filter(|item| {
            search
                .as_ref()
                .map(|keyword| item.to_string().to_lowercase().contains(keyword))
                .unwrap_or(true)
        })
        .collect::<Vec<_>>();
    let total = filtered.len() as i64;
    let start = ((page - 1) * page_size) as usize;
    let page_items = filtered
        .into_iter()
        .skip(start)
        .take(page_size as usize)
        .collect::<Vec<_>>();
    paginated_value(page_items, total, page, page_size)
}

