async fn admin_user_attributes_batch(
    State(state): State<AppState>,
    Json(payload): Json<Value>,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    let user_ids = payload
        .get("user_ids")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();
    let mut result = serde_json::Map::new();
    for user_id in user_ids {
        if let Some(id) = user_id.as_i64() {
            let values = match ensure_repository_user(&state, id).await {
                Ok(()) => state
                    .repository
                    .list_user_attribute_values(id)
                    .await
                    .map_err(repository_api_error)?,
                Err(error)
                    if matches!(
                        error.status(),
                        StatusCode::NOT_FOUND | StatusCode::UNAUTHORIZED
                    ) =>
                {
                    Vec::new()
                }
                Err(error) => return Err(error),
            };
            result.insert(id.to_string(), user_attribute_value_map(values));
        }
    }
    Ok(success(json!({ "attributes": result })))
}

