async fn create_backup_with_payload(state: &AppState, payload: Value) -> Result<Value, ApiError> {
    let executor = backup_create_executor(&payload)?;
    let backup = state.admin_portal.create_backup(payload.clone());
    let manifest = build_repository_backup_manifest(&state).await?;
    let backup = match executor.as_str() {
        "repository_manifest" => {
            crate::backup_executor::execute_repository_manifest_backup(backup, manifest).await?
        }
        "postgres_s3" => {
            let config = postgres_s3_backup_config_from_payload(&state, &payload).await?;
            crate::backup_executor::execute_postgres_s3_backup(backup, manifest, config).await?
        }
        _ => unreachable!("backup_create_executor validates supported values"),
    };
    store_backup_record(&state, backup.clone()).await?;
    Ok(backup)
}

async fn admin_backup_schedule_run_due(
    State(state): State<AppState>,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    let schedule = backup_schedule_with_repository(&state).await?;
    let now_unix = current_unix_time();
    let schedule_for_input = schedule.clone();
    let executor = backup_create_executor(&schedule_for_input)?;
    let mut backup_payload = schedule_for_input.clone();
    backup_payload["triggered_by"] = json!("schedule");
    backup_payload["expire_days"] = backup_payload
        .get("retain_days")
        .or_else(|| backup_payload.get("expire_days"))
        .cloned()
        .unwrap_or_else(|| json!(7));
    let base_backup = state.admin_portal.create_backup(backup_payload);
    let manifest = build_repository_backup_manifest(&state).await?;
    let postgres_s3_config = if executor == "postgres_s3" {
        Some(postgres_s3_backup_config_from_payload(&state, &schedule_for_input).await?)
    } else {
        None
    };
    let result = crate::backup_scheduler::run_due_backup_schedule(
        state.repository.as_ref(),
        crate::backup_scheduler::BackupScheduleRunInput {
            schedule: schedule_for_input,
            now_unix,
            owner: format!("backend-next-{}", std::process::id()),
            base_backup,
            manifest,
            postgres_s3_config,
        },
    )
    .await?;
    if let Some(backup) = &result.backup {
        store_backup_record(&state, backup.clone()).await?;
    }
    let stored_schedule =
        store_system_setting(&state, "backup", "schedule", result.schedule.clone()).await?;
    Ok(success(json!({
        "status": match result.status {
            crate::backup_scheduler::BackupScheduleRunStatus::Disabled => "disabled",
            crate::backup_scheduler::BackupScheduleRunStatus::NotDue => "not_due",
            crate::backup_scheduler::BackupScheduleRunStatus::Locked => "locked",
            crate::backup_scheduler::BackupScheduleRunStatus::Created => "created"
        },
        "schedule": stored_schedule,
        "backup": result.backup
    })))
}

fn backup_create_executor(payload: &Value) -> Result<String, ApiError> {
    let executor = string_from_value(payload, "executor")
        .or_else(|| string_from_value(payload, "backup_executor"))
        .unwrap_or_else(|| "repository_manifest".to_owned());
    match executor.as_str() {
        "repository_manifest" | "postgres_s3" => Ok(executor),
        _ => Err(ApiError::bad_request(
            "backup executor must be repository_manifest or postgres_s3",
        )),
    }
}

async fn postgres_s3_backup_config_from_payload(
    state: &AppState,
    payload: &Value,
) -> Result<PostgresS3BackupConfig, ApiError> {
    let saved_s3 = backup_s3_config_with_repository(state).await?;
    let s3_patch = payload
        .get("s3")
        .or_else(|| payload.get("s3_config"))
        .cloned()
        .unwrap_or_else(|| payload.clone());
    let merged_s3 = merge_json_value(saved_s3.clone(), s3_patch);
    let s3 = S3ProbeConfig::from_payload(&merged_s3).merge_missing_secret(&saved_s3);
    let prefix = string_from_value(&merged_s3, "prefix").unwrap_or_else(|| "backups/".to_owned());
    let database = PostgresDumpConfig::from_payload_or_runtime(payload)?;
    Ok(PostgresS3BackupConfig {
        database,
        s3,
        prefix,
    })
}

