async fn backup_list_with_repository(state: &AppState) -> Result<Value, ApiError> {
    let records = state
        .repository
        .list_admin_collection_items("backups")
        .await
        .map_err(repository_api_error)?;
    let mut items = records
        .into_iter()
        .map(|record| record.item)
        .collect::<Vec<_>>();
    items.sort_by(|left, right| {
        right
            .get("started_at")
            .and_then(Value::as_str)
            .cmp(&left.get("started_at").and_then(Value::as_str))
            .then_with(|| {
                right
                    .get("id")
                    .and_then(Value::as_str)
                    .cmp(&left.get("id").and_then(Value::as_str))
            })
    });
    if items.is_empty() {
        return Ok(state.admin_portal.list_backups());
    }
    Ok(json!({ "items": items }))
}

