async fn admin_activate_source_profile(
    State(state): State<AppState>,
    Path((source_type, profile_id)): Path<(String, String)>,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    let mut profiles = data_management_source_profile_items(&state, &source_type).await?;
    if profiles.is_empty() {
        let profile = state
            .admin_portal
            .activate_source_profile(&source_type, &profile_id)?;
        store_data_management_source_profile(&state, &source_type, profile.clone()).await?;
        return Ok(success(profile));
    }
    let mut activated = None;
    for profile in &mut profiles {
        let is_target =
            profile.get("profile_id").and_then(Value::as_str) == Some(profile_id.as_str());
        profile["is_active"] = json!(is_target);
        store_data_management_source_profile(&state, &source_type, profile.clone()).await?;
        if is_target {
            activated = Some(profile.clone());
        }
    }
    Ok(success(activated.ok_or_else(|| {
        ApiError::not_found("source profile not found")
    })?))
}

