async fn data_management_agent_health_with_repository(state: &AppState) -> Result<Value, ApiError> {
    let config = data_management_config_with_repository(state).await?;
    let enabled = config
        .get("agent_enabled")
        .or_else(|| config.get("agent").and_then(|agent| agent.get("enabled")))
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let socket_path = config
        .get("agent_socket_path")
        .or_else(|| {
            config
                .get("agent")
                .and_then(|agent| agent.get("socket_path"))
        })
        .and_then(Value::as_str)
        .map(str::trim)
        .unwrap_or("")
        .to_owned();
    if !enabled {
        return Ok(json!({
            "enabled": false,
            "reason": config
                .get("agent_disabled_reason")
                .or_else(|| config.get("agent").and_then(|agent| agent.get("disabled_reason")))
                .and_then(Value::as_str)
                .unwrap_or("agent disabled by data management config"),
            "socket_path": socket_path,
            "agent": null
        }));
    }

    let status = config
        .get("agent_status")
        .or_else(|| config.get("agent").and_then(|agent| agent.get("status")))
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .unwrap_or("configured");
    let version = config
        .get("agent_version")
        .or_else(|| config.get("agent").and_then(|agent| agent.get("version")))
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .unwrap_or("unknown");
    Ok(json!({
        "enabled": true,
        "reason": "",
        "socket_path": socket_path,
        "agent": {
            "status": status,
            "version": version,
            "last_seen_at": config
                .get("agent_last_seen_at")
                .or_else(|| config.get("agent").and_then(|agent| agent.get("last_seen_at")))
                .cloned()
                .unwrap_or(Value::Null),
            "pid": config
                .get("agent_pid")
                .or_else(|| config.get("agent").and_then(|agent| agent.get("pid")))
                .cloned()
                .unwrap_or(Value::Null)
        }
    }))
}

