async fn data_management_jobs_with_repository(
    state: &AppState,
    query: &HashMap<String, String>,
) -> Result<Value, ApiError> {
    let mut items = state
        .repository
        .list_admin_collection_items("data-management-backup-jobs")
        .await
        .map_err(repository_api_error)?
        .into_iter()
        .map(|record| record.item)
        .collect::<Vec<_>>();
    items.sort_by(|left, right| {
        right
            .get("started_at")
            .and_then(Value::as_str)
            .cmp(&left.get("started_at").and_then(Value::as_str))
            .then_with(|| {
                right
                    .get("job_id")
                    .and_then(Value::as_str)
                    .cmp(&left.get("job_id").and_then(Value::as_str))
            })
    });
    if items.is_empty() {
        return Ok(state.admin_portal.list_data_management_jobs());
    }
    let status = query
        .get("status")
        .map(|value| value.trim().to_ascii_lowercase())
        .filter(|value| !value.is_empty());
    let backup_type = query
        .get("backup_type")
        .map(|value| value.trim().to_ascii_lowercase())
        .filter(|value| !value.is_empty());
    let filtered = items
        .into_iter()
        .filter(|item| {
            status
                .as_ref()
                .map(|status| {
                    item.get("status")
                        .and_then(Value::as_str)
                        .map(|value| value.eq_ignore_ascii_case(status))
                        .unwrap_or(false)
                })
                .unwrap_or(true)
        })
        .filter(|item| {
            backup_type
                .as_ref()
                .map(|backup_type| {
                    item.get("backup_type")
                        .and_then(Value::as_str)
                        .map(|value| value.eq_ignore_ascii_case(backup_type))
                        .unwrap_or(false)
                })
                .unwrap_or(true)
        })
        .collect::<Vec<_>>();
    let page_size = query
        .get("page_size")
        .and_then(|value| value.trim().parse::<usize>().ok())
        .unwrap_or(20)
        .clamp(1, 100);
    let page_token = query
        .get("page_token")
        .and_then(|value| value.trim().parse::<usize>().ok())
        .unwrap_or(0);
    let next_offset = page_token + page_size;
    let items = filtered
        .iter()
        .skip(page_token)
        .take(page_size)
        .cloned()
        .collect::<Vec<_>>();
    let next_page_token = if next_offset < filtered.len() {
        json!(next_offset.to_string())
    } else {
        Value::Null
    };
    Ok(json!({
        "items": items,
        "next_page_token": next_page_token,
        "total": filtered.len()
    }))
}

async fn create_data_management_job_record(
    state: &AppState,
    headers: &HeaderMap,
    payload: Value,
) -> Result<Value, ApiError> {
    if !payload.is_object() {
        return Err(ApiError::bad_request("Invalid request body"));
    }
    let backup_type = payload
        .get("backup_type")
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .unwrap_or("full")
        .to_ascii_lowercase();
    if !matches!(backup_type.as_str(), "postgres" | "redis" | "full") {
        return Err(ApiError::bad_request(
            "backup_type must be postgres, redis, or full",
        ));
    }

    let idempotency_key = data_management_idempotency_key(headers, &payload);
    if let Some(key) = idempotency_key.as_deref() {
        if let Some(existing) = data_management_job_by_idempotency_key(state, key).await? {
            return Ok(existing);
        }
    }

    let config = data_management_config_with_repository(state).await?;
    let postgres_profile_id = data_management_requested_profile_id(
        &payload,
        &config,
        "postgres_profile_id",
        "active_postgres_profile_id",
    );
    let redis_profile_id = data_management_requested_profile_id(
        &payload,
        &config,
        "redis_profile_id",
        "active_redis_profile_id",
    );
    let s3_profile_id = data_management_requested_profile_id(
        &payload,
        &config,
        "s3_profile_id",
        "active_s3_profile_id",
    );
    let upload_to_s3 = payload
        .get("upload_to_s3")
        .and_then(Value::as_bool)
        .unwrap_or_else(|| s3_profile_id.is_some() || data_management_embedded_s3_enabled(&config));

    let postgres_profile = match postgres_profile_id.as_deref() {
        Some(id) if backup_type == "postgres" || backup_type == "full" => Some(
            data_management_source_profile_with_repository(state, "postgres", id)
                .await?
                .ok_or_else(|| ApiError::bad_request("postgres profile not found"))?,
        ),
        _ => None,
    };
    let redis_profile = match redis_profile_id.as_deref() {
        Some(id) if backup_type == "redis" || backup_type == "full" => Some(
            data_management_source_profile_with_repository(state, "redis", id)
                .await?
                .ok_or_else(|| ApiError::bad_request("redis profile not found"))?,
        ),
        _ => None,
    };
    let s3_profile = match s3_profile_id.as_deref() {
        Some(id) if upload_to_s3 => Some(
            data_management_s3_profile_with_repository(state, id)
                .await?
                .ok_or_else(|| ApiError::bad_request("s3 profile not found"))?,
        ),
        _ => None,
    };

    let now = Utc::now().to_rfc3339();
    let job_id = format!("job-{}", uuid::Uuid::new_v4().simple());
    let backup_root = config
        .get("backup_root")
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .unwrap_or("data/backups");
    let artifact_name = format!("sub2api-{backup_type}-{job_id}.tar.gz");
    let local_path = format!(
        "{}/{}",
        backup_root.trim_end_matches(['/', '\\']),
        artifact_name
    );
    let triggered_by = authenticated_user_id(state, headers)
        .map(|user_id| format!("admin:{user_id}"))
        .unwrap_or_else(|_| "admin:api-key".to_owned());

    let job = json!({
        "job_id": job_id,
        "backup_type": backup_type,
        "status": "planned",
        "triggered_by": triggered_by,
        "idempotency_key": idempotency_key.unwrap_or_default(),
        "upload_to_s3": upload_to_s3,
        "s3_profile_id": s3_profile_id.unwrap_or_default(),
        "postgres_profile_id": postgres_profile_id.unwrap_or_default(),
        "redis_profile_id": redis_profile_id.unwrap_or_default(),
        "started_at": now,
        "finished_at": Value::Null,
        "error_message": "data-management executor is not configured",
        "artifact": {
            "local_path": local_path,
            "size_bytes": 0,
            "sha256": ""
        },
        "s3": data_management_job_s3_object(&job_id, &backup_type, &config, s3_profile.as_ref()),
        "execution_plan": {
            "executor": "repository-planned",
            "requires_executor": true,
            "sources": data_management_job_sources(&backup_type, postgres_profile.as_ref(), redis_profile.as_ref(), &config),
            "s3_profile": s3_profile.as_ref().map(data_management_job_profile_summary),
            "config": {
                "source_mode": config.get("source_mode").cloned().unwrap_or_else(|| json!("direct")),
                "backup_root": backup_root,
                "retention_days": config.get("retention_days").cloned().unwrap_or_else(|| json!(7)),
                "keep_last": config.get("keep_last").cloned().unwrap_or_else(|| json!(10))
            }
        }
    });
    let s3 = if upload_to_s3 {
        Some(data_management_s3_probe_config_from_profile(
            s3_profile
                .as_ref()
                .ok_or_else(|| ApiError::bad_request("s3 profile not found"))?,
        )?)
    } else {
        None
    };
    crate::data_management_executor::execute_data_management_backup_job(
        DataManagementExecutionInput {
            job,
            upload_to_s3,
            s3,
            redis_dump: data_management_redis_dump_config(&backup_type, redis_profile.as_ref())?,
            filesystem_dump: data_management_filesystem_dump_config(
                &backup_type,
                &payload,
                &config,
            )?,
            postgres_dump: data_management_postgres_dump_config(
                &backup_type,
                postgres_profile.as_ref(),
            )?,
        },
    )
    .await
}

fn data_management_postgres_dump_config(
    backup_type: &str,
    postgres_profile: Option<&Value>,
) -> Result<Option<PostgresDumpConfig>, ApiError> {
    if backup_type != "postgres" && backup_type != "full" {
        return Ok(None);
    }
    let Some(profile) = postgres_profile else {
        return Ok(None);
    };
    let config = profile.get("config").unwrap_or(profile);
    Ok(Some(PostgresDumpConfig::from_value(config)?))
}

fn data_management_filesystem_dump_config(
    backup_type: &str,
    payload: &Value,
    config: &Value,
) -> Result<Option<crate::filesystem_dump::FilesystemDumpConfig>, ApiError> {
    if backup_type != "full"
        && payload
            .get("include_filesystem")
            .and_then(Value::as_bool)
            .unwrap_or(false)
            == false
    {
        return Ok(None);
    }
    let Some(paths) = data_management_filesystem_paths(payload, config) else {
        return Ok(None);
    };
    if paths.is_empty() {
        return Ok(None);
    }
    let max_file_bytes = payload
        .get("max_asset_file_bytes")
        .or_else(|| {
            config
                .get("filesystem")
                .and_then(|filesystem| filesystem.get("max_file_bytes"))
        })
        .and_then(|value| {
            value
                .as_u64()
                .or_else(|| value.as_str()?.trim().parse::<u64>().ok())
        })
        .unwrap_or(25 * 1024 * 1024);
    Ok(Some(crate::filesystem_dump::FilesystemDumpConfig {
        roots: paths.into_iter().map(std::path::PathBuf::from).collect(),
        max_file_bytes,
    }))
}

fn data_management_filesystem_paths(payload: &Value, config: &Value) -> Option<Vec<String>> {
    for value in [
        payload.get("asset_paths"),
        payload.get("filesystem_paths"),
        payload
            .get("filesystem")
            .and_then(|filesystem| filesystem.get("include_paths")),
        config
            .get("filesystem")
            .and_then(|filesystem| filesystem.get("include_paths")),
        config.get("asset_paths"),
    ]
    .into_iter()
    .flatten()
    {
        let paths = string_list_from_value(value);
        if !paths.is_empty() {
            return Some(paths);
        }
    }
    None
}

fn string_list_from_value(value: &Value) -> Vec<String> {
    match value {
        Value::Array(items) => items
            .iter()
            .filter_map(Value::as_str)
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(ToOwned::to_owned)
            .collect(),
        Value::String(value) => value
            .split([',', ';'])
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(ToOwned::to_owned)
            .collect(),
        _ => Vec::new(),
    }
}

fn data_management_redis_dump_config(
    backup_type: &str,
    redis_profile: Option<&Value>,
) -> Result<Option<crate::redis_dump::RedisDumpConfig>, ApiError> {
    if backup_type != "redis" && backup_type != "full" {
        return Ok(None);
    }
    let Some(profile) = redis_profile else {
        return Ok(None);
    };
    let config = profile.get("config").unwrap_or(profile);
    let (host, port) = data_management_redis_host_port(config)?;
    let db = config
        .get("db")
        .or_else(|| config.get("database"))
        .and_then(|value| {
            value
                .as_u64()
                .or_else(|| value.as_str()?.trim().parse::<u64>().ok())
        })
        .unwrap_or(0)
        .min(u8::MAX as u64) as u8;
    let password = config
        .get("password")
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(ToOwned::to_owned);
    let username = config
        .get("username")
        .or_else(|| config.get("user"))
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(ToOwned::to_owned);
    let enable_tls = config
        .get("enable_tls")
        .or_else(|| config.get("tls"))
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let scan_count = config
        .get("scan_count")
        .and_then(|value| {
            value
                .as_u64()
                .or_else(|| value.as_str()?.trim().parse::<u64>().ok())
        })
        .unwrap_or(100)
        .clamp(1, 10_000) as usize;
    Ok(Some(crate::redis_dump::RedisDumpConfig {
        connection: RedisConfig {
            host,
            port,
            password,
            db: Some(db),
            enable_tls: Some(enable_tls),
        },
        username,
        scan_count,
    }))
}

fn data_management_redis_host_port(config: &Value) -> Result<(String, u16), ApiError> {
    if let Some(addr) = config
        .get("addr")
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
    {
        if let Some((host, port)) = addr.rsplit_once(':') {
            let port = port
                .parse::<u16>()
                .map_err(|_| ApiError::bad_request("redis addr port is invalid"))?;
            return Ok((host.trim_matches(['[', ']']).to_owned(), port));
        }
    }
    let host = config
        .get("host")
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .unwrap_or("127.0.0.1")
        .to_owned();
    let port = config
        .get("port")
        .and_then(|value| {
            value
                .as_u64()
                .or_else(|| value.as_str()?.trim().parse::<u64>().ok())
        })
        .unwrap_or(6379);
    if port == 0 || port > u16::MAX as u64 {
        return Err(ApiError::bad_request("redis port is invalid"));
    }
    Ok((host, port as u16))
}

