fn data_management_job_sources(
    backup_type: &str,
    postgres_profile: Option<&Value>,
    redis_profile: Option<&Value>,
    config: &Value,
) -> Value {
    let mut sources = Map::new();
    if backup_type == "postgres" || backup_type == "full" {
        sources.insert(
            "postgres".to_owned(),
            postgres_profile
                .map(data_management_job_profile_summary)
                .unwrap_or_else(|| {
                    json!({
                        "profile_id": Value::Null,
                        "source": "config",
                        "config": data_management_redacted_source_config(config.get("postgres"))
                    })
                }),
        );
    }
    if backup_type == "redis" || backup_type == "full" {
        sources.insert(
            "redis".to_owned(),
            redis_profile
                .map(data_management_job_profile_summary)
                .unwrap_or_else(|| {
                    json!({
                        "profile_id": Value::Null,
                        "source": "config",
                        "config": data_management_redacted_source_config(config.get("redis"))
                    })
                }),
        );
    }
    Value::Object(sources)
}

fn data_management_job_profile_summary(profile: &Value) -> Value {
    json!({
        "profile_id": profile.get("profile_id").cloned().unwrap_or(Value::Null),
        "name": profile.get("name").cloned().unwrap_or(Value::Null),
        "source": "profile",
        "config": data_management_redacted_source_config(profile.get("config").or_else(|| profile.get("s3")))
    })
}

fn data_management_redacted_source_config(config: Option<&Value>) -> Value {
    let Some(Value::Object(source)) = config else {
        return json!({});
    };
    let mut redacted = source.clone();
    for secret_key in ["password", "secret_access_key", "access_key_id"] {
        if let Some(value) = redacted.get(secret_key).and_then(Value::as_str) {
            redacted.insert(
                secret_key.to_owned(),
                json!(if value.is_empty() { "" } else { "***" }),
            );
        }
    }
    Value::Object(redacted)
}

fn data_management_job_s3_object(
    job_id: &str,
    backup_type: &str,
    config: &Value,
    s3_profile: Option<&Value>,
) -> Value {
    let Some(s3_profile) = s3_profile else {
        return Value::Null;
    };
    let s3_config = s3_profile
        .get("s3")
        .or_else(|| config.get("s3"))
        .unwrap_or(&Value::Null);
    let prefix = s3_config
        .get("prefix")
        .and_then(Value::as_str)
        .unwrap_or("backups/")
        .trim_matches('/');
    let key = if prefix.is_empty() {
        format!("sub2api-{backup_type}-{job_id}.tar.gz")
    } else {
        format!("{prefix}/sub2api-{backup_type}-{job_id}.tar.gz")
    };
    json!({
        "bucket": s3_config.get("bucket").cloned().unwrap_or(Value::Null),
        "key": key,
        "etag": ""
    })
}

