async fn store_data_management_job(state: &AppState, job: Value) -> Result<(), ApiError> {
    let job_id = job
        .get("job_id")
        .and_then(Value::as_str)
        .ok_or_else(|| ApiError::bad_request("job_id is required"))?;
    state
        .repository
        .upsert_admin_collection_item(repository::AdminCollectionItemRecord {
            collection: "data-management-backup-jobs".to_owned(),
            id: string_storage_id(job_id, "job id")?,
            item: job,
        })
        .await
        .map_err(repository_api_error)?;
    Ok(())
}

fn data_management_source_collection(source_type: &str) -> Result<String, ApiError> {
    let source_type = source_type.trim().to_ascii_lowercase();
    if source_type.is_empty()
        || !source_type
            .chars()
            .all(|ch| ch.is_ascii_lowercase() || ch.is_ascii_digit() || ch == '-' || ch == '_')
    {
        return Err(ApiError::bad_request("invalid source type"));
    }
    Ok(format!("data-management-source-{source_type}-profiles"))
}

fn data_management_s3_profile_patch(payload: Value) -> Value {
    let secret_configured = payload
        .get("secret_access_key")
        .and_then(Value::as_str)
        .map(|value| !value.is_empty());
    let mut patch = json!({
        "name": payload.get("name").cloned().unwrap_or(Value::Null),
        "s3": {
            "endpoint": payload.get("endpoint").cloned().unwrap_or(Value::Null),
            "region": payload.get("region").cloned().unwrap_or_else(|| json!("auto")),
            "bucket": payload.get("bucket").cloned().unwrap_or(Value::Null),
            "access_key_id": payload.get("access_key_id").cloned().unwrap_or(Value::Null),
            "prefix": payload.get("prefix").cloned().unwrap_or_else(|| json!("backups/")),
            "force_path_style": payload.get("force_path_style").cloned().unwrap_or_else(|| json!(true)),
            "use_ssl": payload.get("use_ssl").cloned().unwrap_or_else(|| json!(true))
        },
        "updated_at": Utc::now().to_rfc3339()
    });
    if let Some(secret_configured) = secret_configured {
        patch["secret_access_key_configured"] = json!(secret_configured);
    }
    patch
}

