async fn admin_update_api_key_group(
    State(state): State<AppState>,
    Path(id): Path<i64>,
    body: Bytes,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    let payload: Value = if body.is_empty() {
        json!({})
    } else {
        serde_json::from_slice(&body).map_err(|_| ApiError::bad_request("invalid json body"))?
    };
    let request: AdminUpdateApiKeyRequest = serde_json::from_value(payload.clone())
        .map_err(|_| ApiError::bad_request("invalid admin api key request"))?;
    state.auth.get_api_key_for_admin(id)?;
    let requested_group = match payload.get("group_id") {
        None | Some(Value::Null) => None,
        Some(value) => {
            let group_id = value
                .as_i64()
                .ok_or_else(|| ApiError::bad_request("group_id must be a number"))?;
            if group_id < 0 {
                return Err(ApiError::bad_request("group_id must be non-negative"));
            }
            if group_id == 0 {
                Some(None)
            } else {
                let group = state
                    .repository
                    .get_group(GroupId(group_id))
                    .await
                    .or_else(|error| match error {
                        repository::RepositoryError::NotFound { .. } => {
                            group_from_admin_collection(&state, group_id)
                        }
                        other => Err(other),
                    })
                    .map_err(repository_api_error)?;
                if group.status != domain::GroupStatus::Active {
                    return Err(ApiError::bad_request("target group is not active"));
                }
                Some(Some(group_id))
            }
        }
    };

    let reset_rate_limit_usage = request.reset_rate_limit_usage.unwrap_or(false);
    let api_key = state
        .auth
        .admin_update_api_key(id, requested_group, reset_rate_limit_usage)?;
    sync_auth_api_key_to_repository(&state, &api_key).await?;
    Ok(success(json!({
        "api_key": api_key,
        "auto_granted_group_access": false,
        "granted_group_id": Value::Null,
        "granted_group_name": ""
    })))
}

