async fn admin_ops_handler(
    State(state): State<AppState>,
    OriginalUri(uri): OriginalUri,
    method: Method,
    Query(query): Query<HashMap<String, String>>,
    body: Bytes,
) -> Result<Json<crate::response::ApiEnvelope<Value>>, ApiError> {
    let data = match method {
        Method::GET => {
            let runtime_snapshots = state
                .gateway_runtime
                .account_runtime_snapshots(&state)
                .await;
            state
                .admin_ops
                .get_with_runtime(uri.path(), &query, &runtime_snapshots)?
        }
        Method::POST => state.admin_ops.post(uri.path(), parse_json_body(&body)?)?,
        Method::PUT => state.admin_ops.put(uri.path(), parse_json_body(&body)?)?,
        Method::DELETE => state.admin_ops.delete(uri.path())?,
        _ => return Err(ApiError::bad_request("unsupported ops method")),
    };
    Ok(success(data))
}

fn parse_json_body(body: &Bytes) -> Result<Value, ApiError> {
    if body.is_empty() {
        return Ok(json!({}));
    }
    serde_json::from_slice(body).map_err(|_| ApiError::bad_request("invalid json body"))
}

fn parse_payment_webhook_payload(
    method: &str,
    query: Option<&str>,
    body: &Bytes,
) -> Result<Value, ApiError> {
    if method.eq_ignore_ascii_case("GET") {
        return Ok(json!({ "_raw": query.unwrap_or_default() }));
    }
    if body.is_empty() {
        return Ok(json!({}));
    }
    match serde_json::from_slice::<Value>(body) {
        Ok(mut value) => {
            if let Value::Object(object) = &mut value {
                if let Ok(raw) = std::str::from_utf8(body) {
                    object.entry("_raw").or_insert(json!(raw));
                }
            }
            Ok(value)
        }
        Err(_) => {
            let raw = std::str::from_utf8(body)
                .map_err(|_| ApiError::bad_request("invalid webhook body"))?;
            Ok(json!({ "_raw": raw }))
        }
    }
}

fn require_trimmed_string<'a>(payload: &'a Value, key: &str) -> Result<&'a str, ApiError> {
    payload
        .get(key)
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .ok_or_else(|| ApiError::bad_request(format!("{key} is required")))
}

fn openai_oauth_account_payload(request: &Value, token_info: &Value) -> Value {
    let credentials = oauth_credentials_from_token_info(token_info);
    let access_token = credentials
        .get("access_token")
        .and_then(Value::as_str)
        .unwrap_or("")
        .to_owned();
    let name = request
        .get("name")
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .or_else(|| {
            token_info
                .get("email")
                .and_then(Value::as_str)
                .map(str::trim)
                .filter(|value| !value.is_empty())
        })
        .unwrap_or("OpenAI OAuth Account");
    let group_ids = group_ids_from_request(request);
    let primary_group_id = group_ids.first().copied().unwrap_or(1);

    json!({
        "name": name,
        "platform": "openai",
        "provider": "openai",
        "type": "oauth",
        "status": "active",
        "group_id": primary_group_id,
        "group_ids": group_ids,
        "api_key": access_token,
        "credentials": credentials.clone(),
        "proxy_id": request.get("proxy_id").cloned().unwrap_or(Value::Null),
        "concurrency": request.get("concurrency").and_then(Value::as_i64).unwrap_or(1),
        "priority": request.get("priority").and_then(Value::as_i64).unwrap_or(1),
        "supported_protocols": ["openai_responses", "openai_chat_completions", "openai_embeddings", "openai_images"],
        "upstream_protocol": "openai_responses",
        "extra": {
            "account_type": "oauth",
            "credentials": credentials,
            "oauth": {
                "provider": "openai",
                "created_at": token_info.get("created_at").cloned().unwrap_or(Value::Null)
            }
        }
    })
}

fn oauth_credentials_from_token_info(token_info: &Value) -> Value {
    let mut credentials = Map::new();
    for key in [
        "access_token",
        "refresh_token",
        "id_token",
        "expires_in",
        "expires_at",
        "token_type",
        "scope",
        "email",
        "client_id",
        "plan_type",
    ] {
        if let Some(value) = token_info.get(key) {
            credentials.insert(key.to_owned(), value.clone());
        }
    }
    Value::Object(credentials)
}

fn group_ids_from_request(request: &Value) -> Vec<i64> {
    let mut ids = request
        .get("group_ids")
        .and_then(Value::as_array)
        .map(|items| {
            items
                .iter()
                .filter_map(Value::as_i64)
                .filter(|id| *id > 0)
                .collect::<Vec<_>>()
        })
        .unwrap_or_default();
    if ids.is_empty() {
        if let Some(group_id) = request.get("group_id").and_then(Value::as_i64) {
            if group_id > 0 {
                ids.push(group_id);
            }
        }
    }
    ids.sort_unstable();
    ids.dedup();
    ids
}

fn account_response_with_redacted_credentials(mut account: Value) -> Value {
    let Some(object) = account.as_object_mut() else {
        return account;
    };
    object.remove("api_key");
    object.insert(
        "account_type".to_owned(),
        object
            .get("type")
            .cloned()
            .unwrap_or_else(|| Value::String("api-key".to_owned())),
    );

    let credentials = object
        .get("credentials")
        .cloned()
        .unwrap_or_else(|| json!({}));
    let (redacted, status) = redact_credentials_for_response(&credentials);
    object.insert("credentials".to_owned(), redacted);
    object.insert("credentials_status".to_owned(), status);
    account
}

fn admin_account_is_oauth(account: &Value) -> bool {
    account
        .get("type")
        .or_else(|| account.get("account_type"))
        .and_then(Value::as_str)
        .map(|value| matches!(value.trim(), "oauth" | "setup-token"))
        .unwrap_or_else(|| {
            account
                .get("extra")
                .and_then(|extra| extra.get("account_type"))
                .and_then(Value::as_str)
                .map(|value| matches!(value.trim(), "oauth" | "setup-token"))
                .unwrap_or(false)
        })
}

fn merge_account_extra(
    existing: Value,
    incoming: Value,
    credentials: &Value,
    account_type: &str,
) -> Value {
    let mut merged = existing.as_object().cloned().unwrap_or_default();
    if let Some(incoming) = incoming.as_object() {
        for (key, value) in incoming {
            merged.insert(key.clone(), value.clone());
        }
    }
    merged.insert("account_type".to_owned(), json!(account_type));
    merged.insert("credentials".to_owned(), credentials.clone());
    Value::Object(merged)
}

async fn probe_admin_account(
    state: &AppState,
    account_id: i64,
    payload: &Value,
) -> Result<Value, ApiError> {
    let account_item = state
        .admin_portal
        .get_collection_item("accounts", account_id)?;
    let group_id = admin_account_group_ids(&account_item)
        .into_iter()
        .next()
        .unwrap_or(1);
    let binding = account_binding_from_admin_json(group_id, &account_item)
        .ok_or_else(|| ApiError::bad_request("account configuration is invalid"))?;
    if !binding.account.enabled {
        return Err(ApiError::bad_request("account is disabled"));
    }

    let probe = AccountTestProbe::from_binding(binding, payload)?;
    Ok(probe.run().await)
}

struct AccountTestProbe {
    provider: domain::Provider,
    upstream_protocol: domain::UpstreamProtocol,
    base_url: String,
    api_key: String,
    requested_model: String,
    upstream_model: String,
    prompt: String,
}

impl AccountTestProbe {
    fn from_binding(
        binding: domain::AccountGroupBinding,
        payload: &Value,
    ) -> Result<Self, ApiError> {
        let upstream_protocol = binding.upstream_protocol();
        let account = binding.account;
        let requested_model = payload
            .get("model_id")
            .or_else(|| payload.get("model"))
            .and_then(Value::as_str)
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(ToOwned::to_owned)
            .unwrap_or_else(|| default_account_test_model(account.provider).to_owned());
        let upstream_model = account
            .resolve_mapped_model(&requested_model)
            .upstream_model;
        let base_url = account
            .base_url
            .as_deref()
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(normalize_upstream_base_url)
            .unwrap_or_else(|| default_account_test_base_url(account.provider).to_owned());
        let api_key = account
            .api_key
            .as_deref()
            .or_else(|| account.extra.get("api_key").and_then(Value::as_str))
            .or_else(|| {
                account
                    .extra
                    .get("credentials")
                    .and_then(|credentials| credentials.get("api_key"))
                    .and_then(Value::as_str)
            })
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .ok_or_else(|| ApiError::bad_request("account api_key is required"))?
            .to_owned();
        let prompt = payload
            .get("prompt")
            .and_then(Value::as_str)
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .unwrap_or("Say ok.")
            .to_owned();

        Ok(Self {
            provider: account.provider,
            upstream_protocol,
            base_url,
            api_key,
            requested_model,
            upstream_model,
            prompt,
        })
    }

    async fn run(&self) -> Value {
        let started = Instant::now();
        let response = match self.upstream_protocol {
            domain::UpstreamProtocol::OpenAiResponses => self.probe_openai_responses().await,
            domain::UpstreamProtocol::OpenAiChatCompletions => {
                self.probe_openai_chat_completions().await
            }
            domain::UpstreamProtocol::AnthropicMessages => self.probe_anthropic_messages().await,
            domain::UpstreamProtocol::GeminiGenerateContent => {
                self.probe_gemini_generate_content().await
            }
        };
        let latency_ms = started.elapsed().as_millis() as i64;
        match response {
            Ok(status) if status.is_success() => json!({
                "success": true,
                "message": "account test succeeded",
                "latency_ms": latency_ms,
                "provider": self.provider.as_str(),
                "protocol": account_test_protocol_name(self.upstream_protocol),
                "model": self.requested_model,
                "upstream_model": self.upstream_model,
                "status_code": status.as_u16()
            }),
            Ok(status) => json!({
                "success": false,
                "message": status.message,
                "latency_ms": latency_ms,
                "provider": self.provider.as_str(),
                "protocol": account_test_protocol_name(self.upstream_protocol),
                "model": self.requested_model,
                "upstream_model": self.upstream_model,
                "status_code": status.status_code
            }),
            Err(error) => json!({
                "success": false,
                "message": error,
                "latency_ms": latency_ms,
                "provider": self.provider.as_str(),
                "protocol": account_test_protocol_name(self.upstream_protocol),
                "model": self.requested_model,
                "upstream_model": self.upstream_model
            }),
        }
    }

    async fn probe_openai_responses(&self) -> Result<AccountProbeStatus, String> {
        let body = json!({
            "model": self.upstream_model,
            "input": self.prompt,
            "stream": false,
        });
        self.post_json(
            &join_url_path(&self.base_url, "/v1/responses"),
            body,
            |request| request.bearer_auth(&self.api_key),
        )
        .await
    }

    async fn probe_openai_chat_completions(&self) -> Result<AccountProbeStatus, String> {
        let body = json!({
            "model": self.upstream_model,
            "messages": [{
                "role": "user",
                "content": self.prompt
            }],
            "stream": false,
        });
        self.post_json(
            &join_url_path(&self.base_url, "/v1/chat/completions"),
            body,
            |request| request.bearer_auth(&self.api_key),
        )
        .await
    }

    async fn probe_anthropic_messages(&self) -> Result<AccountProbeStatus, String> {
        let body = json!({
            "model": self.upstream_model,
            "max_tokens": 64,
            "messages": [{
                "role": "user",
                "content": self.prompt
            }],
        });
        self.post_json(
            &join_url_path(&self.base_url, "/v1/messages"),
            body,
            |request| {
                request
                    .header("x-api-key", &self.api_key)
                    .header("anthropic-version", "2023-06-01")
            },
        )
        .await
    }

    async fn probe_gemini_generate_content(&self) -> Result<AccountProbeStatus, String> {
        let path = format!("/v1beta/models/{}:generateContent", self.upstream_model);
        let body = json!({
            "contents": [{
                "role": "user",
                "parts": [{ "text": self.prompt }]
            }]
        });
        self.post_json(&join_url_path(&self.base_url, &path), body, |request| {
            request.header("x-goog-api-key", &self.api_key)
        })
        .await
    }

    async fn post_json<F>(
        &self,
        url: &str,
        body: Value,
        decorate: F,
    ) -> Result<AccountProbeStatus, String>
    where
        F: FnOnce(reqwest::RequestBuilder) -> reqwest::RequestBuilder,
    {
        let client = reqwest::Client::new();
        let response = decorate(client.post(url).json(&body))
            .send()
            .await
            .map_err(|error| format!("request failed: {error}"))?;
        let status_code = response.status().as_u16();
        let text = response
            .text()
            .await
            .map_err(|error| format!("failed to read response body: {error}"))?;
        Ok(AccountProbeStatus {
            status_code,
            message: if (200..300).contains(&status_code) {
                "ok".to_owned()
            } else {
                format!("upstream returned {status_code}: {}", body_preview(&text))
            },
        })
    }
}

struct AccountProbeStatus {
    status_code: u16,
    message: String,
}

impl AccountProbeStatus {
    fn is_success(&self) -> bool {
        (200..300).contains(&self.status_code)
    }

    fn as_u16(&self) -> u16 {
        self.status_code
    }
}

fn parse_optional_json_body(body: &Bytes) -> Result<Value, ApiError> {
    if body.is_empty() {
        return Ok(json!({}));
    }
    serde_json::from_slice(body).map_err(|_| ApiError::bad_request("invalid JSON body"))
}

fn default_account_test_model(provider: domain::Provider) -> &'static str {
    match provider {
        domain::Provider::Anthropic | domain::Provider::Antigravity => "claude-sonnet-4-5-20250929",
        domain::Provider::Gemini | domain::Provider::Vertex => "gemini-2.0-flash",
        domain::Provider::OpenAi | domain::Provider::DeepSeek => "gpt-5.4",
    }
}

fn default_account_test_base_url(provider: domain::Provider) -> &'static str {
    match provider {
        domain::Provider::Anthropic | domain::Provider::Antigravity => "https://api.anthropic.com",
        domain::Provider::Gemini | domain::Provider::Vertex => {
            "https://generativelanguage.googleapis.com"
        }
        domain::Provider::DeepSeek => "https://api.deepseek.com",
        domain::Provider::OpenAi => "https://api.openai.com",
    }
}

fn account_test_protocol_name(protocol: domain::UpstreamProtocol) -> &'static str {
    match protocol {
        domain::UpstreamProtocol::OpenAiResponses => "openai_responses",
        domain::UpstreamProtocol::OpenAiChatCompletions => "openai_chat_completions",
        domain::UpstreamProtocol::AnthropicMessages => "anthropic_messages",
        domain::UpstreamProtocol::GeminiGenerateContent => "gemini_generate_content",
    }
}

fn normalize_upstream_base_url(value: &str) -> String {
    value.trim().trim_end_matches('/').to_owned()
}

fn join_url_path(base_url: &str, path: &str) -> String {
    format!(
        "{}/{}",
        base_url.trim_end_matches('/'),
        path.trim_start_matches('/')
    )
}

fn body_preview(value: &str) -> String {
    let value = value.trim();
    const MAX_PREVIEW_CHARS: usize = 512;
    if value.chars().count() <= MAX_PREVIEW_CHARS {
        return value.to_owned();
    }
    value.chars().take(MAX_PREVIEW_CHARS).collect::<String>() + "..."
}

fn current_rfc3339_timestamp() -> String {
    Utc::now().to_rfc3339()
}

async fn probe_admin_proxy(
    state: &AppState,
    proxy_id: i64,
    payload: &Value,
) -> Result<Value, ApiError> {
    let proxy = state
        .admin_portal
        .get_collection_item("proxies", proxy_id)?;
    let test_url = payload
        .get("test_url")
        .or_else(|| payload.get("url"))
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .unwrap_or("http://httpbin.org/ip");
    let proxy_url = build_admin_proxy_url(&proxy)?;
    let started = Instant::now();
    let response = request_through_proxy(test_url, proxy_url.as_deref()).await;
    let latency_ms = started.elapsed().as_millis() as i64;
    let tested_at = current_rfc3339_timestamp();
    let result = match response {
        Ok(status) if status.is_success() => json!({
            "id": proxy_id,
            "success": true,
            "message": "proxy test succeeded",
            "latency_ms": latency_ms,
            "tested_at": tested_at,
            "status_code": status.as_u16(),
            "proxy_url": proxy_url.clone().unwrap_or_default(),
            "target_url": test_url
        }),
        Ok(status) => json!({
            "id": proxy_id,
            "success": false,
            "message": status.message,
            "latency_ms": latency_ms,
            "tested_at": tested_at,
            "status_code": status.status_code,
            "proxy_url": proxy_url.clone().unwrap_or_default(),
            "target_url": test_url
        }),
        Err(error) => json!({
            "id": proxy_id,
            "success": false,
            "message": error,
            "latency_ms": latency_ms,
            "tested_at": tested_at,
            "proxy_url": proxy_url.clone().unwrap_or_default(),
            "target_url": test_url
        }),
    };
    let success = result
        .get("success")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    state.admin_portal.update_collection_item(
        "proxies",
        proxy_id,
        json!({
            "last_tested_at": tested_at,
            "last_test_success": success,
            "latency_ms": latency_ms,
            "latency_status": if success { "success" } else { "failed" },
            "latency_message": result.get("message").cloned().unwrap_or_else(|| json!("")),
        }),
    )?;
    Ok(result)
}

async fn request_through_proxy(
    target_url: &str,
    proxy_url: Option<&str>,
) -> Result<AccountProbeStatus, String> {
    let mut builder = reqwest::Client::builder().timeout(std::time::Duration::from_secs(10));
    if let Some(proxy_url) = proxy_url {
        let proxy = reqwest::Proxy::all(proxy_url)
            .map_err(|error| format!("invalid proxy URL: {error}"))?;
        builder = builder.proxy(proxy);
    }
    let client = builder
        .build()
        .map_err(|error| format!("failed to create proxy client: {error}"))?;
    let response = client
        .get(target_url)
        .send()
        .await
        .map_err(|error| format!("proxy request failed: {error}"))?;
    let status_code = response.status().as_u16();
    let text = response
        .text()
        .await
        .map_err(|error| format!("failed to read response body: {error}"))?;
    Ok(AccountProbeStatus {
        status_code,
        message: if (200..300).contains(&status_code) {
            "ok".to_owned()
        } else {
            format!("target returned {status_code}: {}", body_preview(&text))
        },
    })
}

fn build_admin_proxy_url(proxy: &Value) -> Result<Option<String>, ApiError> {
    if let Some(url) = proxy
        .get("url")
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
    {
        return if url.eq_ignore_ascii_case("direct") {
            Ok(None)
        } else {
            Ok(Some(url.to_owned()))
        };
    }
    let protocol = proxy
        .get("protocol")
        .or_else(|| proxy.get("type"))
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .unwrap_or("direct");
    if protocol.eq_ignore_ascii_case("direct") {
        return Ok(None);
    }
    let host = proxy
        .get("host")
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .ok_or_else(|| ApiError::bad_request("proxy host is required"))?;
    let port = proxy
        .get("port")
        .and_then(Value::as_i64)
        .filter(|port| *port > 0)
        .ok_or_else(|| ApiError::bad_request("proxy port is required"))?;
    let username = proxy
        .get("username")
        .and_then(Value::as_str)
        .map(str::trim)
        .unwrap_or("");
    let password = proxy
        .get("password")
        .and_then(Value::as_str)
        .map(str::trim)
        .unwrap_or("");
    let credentials = if username.is_empty() && password.is_empty() {
        String::new()
    } else {
        format!(
            "{}:{}@",
            percent_encode_proxy_component(username),
            percent_encode_proxy_component(password)
        )
    };
    Ok(Some(format!(
        "{}://{}{}:{}",
        protocol.trim().to_ascii_lowercase(),
        credentials,
        host,
        port
    )))
}

fn percent_encode_proxy_component(value: &str) -> String {
    const HEX: &[u8; 16] = b"0123456789ABCDEF";
    let mut encoded = String::new();
    for byte in value.as_bytes() {
        let ch = *byte as char;
        if ch.is_ascii_alphanumeric() || matches!(ch, '-' | '.' | '_' | '~') {
            encoded.push(ch);
        } else {
            encoded.push('%');
            encoded.push(HEX[(byte >> 4) as usize] as char);
            encoded.push(HEX[(byte & 0x0f) as usize] as char);
        }
    }
    encoded
}

fn proxy_accounts_for_stats(state: &AppState, proxy_id: i64) -> Vec<Value> {
    state
        .admin_portal
        .list_all("accounts", &HashMap::new())
        .as_array()
        .cloned()
        .unwrap_or_default()
        .into_iter()
        .filter(|account| {
            account
                .get("proxy_id")
                .and_then(Value::as_i64)
                .map(|id| id == proxy_id)
                .unwrap_or(false)
        })
        .collect()
}

async fn check_admin_proxy_quality(
    state: &AppState,
    proxy_id: i64,
    payload: &Value,
) -> Result<Value, ApiError> {
    let proxy = state
        .admin_portal
        .get_collection_item("proxies", proxy_id)?;
    let proxy_url = build_admin_proxy_url(&proxy)?;
    let targets = proxy_quality_targets_from_payload(payload);
    if targets.is_empty() {
        return Err(ApiError::bad_request(
            "quality check targets cannot be empty",
        ));
    }
    let started = Instant::now();
    let mut items = Vec::with_capacity(targets.len());
    let mut passed_count = 0_i64;
    let mut warn_count = 0_i64;
    let mut failed_count = 0_i64;

    for target in targets {
        let item = run_proxy_quality_target(&target, proxy_url.as_deref()).await;
        match item.get("status").and_then(Value::as_str).unwrap_or("fail") {
            "pass" => passed_count += 1,
            "warn" => warn_count += 1,
            _ => failed_count += 1,
        }
        items.push(item);
    }

    let score = proxy_quality_score(warn_count, failed_count);
    let grade = proxy_quality_grade(score);
    let status = if failed_count == 0 {
        "healthy"
    } else if passed_count > 0 || warn_count > 0 {
        "degraded"
    } else {
        "failed"
    };
    let checked_at = current_rfc3339_timestamp();
    let result = json!({
        "id": proxy_id,
        "success": failed_count == 0,
        "status": status,
        "score": score,
        "grade": grade,
        "passed_count": passed_count,
        "warn_count": warn_count,
        "failed_count": failed_count,
        "challenge_count": 0,
        "latency_ms": started.elapsed().as_millis() as i64,
        "checked_at": checked_at,
        "summary": format!("passed {passed_count}, warnings {warn_count}, failed {failed_count}"),
        "items": items,
    });
    state.admin_portal.update_collection_item(
        "proxies",
        proxy_id,
        json!({
            "quality_status": status,
            "quality_score": score,
            "quality_grade": grade,
            "quality_summary": result["summary"].clone(),
            "quality_checked_at": checked_at,
            "quality_items": result["items"].clone(),
        }),
    )?;
    Ok(result)
}

#[derive(Debug, Clone)]
struct ProxyQualityTarget {
    name: String,
    url: String,
    method: String,
    allowed_statuses: Vec<u16>,
}

fn proxy_quality_targets_from_payload(payload: &Value) -> Vec<ProxyQualityTarget> {
    payload
        .get("targets")
        .and_then(Value::as_array)
        .map(|items| {
            items
                .iter()
                .filter_map(proxy_quality_target_from_value)
                .collect::<Vec<_>>()
        })
        .filter(|items| !items.is_empty())
        .unwrap_or_else(default_proxy_quality_targets)
}

fn proxy_quality_target_from_value(value: &Value) -> Option<ProxyQualityTarget> {
    let url = value.get("url").and_then(Value::as_str)?.trim();
    if url.is_empty() {
        return None;
    }
    let name = value
        .get("target")
        .or_else(|| value.get("name"))
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .unwrap_or(url)
        .to_owned();
    let method = value
        .get("method")
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .unwrap_or("GET")
        .to_ascii_uppercase();
    let allowed_statuses = value
        .get("allowed_statuses")
        .or_else(|| value.get("allowed_status"))
        .and_then(Value::as_array)
        .map(|items| {
            items
                .iter()
                .filter_map(|item| item.as_u64().map(|value| value as u16))
                .collect::<Vec<_>>()
        })
        .filter(|items| !items.is_empty())
        .unwrap_or_else(|| vec![200]);
    Some(ProxyQualityTarget {
        name,
        url: url.to_owned(),
        method,
        allowed_statuses,
    })
}

fn default_proxy_quality_targets() -> Vec<ProxyQualityTarget> {
    vec![
        ProxyQualityTarget {
            name: "openai".to_owned(),
            url: "https://api.openai.com/v1/models".to_owned(),
            method: "GET".to_owned(),
            allowed_statuses: vec![200, 401],
        },
        ProxyQualityTarget {
            name: "anthropic".to_owned(),
            url: "https://api.anthropic.com/v1/messages".to_owned(),
            method: "GET".to_owned(),
            allowed_statuses: vec![200, 400, 401, 404, 405],
        },
        ProxyQualityTarget {
            name: "gemini".to_owned(),
            url: "https://generativelanguage.googleapis.com/$discovery/rest?version=v1beta"
                .to_owned(),
            method: "GET".to_owned(),
            allowed_statuses: vec![200],
        },
    ]
}

async fn run_proxy_quality_target(target: &ProxyQualityTarget, proxy_url: Option<&str>) -> Value {
    let started = Instant::now();
    let mut builder = reqwest::Client::builder().timeout(std::time::Duration::from_secs(15));
    if let Some(proxy_url) = proxy_url {
        match reqwest::Proxy::all(proxy_url) {
            Ok(proxy) => builder = builder.proxy(proxy),
            Err(error) => {
                return json!({
                    "target": target.name,
                    "url": target.url,
                    "status": "fail",
                    "latency_ms": started.elapsed().as_millis() as i64,
                    "message": format!("invalid proxy URL: {error}")
                });
            }
        }
    }
    let client = match builder.build() {
        Ok(client) => client,
        Err(error) => {
            return json!({
                "target": target.name,
                "url": target.url,
                "status": "fail",
                "latency_ms": started.elapsed().as_millis() as i64,
                "message": format!("failed to create proxy client: {error}")
            });
        }
    };
    let method =
        reqwest::Method::from_bytes(target.method.as_bytes()).unwrap_or(reqwest::Method::GET);
    let response = client
        .request(method, &target.url)
        .header("accept", "application/json,text/html,*/*")
        .header("user-agent", "backend_next-proxy-quality/0.1")
        .send()
        .await;
    let latency_ms = started.elapsed().as_millis() as i64;
    match response {
        Ok(response) => {
            let status_code = response.status().as_u16();
            let body = response.text().await.unwrap_or_default();
            let status = if (200..300).contains(&status_code) {
                "pass"
            } else if target.allowed_statuses.contains(&status_code) || status_code == 429 {
                "warn"
            } else {
                "fail"
            };
            json!({
                "target": target.name,
                "url": target.url,
                "status": status,
                "http_status": status_code,
                "latency_ms": latency_ms,
                "message": if status == "fail" {
                    format!("unexpected HTTP {status_code}: {}", body_preview(&body))
                } else {
                    format!("HTTP {status_code}")
                }
            })
        }
        Err(error) => json!({
            "target": target.name,
            "url": target.url,
            "status": "fail",
            "latency_ms": latency_ms,
            "message": format!("request failed: {error}")
        }),
    }
}

fn proxy_quality_score(warn_count: i64, failed_count: i64) -> i64 {
    (100 - warn_count * 10 - failed_count * 22).clamp(0, 100)
}

fn proxy_quality_grade(score: i64) -> &'static str {
    match score {
        90..=100 => "A",
        75..=89 => "B",
        60..=74 => "C",
        40..=59 => "D",
        _ => "F",
    }
}

fn redact_credentials_for_response(credentials: &Value) -> (Value, Value) {
    let Some(credentials) = credentials.as_object() else {
        return (Value::Null, Value::Null);
    };
    let mut redacted = Map::new();
    let mut status = Map::new();
    for (key, value) in credentials {
        if is_sensitive_credential_key(key) {
            status.insert(format!("has_{key}"), json!(credential_value_present(value)));
        } else {
            redacted.insert(key.clone(), value.clone());
        }
    }
    (Value::Object(redacted), Value::Object(status))
}

fn is_sensitive_credential_key(key: &str) -> bool {
    matches!(
        key,
        "access_token"
            | "refresh_token"
            | "id_token"
            | "api_key"
            | "session_key"
            | "cookie"
            | "aws_secret_access_key"
            | "aws_session_token"
            | "service_account_json"
            | "service_account"
            | "private_key"
    )
}

fn credential_value_present(value: &Value) -> bool {
    match value {
        Value::Null => false,
        Value::String(text) => !text.is_empty(),
        Value::Bool(flag) => *flag,
        _ => true,
    }
}

fn user_platform_quota_records_from_payload(
    user_id: i64,
    payload: &Value,
) -> Result<Vec<repository::UserPlatformQuotaRecord>, ApiError> {
    let quotas = payload
        .get("quotas")
        .and_then(Value::as_array)
        .ok_or_else(|| ApiError::bad_request("quotas is required"))?;
    if quotas.len() > 4 {
        return Err(ApiError::bad_request("quotas length must be <= 4"));
    }
    quotas
        .iter()
        .map(|quota| {
            let platform = quota
                .get("platform")
                .and_then(Value::as_str)
                .ok_or_else(|| ApiError::bad_request("platform is required"))?
                .to_owned();
            for field in ["daily_limit_usd", "weekly_limit_usd", "monthly_limit_usd"] {
                if let Some(value) = quota.get(field).and_then(Value::as_f64) {
                    if !value.is_finite() || value < 0.0 {
                        return Err(ApiError::bad_request(format!(
                            "{field} must be a finite number >= 0"
                        )));
                    }
                }
            }
            Ok(repository::UserPlatformQuotaRecord {
                id: 0,
                user_id,
                platform,
                daily_limit_usd: quota.get("daily_limit_usd").and_then(Value::as_f64),
                weekly_limit_usd: quota.get("weekly_limit_usd").and_then(Value::as_f64),
                monthly_limit_usd: quota.get("monthly_limit_usd").and_then(Value::as_f64),
                daily_usage_usd: 0.0,
                weekly_usage_usd: 0.0,
                monthly_usage_usd: 0.0,
                daily_window_start: None,
                weekly_window_start: None,
                monthly_window_start: None,
            })
        })
        .collect()
}

