fn payment_plan_from_payload(
    id: i64,
    payload: Value,
    existing: Option<repository::PaymentPlanRecord>,
) -> Result<repository::PaymentPlanRecord, ApiError> {
    let object = payload
        .as_object()
        .ok_or_else(|| ApiError::bad_request("payment plan payload must be an object"))?;
    let now = Utc::now().to_rfc3339();
    let base = existing.unwrap_or_else(|| repository::PaymentPlanRecord {
        id,
        group_id: 0,
        name: String::new(),
        description: String::new(),
        price: 0.0,
        original_price: None,
        validity_days: 0,
        validity_unit: "day".to_owned(),
        features: json!([]),
        product_name: String::new(),
        for_sale: true,
        sort_order: 0,
        created_at: now.clone(),
        updated_at: now.clone(),
    });
    let plan = repository::PaymentPlanRecord {
        id: if id > 0 { id } else { base.id },
        group_id: value_i64(object, "group_id").unwrap_or(base.group_id),
        name: value_string(object, "name").unwrap_or(base.name),
        description: value_string(object, "description").unwrap_or(base.description),
        price: value_f64(object, "price").unwrap_or(base.price),
        original_price: if object.contains_key("original_price") {
            object.get("original_price").and_then(Value::as_f64)
        } else {
            base.original_price
        },
        validity_days: value_i64(object, "validity_days")
            .map(|value| value as i32)
            .unwrap_or(base.validity_days),
        validity_unit: value_string(object, "validity_unit").unwrap_or(base.validity_unit),
        features: object
            .get("features")
            .cloned()
            .map(normalize_plan_features_value)
            .unwrap_or(base.features),
        product_name: value_string(object, "product_name").unwrap_or(base.product_name),
        for_sale: value_bool(object, "for_sale").unwrap_or(base.for_sale),
        sort_order: value_i64(object, "sort_order")
            .map(|value| value as i32)
            .unwrap_or(base.sort_order),
        created_at: base.created_at,
        updated_at: now,
    };
    validate_payment_plan_payload(&plan)?;
    Ok(plan)
}

async fn resolve_payment_order_plan(
    state: &AppState,
    request: &CreateOrderRequest,
) -> Result<Option<repository::PaymentPlanRecord>, ApiError> {
    let requested_order_type = request
        .order_type
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .unwrap_or("balance")
        .to_ascii_lowercase();
    let plan_id = request.plan_id.filter(|id| *id > 0);
    if requested_order_type != "subscription" && plan_id.is_none() {
        return Ok(None);
    }
    let plan_id =
        plan_id.ok_or_else(|| ApiError::bad_request("subscription order requires a plan"))?;
    let plan = state
        .repository
        .get_payment_plan(plan_id)
        .await
        .map_err(|error| match error {
            repository::RepositoryError::NotFound { .. } => {
                ApiError::not_found("plan not found or not for sale")
            }
            other => repository_api_error(other),
        })?;
    if !plan.for_sale {
        return Err(ApiError::not_found("plan not found or not for sale"));
    }
    Ok(Some(plan))
}

fn request_with_resolved_plan(
    mut request: CreateOrderRequest,
    plan: Option<&repository::PaymentPlanRecord>,
) -> CreateOrderRequest {
    if let Some(plan) = plan {
        request.amount = plan.price;
        request.order_type = Some("subscription".to_owned());
        request.plan_id = Some(plan.id);
    }
    request
}

fn enrich_payment_order_response_with_plan(
    order: &mut Value,
    plan: Option<&repository::PaymentPlanRecord>,
) {
    let Some(plan) = plan else {
        return;
    };
    if let Value::Object(object) = order {
        object.insert("amount".to_owned(), json!(plan.price));
        object.insert("pay_amount".to_owned(), json!(plan.price));
        object.insert("order_type".to_owned(), json!("subscription"));
        object.insert("plan_id".to_owned(), json!(plan.id));
        object.insert("plan_group_id".to_owned(), json!(plan.group_id));
        object.insert(
            "plan_validity_days".to_owned(),
            json!(plan_validity_days(plan)),
        );
    }
}

fn plan_validity_days(plan: &repository::PaymentPlanRecord) -> i32 {
    match plan.validity_unit.trim().to_ascii_lowercase().as_str() {
        "month" | "months" => plan.validity_days * 30,
        "year" | "years" => plan.validity_days * 365,
        _ => plan.validity_days,
    }
}

fn validate_payment_plan_payload(plan: &repository::PaymentPlanRecord) -> Result<(), ApiError> {
    if plan.name.trim().is_empty() {
        return Err(ApiError::bad_request("plan name is required"));
    }
    if plan.group_id <= 0 {
        return Err(ApiError::bad_request("group is required"));
    }
    if !plan.price.is_finite() || plan.price <= 0.0 {
        return Err(ApiError::bad_request("price must be > 0"));
    }
    if let Some(original_price) = plan.original_price {
        if !original_price.is_finite() || original_price < 0.0 {
            return Err(ApiError::bad_request("original price must be >= 0"));
        }
    }
    if plan.validity_days <= 0 {
        return Err(ApiError::bad_request("validity days must be > 0"));
    }
    if plan.validity_unit.trim().is_empty() {
        return Err(ApiError::bad_request("validity unit is required"));
    }
    Ok(())
}

fn normalize_plan_features_value(value: Value) -> Value {
    match value {
        Value::Array(_) => value,
        Value::String(text) => {
            let items = text
                .split('\n')
                .flat_map(|line| line.split(','))
                .map(str::trim)
                .filter(|item| !item.is_empty())
                .map(|item| Value::String(item.to_owned()))
                .collect::<Vec<_>>();
            Value::Array(items)
        }
        Value::Null => Value::Array(Vec::new()),
        other => other,
    }
}

fn plan_features_for_response(value: &Value) -> Value {
    normalize_plan_features_value(value.clone())
}

fn value_string(object: &Map<String, Value>, key: &str) -> Option<String> {
    object.get(key)?.as_str().map(ToOwned::to_owned)
}

fn value_i64(object: &Map<String, Value>, key: &str) -> Option<i64> {
    object.get(key)?.as_i64()
}

fn value_f64(object: &Map<String, Value>, key: &str) -> Option<f64> {
    object.get(key)?.as_f64()
}

fn value_bool(object: &Map<String, Value>, key: &str) -> Option<bool> {
    object.get(key)?.as_bool()
}

async fn assign_repository_subscription(
    state: &AppState,
    payload: &Value,
) -> Result<repository::UserSubscriptionRecord, ApiError> {
    let object = payload
        .as_object()
        .ok_or_else(|| ApiError::bad_request("subscription payload must be an object"))?;
    let user_id =
        value_i64(object, "user_id").ok_or_else(|| ApiError::bad_request("user_id is required"))?;
    let group_id = value_i64(object, "group_id")
        .ok_or_else(|| ApiError::bad_request("group_id is required"))?;
    let validity_days = value_i64(object, "validity_days")
        .unwrap_or(30)
        .clamp(1, 36500);
    ensure_repository_user(state, user_id).await?;
    let _ = match state.repository.get_group(GroupId(group_id)).await {
        Ok(group) => group,
        Err(repository::RepositoryError::NotFound { .. }) => {
            group_from_admin_collection(state, group_id).map_err(repository_api_error)?
        }
        Err(error) => return Err(repository_api_error(error)),
    };
    let now = Utc::now();
    let source_order_id = value_string(object, "source_order_id")
        .filter(|value| !value.trim().is_empty())
        .unwrap_or_else(|| {
            format!(
                "admin-subscription-{user_id}-{group_id}-{}",
                now.timestamp()
            )
        });
    state
        .repository
        .upsert_user_subscription(repository::UserSubscriptionRecord {
            id: 0,
            user_id,
            group_id,
            plan_id: value_i64(object, "plan_id"),
            status: value_string(object, "status").unwrap_or_else(|| "active".to_owned()),
            starts_at: now.to_rfc3339(),
            expires_at: (now + Duration::days(validity_days)).to_rfc3339(),
            daily_usage_usd: 0.0,
            weekly_usage_usd: 0.0,
            monthly_usage_usd: 0.0,
            daily_window_start: None,
            weekly_window_start: None,
            monthly_window_start: None,
            source_order_id,
            created_at: now.to_rfc3339(),
            metadata: json!({
                "source": "admin",
                "validity_days": validity_days,
                "notes": value_string(object, "notes").unwrap_or_default()
            }),
        })
        .await
        .map_err(repository_api_error)
}

async fn admin_filtered_subscriptions(
    state: &AppState,
    query: &HashMap<String, String>,
    forced_user_id: Option<i64>,
    forced_group_id: Option<i64>,
) -> Result<Vec<repository::UserSubscriptionRecord>, ApiError> {
    let requested_user_id = forced_user_id.or_else(|| query.get("user_id")?.parse().ok());
    let requested_group_id = forced_group_id.or_else(|| query.get("group_id")?.parse().ok());
    let status = query
        .get("status")
        .map(|value| value.trim().to_ascii_lowercase())
        .filter(|value| !value.is_empty());
    let mut records = state
        .repository
        .list_subscriptions()
        .await
        .map_err(repository_api_error)?
        .into_iter()
        .filter(|record| requested_user_id.map_or(true, |user_id| record.user_id == user_id))
        .filter(|record| requested_group_id.map_or(true, |group_id| record.group_id == group_id))
        .filter(|record| {
            status
                .as_ref()
                .map_or(true, |status| record.status.eq_ignore_ascii_case(status))
        })
        .collect::<Vec<_>>();
    match query
        .get("sort_order")
        .map(|value| value.to_ascii_lowercase())
        .as_deref()
    {
        Some("asc") => records.sort_by_key(|record| record.id),
        _ => records.sort_by(|left, right| right.id.cmp(&left.id)),
    }
    Ok(records)
}

async fn admin_subscription_page(
    state: &AppState,
    subscriptions: Vec<repository::UserSubscriptionRecord>,
    query: &HashMap<String, String>,
) -> Result<Value, ApiError> {
    let page = query_i64(query, "page", 1).max(1);
    let page_size = query_i64(query, "page_size", 20).clamp(1, 200);
    let total = subscriptions.len() as i64;
    let start = ((page - 1) * page_size) as usize;
    let mut items = Vec::new();
    for subscription in subscriptions
        .into_iter()
        .skip(start)
        .take(page_size as usize)
    {
        items.push(admin_subscription_json(state, &subscription).await);
    }
    Ok(paginated_value(items, total, page, page_size))
}

