async fn validate_admin_api_key(state: &AppState, candidate: &str) -> Result<bool, ApiError> {
    let stored = match state
        .repository
        .get_system_setting("admin", "admin_api_key")
        .await
    {
        Ok(record) => record
            .value
            .get("key")
            .and_then(Value::as_str)
            .map(str::to_owned),
        Err(repository::RepositoryError::NotFound { .. }) => None,
        Err(error) => return Err(repository_api_error(error)),
    };
    Ok(stored
        .as_deref()
        .map(|key| constant_time_eq(candidate.as_bytes(), key.as_bytes()))
        .unwrap_or(false))
}

async fn admin_api_key_status(state: &AppState) -> Result<Value, ApiError> {
    let key = match state
        .repository
        .get_system_setting("admin", "admin_api_key")
        .await
    {
        Ok(record) => record
            .value
            .get("key")
            .and_then(Value::as_str)
            .map(str::to_owned),
        Err(repository::RepositoryError::NotFound { .. }) => None,
        Err(error) => return Err(repository_api_error(error)),
    };
    Ok(match key.as_deref() {
        Some(value) => json!({
            "exists": true,
            "masked_key": mask_admin_api_key(value)
        }),
        None => json!({
            "exists": false,
            "masked_key": null
        }),
    })
}

fn mask_admin_api_key(key: &str) -> String {
    let chars = key.chars().collect::<Vec<_>>();
    if chars.len() <= 12 {
        return "****".to_owned();
    }
    let prefix = chars.iter().take(8).collect::<String>();
    let suffix = chars
        .iter()
        .skip(chars.len().saturating_sub(4))
        .collect::<String>();
    format!("{prefix}...{suffix}")
}

fn constant_time_eq(left: &[u8], right: &[u8]) -> bool {
    let max_len = left.len().max(right.len());
    let mut diff = left.len() ^ right.len();
    for index in 0..max_len {
        let left_byte = left.get(index).copied().unwrap_or(0);
        let right_byte = right.get(index).copied().unwrap_or(0);
        diff |= (left_byte ^ right_byte) as usize;
    }
    diff == 0
}

async fn repository_email_templates(state: &AppState) -> Result<Value, ApiError> {
    let mut data = state.admin_portal.email_templates();
    let records = state
        .repository
        .list_system_settings("email_templates")
        .await
        .map_err(repository_api_error)?;
    let mut summaries = data
        .get("templates")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();
    for record in records {
        if let Some(summary) = email_template_summary(record.value) {
            upsert_email_template_summary(&mut summaries, summary);
        }
    }
    summaries.sort_by(|left, right| {
        let left_key = format!("{}:{}", left["event"], left["locale"]);
        let right_key = format!("{}:{}", right["event"], right["locale"]);
        left_key.cmp(&right_key)
    });
    if let Some(object) = data.as_object_mut() {
        object.insert("templates".to_owned(), Value::Array(summaries));
    }
    Ok(data)
}

async fn repository_email_template_detail(
    state: &AppState,
    event: &str,
    locale: &str,
) -> Result<Value, ApiError> {
    let key = email_template_setting_key(event, locale)?;
    match state
        .repository
        .get_system_setting("email_templates", &key)
        .await
    {
        Ok(record) => Ok(record.value),
        Err(repository::RepositoryError::NotFound { .. }) => {
            Ok(state.admin_portal.email_template_detail(event, locale)?)
        }
        Err(error) => Err(repository_api_error(error)),
    }
}

async fn repository_email_template_preview(
    state: &AppState,
    payload: Value,
) -> Result<Value, ApiError> {
    let variables = payload
        .get("variables")
        .and_then(Value::as_object)
        .cloned()
        .unwrap_or_default();
    let event = payload
        .get("event")
        .and_then(Value::as_str)
        .unwrap_or("verify_email");
    let locale = payload
        .get("locale")
        .and_then(Value::as_str)
        .unwrap_or("zh-CN");
    let template = repository_email_template_detail(state, event, locale).await?;
    let subject = payload
        .get("subject")
        .and_then(Value::as_str)
        .or_else(|| template.get("subject").and_then(Value::as_str))
        .unwrap_or_default();
    let html = payload
        .get("html")
        .and_then(Value::as_str)
        .or_else(|| template.get("html").and_then(Value::as_str))
        .unwrap_or_default();
    Ok(json!({
        "subject": render_template_text(subject, &variables),
        "html": render_template_text(html, &variables)
    }))
}

async fn delete_email_template_setting(
    state: &AppState,
    event: &str,
    locale: &str,
) -> Result<(), ApiError> {
    let key = email_template_setting_key(event, locale)?;
    match state
        .repository
        .delete_system_setting("email_templates", &key)
        .await
    {
        Ok(()) | Err(repository::RepositoryError::NotFound { .. }) => Ok(()),
        Err(error) => Err(repository_api_error(error)),
    }
}

fn email_template_setting_key(event: &str, locale: &str) -> Result<String, ApiError> {
    let event = event.trim();
    let locale = locale.trim();
    if event.is_empty() {
        return Err(ApiError::bad_request("event is required"));
    }
    if locale.is_empty() {
        return Err(ApiError::bad_request("locale is required"));
    }
    Ok(format!("{event}.{locale}"))
}

fn email_template_summary(template: Value) -> Option<Value> {
    Some(json!({
        "event": template.get("event")?.clone(),
        "locale": template.get("locale")?.clone(),
        "subject": template.get("subject").cloned().unwrap_or_else(|| json!("")),
        "is_custom": template
            .get("is_custom")
            .and_then(Value::as_bool)
            .unwrap_or(false),
        "updated_at": template.get("updated_at").cloned().unwrap_or_else(|| json!(""))
    }))
}

fn upsert_email_template_summary(summaries: &mut Vec<Value>, summary: Value) {
    let event = summary.get("event").cloned().unwrap_or(Value::Null);
    let locale = summary.get("locale").cloned().unwrap_or(Value::Null);
    if let Some(existing) = summaries
        .iter_mut()
        .find(|item| item.get("event") == Some(&event) && item.get("locale") == Some(&locale))
    {
        *existing = summary;
    } else {
        summaries.push(summary);
    }
}

fn render_template_text(input: &str, variables: &Map<String, Value>) -> String {
    let mut output = input.to_owned();
    for (key, value) in variables {
        let replacement = value
            .as_str()
            .map(ToOwned::to_owned)
            .unwrap_or_else(|| value.to_string());
        output = output.replace(&format!("{{{{{key}}}}}"), &replacement);
    }
    output
}

async fn admin_payment_config_with_defaults(state: &AppState) -> Result<Value, ApiError> {
    repository_setting_or_default(
        state,
        "admin",
        "payment_config",
        default_admin_payment_config(),
    )
    .await
}

async fn payment_config_with_portal_defaults(state: &AppState) -> Result<Value, ApiError> {
    let admin_config = admin_payment_config_with_defaults(state).await?;
    let mut user_config = state.payment_portal.config();
    apply_payment_config_to_user_config(&mut user_config, &admin_config);
    Ok(user_config)
}

async fn payment_checkout_info_with_config(state: &AppState) -> Result<Value, ApiError> {
    let admin_config = admin_payment_config_with_defaults(state).await?;
    let mut checkout_info = state.payment_portal.checkout_info();
    if let Ok(plans) = state.repository.list_payment_plans_for_sale().await {
        checkout_info["plans"] = payment_plans_json(&plans);
    }
    if let Ok(provider_instances) = repository_payment_provider_instances(state).await {
        if let Some(methods) = checkout_methods_from_provider_instances(&provider_instances) {
            let (global_min, global_max) = methods_global_range(&methods);
            checkout_info["methods"] = methods;
            checkout_info["global_min"] = json!(global_min);
            checkout_info["global_max"] = json!(global_max);
        } else {
            checkout_info["methods"] = json!({});
            checkout_info["global_min"] = json!(0.0);
            checkout_info["global_max"] = json!(0.0);
        }
        if let Some(stripe_publishable_key) =
            stripe_publishable_key_from_provider_instances(&provider_instances)
        {
            checkout_info["stripe_publishable_key"] = json!(stripe_publishable_key);
        }
        apply_payment_config_to_checkout_info(&mut checkout_info, &admin_config);
    } else {
        checkout_info["methods"] = json!({});
        checkout_info["global_min"] = json!(0.0);
        checkout_info["global_max"] = json!(0.0);
        apply_payment_config_to_checkout_info(&mut checkout_info, &admin_config);
    }
    Ok(checkout_info)
}

fn payment_limits_from_provider_instances(
    instances: &[repository::PaymentProviderInstanceRecord],
) -> Value {
    if let Some(methods) = checkout_methods_from_provider_instances(instances) {
        let (global_min, global_max) = methods_global_range(&methods);
        json!({
            "methods": methods,
            "global_min": global_min,
            "global_max": global_max
        })
    } else {
        json!({
            "methods": {},
            "global_min": 0.0,
            "global_max": 0.0
        })
    }
}

async fn admin_settings_with_payment_config(state: &AppState) -> Result<Value, ApiError> {
    let mut settings =
        repository_setting_or_default(state, "admin", "settings", default_admin_settings()).await?;
    if let Some(object) = settings.as_object_mut() {
        object.insert(
            "totp_encryption_key_configured".to_owned(),
            json!(state.totp_secret.is_configured()),
        );
    }
    let payment_config = admin_payment_config_with_defaults(state).await?;
    Ok(merge_admin_settings_and_payment_config(
        settings,
        payment_config,
    ))
}

