fn insert_public_setting(
    target: &mut Map<String, Value>,
    settings: &Value,
    key: &str,
    default: Value,
) {
    target.insert(key.to_owned(), public_setting(settings, key, default));
}

fn public_password_reset_enabled(settings: &Value) -> bool {
    let reset_enabled = bool_setting(settings, "password_reset_enabled", true);
    let email_enabled = if settings.get("email_verify_enabled").is_some() {
        bool_setting(settings, "email_verify_enabled", false)
    } else {
        bool_setting(settings, "email_enabled", false)
    };
    reset_enabled && email_enabled
}

fn public_setting(settings: &Value, key: &str, default: Value) -> Value {
    settings.get(key).cloned().unwrap_or(default)
}

fn validate_code_value(code: &str) -> Result<&str, ApiError> {
    let code = code.trim();
    if code.is_empty() {
        return Err(ApiError::bad_request("code is required"));
    }
    if code.len() > 128 {
        return Err(ApiError::bad_request("code is too long"));
    }
    Ok(code)
}

fn bool_setting(settings: &Value, key: &str, default: bool) -> bool {
    settings
        .get(key)
        .and_then(Value::as_bool)
        .unwrap_or(default)
}

async fn find_admin_collection_item_by_code(
    state: &AppState,
    collection: &str,
    code: &str,
) -> Result<Option<Value>, ApiError> {
    let needle = code.trim();
    let items = repository_admin_collection_items(state, collection)
        .await?
        .unwrap_or_default();
    Ok(items.into_iter().find(|item| {
        item.get("code")
            .and_then(Value::as_str)
            .is_some_and(|candidate| candidate.trim().eq_ignore_ascii_case(needle))
    }))
}

fn string_field_eq_any(item: &Value, key: &str, expected: &[&str]) -> bool {
    item.get(key)
        .and_then(Value::as_str)
        .map(str::trim)
        .is_some_and(|value| {
            expected
                .iter()
                .any(|expected| value.eq_ignore_ascii_case(expected))
        })
}

fn promo_code_max_used(item: &Value) -> bool {
    let max_uses = item.get("max_uses").and_then(Value::as_i64).unwrap_or(0);
    if max_uses <= 0 {
        return false;
    }
    let used_count = item.get("used_count").and_then(Value::as_i64).unwrap_or(0);
    used_count >= max_uses
}

fn promo_code_is_expired(item: &Value) -> bool {
    let Some(expires_at) = item.get("expires_at") else {
        return false;
    };
    if expires_at.is_null() {
        return false;
    }
    let now = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|duration| duration.as_secs() as i64)
        .unwrap_or(0);
    if let Some(timestamp) = expires_at.as_i64() {
        return timestamp > 0 && timestamp <= now;
    }
    if let Some(value) = expires_at.as_str() {
        let value = value.trim();
        if value.is_empty() {
            return false;
        }
        if let Ok(timestamp) = value.parse::<i64>() {
            return timestamp > 0 && timestamp <= now;
        }
        if let Ok(timestamp) = chrono::DateTime::parse_from_rfc3339(value) {
            return timestamp.timestamp() <= now;
        }
    }
    false
}

