fn strip_payment_config_patch(payload: Value) -> Value {
    let Some(payload_object) = payload.as_object() else {
        return payload;
    };
    let mut object = payload_object.clone();
    for key in PAYMENT_SETTING_KEYS {
        object.remove(*key);
    }
    Value::Object(object)
}

fn payment_config_patch_from_settings(payload: &Value) -> Option<Value> {
    let payload_object = payload.as_object()?;
    let mut object = Map::new();
    for (setting_key, payment_key) in PAYMENT_SETTING_KEY_MAP {
        if let Some(value) = payload_object.get(*setting_key) {
            object.insert((*payment_key).to_owned(), value.clone());
        }
    }
    if object.is_empty() {
        None
    } else {
        Some(Value::Object(object))
    }
}

fn apply_payment_config_to_user_config(user_config: &mut Value, admin_config: &Value) {
    let Some(user_object) = user_config.as_object_mut() else {
        return;
    };
    copy_if_present(user_object, admin_config, "enabled", "payment_enabled");
    copy_if_present(user_object, admin_config, "enabled", "enabled");
    for key in [
        "min_amount",
        "max_amount",
        "daily_limit",
        "max_pending_orders",
        "order_timeout_minutes",
        "balance_disabled",
        "balance_recharge_multiplier",
        "enabled_payment_types",
        "recharge_fee_rate",
        "load_balance_strategy",
        "product_name_prefix",
        "product_name_suffix",
        "help_image_url",
        "help_text",
        "cancel_rate_limit_enabled",
        "cancel_rate_limit_max",
        "cancel_rate_limit_window",
        "cancel_rate_limit_unit",
        "cancel_rate_limit_window_mode",
        "alipay_force_qrcode",
        "payment_visible_method_alipay_source",
        "payment_visible_method_wxpay_source",
        "payment_visible_method_alipay_enabled",
        "payment_visible_method_wxpay_enabled",
    ] {
        if let Some(value) = admin_config.get(key) {
            user_object.insert(key.to_owned(), value.clone());
        }
    }
}

fn apply_payment_config_to_checkout_info(checkout_info: &mut Value, admin_config: &Value) {
    let Some(checkout_object) = checkout_info.as_object_mut() else {
        return;
    };
    for (source_key, target_key) in [
        ("balance_disabled", "balance_disabled"),
        ("balance_recharge_multiplier", "balance_recharge_multiplier"),
        ("recharge_fee_rate", "recharge_fee_rate"),
        ("help_text", "help_text"),
        ("help_image_url", "help_image_url"),
        ("alipay_force_qrcode", "alipay_force_qrcode"),
    ] {
        copy_if_present(checkout_object, admin_config, source_key, target_key);
    }
}

fn checkout_methods_from_provider_instances(
    instances: &[repository::PaymentProviderInstanceRecord],
) -> Option<Value> {
    let enabled = instances
        .iter()
        .filter(|instance| instance.enabled)
        .filter(|instance| !instance.supported_types.is_empty())
        .collect::<Vec<_>>();
    let method_keys = enabled
        .iter()
        .flat_map(|instance| {
            if instance.provider_key.eq_ignore_ascii_case("stripe") {
                vec!["stripe".to_owned()]
            } else {
                instance.supported_types.clone()
            }
        })
        .collect::<std::collections::BTreeSet<_>>();

    let mut methods = Map::new();
    for payment_type in method_keys {
        let matching = enabled
            .iter()
            .copied()
            .filter(|instance| checkout_instance_supports_method(instance, &payment_type))
            .collect::<Vec<_>>();
        if matching.is_empty() || !checkout_method_currency_is_consistent(&matching, &payment_type)
        {
            continue;
        }
        methods.insert(
            payment_type.clone(),
            payment_method_limit(&matching, &payment_type),
        );
    }
    if methods.is_empty() {
        None
    } else {
        Some(Value::Object(methods))
    }
}

fn checkout_instance_supports_method(
    instance: &repository::PaymentProviderInstanceRecord,
    payment_type: &str,
) -> bool {
    if instance.provider_key.eq_ignore_ascii_case("stripe") && payment_type == "stripe" {
        return true;
    }
    instance
        .supported_types
        .iter()
        .any(|supported| supported.eq_ignore_ascii_case(payment_type))
}

fn checkout_method_currency_is_consistent(
    instances: &[&repository::PaymentProviderInstanceRecord],
    payment_type: &str,
) -> bool {
    let mut currency: Option<String> = None;
    for instance in instances {
        let next = provider_limit_for_payment_type(instance, payment_type)
            .get("currency")
            .and_then(Value::as_str)
            .map(ToOwned::to_owned)
            .or_else(|| string_from_value(&instance.config, "currency"))
            .unwrap_or_else(|| default_payment_currency(payment_type).to_owned());
        if let Some(current) = &currency {
            if !current.eq_ignore_ascii_case(&next) {
                return false;
            }
        } else {
            currency = Some(next);
        }
    }
    true
}

fn payment_method_limit(
    instances: &[&repository::PaymentProviderInstanceRecord],
    payment_type: &str,
) -> Value {
    let currency = instances
        .iter()
        .find_map(|instance| {
            provider_limit_for_payment_type(instance, payment_type)
                .get("currency")
                .and_then(Value::as_str)
                .map(ToOwned::to_owned)
                .or_else(|| string_from_value(&instance.config, "currency"))
        })
        .unwrap_or_else(|| default_payment_currency(payment_type).to_owned());
    let mut daily_limit = LimitUnion::new(false);
    let mut single_min = LimitUnion::new(true);
    let mut single_max = LimitUnion::new(false);
    let mut fee_rate = 0.0;
    for instance in instances {
        let limit = provider_limit_for_payment_type(instance, payment_type);
        daily_limit.push(f64_limit_value(&limit, "daily_limit", "dailyLimit").unwrap_or(0.0));
        single_min.push(f64_limit_value(&limit, "single_min", "singleMin").unwrap_or(0.0));
        single_max.push(f64_limit_value(&limit, "single_max", "singleMax").unwrap_or(0.0));
        if fee_rate == 0.0 {
            fee_rate = f64_limit_value(&limit, "fee_rate", "feeRate").unwrap_or(0.0);
        }
    }
    let daily_limit = daily_limit.value();
    let single_min = single_min.value();
    let single_max = single_max.value();
    json!({
        "payment_type": payment_type,
        "currency": currency,
        "daily_limit": daily_limit,
        "daily_used": 0.0,
        "daily_remaining": daily_limit,
        "single_min": single_min,
        "single_max": single_max,
        "fee_rate": fee_rate,
        "available": true,
        "provider_key": instances[0].provider_key,
        "provider_instance_id": instances[0].id,
        "payment_mode": instances[0].payment_mode
    })
}

struct LimitUnion {
    value: f64,
    limited: bool,
    want_min: bool,
}

impl LimitUnion {
    const fn new(want_min: bool) -> Self {
        Self {
            value: 0.0,
            limited: true,
            want_min,
        }
    }

    fn push(&mut self, next: f64) {
        if next == 0.0 {
            self.limited = false;
            return;
        }
        if !self.limited {
            return;
        }
        if self.value == 0.0
            || (self.want_min && next < self.value)
            || (!self.want_min && next > self.value)
        {
            self.value = next;
        }
    }

    fn value(&self) -> f64 {
        if self.limited {
            self.value
        } else {
            0.0
        }
    }
}

fn provider_limit_for_payment_type(
    instance: &repository::PaymentProviderInstanceRecord,
    payment_type: &str,
) -> Value {
    if instance.provider_key.eq_ignore_ascii_case("stripe") {
        if let Some(stripe_limit) = instance.limits.get("stripe") {
            return stripe_limit.clone();
        }
    }
    if let Some(method_limit) = instance.limits.get(payment_type) {
        return method_limit.clone();
    }
    if instance.limits.is_object()
        && (instance.limits.get("single_min").is_some()
            || instance.limits.get("singleMin").is_some())
    {
        return instance.limits.clone();
    }
    Value::Null
}

fn f64_limit_value(value: &Value, snake_key: &str, camel_key: &str) -> Option<f64> {
    f64_from_value(value, snake_key).or_else(|| f64_from_value(value, camel_key))
}

fn methods_global_range(methods: &Value) -> (f64, f64) {
    let Some(object) = methods.as_object() else {
        return (0.0, 0.0);
    };
    if object.is_empty() {
        return (0.0, 0.0);
    }
    let mut single_min = LimitUnion::new(true);
    let mut single_max = LimitUnion::new(false);
    for method in object.values() {
        single_min.push(f64_from_value(method, "single_min").unwrap_or(0.0));
        single_max.push(f64_from_value(method, "single_max").unwrap_or(0.0));
    }
    (single_min.value(), single_max.value())
}

fn stripe_publishable_key_from_provider_instances(
    instances: &[repository::PaymentProviderInstanceRecord],
) -> Option<String> {
    instances
        .iter()
        .filter(|instance| instance.enabled)
        .filter(|instance| instance.provider_key.eq_ignore_ascii_case("stripe"))
        .find_map(|instance| {
            string_from_value(&instance.config, "publishableKey")
                .or_else(|| string_from_value(&instance.config, "publishable_key"))
        })
}

fn default_payment_currency(payment_type: &str) -> &'static str {
    match payment_type.to_ascii_lowercase().as_str() {
        "stripe" | "card" | "link" | "airwallex" => "USD",
        _ => "CNY",
    }
}

fn string_from_value(value: &Value, key: &str) -> Option<String> {
    value
        .get(key)
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(ToOwned::to_owned)
}

fn f64_from_value(value: &Value, key: &str) -> Option<f64> {
    value.get(key).and_then(Value::as_f64)
}

fn copy_if_present(
    target: &mut Map<String, Value>,
    source: &Value,
    source_key: &str,
    target_key: &str,
) {
    if let Some(value) = source.get(source_key) {
        target.insert(target_key.to_owned(), value.clone());
    }
}

fn merge_json_value(mut base: Value, patch: Value) -> Value {
    match (base.as_object_mut(), patch) {
        (Some(base_object), Value::Object(patch_object)) => {
            for (key, value) in patch_object {
                base_object.insert(key, value);
            }
            base
        }
        (_, patch) => patch,
    }
}

