fn repository_api_error(error: repository::RepositoryError) -> ApiError {
    match error {
        repository::RepositoryError::NotFound { entity, id } => {
            ApiError::not_found(format!("{entity} {id} not found"))
        }
        repository::RepositoryError::InvalidInput(message) => ApiError::bad_request(message),
        repository::RepositoryError::Conflict(message) => ApiError::conflict(message),
        repository::RepositoryError::Duplicate { entity, key } => {
            ApiError::conflict(format!("duplicate {entity}: {key}"))
        }
        repository::RepositoryError::Database(message) => {
            ApiError::internal_server_error(format!("repository error: {message}"))
        }
    }
}

async fn public_repository_api_keys_by_user(
    state: &AppState,
    user_id: i64,
) -> Result<Vec<ApiKey>, ApiError> {
    Ok(state
        .repository
        .list_api_keys_by_user(user_id)
        .await
        .map_err(repository_api_error)?
        .into_iter()
        .filter(is_public_repository_api_key)
        .collect())
}

fn is_public_repository_api_key(api_key: &ApiKey) -> bool {
    !(api_key.id == ApiKeyId(0) && api_key.key == "sk-dev-admin")
}

async fn repository_usage_records(
    state: &AppState,
    filter: repository::UsageFilter,
) -> Result<Vec<repository::UsageRecord>, ApiError> {
    state
        .repository
        .list_usage(filter)
        .await
        .map_err(repository_api_error)
}

async fn repository_dashboard_stats(
    state: &AppState,
    records: &[repository::UsageRecord],
) -> Result<Value, ApiError> {
    let users = state
        .repository
        .list_users()
        .await
        .map_err(repository_api_error)?;
    let groups = state
        .repository
        .list_groups()
        .await
        .map_err(repository_api_error)?;
    let groups = public_groups_with_bindings(state, groups).await?;
    let accounts = state
        .repository
        .list_accounts()
        .await
        .map_err(repository_api_error)?;
    let (today_start, today_end) = admin_account_today_window();
    let today_records = records
        .iter()
        .filter(|record| {
            record.created_at_unix >= today_start && record.created_at_unix < today_end
        })
        .cloned()
        .collect::<Vec<_>>();
    let total_api_keys = repository_total_api_keys(state, &users).await?;
    let active_api_keys = repository_active_api_keys(state, &users).await?;
    let today_new_users = users
        .iter()
        .filter(|user| repository_user_created_today(user, today_start, today_end))
        .count() as i64;
    let account_counts = repository_account_status_counts(&accounts);
    Ok(usage_views::admin_dashboard_stats(
        records,
        &today_records,
        users.len() as i64,
        today_new_users,
        total_api_keys,
        active_api_keys,
        accounts.len() as i64,
        account_counts.normal,
        account_counts.error,
        account_counts.ratelimit,
        account_counts.overload,
        groups.len() as i64,
    ))
}

async fn repository_total_api_keys(
    state: &AppState,
    users: &[repository::UserRecord],
) -> Result<i64, ApiError> {
    let mut total = 0_i64;
    for user in users {
        total += public_repository_api_keys_by_user(state, user.id)
            .await?
            .len() as i64;
    }
    Ok(total)
}

async fn repository_active_api_keys(
    state: &AppState,
    users: &[repository::UserRecord],
) -> Result<i64, ApiError> {
    let mut total = 0_i64;
    for user in users {
        total += public_repository_api_keys_by_user(state, user.id)
            .await?
            .into_iter()
            .filter(|api_key| api_key.status == ApiKeyStatus::Active)
            .count() as i64;
    }
    Ok(total)
}

#[derive(Debug, Clone, Copy, Default)]
struct AccountStatusCounts {
    normal: i64,
    error: i64,
    ratelimit: i64,
    overload: i64,
}

fn repository_account_status_counts(accounts: &[Account]) -> AccountStatusCounts {
    let mut counts = AccountStatusCounts::default();
    for account in accounts {
        let status = account
            .extra
            .get("status")
            .and_then(Value::as_str)
            .unwrap_or(if account.enabled {
                "active"
            } else {
                "disabled"
            })
            .to_ascii_lowercase();
        let rate_limited = account
            .extra
            .get("rate_limited")
            .or_else(|| account.extra.get("rate_limit"))
            .and_then(Value::as_bool)
            .unwrap_or(false)
            || status.contains("ratelimit")
            || status.contains("rate_limit");
        let overloaded = account
            .extra
            .get("overloaded")
            .or_else(|| account.extra.get("overload"))
            .and_then(Value::as_bool)
            .unwrap_or(false)
            || status.contains("overload");
        let has_error = account
            .extra
            .get("error_message")
            .and_then(Value::as_str)
            .map(|value| !value.trim().is_empty())
            .unwrap_or(false)
            || status.contains("error");
        if overloaded {
            counts.overload += 1;
        } else if rate_limited {
            counts.ratelimit += 1;
        } else if has_error || !account.enabled {
            counts.error += 1;
        } else {
            counts.normal += 1;
        }
    }
    counts
}

fn repository_user_created_today(
    user: &repository::UserRecord,
    today_start: i64,
    today_end: i64,
) -> bool {
    let created_at = user
        .status
        .strip_prefix("created_at:")
        .and_then(|value| value.parse::<i64>().ok());
    created_at
        .map(|created_at| created_at >= today_start && created_at < today_end)
        .unwrap_or(false)
}

