async fn repository_usage_references(
    state: &AppState,
) -> Result<usage_views::UsageReferenceData, ApiError> {
    let users = state
        .repository
        .list_users()
        .await
        .map_err(repository_api_error)?;
    let mut references = usage_views::UsageReferenceData::default();
    for user in users {
        references.users.insert(
            user.id,
            usage_views::UsageUserReference {
                id: user.id,
                email: user.email,
                username: user.username,
                role: user.role,
                status: user.status,
            },
        );
        for api_key in public_repository_api_keys_by_user(state, user.id).await? {
            references.api_keys.insert(
                api_key.id.0,
                usage_views::UsageApiKeyReference {
                    id: api_key.id.0,
                    user_id: api_key.user_id,
                    name: api_key.name,
                    group_id: api_key.group_id.map(|id| id.0),
                    status: api_key_status_to_admin_str(api_key.status).to_owned(),
                },
            );
        }
    }
    for group in state
        .repository
        .list_groups()
        .await
        .map_err(repository_api_error)?
    {
        references.groups.insert(
            group.id.0,
            usage_views::UsageGroupReference {
                id: group.id.0,
                name: group.name,
                status: group_status_to_admin_str(group.status).to_owned(),
            },
        );
    }
    for account in state
        .repository
        .list_accounts()
        .await
        .map_err(repository_api_error)?
    {
        references.accounts.insert(
            account.id.0,
            usage_views::UsageAccountReference {
                id: account.id.0,
                name: account.name,
                provider: account.provider.as_str().to_owned(),
                status: if account.enabled {
                    "active"
                } else {
                    "disabled"
                }
                .to_owned(),
            },
        );
    }
    for subscription in state
        .repository
        .list_subscriptions()
        .await
        .map_err(repository_api_error)?
    {
        references.subscriptions.insert(
            (subscription.user_id, subscription.group_id),
            usage_views::UsageSubscriptionReference {
                id: subscription.id,
                user_id: subscription.user_id,
                group_id: subscription.group_id,
                status: subscription.status,
                starts_at: subscription.starts_at,
                expires_at: subscription.expires_at,
            },
        );
    }
    Ok(references)
}

fn admin_usage_filter_from_query(
    query: &HashMap<String, String>,
) -> Result<repository::UsageFilter, ApiError> {
    let mut filter = repository::UsageFilter::all();
    filter.user_id = parse_optional_i64_query(query, "user_id", "Invalid user_id")?;
    filter.api_key_id =
        parse_optional_i64_query(query, "api_key_id", "Invalid api_key_id")?.map(ApiKeyId);
    filter.account_id =
        parse_optional_i64_query(query, "account_id", "Invalid account_id")?.map(AccountId);
    filter.group_id = parse_optional_i64_query(query, "group_id", "Invalid group_id")?.map(GroupId);
    filter.downstream_protocol = query
        .get("downstream_protocol")
        .map(|value| {
            protocol::DownstreamProtocol::from_str(value)
                .map_err(|_| ApiError::bad_request("Invalid downstream_protocol"))
        })
        .transpose()?;
    filter.model_contains = query
        .get("model")
        .map(|value| value.trim().to_owned())
        .filter(|value| !value.is_empty());
    filter.status = query
        .get("status")
        .map(|value| value.trim().to_owned())
        .filter(|value| !value.is_empty());
    filter.billing_mode = query
        .get("billing_mode")
        .map(|value| value.trim().to_owned())
        .filter(|value| !value.is_empty());
    filter.billing_type = parse_optional_i8_query(query, "billing_type", "Invalid billing_type")?;
    if let Some(request_type) = query
        .get("request_type")
        .map(|value| value.trim())
        .filter(|value| !value.is_empty())
    {
        filter.request_type = Some(parse_usage_request_type(request_type)?.to_owned());
    } else if let Some(stream) =
        parse_optional_bool_query(query, "stream", "Invalid stream value, use true or false")?
    {
        filter.stream = Some(stream);
    }
    if let Some(start) = query
        .get("start_date")
        .map(|value| {
            parse_admin_usage_date_start(value, "Invalid start_date format, use YYYY-MM-DD")
        })
        .transpose()?
    {
        filter.created_at_unix_gte = Some(start);
    }
    if let Some(end) = query
        .get("end_date")
        .map(|value| parse_admin_usage_date_start(value, "Invalid end_date format, use YYYY-MM-DD"))
        .transpose()?
    {
        filter.created_at_unix_lt = Some(end + 24 * 60 * 60);
    }
    Ok(filter)
}

fn dashboard_usage_filter_from_query(
    query: &HashMap<String, String>,
    strict_ids: bool,
    validate_model_source: bool,
) -> Result<repository::UsageFilter, ApiError> {
    let mut filter = repository::UsageFilter::all();
    filter.user_id =
        parse_dashboard_optional_i64_query(query, "user_id", "Invalid user_id", strict_ids)?;
    filter.api_key_id =
        parse_dashboard_optional_i64_query(query, "api_key_id", "Invalid api_key_id", strict_ids)?
            .map(ApiKeyId);
    filter.account_id =
        parse_dashboard_optional_i64_query(query, "account_id", "Invalid account_id", strict_ids)?
            .map(AccountId);
    filter.group_id =
        parse_dashboard_optional_i64_query(query, "group_id", "Invalid group_id", strict_ids)?
            .map(GroupId);
    filter.model_contains = query
        .get("model")
        .map(|value| value.trim().to_owned())
        .filter(|value| !value.is_empty());
    if validate_model_source {
        if let Some(model_source) = query
            .get("model_source")
            .map(|value| value.trim())
            .filter(|value| !value.is_empty())
        {
            match model_source {
                "requested" | "upstream" | "mapping" => {}
                _ => {
                    return Err(ApiError::bad_request(
                        "Invalid model_source, use requested/upstream/mapping",
                    ))
                }
            }
        }
    }
    filter.billing_type = parse_optional_i8_query(query, "billing_type", "Invalid billing_type")?;
    if let Some(request_type) = query
        .get("request_type")
        .map(|value| value.trim())
        .filter(|value| !value.is_empty())
    {
        filter.request_type = Some(parse_usage_request_type(request_type)?.to_owned());
    } else if let Some(stream) =
        parse_optional_bool_query(query, "stream", "Invalid stream value, use true or false")?
    {
        filter.stream = Some(stream);
    }

    let timezone = query_timezone(query);
    let (default_start, default_end) = default_dashboard_period_in_timezone(timezone);
    filter.created_at_unix_gte = Some(
        query
            .get("start_date")
            .and_then(|value| parse_dashboard_date_start_in_timezone(value, timezone).ok())
            .unwrap_or(default_start),
    );
    filter.created_at_unix_lt = Some(
        query
            .get("end_date")
            .and_then(|value| parse_dashboard_date_start_in_timezone(value, timezone).ok())
            .map(|value| value + 24 * 60 * 60)
            .unwrap_or(default_end),
    );
    Ok(filter)
}

fn parse_dashboard_optional_i64_query(
    query: &HashMap<String, String>,
    key: &str,
    message: &'static str,
    strict: bool,
) -> Result<Option<i64>, ApiError> {
    if strict {
        parse_optional_i64_query(query, key, message)
    } else {
        Ok(query
            .get(key)
            .and_then(|value| value.trim().parse::<i64>().ok()))
    }
}

fn user_dashboard_filter_from_query(
    user_id: i64,
    query: &HashMap<String, String>,
) -> repository::UsageFilter {
    let timezone = query_timezone(query);
    let (default_start, default_end) = default_dashboard_period_in_timezone(timezone);
    let mut filter = usage_views::filter_from_query(Some(user_id), None, query);
    filter.created_at_unix_gte = Some(
        query
            .get("start_date")
            .and_then(|value| parse_dashboard_date_start_in_timezone(value, timezone).ok())
            .unwrap_or(default_start),
    );
    filter.created_at_unix_lt = Some(
        query
            .get("end_date")
            .and_then(|value| parse_dashboard_date_start_in_timezone(value, timezone).ok())
            .map(|value| value + 24 * 60 * 60)
            .unwrap_or(default_end),
    );
    filter
}

fn parse_user_api_key_daily_days(query: &HashMap<String, String>) -> Result<i64, ApiError> {
    match query.get("days").map(|value| value.trim()) {
        Some("") | None => Ok(30),
        Some(value) => {
            let days = value
                .parse::<i64>()
                .map_err(|_| ApiError::bad_request("Invalid days, allowed range is 1-90"))?;
            if !(1..=90).contains(&days) {
                return Err(ApiError::bad_request("Invalid days, allowed range is 1-90"));
            }
            Ok(days)
        }
    }
}

fn user_api_key_daily_window(days: i64, query: &HashMap<String, String>) -> (i64, i64) {
    let timezone = query_timezone(query);
    let today = Utc::now().with_timezone(&timezone).date_naive();
    let start =
        date_start_unix_in_timezone(today - Duration::days(days.saturating_sub(1)), timezone)
            .expect("valid api key daily start date");
    let end = date_start_unix_in_timezone(today + Duration::days(1), timezone)
        .expect("valid api key daily end date");
    (start, end)
}

fn default_dashboard_period_in_timezone(timezone: Tz) -> (i64, i64) {
    let today = Utc::now().with_timezone(&timezone).date_naive();
    let start = date_start_unix_in_timezone(today - Duration::days(7), timezone)
        .expect("valid dashboard start date");
    let end = date_start_unix_in_timezone(today + Duration::days(1), timezone)
        .expect("valid dashboard end date");
    (start, end)
}

fn default_admin_usage_stats_period(query: &HashMap<String, String>) -> Option<(i64, i64)> {
    let today = Utc::now().date_naive();
    let end = date_start_unix(today + Duration::days(1))?;
    let start_date = match query.get("period").map(String::as_str).unwrap_or("today") {
        "week" => today - Duration::days(6),
        "month" => today - Duration::days(29),
        _ => today,
    };
    Some((date_start_unix(start_date)?, end))
}

fn admin_account_today_window() -> (i64, i64) {
    let today = Utc::now().date_naive();
    let start = date_start_unix(today).expect("valid fixed date");
    let end = date_start_unix(today + Duration::days(1)).expect("valid fixed date");
    (start, end)
}

fn admin_account_stats_window(days: i64) -> (i64, i64) {
    let today = Utc::now().date_naive();
    let end = date_start_unix(today + Duration::days(1)).expect("valid fixed date");
    let start_date = today - Duration::days(days.saturating_sub(1));
    let start = date_start_unix(start_date).expect("valid fixed date");
    (start, end)
}

fn parse_optional_i64_query(
    query: &HashMap<String, String>,
    key: &str,
    message: &'static str,
) -> Result<Option<i64>, ApiError> {
    query
        .get(key)
        .map(|value| {
            value
                .trim()
                .parse::<i64>()
                .map_err(|_| ApiError::bad_request(message))
        })
        .transpose()
}

fn parse_optional_i8_query(
    query: &HashMap<String, String>,
    key: &str,
    message: &'static str,
) -> Result<Option<i8>, ApiError> {
    query
        .get(key)
        .map(|value| {
            value
                .trim()
                .parse::<i8>()
                .map_err(|_| ApiError::bad_request(message))
        })
        .transpose()
}

fn parse_optional_bool_query(
    query: &HashMap<String, String>,
    key: &str,
    message: &'static str,
) -> Result<Option<bool>, ApiError> {
    query
        .get(key)
        .map(|value| {
            value
                .trim()
                .parse::<bool>()
                .map_err(|_| ApiError::bad_request(message))
        })
        .transpose()
}

fn parse_usage_request_type(value: &str) -> Result<&'static str, ApiError> {
    match value.trim().to_ascii_lowercase().as_str() {
        "unknown" => Ok("unknown"),
        "sync" => Ok("sync"),
        "stream" => Ok("stream"),
        "ws_v2" => Ok("ws_v2"),
        _ => Err(ApiError::bad_request(
            "invalid request_type, allowed values: unknown, sync, stream, ws_v2",
        )),
    }
}

fn parse_admin_usage_date_start(value: &str, message: &'static str) -> Result<i64, ApiError> {
    let date = NaiveDate::parse_from_str(value.trim(), "%Y-%m-%d")
        .map_err(|_| ApiError::bad_request(message))?;
    date_start_unix(date).ok_or_else(|| ApiError::bad_request(message))
}

fn parse_dashboard_date_start_in_timezone(value: &str, timezone: Tz) -> Result<i64, ()> {
    let date = NaiveDate::parse_from_str(value.trim(), "%Y-%m-%d").map_err(|_| ())?;
    date_start_unix_in_timezone(date, timezone).ok_or(())
}

fn date_start_unix(date: NaiveDate) -> Option<i64> {
    let dt = date.and_hms_opt(0, 0, 0)?;
    Some(Utc.from_utc_datetime(&dt).timestamp())
}

fn date_start_unix_in_timezone(date: NaiveDate, timezone: Tz) -> Option<i64> {
    let local = date.and_hms_opt(0, 0, 0)?;
    match timezone.from_local_datetime(&local) {
        LocalResult::Single(value) => Some(value.with_timezone(&Utc).timestamp()),
        LocalResult::Ambiguous(value, _) => Some(value.with_timezone(&Utc).timestamp()),
        LocalResult::None => None,
    }
}

fn query_timezone(query: &HashMap<String, String>) -> Tz {
    query
        .get("timezone")
        .and_then(|value| value.trim().parse::<Tz>().ok())
        .unwrap_or_else(default_timezone)
}

fn default_timezone() -> Tz {
    chrono_tz::Asia::Shanghai
}

fn payload_ids(payload: &Value, key: &str) -> Vec<i64> {
    payload
        .get(key)
        .and_then(Value::as_array)
        .map(|ids| ids.iter().filter_map(Value::as_i64).collect())
        .unwrap_or_default()
}

async fn sync_admin_collection_item_to_repository(
    state: &AppState,
    collection: &str,
    item: &Value,
) -> Result<(), ApiError> {
    match collection {
        "users" => {
            if let Some(user) = user_record_from_admin_json(item) {
                state
                    .repository
                    .upsert_user(user)
                    .await
                    .map_err(repository_api_error)?;
            }
        }
        "groups" => {
            if let Some(group) = group_from_admin_json(item) {
                state
                    .repository
                    .upsert_group(group)
                    .await
                    .map_err(repository_api_error)?;
            }
        }
        "accounts" => {
            let group_ids = admin_account_group_ids(item);
            let mut account_synced = false;
            for group_id in group_ids {
                if state
                    .repository
                    .get_group(domain::GroupId(group_id))
                    .await
                    .is_err()
                {
                    state
                        .repository
                        .upsert_group(domain::Group {
                            id: domain::GroupId(group_id),
                            name: item
                                .get("group_name")
                                .and_then(Value::as_str)
                                .unwrap_or("Default")
                                .to_owned(),
                            status: domain::GroupStatus::Active,
                        })
                        .await
                        .map_err(repository_api_error)?;
                }
                if let Some(binding) = account_binding_from_admin_json(group_id, item) {
                    if !account_synced {
                        state
                            .repository
                            .upsert_account(binding.account.clone())
                            .await
                            .map_err(repository_api_error)?;
                        account_synced = true;
                    }
                    state
                        .repository
                        .bind_account_to_group(binding)
                        .await
                        .map_err(repository_api_error)?;
                }
            }
        }
        _ => {
            if let Some(record) = admin_collection_record_from_json(collection, item) {
                state
                    .repository
                    .upsert_admin_collection_item(record)
                    .await
                    .map_err(repository_api_error)?;
            }
        }
    }
    Ok(())
}

async fn sync_admin_collection_items_to_repository(
    state: &AppState,
    collection: &str,
    items: &Value,
) -> Result<(), ApiError> {
    let Some(items) = items.as_array() else {
        sync_admin_collection_item_to_repository(state, collection, items).await?;
        return Ok(());
    };
    for item in items {
        sync_admin_collection_item_to_repository(state, collection, item).await?;
    }
    Ok(())
}

fn admin_account_group_ids(item: &Value) -> Vec<i64> {
    let mut group_ids = item
        .get("group_ids")
        .and_then(Value::as_array)
        .map(|items| {
            items
                .iter()
                .filter_map(Value::as_i64)
                .filter(|id| *id > 0)
                .collect::<Vec<_>>()
        })
        .unwrap_or_default();

    if let Some(group_id) = item.get("group_id").and_then(Value::as_i64) {
        if group_id > 0 {
            group_ids.push(group_id);
        }
    }

    if group_ids.is_empty() {
        group_ids.push(1);
    }
    group_ids.sort_unstable();
    group_ids.dedup();
    group_ids
}

async fn repository_admin_collection_items(
    state: &AppState,
    collection: &str,
) -> Result<Option<Vec<Value>>, ApiError> {
    match collection {
        "users" => {
            let mut items = admin_portal_collection_items(state, "users");
            let users = state
                .repository
                .list_users()
                .await
                .map_err(repository_api_error)?;
            for user in users {
                upsert_admin_repository_item(&mut items, user.id, user_record_to_admin_json(user));
            }
            sort_admin_items_by_id(&mut items);
            Ok(Some(items))
        }
        "groups" => {
            let mut items = admin_portal_collection_items(state, "groups");
            let groups = state
                .repository
                .list_groups()
                .await
                .map_err(repository_api_error)?;
            for group in groups {
                upsert_admin_repository_item(&mut items, group.id.0, group_to_admin_json(group));
            }
            sort_admin_items_by_id(&mut items);
            Ok(Some(items))
        }
        "accounts" => {
            let mut items = admin_portal_collection_items(state, "accounts");
            let accounts = state
                .repository
                .list_accounts()
                .await
                .map_err(repository_api_error)?;
            for account in accounts {
                upsert_admin_repository_item(
                    &mut items,
                    account.id.0,
                    account_to_admin_json(account),
                );
            }
            sort_admin_items_by_id(&mut items);
            Ok(Some(items))
        }
        _ => {
            let mut items = admin_portal_collection_items(state, collection);
            let records = state
                .repository
                .list_admin_collection_items(collection)
                .await
                .map_err(repository_api_error)?;
            for record in records {
                upsert_admin_repository_item(&mut items, record.id, record.item);
            }
            sort_admin_items_by_id(&mut items);
            Ok(Some(items))
        }
    }
}

async fn repository_admin_collection_item(
    state: &AppState,
    collection: &str,
    id: i64,
) -> Result<Option<Value>, ApiError> {
    match collection {
        "users" => {
            let Ok(user) = state.repository.get_user(id).await else {
                return Ok(None);
            };
            Ok(Some(merge_admin_repository_item(
                state.admin_portal.get_collection_item("users", id).ok(),
                user_record_to_admin_json(user),
            )))
        }
        "groups" => {
            let Ok(group) = state.repository.get_group(GroupId(id)).await else {
                return Ok(None);
            };
            Ok(Some(merge_admin_repository_item(
                state.admin_portal.get_collection_item("groups", id).ok(),
                group_to_admin_json(group),
            )))
        }
        "accounts" => {
            let Ok(account) = state.repository.get_account(AccountId(id)).await else {
                return Ok(None);
            };
            Ok(Some(merge_admin_repository_item(
                state.admin_portal.get_collection_item("accounts", id).ok(),
                account_to_admin_json(account),
            )))
        }
        _ => match state
            .repository
            .get_admin_collection_item(collection, id)
            .await
        {
            Ok(record) => Ok(Some(merge_admin_repository_item(
                state.admin_portal.get_collection_item(collection, id).ok(),
                record.item,
            ))),
            Err(repository::RepositoryError::NotFound { .. }) => Ok(None),
            Err(error) => Err(repository_api_error(error)),
        },
    }
}

async fn delete_admin_collection_item_from_repository(
    state: &AppState,
    collection: &str,
    id: i64,
) -> Result<(), ApiError> {
    match collection {
        "users" => match state.repository.delete_user(id).await {
            Ok(()) | Err(repository::RepositoryError::NotFound { .. }) => Ok(()),
            Err(error) => Err(repository_api_error(error)),
        },
        "groups" => match state.repository.delete_group(GroupId(id)).await {
            Ok(()) | Err(repository::RepositoryError::NotFound { .. }) => Ok(()),
            Err(error) => Err(repository_api_error(error)),
        },
        "accounts" => match state.repository.delete_account(AccountId(id)).await {
            Ok(()) | Err(repository::RepositoryError::NotFound { .. }) => Ok(()),
            Err(error) => Err(repository_api_error(error)),
        },
        _ => match state
            .repository
            .delete_admin_collection_item(collection, id)
            .await
        {
            Ok(()) | Err(repository::RepositoryError::NotFound { .. }) => Ok(()),
            Err(error) => Err(repository_api_error(error)),
        },
    }
}

fn admin_collection_record_from_json(
    collection: &str,
    item: &Value,
) -> Option<repository::AdminCollectionItemRecord> {
    let id = value_id(item)?;
    Some(repository::AdminCollectionItemRecord {
        collection: collection.to_owned(),
        id,
        item: item.clone(),
    })
}

fn admin_portal_collection_items(state: &AppState, collection: &str) -> Vec<Value> {
    let mut query = HashMap::new();
    query.insert("page_size".to_owned(), "200".to_owned());
    state
        .admin_portal
        .list_all(collection, &query)
        .as_array()
        .cloned()
        .unwrap_or_default()
}

fn upsert_admin_repository_item(items: &mut Vec<Value>, id: i64, repository_item: Value) {
    if let Some(index) = items.iter().position(|item| value_id(item) == Some(id)) {
        let admin_item = items.get(index).cloned();
        items[index] = merge_admin_repository_item(admin_item, repository_item);
        return;
    }
    items.push(repository_item);
}

fn sort_admin_items_by_id(items: &mut [Value]) {
    items.sort_by_key(|item| value_id(item).unwrap_or(i64::MAX));
}

fn merge_admin_repository_item(admin_item: Option<Value>, repository_item: Value) -> Value {
    let Some(mut merged) = admin_item else {
        return repository_item;
    };
    let Some(repository_fields) = repository_item.as_object() else {
        return repository_item;
    };
    let Some(merged_fields) = merged.as_object_mut() else {
        return repository_item;
    };
    for (key, value) in repository_fields {
        merged_fields.insert(key.clone(), value.clone());
    }
    merged
}

fn value_id(item: &Value) -> Option<i64> {
    item.get("id").and_then(Value::as_i64)
}

fn payload_ids_from_value(payload: &Value) -> Result<Vec<i64>, ApiError> {
    let ids = payload
        .get("ids")
        .and_then(Value::as_array)
        .ok_or_else(|| ApiError::bad_request("ids is required"))?
        .iter()
        .filter_map(Value::as_i64)
        .filter(|id| *id > 0)
        .collect::<Vec<_>>();
    if ids.is_empty() {
        return Err(ApiError::bad_request("ids is required"));
    }
    Ok(ids)
}

fn user_record_to_admin_json(user: repository::UserRecord) -> Value {
    json!({
        "id": user.id,
        "email": user.email,
        "username": user.username,
        "role": user.role,
        "status": user.status
    })
}

fn user_record_from_admin_json(item: &Value) -> Option<repository::UserRecord> {
    let id = item.get("id").and_then(Value::as_i64)?;
    let email = item
        .get("email")
        .and_then(Value::as_str)
        .unwrap_or("")
        .trim()
        .to_owned();
    if email.is_empty() {
        return None;
    }
    Some(repository::UserRecord {
        id,
        email,
        username: item
            .get("username")
            .and_then(Value::as_str)
            .unwrap_or("user")
            .to_owned(),
        role: item
            .get("role")
            .and_then(Value::as_str)
            .unwrap_or("user")
            .to_owned(),
        status: item
            .get("status")
            .and_then(Value::as_str)
            .unwrap_or("active")
            .to_owned(),
    })
}

fn group_to_admin_json(group: Group) -> Value {
    json!({
        "id": group.id.0,
        "name": group.name,
        "status": group_status_to_admin_str(group.status)
    })
}

