fn bearer_token_from_headers(headers: &HeaderMap) -> Option<&str> {
    headers
        .get(http::header::AUTHORIZATION)?
        .to_str()
        .ok()?
        .strip_prefix("Bearer ")
}

async fn ensure_repository_oauth_identity_available(
    state: &AppState,
    session: &PendingOAuthSession,
    user_id: Option<i64>,
) -> Result<(), ApiError> {
    match state
        .repository
        .get_oauth_identity(
            &session.provider,
            &session.provider_key,
            &session.provider_subject,
        )
        .await
    {
        Ok(existing) if user_id == Some(existing.user_id) => Ok(()),
        Ok(_) => Err(ApiError::conflict(
            "oauth identity is already bound to another user",
        )),
        Err(repository::RepositoryError::NotFound { .. }) => Ok(()),
        Err(error) => Err(repository_api_error(error)),
    }
}

async fn persist_oauth_identity_from_session(
    state: &AppState,
    session: &PendingOAuthSession,
    user_id: i64,
    user: &Value,
) -> Result<(), ApiError> {
    sync_auth_user_to_repository(state, user).await?;
    let email = user
        .get("email")
        .and_then(Value::as_str)
        .map(ToOwned::to_owned)
        .or_else(|| session.resolved_email.clone());
    state
        .repository
        .upsert_oauth_identity(repository::OAuthIdentityRecord {
            id: 0,
            user_id,
            provider: session.provider.clone(),
            provider_key: session.provider_key.clone(),
            provider_subject: session.provider_subject.clone(),
            email,
            bound_at_unix: current_unix_time(),
            metadata: json!({
                "intent": session.intent,
                "redirect": session.redirect,
                "session_created_at_unix": session.created_at
            }),
        })
        .await
        .map_err(repository_api_error)?;
    Ok(())
}

async fn sync_auth_api_key_to_repository(
    state: &AppState,
    api_key: &Value,
) -> Result<(), ApiError> {
    let id = api_key
        .get("id")
        .and_then(Value::as_i64)
        .ok_or_else(|| ApiError::bad_request("api key id is required"))?;
    let user_id = api_key
        .get("user_id")
        .and_then(Value::as_i64)
        .ok_or_else(|| ApiError::bad_request("api key user_id is required"))?;
    ensure_repository_user(state, user_id).await?;
    let group_id = api_key.get("group_id").and_then(Value::as_i64).map(GroupId);
    if let Some(group_id) = group_id {
        ensure_repository_group(state, group_id).await?;
    }
    state
        .repository
        .upsert_api_key(ApiKey {
            id: ApiKeyId(id),
            user_id,
            key: api_key
                .get("key")
                .and_then(Value::as_str)
                .unwrap_or("")
                .to_owned(),
            name: api_key
                .get("name")
                .and_then(Value::as_str)
                .unwrap_or("api key")
                .to_owned(),
            group_id,
            status: parse_auth_api_key_status(
                api_key
                    .get("status")
                    .and_then(Value::as_str)
                    .unwrap_or("active"),
            ),
            quota: api_key.get("quota").and_then(Value::as_f64).unwrap_or(0.0),
            quota_used: api_key
                .get("quota_used")
                .and_then(Value::as_f64)
                .unwrap_or(0.0),
            rate_limit_5h: api_key
                .get("rate_limit_5h")
                .and_then(Value::as_f64)
                .unwrap_or(0.0),
            rate_limit_1d: api_key
                .get("rate_limit_1d")
                .and_then(Value::as_f64)
                .unwrap_or(0.0),
            rate_limit_7d: api_key
                .get("rate_limit_7d")
                .and_then(Value::as_f64)
                .unwrap_or(0.0),
            usage_5h: api_key
                .get("usage_5h")
                .and_then(Value::as_f64)
                .unwrap_or(0.0),
            usage_1d: api_key
                .get("usage_1d")
                .and_then(Value::as_f64)
                .unwrap_or(0.0),
            usage_7d: api_key
                .get("usage_7d")
                .and_then(Value::as_f64)
                .unwrap_or(0.0),
            window_5h_start: api_key.get("window_5h_start").and_then(Value::as_i64),
            window_1d_start: api_key.get("window_1d_start").and_then(Value::as_i64),
            window_7d_start: api_key.get("window_7d_start").and_then(Value::as_i64),
        })
        .await
        .map_err(repository_api_error)?;
    Ok(())
}

async fn ensure_repository_group(state: &AppState, group_id: GroupId) -> Result<(), ApiError> {
    if state.repository.get_group(group_id).await.is_ok() {
        return Ok(());
    }
    let admin_group = state
        .admin_portal
        .get_collection_item("groups", group_id.0)
        .ok();
    let name = admin_group
        .as_ref()
        .and_then(|group| group.get("name"))
        .and_then(Value::as_str)
        .unwrap_or("Default")
        .to_owned();
    state
        .repository
        .upsert_group(domain::Group {
            id: group_id,
            name,
            status: domain::GroupStatus::Active,
        })
        .await
        .map_err(repository_api_error)?;
    Ok(())
}

fn parse_auth_api_key_status(status: &str) -> ApiKeyStatus {
    match status.trim().to_ascii_lowercase().as_str() {
        "active" => ApiKeyStatus::Active,
        "quota_exhausted" => ApiKeyStatus::QuotaExhausted,
        "expired" => ApiKeyStatus::Expired,
        _ => ApiKeyStatus::Disabled,
    }
}

async fn sync_payment_order_from_webhook_result(
    state: &AppState,
    webhook_result: &Value,
) -> Result<(), ApiError> {
    if let Some(order) = webhook_result.get("order").filter(|order| !order.is_null()) {
        sync_payment_order_from_json(state, order).await?;
    }
    Ok(())
}

async fn payment_webhook_result_with_repository_order(
    state: &AppState,
    mut webhook_result: Value,
) -> Result<Value, ApiError> {
    if webhook_result
        .get("matched_order")
        .and_then(Value::as_bool)
        .unwrap_or(false)
        || webhook_result
            .get("order")
            .is_some_and(|order| !order.is_null())
    {
        return Ok(webhook_result);
    }
    let Some(notification) = webhook_result.get("notification") else {
        return Ok(webhook_result);
    };
    let status = string_field(notification, "status").unwrap_or_default();
    if !matches!(status.to_ascii_lowercase().as_str(), "success" | "paid") {
        return Ok(webhook_result);
    }
    let Some(out_trade_no) = string_field(notification, "order_id").or_else(|| {
        webhook_result
            .get("out_trade_no")
            .and_then(Value::as_str)
            .map(ToOwned::to_owned)
    }) else {
        return Ok(webhook_result);
    };
    let Some(mut order) = repository_payment_order_by_trade_no(state, &out_trade_no).await? else {
        return Ok(webhook_result);
    };
    validate_repository_payment_notification(&order, notification)?;

    let already_completed = order.status.eq_ignore_ascii_case("COMPLETED");
    order.webhook_count += 1;
    if !already_completed {
        let settled_at = Utc::now().to_rfc3339_opts(chrono::SecondsFormat::Secs, true);
        order.pay_amount = f64_field(notification, "amount").unwrap_or(order.pay_amount);
        order.status = "COMPLETED".to_owned();
        order.paid_at = Some(settled_at.clone());
        order.completed_at = Some(settled_at);
        order.metadata = merge_metadata(
            order.metadata,
            json!({
                "payment_trade_no": string_field(notification, "trade_no"),
                "webhook_recovered_from_repository": true,
                "webhook_provider": webhook_result.get("provider").cloned().unwrap_or(Value::Null),
                "notification_metadata": notification.get("metadata").cloned().unwrap_or_else(|| json!({}))
            }),
        );
        insert_payment_audit_once(
            state,
            &order.out_trade_no,
            "ORDER_PAID",
            json!({
                "trade_no": string_field(notification, "trade_no"),
                "paid_amount": order.pay_amount,
                "provider": webhook_result.get("provider").cloned().unwrap_or(Value::Null),
                "source": "repository_webhook_recovery"
            }),
        )
        .await?;
        insert_payment_audit_once(
            state,
            &order.out_trade_no,
            "ORDER_COMPLETED",
            json!({
                "mode": "repository_webhook_recovery",
                "order_type": order.order_type,
                "amount": order.amount
            }),
        )
        .await?;
    }
    state
        .repository
        .upsert_payment_order(order.clone())
        .await
        .map_err(repository_api_error)?;

    if let Value::Object(object) = &mut webhook_result {
        object.insert("matched_order".to_owned(), json!(true));
        object.insert("order_status".to_owned(), json!(order.status));
        object.insert("order".to_owned(), payment_views::public_json(&order));
        object.insert("idempotent".to_owned(), json!(already_completed));
        object.insert("repository_recovered".to_owned(), json!(true));
    }
    Ok(webhook_result)
}

fn validate_repository_payment_notification(
    order: &repository::PaymentOrderRecord,
    notification: &Value,
) -> Result<(), ApiError> {
    let status = string_field(notification, "status").unwrap_or_default();
    if !matches!(status.to_ascii_lowercase().as_str(), "success" | "paid") {
        return Err(ApiError::bad_request(
            "payment notification is not successful",
        ));
    }
    let paid_amount = f64_field(notification, "amount")
        .ok_or_else(|| ApiError::bad_request("payment notification amount is missing"))?;
    if paid_amount <= 0.0 || (paid_amount - order.pay_amount).abs() > 0.000_001 {
        return Err(ApiError::bad_request(format!(
            "amount mismatch: expected {}, got {}",
            order.pay_amount, paid_amount
        )));
    }
    Ok(())
}

async fn fulfill_payment_order_from_webhook_result(
    state: &AppState,
    webhook_result: &Value,
) -> Result<(), ApiError> {
    let Some(order) = webhook_result.get("order").filter(|order| !order.is_null()) else {
        return Ok(());
    };
    let out_trade_no = string_field(order, "out_trade_no")
        .ok_or_else(|| ApiError::internal_server_error("payment order out_trade_no is missing"))?;
    let Some(record) = repository_payment_order_by_trade_no(state, &out_trade_no).await? else {
        return Ok(());
    };
    if !record.status.eq_ignore_ascii_case("COMPLETED") {
        return Ok(());
    }
    if let Err(error) = fulfill_completed_payment_order(state, &record).await {
        let error_message = error.message().to_owned();
        let mut failed = record.clone();
        failed.status = "FAILED".to_owned();
        failed.metadata = merge_metadata(
            failed.metadata,
            json!({
                "fulfillment_failed_at": "2026-06-06T00:00:00Z",
                "fulfillment_error": error_message
            }),
        );
        state
            .repository
            .upsert_payment_order(failed)
            .await
            .map_err(repository_api_error)?;
        state
            .repository
            .insert_payment_audit(repository::PaymentAuditRecord {
                id: 0,
                order_id: out_trade_no,
                action: "FULFILLMENT_FAILED".to_owned(),
                detail: json!({ "error": error_message }).to_string(),
                operator: "system".to_owned(),
                created_at: "2026-06-06T00:00:00Z".to_owned(),
            })
            .await
            .map_err(repository_api_error)?;
        return Err(error);
    }
    Ok(())
}

async fn fulfill_completed_payment_order(
    state: &AppState,
    order: &repository::PaymentOrderRecord,
) -> Result<(), ApiError> {
    match order.order_type.to_ascii_lowercase().as_str() {
        "balance" | "" => fulfill_balance_payment_order(state, order).await,
        "subscription" => fulfill_subscription_payment_order(state, order).await,
        other => Err(ApiError::bad_request(format!(
            "unsupported payment order_type {other}"
        ))),
    }
}

async fn fulfill_balance_payment_order(
    state: &AppState,
    order: &repository::PaymentOrderRecord,
) -> Result<(), ApiError> {
    let transaction = state
        .repository
        .apply_balance_transaction(repository::BalanceTransactionRecord {
            id: 0,
            user_id: order.user_id,
            order_id: order.out_trade_no.clone(),
            transaction_type: "payment_recharge".to_owned(),
            amount: order.amount,
            balance_after: 0.0,
            created_at: order.completed_at.clone().unwrap_or_else(|| {
                order
                    .paid_at
                    .clone()
                    .unwrap_or_else(|| "2026-06-06T00:00:00Z".to_owned())
            }),
            metadata: json!({
                "payment_order_id": order.id,
                "payment_type": order.payment_type,
                "currency": order.currency,
                "pay_amount": order.pay_amount
            }),
        })
        .await
        .map_err(repository_api_error)?;
    insert_payment_audit_once(
        state,
        &order.out_trade_no,
        "BALANCE_RECHARGE_APPLIED",
        json!({
            "amount": transaction.amount,
            "balance_after": transaction.balance_after,
            "transaction_id": transaction.id
        }),
    )
    .await?;
    accrue_affiliate_rebate_for_order(state, order).await
}

async fn fulfill_subscription_payment_order(
    state: &AppState,
    order: &repository::PaymentOrderRecord,
) -> Result<(), ApiError> {
    let (group_id, validity_days) = subscription_order_terms(state, order).await?;
    let subscription = state
        .repository
        .upsert_user_subscription(repository::UserSubscriptionRecord {
            id: 0,
            user_id: order.user_id,
            group_id,
            plan_id: order.plan_id,
            status: "active".to_owned(),
            starts_at: order.completed_at.clone().unwrap_or_else(|| {
                order
                    .paid_at
                    .clone()
                    .unwrap_or_else(|| "2026-06-06T00:00:00Z".to_owned())
            }),
            expires_at: format!("2026-06-06T00:00:00Z+{validity_days}d"),
            daily_usage_usd: 0.0,
            weekly_usage_usd: 0.0,
            monthly_usage_usd: 0.0,
            daily_window_start: None,
            weekly_window_start: None,
            monthly_window_start: None,
            source_order_id: order.out_trade_no.clone(),
            created_at: "2026-06-06T00:00:00Z".to_owned(),
            metadata: json!({
                "payment_order_id": order.id,
                "amount": order.amount,
                "validity_days": validity_days
            }),
        })
        .await
        .map_err(repository_api_error)?;
    insert_payment_audit_once(
        state,
        &order.out_trade_no,
        "SUBSCRIPTION_APPLIED",
        json!({
            "subscription_id": subscription.id,
            "group_id": subscription.group_id,
            "plan_id": subscription.plan_id,
            "expires_at": subscription.expires_at
        }),
    )
    .await?;
    accrue_affiliate_rebate_for_order(state, order).await
}

async fn subscription_order_terms(
    state: &AppState,
    order: &repository::PaymentOrderRecord,
) -> Result<(i64, i64), ApiError> {
    let metadata_group_id = order.metadata.get("plan_group_id").and_then(Value::as_i64);
    let metadata_validity_days = order
        .metadata
        .get("plan_validity_days")
        .and_then(Value::as_i64);
    let plan = match order.plan_id {
        Some(plan_id) => match state.repository.get_payment_plan(plan_id).await {
            Ok(plan) => Some(plan),
            Err(repository::RepositoryError::NotFound { .. }) if metadata_group_id.is_some() => {
                None
            }
            Err(repository::RepositoryError::NotFound { .. }) => {
                return Err(ApiError::internal_server_error(
                    "subscription plan is missing",
                ));
            }
            Err(error) => return Err(repository_api_error(error)),
        },
        None => None,
    };
    let group_id = plan
        .as_ref()
        .map(|plan| plan.group_id)
        .or(metadata_group_id)
        .ok_or_else(|| ApiError::internal_server_error("subscription group is missing"))?;
    let validity_days = plan
        .as_ref()
        .map(|plan| plan_validity_days(plan) as i64)
        .or(metadata_validity_days)
        .unwrap_or(30)
        .max(1);
    Ok((group_id, validity_days))
}

async fn apply_refund_deduction_from_json(state: &AppState, order: &Value) -> Result<(), ApiError> {
    let record = payment_order_record_from_json(order)?;
    if !matches!(
        record.status.to_ascii_uppercase().as_str(),
        "REFUNDED" | "PARTIALLY_REFUNDED"
    ) {
        return Ok(());
    }
    apply_refund_deduction(state, &record).await
}

async fn apply_refund_deduction(
    state: &AppState,
    order: &repository::PaymentOrderRecord,
) -> Result<(), ApiError> {
    match order.order_type.to_ascii_lowercase().as_str() {
        "balance" | "" => apply_balance_refund_deduction(state, order).await,
        "subscription" => apply_subscription_refund_deduction(state, order).await,
        _ => Ok(()),
    }
}

async fn apply_balance_refund_deduction(
    state: &AppState,
    order: &repository::PaymentOrderRecord,
) -> Result<(), ApiError> {
    let refund_amount = if order.refund_amount > 0.0 {
        order.refund_amount
    } else {
        order.amount
    };
    let transaction = state
        .repository
        .apply_balance_transaction(repository::BalanceTransactionRecord {
            id: 0,
            user_id: order.user_id,
            order_id: order.out_trade_no.clone(),
            transaction_type: "payment_refund".to_owned(),
            amount: -refund_amount,
            balance_after: 0.0,
            created_at: order
                .refunded_at
                .clone()
                .unwrap_or_else(|| "2026-06-06T00:00:00Z".to_owned()),
            metadata: json!({
                "payment_order_id": order.id,
                "refund_reason": order.refund_reason,
                "currency": order.currency
            }),
        })
        .await
        .map_err(repository_api_error)?;
    insert_payment_audit_once(
        state,
        &order.out_trade_no,
        "REFUND_BALANCE_DEDUCTED",
        json!({
            "amount": refund_amount,
            "balance_after": transaction.balance_after,
            "transaction_id": transaction.id
        }),
    )
    .await
}

async fn apply_subscription_refund_deduction(
    state: &AppState,
    order: &repository::PaymentOrderRecord,
) -> Result<(), ApiError> {
    let subscription = state
        .repository
        .update_subscription_status_by_source_order(
            &order.out_trade_no,
            "refunded",
            json!({
                "refund_amount": order.refund_amount,
                "refund_reason": order.refund_reason,
                "refunded_at": order.refunded_at
            }),
        )
        .await
        .map_err(repository_api_error)?;
    insert_payment_audit_once(
        state,
        &order.out_trade_no,
        "REFUND_SUBSCRIPTION_REVOKED",
        json!({
            "subscription_id": subscription.id,
            "group_id": subscription.group_id,
            "status": subscription.status
        }),
    )
    .await
}

async fn insert_payment_audit_once(
    state: &AppState,
    order_id: &str,
    action: &str,
    detail: Value,
) -> Result<(), ApiError> {
    let existing = state
        .repository
        .list_payment_audits(order_id)
        .await
        .map_err(repository_api_error)?;
    if existing.iter().any(|record| record.action == action) {
        return Ok(());
    }
    state
        .repository
        .insert_payment_audit(repository::PaymentAuditRecord {
            id: 0,
            order_id: order_id.to_owned(),
            action: action.to_owned(),
            detail: detail.to_string(),
            operator: "system".to_owned(),
            created_at: "2026-06-06T00:00:00Z".to_owned(),
        })
        .await
        .map_err(repository_api_error)?;
    Ok(())
}

fn merge_metadata(mut metadata: Value, patch: Value) -> Value {
    let Some(target) = metadata.as_object_mut() else {
        return patch;
    };
    if let Value::Object(patch) = patch {
        for (key, value) in patch {
            target.insert(key, value);
        }
    }
    metadata
}

async fn sync_payment_audits_from_webhook_result(
    state: &AppState,
    audits: &[Value],
) -> Result<(), ApiError> {
    for audit in audits {
        let record = payment_audit_record_from_json(audit)?;
        state
            .repository
            .insert_payment_audit(record)
            .await
            .map_err(repository_api_error)?;
    }
    Ok(())
}

async fn sync_payment_order_from_json(state: &AppState, order: &Value) -> Result<(), ApiError> {
    let mut record = payment_order_record_from_json(order)?;
    if let Some(existing) = existing_payment_order_for_sync(state, &record).await? {
        record.metadata = merge_metadata(existing.metadata, record.metadata);
    }
    ensure_repository_user(state, record.user_id).await?;
    state
        .repository
        .upsert_payment_order(record)
        .await
        .map_err(repository_api_error)?;
    Ok(())
}

async fn existing_payment_order_for_sync(
    state: &AppState,
    record: &repository::PaymentOrderRecord,
) -> Result<Option<repository::PaymentOrderRecord>, ApiError> {
    match state.repository.get_payment_order(record.id).await {
        Ok(existing) => Ok(Some(existing)),
        Err(repository::RepositoryError::NotFound { .. }) => {
            repository_payment_order_by_trade_no(state, &record.out_trade_no).await
        }
        Err(error) => Err(repository_api_error(error)),
    }
}

async fn repository_payment_orders(
    state: &AppState,
) -> Result<Vec<repository::PaymentOrderRecord>, ApiError> {
    state
        .repository
        .list_payment_orders(repository::PaymentOrderFilter::all())
        .await
        .map_err(repository_api_error)
}

async fn repository_payment_order(
    state: &AppState,
    id: i64,
) -> Result<Option<repository::PaymentOrderRecord>, ApiError> {
    match state.repository.get_payment_order(id).await {
        Ok(order) => Ok(Some(order)),
        Err(repository::RepositoryError::NotFound { .. }) => Ok(None),
        Err(error) => Err(repository_api_error(error)),
    }
}

async fn repository_payment_order_for_user(
    state: &AppState,
    user_id: i64,
    id: i64,
) -> Result<Option<repository::PaymentOrderRecord>, ApiError> {
    Ok(repository_payment_order(state, id)
        .await?
        .filter(|order| order.user_id == user_id))
}

async fn repository_payment_order_by_trade_no(
    state: &AppState,
    out_trade_no: &str,
) -> Result<Option<repository::PaymentOrderRecord>, ApiError> {
    match state
        .repository
        .get_payment_order_by_trade_no(out_trade_no)
        .await
    {
        Ok(order) => Ok(Some(order)),
        Err(repository::RepositoryError::NotFound { .. })
        | Err(repository::RepositoryError::Duplicate { .. }) => Ok(None),
        Err(error) => Err(repository_api_error(error)),
    }
}

async fn pending_payment_provider_instance_ids(state: &AppState) -> Vec<String> {
    match repository_payment_orders(state).await {
        Ok(orders) if !orders.is_empty() => payment_views::pending_provider_instance_ids(&orders),
        _ => state.payment_portal.pending_provider_instance_ids(),
    }
}

async fn repository_payment_provider_instances(
    state: &AppState,
) -> Result<Vec<repository::PaymentProviderInstanceRecord>, ApiError> {
    state
        .repository
        .list_payment_provider_instances()
        .await
        .map_err(repository_api_error)
}

async fn sync_payment_provider_instance_by_id(state: &AppState, id: i64) -> Result<(), ApiError> {
    let item = state.admin_portal.get_payment_provider_internal(id)?;
    let record = payment_provider_instance_record_from_json(&item)?;
    state
        .repository
        .upsert_payment_provider_instance(record)
        .await
        .map_err(repository_api_error)?;
    Ok(())
}

fn payment_provider_instance_record_from_json(
    item: &Value,
) -> Result<repository::PaymentProviderInstanceRecord, ApiError> {
    let id = item
        .get("id")
        .and_then(Value::as_i64)
        .ok_or_else(|| ApiError::internal_server_error("payment provider id is missing"))?;
    let provider_key = string_field(item, "provider_key")
        .or_else(|| string_field(item, "payment_type"))
        .map(|value| normalize_payment_provider_key(&value))
        .ok_or_else(|| ApiError::internal_server_error("payment provider key is missing"))?;
    let name = string_field(item, "name").unwrap_or_else(|| provider_key.clone());
    let supported_types = item
        .get("supported_types")
        .and_then(Value::as_array)
        .map(|items| {
            items
                .iter()
                .filter_map(Value::as_str)
                .map(normalize_payment_provider_key)
                .filter(|value| !value.is_empty())
                .collect::<Vec<_>>()
        })
        .filter(|items| !items.is_empty())
        .unwrap_or_else(|| vec![provider_key.clone()]);
    Ok(repository::PaymentProviderInstanceRecord {
        id,
        provider_key,
        name,
        config: item.get("config").cloned().unwrap_or_else(|| json!({})),
        supported_types,
        enabled: item.get("enabled").and_then(Value::as_bool).unwrap_or(true),
        payment_mode: string_field(item, "payment_mode").unwrap_or_default(),
        sort_order: item
            .get("sort_order")
            .or_else(|| item.get("priority"))
            .and_then(Value::as_i64)
            .unwrap_or_default() as i32,
        limits: item.get("limits").cloned().unwrap_or_else(|| json!({})),
        refund_enabled: item
            .get("refund_enabled")
            .and_then(Value::as_bool)
            .unwrap_or(false),
        allow_user_refund: item
            .get("allow_user_refund")
            .and_then(Value::as_bool)
            .unwrap_or(false),
        created_at: string_field(item, "created_at")
            .unwrap_or_else(|| "2026-06-06T00:00:00Z".to_owned()),
        updated_at: string_field(item, "updated_at")
            .unwrap_or_else(|| "2026-06-06T00:00:00Z".to_owned()),
    })
}

fn normalize_payment_provider_key(value: &str) -> String {
    match value.trim().to_ascii_lowercase().as_str() {
        "wechat" | "weixin" | "wx" | "wxpay_direct" => "wxpay".to_owned(),
        "alipay_direct" => "alipay".to_owned(),
        other => other.to_owned(),
    }
}

fn payment_audit_record_from_json(
    audit: &Value,
) -> Result<repository::PaymentAuditRecord, ApiError> {
    let order_id = string_field(audit, "order_id")
        .ok_or_else(|| ApiError::internal_server_error("payment audit order_id is missing"))?;
    let action = string_field(audit, "action")
        .ok_or_else(|| ApiError::internal_server_error("payment audit action is missing"))?;
    let detail = audit
        .get("detail")
        .map(Value::to_string)
        .unwrap_or_else(|| "{}".to_owned());
    Ok(repository::PaymentAuditRecord {
        id: audit.get("id").and_then(Value::as_i64).unwrap_or_default(),
        order_id,
        action,
        detail,
        operator: string_field(audit, "operator").unwrap_or_else(|| "system".to_owned()),
        created_at: string_field(audit, "created_at")
            .unwrap_or_else(|| "2026-06-06T00:00:00Z".to_owned()),
    })
}

fn payment_order_record_from_json(
    order: &Value,
) -> Result<repository::PaymentOrderRecord, ApiError> {
    let id = order
        .get("id")
        .or_else(|| order.get("order_id"))
        .and_then(Value::as_i64)
        .ok_or_else(|| ApiError::internal_server_error("payment order id is missing"))?;
    let user_id = order.get("user_id").and_then(Value::as_i64).unwrap_or(1);
    let out_trade_no = string_field(order, "out_trade_no")
        .ok_or_else(|| ApiError::internal_server_error("payment order out_trade_no is missing"))?;
    let payment_type = string_field(order, "payment_type")
        .ok_or_else(|| ApiError::internal_server_error("payment order payment_type is missing"))?;
    let amount = f64_field(order, "amount").unwrap_or(0.0);
    let pay_amount = f64_field(order, "pay_amount").unwrap_or(amount);
    Ok(repository::PaymentOrderRecord {
        id,
        user_id,
        amount,
        pay_amount,
        currency: string_field(order, "currency").unwrap_or_else(|| "CNY".to_owned()),
        fee_rate: f64_field(order, "fee_rate").unwrap_or(0.0),
        payment_type,
        out_trade_no,
        status: string_field(order, "status").unwrap_or_else(|| "PENDING".to_owned()),
        order_type: string_field(order, "order_type").unwrap_or_else(|| "balance".to_owned()),
        refund_amount: f64_field(order, "refund_amount").unwrap_or(0.0),
        refund_reason: string_field(order, "refund_reason"),
        refund_request_reason: string_field(order, "refund_request_reason"),
        plan_id: order.get("plan_id").and_then(Value::as_i64),
        provider_instance_id: string_field(order, "provider_instance_id"),
        created_at: string_field(order, "created_at")
            .unwrap_or_else(|| "2026-06-06T00:00:00Z".to_owned()),
        expires_at: string_field(order, "expires_at")
            .unwrap_or_else(|| "2026-06-06T01:00:00Z".to_owned()),
        paid_at: string_field(order, "paid_at"),
        completed_at: string_field(order, "completed_at"),
        cancelled_at: string_field(order, "cancelled_at"),
        refund_requested_at: string_field(order, "refund_requested_at"),
        refunded_at: string_field(order, "refunded_at"),
        webhook_count: order
            .get("webhook_count")
            .and_then(Value::as_i64)
            .unwrap_or_default(),
        metadata: payment_order_metadata(order),
    })
}

fn string_field(value: &Value, key: &str) -> Option<String> {
    value
        .get(key)
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(ToOwned::to_owned)
}

fn f64_field(value: &Value, key: &str) -> Option<f64> {
    value.get(key).and_then(Value::as_f64)
}

fn payment_order_metadata(order: &Value) -> Value {
    let mut metadata = Map::new();
    for key in [
        "pay_url",
        "qr_code",
        "client_secret",
        "intent_id",
        "country_code",
        "payment_env",
        "result_type",
        "recharge_code",
        "payment_mode",
        "payment_trade_no",
        "resume_token",
        "plan_group_id",
        "plan_validity_days",
        "provider_key",
        "provider_snapshot",
        "oauth",
        "jsapi",
        "jsapi_payload",
    ] {
        if let Some(value) = order.get(key) {
            metadata.insert(key.to_owned(), value.clone());
        }
    }
    Value::Object(metadata)
}

fn admin_collection_from_path(path: &str) -> String {
    let trimmed = path.trim_start_matches("/api/v1/admin/");
    let mut parts = trimmed.split('/');
    let first = parts.next().unwrap_or_default();
    if first == "payment" {
        if let Some(second) = parts.next() {
            return format!("payment/{second}");
        }
    }
    first.to_owned()
}

fn query_i64(query: &HashMap<String, String>, key: &str, default: i64) -> i64 {
    query
        .get(key)
        .and_then(|value| value.parse::<i64>().ok())
        .unwrap_or(default)
}

fn query_trimmed(query: &HashMap<String, String>, key: &str) -> Option<String> {
    query
        .get(key)
        .map(|value| value.trim())
        .filter(|value| !value.is_empty())
        .map(ToOwned::to_owned)
}

fn query_bool(query: &HashMap<String, String>, key: &str) -> bool {
    query
        .get(key)
        .map(|value| {
            matches!(
                value.trim().to_ascii_lowercase().as_str(),
                "1" | "true" | "yes" | "y" | "on"
            )
        })
        .unwrap_or(false)
}

fn cleanup_filter_from_payload(
    payload: &Value,
) -> Result<repository::UsageCleanupFilter, ApiError> {
    let object = payload
        .as_object()
        .ok_or_else(|| ApiError::bad_request("cleanup payload must be an object"))?;
    let start_date = value_string(object, "start_date")
        .map(|value| value.trim().to_owned())
        .filter(|value| !value.is_empty())
        .ok_or_else(|| ApiError::bad_request("start_date and end_date are required"))?;
    let end_date = value_string(object, "end_date")
        .map(|value| value.trim().to_owned())
        .filter(|value| !value.is_empty())
        .ok_or_else(|| ApiError::bad_request("start_date and end_date are required"))?;
    let start_time_unix = parse_cleanup_date_start(&start_date)?;
    let end_time_unix = parse_cleanup_date_start(&end_date)? + 24 * 60 * 60;
    if end_time_unix <= start_time_unix {
        return Err(ApiError::bad_request("end_date must be after start_date"));
    }
    let model = value_string(object, "model")
        .map(|value| value.trim().to_owned())
        .filter(|value| !value.is_empty());
    let request_type = value_string(object, "request_type")
        .map(|value| value.trim().to_owned())
        .filter(|value| !value.is_empty());
    Ok(repository::UsageCleanupFilter {
        start_time_unix,
        end_time_unix,
        user_id: positive_i64(value_i64(object, "user_id")),
        api_key_id: positive_i64(value_i64(object, "api_key_id")).map(domain::ApiKeyId),
        group_id: positive_i64(value_i64(object, "group_id")).map(domain::GroupId),
        account_id: positive_i64(value_i64(object, "account_id")).map(domain::AccountId),
        model,
        request_type,
        stream: value_bool(object, "stream"),
        billing_type: value_i64(object, "billing_type").and_then(|value| i8::try_from(value).ok()),
    })
}

fn parse_cleanup_date_start(value: &str) -> Result<i64, ApiError> {
    let date = NaiveDate::parse_from_str(value.trim(), "%Y-%m-%d")
        .map_err(|_| ApiError::bad_request("Invalid date format, use YYYY-MM-DD"))?;
    let dt = date
        .and_hms_opt(0, 0, 0)
        .ok_or_else(|| ApiError::bad_request("Invalid date format, use YYYY-MM-DD"))?;
    Ok(Utc.from_utc_datetime(&dt).timestamp())
}

fn parse_risk_control_log_date(value: &str, end_of_day: bool) -> Result<String, ApiError> {
    let value = value.trim();
    if value.is_empty() {
        return Err(ApiError::bad_request("Invalid date"));
    }
    if let Ok(date) = NaiveDate::parse_from_str(value, "%Y-%m-%d") {
        let dt = if end_of_day {
            date.and_hms_opt(23, 59, 59)
        } else {
            date.and_hms_opt(0, 0, 0)
        }
        .ok_or_else(|| ApiError::bad_request("Invalid date"))?;
        return Ok(Utc
            .from_utc_datetime(&dt)
            .to_rfc3339_opts(chrono::SecondsFormat::Secs, true));
    }
    DateTime::parse_from_rfc3339(value)
        .map(|datetime| {
            datetime
                .with_timezone(&Utc)
                .to_rfc3339_opts(chrono::SecondsFormat::Secs, true)
        })
        .map_err(|_| ApiError::bad_request("Invalid date"))
}

fn positive_i64(value: Option<i64>) -> Option<i64> {
    value.filter(|value| *value > 0)
}

async fn run_usage_cleanup_once(
    state: &AppState,
    created: repository::UsageCleanupTaskRecord,
) -> Result<repository::UsageCleanupTaskRecord, repository::UsageCleanupTaskRecord> {
    let claimed = match state.repository.claim_next_usage_cleanup_task(1800).await {
        Ok(Some(task)) if task.id == created.id => task,
        Ok(Some(task)) => return Ok(task),
        Ok(None) => return Ok(created),
        Err(error) => {
            return Err(mark_cleanup_failed_best_effort(state, created, error.to_string()).await);
        }
    };
    let mut deleted_total = claimed.deleted_rows;
    loop {
        match state
            .repository
            .get_usage_cleanup_task_status(claimed.id)
            .await
        {
            Ok(status) if status == "canceled" => {
                return Ok(state
                    .repository
                    .cancel_usage_cleanup_task(claimed.id, claimed.created_by)
                    .await
                    .unwrap_or(claimed));
            }
            Ok(_) => {}
            Err(error) => {
                return Err(
                    mark_cleanup_failed_best_effort(state, claimed, error.to_string()).await,
                );
            }
        }
        let deleted = match state
            .repository
            .delete_usage_batch(claimed.filters.clone(), 5_000)
            .await
        {
            Ok(deleted) => deleted,
            Err(error) => {
                return Err(
                    mark_cleanup_failed_best_effort(state, claimed, error.to_string()).await,
                );
            }
        };
        deleted_total += deleted;
        if deleted > 0 {
            if let Err(error) = state
                .repository
                .update_usage_cleanup_task_progress(claimed.id, deleted_total)
                .await
            {
                return Err(
                    mark_cleanup_failed_best_effort(state, claimed, error.to_string()).await,
                );
            }
        }
        if deleted < 5_000 {
            break;
        }
    }
    state
        .repository
        .mark_usage_cleanup_task_succeeded(claimed.id, deleted_total)
        .await
        .map_err(|error| repository::UsageCleanupTaskRecord {
            error_message: Some(error.to_string()),
            ..claimed.clone()
        })
}

async fn mark_cleanup_failed_best_effort(
    state: &AppState,
    task: repository::UsageCleanupTaskRecord,
    message: String,
) -> repository::UsageCleanupTaskRecord {
    let message = if message.len() > 500 {
        message.chars().take(500).collect::<String>()
    } else {
        message
    };
    state
        .repository
        .mark_usage_cleanup_task_failed(task.id, task.deleted_rows, message.clone())
        .await
        .unwrap_or(repository::UsageCleanupTaskRecord {
            status: "failed".to_owned(),
            error_message: Some(message),
            ..task
        })
}

fn cleanup_task_json(task: repository::UsageCleanupTaskRecord) -> Value {
    json!({
        "id": task.id,
        "status": task.status,
        "filters": cleanup_filter_json(&task.filters),
        "created_by": task.created_by,
        "deleted_rows": task.deleted_rows,
        "error_message": task.error_message,
        "canceled_by": task.canceled_by,
        "canceled_at": task.canceled_at,
        "started_at": task.started_at,
        "finished_at": task.finished_at,
        "created_at": task.created_at,
        "updated_at": task.updated_at
    })
}

fn cleanup_filter_json(filter: &repository::UsageCleanupFilter) -> Value {
    json!({
        "start_time": unix_to_rfc3339(filter.start_time_unix),
        "end_time": unix_to_rfc3339(filter.end_time_unix),
        "user_id": filter.user_id,
        "api_key_id": filter.api_key_id.map(|id| id.0),
        "account_id": filter.account_id.map(|id| id.0),
        "group_id": filter.group_id.map(|id| id.0),
        "model": filter.model.clone(),
        "request_type": filter.request_type.clone(),
        "stream": filter.stream,
        "billing_type": filter.billing_type
    })
}

fn unix_to_rfc3339(value: i64) -> String {
    Utc.timestamp_opt(value, 0)
        .single()
        .unwrap_or_else(Utc::now)
        .to_rfc3339_opts(chrono::SecondsFormat::Secs, true)
}

fn current_unix_time() -> i64 {
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|duration| duration.as_secs().min(i64::MAX as u64) as i64)
        .unwrap_or_default()
}

fn oauth_provider_from_path(path: &str) -> String {
    let mut parts = path.split('/');
    while let Some(part) = parts.next() {
        if part == "oauth" {
            return parts.next().unwrap_or("unknown").to_owned();
        }
    }
    "unknown".to_owned()
}

fn oauth_start_redirect(
    uri: &http::Uri,
    query: &HashMap<String, String>,
    bind: bool,
    payment: bool,
    headers: Option<&HeaderMap>,
) -> Response {
    let provider = oauth_provider_from_path(uri.path());
    let state = format!("demo-state-{}", uuid::Uuid::new_v4().simple());
    let redirect = sanitize_oauth_redirect(query.get("redirect").map(String::as_str));
    let mode = query
        .get("mode")
        .map(|value| sanitize_oauth_token_fragment(value))
        .filter(|value| !value.is_empty())
        .unwrap_or_else(|| "open".to_owned());
    let mut target = HashMap::new();
    target.insert("code".to_owned(), format!("demo-{provider}-code"));
    target.insert("state".to_owned(), state.clone());
    target.insert("redirect".to_owned(), redirect.clone());
    if provider == "wechat" {
        target.insert("mode".to_owned(), mode.clone());
    }
    if let Some(aff_code) = query.get("aff_code").or_else(|| query.get("aff")) {
        target.insert(
            "aff_code".to_owned(),
            sanitize_oauth_token_fragment(aff_code),
        );
    }
    if let Some(bind_token) = query
        .get("bind_token")
        .or_else(|| query.get("oauth_bind_access_token"))
    {
        target.insert(
            "bind_token".to_owned(),
            sanitize_oauth_token_fragment(bind_token),
        );
    }
    if bind && !target.contains_key("bind_token") {
        if let Some(bind_token) = headers.and_then(oauth_bind_token_from_headers) {
            target.insert(
                "bind_token".to_owned(),
                sanitize_oauth_token_fragment(&bind_token),
            );
        }
    }
    if bind {
        target.insert("intent".to_owned(), "bind_current_user".to_owned());
    }
    let callback_path = if payment {
        "/api/v1/auth/oauth/wechat/payment/callback".to_owned()
    } else {
        format!("/api/v1/auth/oauth/{provider}/callback")
    };
    let callback = format!(
        "{callback_path}?{}",
        crate::payment_provider::form_urlencode(&target)
    );

    let intent = if bind {
        "bind_current_user"
    } else if payment {
        "payment"
    } else {
        "login"
    };
    redirect_response(
        &callback,
        &[
            oauth_cookie("oauth_state", &state, 600),
            oauth_cookie("oauth_provider", &provider, 600),
            oauth_cookie("oauth_redirect", &redirect, 600),
            oauth_cookie("oauth_intent", intent, 600),
            oauth_cookie("oauth_mode", &mode, 600),
            oauth_cookie(
                "oauth_pending_browser",
                &format!("browser-{}", uuid::Uuid::new_v4().simple()),
                600,
            ),
        ],
    )
}

async fn oauth_callback_redirect(
    state: &AppState,
    path: &str,
    query: &HashMap<String, String>,
) -> Response {
    let provider = oauth_provider_from_path(path);
    let frontend_callback = oauth_frontend_callback(path, &provider);
    if let Some(error) = query.get("error").filter(|value| !value.trim().is_empty()) {
        return oauth_error_redirect(
            &frontend_callback,
            "provider_error",
            error,
            query
                .get("error_description")
                .map(String::as_str)
                .unwrap_or(""),
        );
    }
    let code = query.get("code").map(String::as_str).unwrap_or("").trim();
    let state_token = query.get("state").map(String::as_str).unwrap_or("").trim();
    if code.is_empty() || state_token.is_empty() {
        return oauth_error_redirect(
            &frontend_callback,
            "missing_params",
            "missing code/state",
            "",
        );
    }

    let redirect = sanitize_oauth_redirect(query.get("redirect").map(String::as_str));
    if path.contains("/payment/callback") {
        let mut fragment = HashMap::new();
        fragment.insert(
            "wechat_resume_token".to_owned(),
            format!("wechat-resume-{}", uuid::Uuid::new_v4().simple()),
        );
        fragment.insert("redirect".to_owned(), redirect);
        fragment.insert("state".to_owned(), state_token.to_owned());
        fragment.insert("payment_type".to_owned(), "wxpay".to_owned());
        return redirect_with_fragment(&frontend_callback, &fragment, &clear_oauth_cookies());
    }

    if matches!(provider.as_str(), "github" | "google") {
        match oauth_resolved_identity_from_provider(state, &provider, code, query).await {
            Ok(Some(identity)) => {
                return oauth_pending_session_redirect(
                    state,
                    &frontend_callback,
                    &provider,
                    &redirect,
                    query,
                    identity,
                );
            }
            Ok(None) => {}
            Err(error) => {
                return oauth_error_redirect(
                    &frontend_callback,
                    "provider_error",
                    error.message(),
                    "",
                );
            }
        }
        return match state.auth.demo_email_oauth_tokens(&provider) {
            Ok((tokens, _user)) => {
                let mut fragment = HashMap::new();
                fragment.insert("access_token".to_owned(), tokens.access_token);
                fragment.insert("refresh_token".to_owned(), tokens.refresh_token);
                fragment.insert("expires_in".to_owned(), tokens.expires_in.to_string());
                fragment.insert("token_type".to_owned(), "Bearer".to_owned());
                fragment.insert("redirect".to_owned(), redirect);
                redirect_with_fragment(&frontend_callback, &fragment, &clear_oauth_cookies())
            }
            Err(error) => {
                oauth_error_redirect(&frontend_callback, "session_error", error.message(), "")
            }
        };
    }

    if let Ok(Some(identity)) =
        oauth_resolved_identity_from_provider(state, &provider, code, query).await
    {
        return oauth_pending_session_redirect(
            state,
            &frontend_callback,
            &provider,
            &redirect,
            query,
            identity,
        );
    }

    oauth_pending_session_redirect(
        state,
        &frontend_callback,
        &provider,
        &redirect,
        query,
        crate::auth::OAuthResolvedIdentity {
            provider_key: provider.clone(),
            provider_subject: format!("{provider}-subject-{}", uuid::Uuid::new_v4().simple()),
            email: None,
        },
    )
}

async fn oauth_resolved_identity_from_provider(
    state: &AppState,
    provider: &str,
    code: &str,
    query: &HashMap<String, String>,
) -> Result<Option<crate::auth::OAuthResolvedIdentity>, ApiError> {
    let redirect_uri = query
        .get("redirect_uri")
        .or_else(|| query.get("callback_url"))
        .map(String::as_str)
        .unwrap_or("")
        .to_owned();
    crate::oauth_provider::exchange_oauth_callback(
        state.repository.clone(),
        crate::oauth_provider::OAuthCallbackInput {
            provider: provider.to_owned(),
            code: code.to_owned(),
            redirect_uri,
        },
    )
    .await
}

fn oauth_pending_session_redirect(
    state: &AppState,
    frontend_callback: &str,
    provider: &str,
    redirect: &str,
    query: &HashMap<String, String>,
    identity: crate::auth::OAuthResolvedIdentity,
) -> Response {
    let intent = query
        .get("intent")
        .map(String::as_str)
        .unwrap_or("login")
        .trim();
    let bind_token = query
        .get("bind_token")
        .map(String::as_str)
        .or_else(|| query.get("oauth_bind_access_token").map(String::as_str));
    let session = match state.auth.create_pending_oauth_session_with_identity(
        provider, redirect, intent, bind_token, identity,
    ) {
        Ok(session) => session,
        Err(error) => {
            return oauth_error_redirect(&frontend_callback, "session_error", error.message(), "");
        }
    };
    let mut fragment = HashMap::new();
    fragment.insert("redirect".to_owned(), session.redirect.clone());
    redirect_with_fragment(
        &frontend_callback,
        &fragment,
        &[
            oauth_cookie("oauth_pending_session", &session.token, 600),
            oauth_cookie(
                "oauth_pending_browser_session",
                &session.browser_session_key,
                600,
            ),
            oauth_cookie("oauth_pending_browser", &session.browser_session_key, 600),
            oauth_cookie("oauth_pending_provider", &provider, 600),
        ],
    )
}

fn oauth_frontend_callback(path: &str, provider: &str) -> String {
    if path.contains("/payment/callback") {
        return "/auth/wechat/payment/callback".to_owned();
    }
    match provider {
        "github" | "google" => "/auth/oauth/callback",
        "linuxdo" => "/auth/linuxdo/callback",
        "wechat" => "/auth/wechat/callback",
        "oidc" => "/auth/oidc/callback",
        "dingtalk" => "/auth/dingtalk/callback",
        _ => "/auth/oauth/callback",
    }
    .to_owned()
}

fn oauth_error_redirect(
    frontend_callback: &str,
    code: &str,
    message: &str,
    description: &str,
) -> Response {
    let mut fragment = HashMap::new();
    fragment.insert("error".to_owned(), sanitize_oauth_token_fragment(code));
    if !message.trim().is_empty() {
        fragment.insert(
            "error_message".to_owned(),
            sanitize_oauth_fragment_value(message),
        );
    }
    if !description.trim().is_empty() {
        fragment.insert(
            "error_description".to_owned(),
            sanitize_oauth_fragment_value(description),
        );
    }
    redirect_with_fragment(frontend_callback, &fragment, &clear_oauth_cookies())
}

fn redirect_with_fragment(
    frontend_callback: &str,
    fragment: &HashMap<String, String>,
    cookies: &[String],
) -> Response {
    let location = if fragment.is_empty() {
        sanitize_oauth_frontend_callback(frontend_callback)
    } else {
        format!(
            "{}#{}",
            sanitize_oauth_frontend_callback(frontend_callback),
            crate::payment_provider::form_urlencode(fragment)
        )
    };
    redirect_response(&location, cookies)
}

fn redirect_response(location: &str, cookies: &[String]) -> Response {
    let mut builder = Response::builder()
        .status(StatusCode::FOUND)
        .header(LOCATION, header_value_or_root(location))
        .header("cache-control", "no-store")
        .header("pragma", "no-cache");
    for cookie in cookies {
        builder = builder.header(SET_COOKIE, header_value_or_root(cookie));
    }
    builder.body(axum::body::Body::empty()).unwrap()
}

fn oauth_cookie(name: &str, value: &str, max_age: i64) -> String {
    oauth_cookie_at_path(name, value, max_age, "/")
}

fn oauth_cookie_at_path(name: &str, value: &str, max_age: i64, path: &str) -> String {
    format!(
        "{}={}; Path={}; Max-Age={}; HttpOnly; SameSite=Lax",
        name,
        sanitize_cookie_value(value),
        sanitize_cookie_path(path),
        max_age
    )
}

fn sanitize_cookie_path(path: &str) -> &str {
    if path.starts_with('/') && !path.contains(';') && !path.contains('\r') && !path.contains('\n')
    {
        path
    } else {
        "/"
    }
}

fn clear_oauth_cookies() -> Vec<String> {
    [
        "oauth_state",
        "oauth_provider",
        "oauth_redirect",
        "oauth_intent",
        "oauth_mode",
        "oauth_pending_browser",
        "oauth_pending_browser_session",
        "oauth_pending_session",
        "oauth_pending_provider",
    ]
    .into_iter()
    .map(|name| oauth_cookie(name, "", -1))
    .collect()
}

fn oauth_pending_session_from_headers(headers: &HeaderMap) -> Option<String> {
    cookie_value(headers, "oauth_pending_session")
}

fn oauth_browser_session_from_headers(headers: &HeaderMap) -> Option<String> {
    cookie_value(headers, "oauth_pending_browser_session")
        .or_else(|| cookie_value(headers, "oauth_pending_browser"))
}

fn oauth_bind_token_from_headers(headers: &HeaderMap) -> Option<String> {
    cookie_value(headers, "oauth_bind_access_token")
}

fn fill_pending_token_from_cookie(request: &mut OAuthCompletionRequest, headers: &HeaderMap) {
    if request
        .pending_token
        .as_deref()
        .is_some_and(|value| !value.trim().is_empty())
        || request
            .pending_auth_token
            .as_deref()
            .is_some_and(|value| !value.trim().is_empty())
        || request
            .pending_oauth_token
            .as_deref()
            .is_some_and(|value| !value.trim().is_empty())
    {
        return;
    }
    request.pending_token = oauth_pending_session_from_headers(headers);
}

fn cookie_value(headers: &HeaderMap, name: &str) -> Option<String> {
    headers
        .get(http::header::COOKIE)?
        .to_str()
        .ok()?
        .split(';')
        .filter_map(|part| part.trim().split_once('='))
        .find_map(|(cookie_name, value)| {
            if cookie_name.trim() == name {
                Some(value.trim().to_owned())
            } else {
                None
            }
        })
        .filter(|value| !value.is_empty())
}

fn sanitize_cookie_value(value: &str) -> String {
    value
        .chars()
        .filter(|ch| ch.is_ascii() && !matches!(ch, ';' | ',' | '\r' | '\n'))
        .collect()
}

fn sanitize_oauth_redirect(value: Option<&str>) -> String {
    let value = value.unwrap_or("/dashboard").trim();
    if value.is_empty()
        || !value.starts_with('/')
        || value.starts_with("//")
        || value.contains("://")
        || value.contains('\r')
        || value.contains('\n')
    {
        "/dashboard".to_owned()
    } else {
        value.to_owned()
    }
}

fn sanitize_oauth_frontend_callback(value: &str) -> String {
    let value = value.trim();
    if value.is_empty()
        || value.starts_with("//")
        || value.contains('\r')
        || value.contains('\n')
        || (value.contains("://")
            && !(value.starts_with("http://") || value.starts_with("https://")))
    {
        "/dashboard".to_owned()
    } else {
        value.to_owned()
    }
}

fn sanitize_oauth_fragment_value(value: &str) -> String {
    value
        .chars()
        .filter(|ch| !matches!(ch, '\r' | '\n'))
        .take(512)
        .collect()
}

fn sanitize_oauth_token_fragment(value: &str) -> String {
    value
        .chars()
        .filter(|ch| ch.is_ascii_alphanumeric() || matches!(ch, '-' | '_' | '.'))
        .take(128)
        .collect()
}

fn header_value_or_root(value: &str) -> HeaderValue {
    HeaderValue::from_str(value).unwrap_or_else(|_| HeaderValue::from_static("/"))
}

fn payment_webhook_provider(path: &str) -> String {
    path.rsplit('/').next().unwrap_or("unknown").to_owned()
}

fn payment_webhook_headers(headers: &HeaderMap) -> HashMap<String, String> {
    headers
        .iter()
        .filter_map(|(name, value)| {
            value
                .to_str()
                .ok()
                .map(|value| (name.as_str().to_ascii_lowercase(), value.to_owned()))
        })
        .collect()
}

async fn gateway_endpoint(
    State(state): State<AppState>,
    OriginalUri(uri): OriginalUri,
    method: Method,
    headers: HeaderMap,
    body: Bytes,
) -> Response {
    let endpoint = GatewayEndpoint::from_method_path(method.as_str(), uri.path())
        .expect("registered gateway path");
    state
        .gateway_runtime
        .handle(&state, endpoint, &uri, method.as_str(), headers, body)
        .await
}

async fn gateway_websocket_endpoint(
    State(state): State<AppState>,
    OriginalUri(uri): OriginalUri,
    headers: HeaderMap,
    ws: Result<WebSocketUpgrade, WebSocketUpgradeRejection>,
) -> Response {
    let endpoint = GatewayEndpoint::from_method_path(Method::GET.as_str(), uri.path())
        .expect("registered gateway websocket path");
    let runtime = state.gateway_runtime.clone();
    runtime
        .handle_websocket(state, endpoint, uri, headers, ws)
        .await
}

