    async fn request(method: &str, uri: &str) -> axum::response::Response {
        let app = app();
        request_with_body(app, method, uri, Body::empty(), None).await
    }

    async fn request_json(method: &str, uri: &str, body: Value) -> axum::response::Response {
        let app = app();
        request_with_body(app, method, uri, Body::from(body.to_string()), None).await
    }

    async fn request_with_body(
        app: Router,
        method: &str,
        uri: &str,
        body: Body,
        token: Option<&str>,
    ) -> axum::response::Response {
        let mut builder = Request::builder()
            .method(method)
            .uri(uri)
            .header("content-type", "application/json");
        if let Some(token) = token {
            builder = builder.header("authorization", format!("Bearer {token}"));
        }
        app.oneshot(builder.body(body).unwrap()).await.unwrap()
    }

    async fn request_with_headers(
        app: Router,
        method: &str,
        uri: &str,
        body: Body,
        headers: &[(&str, &str)],
    ) -> axum::response::Response {
        let has_content_type = headers
            .iter()
            .any(|(name, _)| name.eq_ignore_ascii_case("content-type"));
        let mut builder = Request::builder().method(method).uri(uri);
        if !has_content_type {
            builder = builder.header("content-type", "application/json");
        }
        for (name, value) in headers {
            builder = builder.header(*name, *value);
        }
        app.oneshot(builder.body(body).unwrap()).await.unwrap()
    }

    async fn request_on(
        app: Router,
        method: &str,
        uri: &str,
        body: Value,
        token: Option<&str>,
    ) -> axum::response::Response {
        request_with_body(app, method, uri, Body::from(body.to_string()), token).await
    }

