    fn spawn_fake_redis() -> (u16, thread::JoinHandle<()>) {
        let listener = TcpListener::bind("127.0.0.1:0").unwrap();
        let port = listener.local_addr().unwrap().port();
        let handle = thread::spawn(move || {
            let Ok((mut stream, _)) = listener.accept() else {
                return;
            };
            let mut buffer = [0_u8; 512];
            for _ in 0..4 {
                let Ok(read) = stream.read(&mut buffer) else {
                    return;
                };
                if read == 0 {
                    return;
                }
                let request = String::from_utf8_lossy(&buffer[..read]).to_ascii_uppercase();
                let response = if request.contains("PING") {
                    b"+PONG\r\n".as_slice()
                } else {
                    b"+OK\r\n".as_slice()
                };
                if stream.write_all(response).is_err() {
                    return;
                }
            }
        });
        (port, handle)
    }

    fn spawn_fake_redis_dump() -> (u16, thread::JoinHandle<Vec<Vec<String>>>) {
        let listener = TcpListener::bind("127.0.0.1:0").unwrap();
        let port = listener.local_addr().unwrap().port();
        let handle = thread::spawn(move || {
            let Ok((mut stream, _)) = listener.accept() else {
                return Vec::new();
            };
            let mut reader = std::io::BufReader::new(stream.try_clone().unwrap());
            let mut commands = Vec::new();
            while let Ok(command) = read_resp_command_bytes(&mut reader) {
                let command_text = command
                    .iter()
                    .map(|part| String::from_utf8_lossy(part).to_string())
                    .collect::<Vec<_>>();
                let name = command_text
                    .first()
                    .map(|value| value.to_ascii_uppercase())
                    .unwrap_or_default();
                commands.push(command_text);
                let response = match name.as_str() {
                    "AUTH" | "SELECT" => b"+OK\r\n".to_vec(),
                    "SCAN" => b"*2\r\n$1\r\n0\r\n*1\r\n$10\r\nsample:key\r\n".to_vec(),
                    "TYPE" => b"+string\r\n".to_vec(),
                    "PTTL" => b":12345\r\n".to_vec(),
                    "GET" => b"$12\r\nsample-value\r\n".to_vec(),
                    _ => b"+OK\r\n".to_vec(),
                };
                if stream.write_all(&response).is_err() || stream.flush().is_err() {
                    break;
                }
            }
            commands
        });
        (port, handle)
    }

    fn read_resp_command_bytes<R: std::io::BufRead>(
        reader: &mut R,
    ) -> std::io::Result<Vec<Vec<u8>>> {
        let line = read_line(reader)?;
        let Some(count) = line
            .strip_prefix('*')
            .and_then(|value| value.parse::<usize>().ok())
        else {
            return Ok(Vec::new());
        };
        let mut parts = Vec::with_capacity(count);
        for _ in 0..count {
            let bulk_header = read_line(reader)?;
            let Some(length) = bulk_header
                .strip_prefix('$')
                .and_then(|value| value.parse::<usize>().ok())
            else {
                return Ok(Vec::new());
            };
            let mut data = vec![0_u8; length + 2];
            reader.read_exact(&mut data)?;
            parts.push(data[..length].to_vec());
        }
        Ok(parts)
    }

    fn read_line<R: std::io::BufRead>(reader: &mut R) -> std::io::Result<String> {
        let mut line = String::new();
        reader.read_line(&mut line)?;
        Ok(line.trim_end_matches(['\r', '\n']).to_owned())
    }

