    #[tokio::test]
    async fn setup_validation_endpoints_accept_valid_config_and_reject_bad_input() {
        let state = AppState::setup_demo();
        let setup = state.setup.clone();
        let app = app_with_state(state.clone());

        let status_response =
            request_with_body(app.clone(), "GET", "/setup/status", Body::empty(), None).await;
        assert_eq!(status_response.status(), StatusCode::OK);
        let status_payload = json_body(status_response).await;
        assert_eq!(status_payload["data"]["needs_setup"], true);
        assert_eq!(status_payload["data"]["step"], "welcome");

        let bad_db_response = request_on(
            app.clone(),
            "POST",
            "/setup/test-db",
            json!({
                "host": "bad host",
                "port": 5432,
                "user": "sub2api",
                "dbname": "sub2api"
            }),
            None,
        )
        .await;
        assert_eq!(bad_db_response.status(), StatusCode::BAD_REQUEST);

        let bad_ssl_response = request_on(
            app.clone(),
            "POST",
            "/setup/test-db",
            json!({
                "host": "127.0.0.1",
                "port": 5432,
                "user": "sub2api",
                "dbname": "sub2api",
                "sslmode": "bad"
            }),
            None,
        )
        .await;
        assert_eq!(bad_ssl_response.status(), StatusCode::BAD_REQUEST);

        let (redis_port, redis_handle) = spawn_fake_redis();
        let redis_response = request_on(
            app.clone(),
            "POST",
            "/setup/test-redis",
            json!({
                "host": "127.0.0.1",
                "port": redis_port,
                "password": "123456",
                "db": 0,
                "enable_tls": false
            }),
            None,
        )
        .await;
        assert_eq!(redis_response.status(), StatusCode::OK);
        redis_handle.join().unwrap();

        let bad_redis_response = request_on(
            app.clone(),
            "POST",
            "/setup/test-redis",
            json!({
                "host": "127.0.0.1",
                "port": 6379,
                "db": 16
            }),
            None,
        )
        .await;
        assert_eq!(bad_redis_response.status(), StatusCode::BAD_REQUEST);

        let install_response = request_on(
            app.clone(),
            "POST",
            "/setup/install",
            valid_install_request(),
            None,
        )
        .await;
        assert_eq!(install_response.status(), StatusCode::OK);
        let install_payload = json_body(install_response).await;
        assert_eq!(install_payload["data"]["restart"], true);
        assert!(setup
            .config_yaml()
            .expect("config yaml generated")
            .contains("dbname: \"sub2api\""));
        assert!(setup
            .install_lock()
            .expect("install lock generated")
            .starts_with("installed_at="));

        let completed_response =
            request_with_body(app.clone(), "GET", "/setup/status", Body::empty(), None).await;
        assert_eq!(completed_response.status(), StatusCode::OK);
        let completed_payload = json_body(completed_response).await;
        assert_eq!(completed_payload["data"]["needs_setup"], false);
        assert_eq!(completed_payload["data"]["step"], "completed");

        let reinstall_response = request_on(
            app.clone(),
            "POST",
            "/setup/install",
            valid_install_request(),
            None,
        )
        .await;
        assert_eq!(reinstall_response.status(), StatusCode::FORBIDDEN);
    }

