    #[tokio::test]
    async fn user_group_rates_reflect_admin_repository_overrides() {
        let state = AppState::demo();
        state
            .repository
            .upsert_group(Group {
                id: GroupId(42),
                name: "Rated group".to_owned(),
                status: GroupStatus::Active,
            })
            .await
            .unwrap();
        state
            .repository
            .upsert_user(repository::UserRecord {
                id: 1,
                email: "admin@example.com".to_owned(),
                username: "admin".to_owned(),
                role: "admin".to_owned(),
                status: "active".to_owned(),
            })
            .await
            .unwrap();
        let app = app_with_state(state);
        let access_token = login_seed_admin(app.clone()).await;

        let initial_response = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/groups/rates",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(initial_response.status(), StatusCode::OK);
        assert_eq!(json_body(initial_response).await["data"], json!({}));

        let set_response = request_on(
            app.clone(),
            "PUT",
            "/api/v1/admin/groups/42/rate-multipliers",
            json!({ "entries": [{ "user_id": 1, "rate_multiplier": 0.75 }] }),
            Some(&access_token),
        )
        .await;
        assert_eq!(set_response.status(), StatusCode::OK);

        let rates_response = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/groups/rates",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(rates_response.status(), StatusCode::OK);
        let rates_payload = json_body(rates_response).await;
        assert_eq!(rates_payload["data"]["42"], 0.75);

        let admin_rates_response = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/admin/groups/42/rate-multipliers",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(admin_rates_response.status(), StatusCode::OK);
        let admin_rates_payload = json_body(admin_rates_response).await;
        assert_eq!(admin_rates_payload["data"][0]["user_id"], 1);
        assert_eq!(
            admin_rates_payload["data"][0]["user_email"],
            "admin@example.com"
        );
        assert_eq!(admin_rates_payload["data"][0]["rate_multiplier"], 0.75);

        let rpm_response = request_on(
            app.clone(),
            "PUT",
            "/api/v1/admin/groups/42/rpm-overrides",
            json!({ "entries": [{ "user_id": 1, "rpm_override": 120 }] }),
            Some(&access_token),
        )
        .await;
        assert_eq!(rpm_response.status(), StatusCode::OK);
        let admin_rates_response = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/admin/groups/42/rate-multipliers",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        let admin_rates_payload = json_body(admin_rates_response).await;
        assert_eq!(admin_rates_payload["data"][0]["rate_multiplier"], 0.75);
        assert_eq!(admin_rates_payload["data"][0]["rpm_override"], 120);

        let clear_response = request_with_body(
            app.clone(),
            "DELETE",
            "/api/v1/admin/groups/42/rate-multipliers",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(clear_response.status(), StatusCode::OK);

        let rates_response = request_with_body(
            app,
            "GET",
            "/api/v1/groups/rates",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(rates_response.status(), StatusCode::OK);
        assert_eq!(json_body(rates_response).await["data"], json!({}));
    }

    #[tokio::test]
    async fn user_channel_monitors_read_repository_collection_without_static_fallback() {
        let state = AppState::demo();
        let app = app_with_state(state);
        let access_token = login_seed_admin(app.clone()).await;

        let empty_response = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/channel-monitors",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(empty_response.status(), StatusCode::OK);
        let empty_payload = json_body(empty_response).await;
        assert_eq!(empty_payload["data"]["total"], 0);

        let create_response = request_on(
            app.clone(),
            "POST",
            "/api/v1/admin/channel-monitors",
            json!({
                "name": "DeepSeek monitor",
                "provider": "deepseek",
                "api_mode": "chat_completions",
                "primary_model": "deepseek-chat",
                "primary_status": "success",
                "primary_latency_ms": 88,
                "last_checked_at": "2026-06-10T00:00:00Z",
                "enabled": true
            }),
            Some(&access_token),
        )
        .await;
        assert_eq!(create_response.status(), StatusCode::OK);
        let monitor_id = json_body(create_response).await["data"]["id"]
            .as_i64()
            .unwrap();

        let disabled_response = request_on(
            app.clone(),
            "POST",
            "/api/v1/admin/channel-monitors",
            json!({
                "name": "Disabled monitor",
                "enabled": false
            }),
            Some(&access_token),
        )
        .await;
        assert_eq!(disabled_response.status(), StatusCode::OK);
        let disabled_id = json_body(disabled_response).await["data"]["id"]
            .as_i64()
            .unwrap();

        let list_response = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/channel-monitors",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(list_response.status(), StatusCode::OK);
        let list_payload = json_body(list_response).await;
        assert_eq!(list_payload["data"]["total"], 1);
        assert_eq!(list_payload["data"]["items"][0]["id"], monitor_id);
        assert_eq!(list_payload["data"]["items"][0]["provider"], "deepseek");
        assert_eq!(
            list_payload["data"]["items"][0]["primary_status"],
            "success"
        );

        let status_response = request_with_body(
            app.clone(),
            "GET",
            &format!("/api/v1/channel-monitors/{monitor_id}/status"),
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(status_response.status(), StatusCode::OK);
        let status_payload = json_body(status_response).await;
        assert_eq!(status_payload["data"]["status"], "success");
        assert_eq!(status_payload["data"]["available"], true);
        assert_eq!(status_payload["data"]["latency_ms"], 88);

        let disabled_status_response = request_with_body(
            app,
            "GET",
            &format!("/api/v1/channel-monitors/{disabled_id}/status"),
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(disabled_status_response.status(), StatusCode::NOT_FOUND);
    }

    #[tokio::test]
    async fn user_subscription_routes_read_repository_records_without_demo_fallback() {
        let state = AppState::demo();
        state
            .repository
            .upsert_user(repository::UserRecord {
                id: 1,
                email: "admin@example.com".to_owned(),
                username: "admin".to_owned(),
                role: "admin".to_owned(),
                status: "active".to_owned(),
            })
            .await
            .unwrap();
        state
            .repository
            .upsert_user_subscription(repository::UserSubscriptionRecord {
                id: 0,
                user_id: 1,
                group_id: 77,
                plan_id: Some(3),
                status: "active".to_owned(),
                starts_at: "2026-06-01T00:00:00Z".to_owned(),
                expires_at: "2026-07-01T00:00:00Z".to_owned(),
                daily_usage_usd: 0.4,
                weekly_usage_usd: 1.5,
                monthly_usage_usd: 2.5,
                daily_window_start: Some("2026-06-06T00:00:00Z".to_owned()),
                weekly_window_start: Some("2026-06-01T00:00:00Z".to_owned()),
                monthly_window_start: Some("2026-06-01T00:00:00Z".to_owned()),
                source_order_id: "sub2_subscription_repo".to_owned(),
                created_at: "2026-06-01T00:00:00Z".to_owned(),
                metadata: json!({ "source": "subscription-route-test" }),
            })
            .await
            .unwrap();
        state
            .repository
            .upsert_user_subscription(repository::UserSubscriptionRecord {
                id: 0,
                user_id: 1,
                group_id: 88,
                plan_id: None,
                status: "expired".to_owned(),
                starts_at: "2026-05-01T00:00:00Z".to_owned(),
                expires_at: "2026-06-01T00:00:00Z".to_owned(),
                daily_usage_usd: 9.0,
                weekly_usage_usd: 9.0,
                monthly_usage_usd: 9.0,
                daily_window_start: None,
                weekly_window_start: None,
                monthly_window_start: None,
                source_order_id: "sub2_subscription_expired".to_owned(),
                created_at: "2026-05-01T00:00:00Z".to_owned(),
                metadata: json!({}),
            })
            .await
            .unwrap();
        let active_subscription = state
            .repository
            .get_subscription_by_source_order("sub2_subscription_repo")
            .await
            .unwrap();
        let app = app_with_state(state);
        let access_token = login_seed_admin(app.clone()).await;

        let list_response = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/subscriptions",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(list_response.status(), StatusCode::OK);
        let list_payload = json_body(list_response).await;
        assert_eq!(list_payload["data"].as_array().unwrap().len(), 2);
        assert_eq!(list_payload["data"][0]["group_id"], 77);
        assert_eq!(list_payload["data"][0]["daily_usage_usd"], 0.4);
        assert_eq!(
            list_payload["data"][0]["daily_window_start"],
            "2026-06-06T00:00:00Z"
        );

        let active_response = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/subscriptions/active",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        let active_payload = json_body(active_response).await;
        assert_eq!(active_payload["data"].as_array().unwrap().len(), 1);
        assert_eq!(active_payload["data"][0]["status"], "active");

        let progress_response = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/subscriptions/progress",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        let progress_payload = json_body(progress_response).await;
        assert_eq!(
            progress_payload["data"][0]["subscription"]["source_order_id"],
            "sub2_subscription_repo"
        );
        assert_eq!(
            progress_payload["data"][0]["progress"]["subscription_id"],
            progress_payload["data"][0]["subscription"]["id"]
        );
        assert!(progress_payload["data"][0].get("subscription_id").is_none());

        let single_progress_response = request_with_body(
            app.clone(),
            "GET",
            &format!("/api/v1/subscriptions/{}/progress", active_subscription.id),
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(single_progress_response.status(), StatusCode::OK);
        let single_progress_payload = json_body(single_progress_response).await;
        assert_eq!(
            single_progress_payload["data"]["subscription"]["source_order_id"],
            "sub2_subscription_repo"
        );
        assert_eq!(
            single_progress_payload["data"]["progress"]["subscription_id"],
            active_subscription.id
        );

        let missing_progress_response = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/subscriptions/999999/progress",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(missing_progress_response.status(), StatusCode::NOT_FOUND);

        let summary_response = request_with_body(
            app,
            "GET",
            "/api/v1/subscriptions/summary",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        let summary_payload = json_body(summary_response).await;
        assert_eq!(summary_payload["data"]["active_count"], 1);
        assert_close(&summary_payload["data"]["total_used_usd"], 2.5);
        assert_eq!(
            summary_payload["data"]["subscriptions"][0]["monthly_used_usd"],
            2.5
        );
    }

