    #[tokio::test]
    async fn admin_account_test_probes_openai_chat_compatible_upstream() {
        let upstream = Router::new().route(
            "/v1/chat/completions",
            post(|headers: HeaderMap, Json(body): Json<Value>| async move {
                assert_eq!(
                    headers
                        .get("authorization")
                        .and_then(|value| value.to_str().ok()),
                    Some("Bearer deepseek-secret")
                );
                assert_eq!(body["model"], "deepseek-v4-pro");
                assert_eq!(body["stream"], false);
                assert_eq!(body["messages"][0]["content"], "ping upstream");
                Json(json!({
                    "id": "chatcmpl_test",
                    "object": "chat.completion",
                    "model": body["model"],
                    "choices": [{
                        "index": 0,
                        "message": { "role": "assistant", "content": "ok" },
                        "finish_reason": "stop"
                    }]
                }))
            }),
        );
        let (base_url, shutdown) = spawn_test_server(upstream).await;
        let state = AppState::demo();
        state
            .admin_portal
            .update_collection_item(
                "accounts",
                1,
                json!({
                    "provider": "deepseek",
                    "platform": "deepseek",
                    "status": "active",
                    "upstream_protocol": "openai_chat_completions",
                    "base_url": base_url,
                    "api_key": "deepseek-secret",
                    "model_mapping": {
                        "gpt-5.4": "deepseek-v4-pro"
                    }
                }),
            )
            .unwrap();
        let app = app_with_state(state.clone());
        let access_token = login_seed_admin(app.clone()).await;

        let response = request_on(
            app,
            "POST",
            "/api/v1/admin/accounts/1/test",
            json!({
                "model_id": "gpt-5.4",
                "prompt": "ping upstream"
            }),
            Some(&access_token),
        )
        .await;

        shutdown.send(()).ok();
        assert_eq!(response.status(), StatusCode::OK);
        let payload = json_body(response).await;
        assert_eq!(payload["data"]["success"], true);
        assert_eq!(payload["data"]["protocol"], "openai_chat_completions");
        assert_eq!(payload["data"]["model"], "gpt-5.4");
        assert_eq!(payload["data"]["upstream_model"], "deepseek-v4-pro");

        let account = state
            .admin_portal
            .get_collection_item("accounts", 1)
            .unwrap();
        assert_eq!(account["last_test_success"], true);
        assert!(account["last_tested_at"].as_str().is_some());
        assert!(account["error_message"].is_null());
    }

    #[tokio::test]
    async fn admin_account_test_records_upstream_failure_without_500() {
        let upstream = Router::new().route(
            "/v1/chat/completions",
            post(|| async {
                (
                    StatusCode::UNAUTHORIZED,
                    Json(json!({ "error": { "message": "bad key" } })),
                )
            }),
        );
        let (base_url, shutdown) = spawn_test_server(upstream).await;
        let state = AppState::demo();
        state
            .admin_portal
            .update_collection_item(
                "accounts",
                1,
                json!({
                    "provider": "openai",
                    "platform": "openai",
                    "status": "active",
                    "upstream_protocol": "openai_chat_completions",
                    "base_url": base_url,
                    "api_key": "wrong-secret"
                }),
            )
            .unwrap();
        let app = app_with_state(state.clone());
        let access_token = login_seed_admin(app.clone()).await;

        let response = request_on(
            app,
            "POST",
            "/api/v1/admin/accounts/1/test",
            json!({ "model": "gpt-5.4" }),
            Some(&access_token),
        )
        .await;

        shutdown.send(()).ok();
        assert_eq!(response.status(), StatusCode::OK);
        let payload = json_body(response).await;
        assert_eq!(payload["data"]["success"], false);
        assert_eq!(payload["data"]["status_code"], 401);
        assert!(payload["data"]["message"]
            .as_str()
            .unwrap()
            .contains("bad key"));

        let account = state
            .admin_portal
            .get_collection_item("accounts", 1)
            .unwrap();
        assert_eq!(account["last_test_success"], false);
        assert!(account["error_message"]
            .as_str()
            .unwrap()
            .contains("bad key"));
    }

    #[tokio::test]
    async fn admin_proxy_test_uses_configured_http_proxy_and_records_latency() {
        let (proxy_url, proxy_requests, proxy_shutdown) = spawn_fake_http_proxy().await;
        let state = AppState::demo();
        state
            .admin_portal
            .update_collection_item(
                "proxies",
                1,
                json!({
                    "name": "local-http-proxy",
                    "type": "http",
                    "protocol": "http",
                    "url": proxy_url
                }),
            )
            .unwrap();
        let app = app_with_state(state.clone());
        let access_token = login_seed_admin(app.clone()).await;

        let response = request_on(
            app,
            "POST",
            "/api/v1/admin/proxies/1/test",
            json!({ "test_url": "http://example.test/proxy-check" }),
            Some(&access_token),
        )
        .await;

        proxy_shutdown.send(()).ok();
        assert_eq!(response.status(), StatusCode::OK);
        let payload = json_body(response).await;
        assert_eq!(payload["data"]["success"], true);
        assert_eq!(payload["data"]["status_code"], 200);
        assert_eq!(
            payload["data"]["target_url"],
            "http://example.test/proxy-check"
        );

        let requests = proxy_requests.lock().unwrap();
        assert_eq!(requests.len(), 1);
        assert!(requests[0].starts_with("GET http://example.test/proxy-check "));

        let proxy = state
            .admin_portal
            .get_collection_item("proxies", 1)
            .unwrap();
        assert_eq!(proxy["last_test_success"], true);
        assert_eq!(proxy["latency_status"], "success");
        assert!(proxy["last_tested_at"].as_str().is_some());
    }

    #[tokio::test]
    async fn admin_proxy_quality_check_runs_targets_and_persists_snapshot() {
        let (proxy_url, proxy_requests, proxy_shutdown) = spawn_fake_http_proxy().await;
        let state = AppState::demo();
        state
            .admin_portal
            .update_collection_item(
                "proxies",
                1,
                json!({
                    "name": "quality-proxy",
                    "type": "http",
                    "protocol": "http",
                    "url": proxy_url
                }),
            )
            .unwrap();
        let app = app_with_state(state.clone());
        let access_token = login_seed_admin(app.clone()).await;

        let response = request_on(
            app,
            "POST",
            "/api/v1/admin/proxies/1/quality-check",
            json!({
                "targets": [
                    {
                        "target": "openai-local",
                        "url": "http://example.test/openai",
                        "allowed_statuses": [200]
                    },
                    {
                        "target": "auth-local",
                        "url": "http://example.test/auth",
                        "allowed_statuses": [401]
                    }
                ]
            }),
            Some(&access_token),
        )
        .await;

        proxy_shutdown.send(()).ok();
        assert_eq!(response.status(), StatusCode::OK);
        let payload = json_body(response).await;
        assert_eq!(payload["data"]["passed_count"], 2);
        assert_eq!(payload["data"]["failed_count"], 0);
        assert_eq!(payload["data"]["score"], 100);
        assert_eq!(payload["data"]["grade"], "A");
        assert_eq!(payload["data"]["items"].as_array().unwrap().len(), 2);

        let requests = proxy_requests.lock().unwrap();
        assert_eq!(requests.len(), 2);
        assert!(requests
            .iter()
            .any(|line| line.starts_with("GET http://example.test/openai ")));
        assert!(requests
            .iter()
            .any(|line| line.starts_with("GET http://example.test/auth ")));

        let proxy = state
            .admin_portal
            .get_collection_item("proxies", 1)
            .unwrap();
        assert_eq!(proxy["quality_status"], "healthy");
        assert_eq!(proxy["quality_score"], 100);
        assert_eq!(proxy["quality_grade"], "A");
        assert_eq!(proxy["quality_items"].as_array().unwrap().len(), 2);
    }

