    #[tokio::test]
    async fn admin_redeem_stats_and_export_read_repository_state() {
        let state = AppState::demo();
        let app = app_with_state(state);
        let access_token = login_seed_admin(app.clone()).await;

        let unused_response = request_on(
            app.clone(),
            "POST",
            "/api/v1/admin/redeem-codes",
            json!({
                "code": "CSV-UNUSED",
                "type": "balance",
                "value": 2.0,
                "status": "unused"
            }),
            Some(&access_token),
        )
        .await;
        assert_eq!(unused_response.status(), StatusCode::OK);

        let expired_response = request_on(
            app.clone(),
            "POST",
            "/api/v1/admin/redeem-codes",
            json!({
                "code": "CSV-EXPIRED",
                "type": "balance",
                "value": 5.0,
                "status": "expired"
            }),
            Some(&access_token),
        )
        .await;
        assert_eq!(expired_response.status(), StatusCode::OK);

        let used_response = request_on(
            app.clone(),
            "POST",
            "/api/v1/admin/redeem-codes",
            json!({
                "code": "CSV-USED",
                "type": "balance",
                "value": 7.0,
                "status": "unused"
            }),
            Some(&access_token),
        )
        .await;
        assert_eq!(used_response.status(), StatusCode::OK);

        let redeem_response = request_on(
            app.clone(),
            "POST",
            "/api/v1/redeem",
            json!({ "code": "CSV-USED" }),
            Some(&access_token),
        )
        .await;
        assert_eq!(redeem_response.status(), StatusCode::OK);

        let stats_response = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/admin/redeem-codes/stats",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(stats_response.status(), StatusCode::OK);
        let stats_payload = json_body(stats_response).await;
        assert_eq!(stats_payload["data"]["total"], 3);
        assert_eq!(stats_payload["data"]["used"], 1);
        assert_eq!(stats_payload["data"]["unused"], 1);
        assert_eq!(stats_payload["data"]["expired"], 1);

        let export_response = request_with_body(
            app,
            "GET",
            "/api/v1/admin/redeem-codes/export",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(export_response.status(), StatusCode::OK);
        let export_payload = json_body(export_response).await;
        assert_eq!(export_payload["data"]["filename"], "redeem-codes.csv");
        let content = export_payload["data"]["content"].as_str().unwrap();
        assert!(content.starts_with("code,type,value,status\n"));
        assert!(content.contains("CSV-UNUSED,balance,2.0,unused"));
        assert!(content.contains("CSV-EXPIRED,balance,5.0,expired"));
        assert!(content.contains("CSV-USED,balance,7.0,used"));
    }

    #[tokio::test]
    async fn payment_channels_read_active_ai_channels_from_repository() {
        let state = AppState::demo();
        let state_for_repository = state.clone();
        let app = app_with_state(state);
        let access_token = login_seed_admin(app.clone()).await;

        let visible_channel = request_on(
            app.clone(),
            "POST",
            "/api/v1/admin/channels",
            json!({
                "name": "Visible AI Channel",
                "description": "shown to payment users",
                "status": "active",
                "group_ids": [1],
                "model_mapping": { "gpt-5.4": "deepseek-v4-pro" }
            }),
            Some(&access_token),
        )
        .await;
        assert_eq!(visible_channel.status(), StatusCode::OK);
        let visible_id = json_body(visible_channel).await["data"]["id"]
            .as_i64()
            .unwrap();

        let hidden_channel = request_on(
            app.clone(),
            "POST",
            "/api/v1/admin/channels",
            json!({
                "name": "Hidden AI Channel",
                "status": "disabled",
                "group_ids": [2]
            }),
            Some(&access_token),
        )
        .await;
        assert_eq!(hidden_channel.status(), StatusCode::OK);
        let hidden_id = json_body(hidden_channel).await["data"]["id"]
            .as_i64()
            .unwrap();

        assert_eq!(
            state_for_repository
                .repository
                .get_admin_collection_item("channels", visible_id)
                .await
                .unwrap()
                .item["name"],
            "Visible AI Channel"
        );

        let payment_channels = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/payment/channels",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(payment_channels.status(), StatusCode::OK);
        let payment_payload = json_body(payment_channels).await;
        let channels = payment_payload["data"].as_array().unwrap();
        assert_eq!(channels.len(), 1);
        assert_eq!(channels[0]["id"], visible_id);
        assert_eq!(channels[0]["name"], "Visible AI Channel");
        assert_eq!(channels[0]["model_mapping"]["gpt-5.4"], "deepseek-v4-pro");
        assert!(!channels
            .iter()
            .any(|channel| channel["id"].as_i64() == Some(hidden_id)));

        let update_hidden = request_on(
            app.clone(),
            "PUT",
            &format!("/api/v1/admin/channels/{hidden_id}"),
            json!({ "status": "active" }),
            Some(&access_token),
        )
        .await;
        assert_eq!(update_hidden.status(), StatusCode::OK);

        let activated_channels = request_with_body(
            app,
            "GET",
            "/api/v1/payment/channels",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(activated_channels.status(), StatusCode::OK);
        let activated_payload = json_body(activated_channels).await;
        assert_eq!(activated_payload["data"].as_array().unwrap().len(), 2);
    }

