    #[tokio::test]
    async fn notify_email_verification_enforces_codes_limits_and_existing_entries() {
        let state = AppState::demo();
        state.auth.set_now_for_tests(1_000);
        let (smtp_port, smtp_log, smtp_shutdown) = spawn_fake_smtp_server().await;
        configure_smtp_settings(&state, smtp_port).await;
        let app = app_with_state(state.clone());
        let access_token = login_seed_admin(app.clone()).await;

        let missing_code_response = request_on(
            app.clone(),
            "POST",
            "/api/v1/user/notify-email/verify",
            json!({ "email": "notify-limit@example.com", "code": "000000" }),
            Some(&access_token),
        )
        .await;
        assert_eq!(missing_code_response.status(), StatusCode::BAD_REQUEST);
        let missing_code_payload = json_body(missing_code_response).await;
        assert!(missing_code_payload["message"]
            .as_str()
            .unwrap()
            .contains("INVALID_VERIFY_CODE"));

        let first_send = request_on(
            app.clone(),
            "POST",
            "/api/v1/user/notify-email/send-code",
            json!({ "email": "notify-limit@example.com" }),
            Some(&access_token),
        )
        .await;
        assert_eq!(first_send.status(), StatusCode::OK);
        let first_send_payload = json_body(first_send).await;
        assert_eq!(first_send_payload["data"]["countdown"], 60);
        assert_eq!(first_send_payload["data"]["expires_in"], 900);

        let cooldown_response = request_on(
            app.clone(),
            "POST",
            "/api/v1/user/notify-email/send-code",
            json!({ "email": "notify-limit@example.com" }),
            Some(&access_token),
        )
        .await;
        assert_eq!(cooldown_response.status(), StatusCode::TOO_MANY_REQUESTS);

        for attempt in 1..=5 {
            let response = request_on(
                app.clone(),
                "POST",
                "/api/v1/user/notify-email/verify",
                json!({ "email": "notify-limit@example.com", "code": "000000" }),
                Some(&access_token),
            )
            .await;
            if attempt < 5 {
                assert_eq!(response.status(), StatusCode::BAD_REQUEST);
            } else {
                assert_eq!(response.status(), StatusCode::TOO_MANY_REQUESTS);
                let payload = json_body(response).await;
                assert!(payload["message"]
                    .as_str()
                    .unwrap()
                    .contains("VERIFY_CODE_MAX_ATTEMPTS"));
            }
        }

        for index in 0..3 {
            let now = 1_100 + index * 61;
            state.auth.set_now_for_tests(now);
            let email = format!("notify-{index}@example.com");
            let send_response = request_on(
                app.clone(),
                "POST",
                "/api/v1/user/notify-email/send-code",
                json!({ "email": email }),
                Some(&access_token),
            )
            .await;
            assert_eq!(send_response.status(), StatusCode::OK);
            let code = state.auth.notify_code_for_tests(&email).unwrap();
            let verify_response = request_on(
                app.clone(),
                "POST",
                "/api/v1/user/notify-email/verify",
                json!({ "email": email, "code": code }),
                Some(&access_token),
            )
            .await;
            assert_eq!(verify_response.status(), StatusCode::OK);
        }

        state.auth.set_now_for_tests(1_400);
        let fourth_send = request_on(
            app.clone(),
            "POST",
            "/api/v1/user/notify-email/send-code",
            json!({ "email": "notify-3@example.com" }),
            Some(&access_token),
        )
        .await;
        assert_eq!(fourth_send.status(), StatusCode::OK);
        let fourth_code = state
            .auth
            .notify_code_for_tests("notify-3@example.com")
            .unwrap();
        let too_many_response = request_on(
            app.clone(),
            "POST",
            "/api/v1/user/notify-email/verify",
            json!({ "email": "notify-3@example.com", "code": fourth_code }),
            Some(&access_token),
        )
        .await;
        assert_eq!(too_many_response.status(), StatusCode::BAD_REQUEST);
        let too_many_payload = json_body(too_many_response).await;
        assert!(too_many_payload["message"]
            .as_str()
            .unwrap()
            .contains("TOO_MANY_NOTIFY_EMAILS"));

        let missing_toggle = request_on(
            app.clone(),
            "PUT",
            "/api/v1/user/notify-email/toggle",
            json!({ "email": "missing@example.com", "disabled": true }),
            Some(&access_token),
        )
        .await;
        assert_eq!(missing_toggle.status(), StatusCode::BAD_REQUEST);

        let missing_remove = request_on(
            app,
            "DELETE",
            "/api/v1/user/notify-email",
            json!({ "email": "missing@example.com" }),
            Some(&access_token),
        )
        .await;
        assert_eq!(missing_remove.status(), StatusCode::BAD_REQUEST);
        smtp_shutdown.send(()).ok();
        assert!(smtp_log.lock().unwrap().iter().any(|line| line == "DATA"));
    }

