    #[tokio::test]
    async fn registered_gateway_routes_are_recognized() {
        let unauthorized = request_on(
            app(),
            "POST",
            "/v1/chat/completions",
            json!({ "model": "gpt-5.4", "messages": [] }),
            None,
        )
        .await;
        assert_eq!(unauthorized.status(), StatusCode::UNAUTHORIZED);
        let unauthorized_payload = json_body(unauthorized).await;
        assert_eq!(
            unauthorized_payload["error"]["message"],
            "API key is required in Authorization header (Bearer scheme), x-api-key header, or x-goog-api-key header"
        );

        let app = app();
        let token = "sk-dev-admin";

        let responses_response = request_on(
            app.clone(),
            "POST",
            "/backend-api/codex/responses/compact",
            json!({ "model": "gpt-5.4", "input": "hello" }),
            Some(token),
        )
        .await;
        assert_eq!(responses_response.status(), StatusCode::SERVICE_UNAVAILABLE);
        let responses_payload = json_body(responses_response).await;
        assert_eq!(
            responses_payload["error"]["message"],
            "OpenAI Responses upstream is not configured"
        );

        let chat_response = request_on(
            app.clone(),
            "POST",
            "/v1/chat/completions",
            json!({
                "model": "gpt-5.4",
                "messages": [{ "role": "user", "content": "hello" }]
            }),
            Some(token),
        )
        .await;
        assert_eq!(chat_response.status(), StatusCode::SERVICE_UNAVAILABLE);
        let chat_payload = json_body(chat_response).await;
        assert_eq!(
            chat_payload["error"]["message"],
            "OpenAI Chat Completions upstream is not configured"
        );

        let chat_stream_response = request_on(
            app.clone(),
            "POST",
            "/v1/chat/completions",
            json!({
                "model": "gpt-5.4",
                "stream": true,
                "messages": [{ "role": "user", "content": "hello" }]
            }),
            Some(token),
        )
        .await;
        assert_eq!(
            chat_stream_response.status(),
            StatusCode::SERVICE_UNAVAILABLE
        );

        let anthropic_response = request_on(
            app.clone(),
            "POST",
            "/v1/messages",
            json!({
                "model": "claude-sonnet-4-6",
                "messages": [{ "role": "user", "content": "hello" }]
            }),
            Some(token),
        )
        .await;
        assert_eq!(anthropic_response.status(), StatusCode::SERVICE_UNAVAILABLE);
        let anthropic_payload = json_body(anthropic_response).await;
        assert_eq!(anthropic_payload["type"], "error");

        let gemini_response = request_on(
            app.clone(),
            "POST",
            "/v1beta/models/gemini-pro:streamGenerateContent",
            json!({ "contents": [{ "parts": [{ "text": "hello" }] }] }),
            Some(token),
        )
        .await;
        assert_eq!(gemini_response.status(), StatusCode::SERVICE_UNAVAILABLE);
        let gemini_payload = json_body(gemini_response).await;
        assert_eq!(
            gemini_payload["error"]["message"],
            "Gemini GenerateContent upstream is not configured"
        );

        let gemini_model_response = request_with_body(
            app.clone(),
            "GET",
            "/v1beta/models/gemini-pro",
            Body::empty(),
            Some(token),
        )
        .await;
        assert_eq!(gemini_model_response.status(), StatusCode::OK);

        let antigravity_gemini_model_response = request_with_body(
            app.clone(),
            "GET",
            "/antigravity/v1beta/models/gemini-pro",
            Body::empty(),
            Some(token),
        )
        .await;
        assert_eq!(
            antigravity_gemini_model_response.status(),
            StatusCode::SERVICE_UNAVAILABLE
        );
        let antigravity_gemini_model_payload = json_body(antigravity_gemini_model_response).await;
        assert!(antigravity_gemini_model_payload["error"]["message"]
            .as_str()
            .unwrap()
            .contains("gemini_generate_content"));

        let models_response =
            request_with_body(app, "GET", "/v1/models", Body::empty(), Some(token)).await;
        assert_eq!(models_response.status(), StatusCode::OK);
        let models_payload = json_body(models_response).await;
        assert_eq!(models_payload["object"], "list");
        assert!(models_payload["data"].as_array().unwrap().len() >= 4);
    }

    #[tokio::test]
    async fn gateway_auth_matches_openai_and_google_entrypoints() {
        let app = app();

        let openai_query_key_response = request_on(
            app.clone(),
            "POST",
            "/v1/chat/completions?key=sk-dev-admin",
            json!({
                "model": "gpt-5.4",
                "messages": [{ "role": "user", "content": "hello" }]
            }),
            None,
        )
        .await;
        assert_eq!(openai_query_key_response.status(), StatusCode::BAD_REQUEST);
        let openai_query_key_payload = json_body(openai_query_key_response).await;
        assert_eq!(
            openai_query_key_payload["error"]["message"],
            "API key in query parameter is deprecated. Please use Authorization header instead."
        );

        let x_api_key_response = request_with_headers(
            app.clone(),
            "POST",
            "/v1/chat/completions",
            Body::from(
                json!({
                    "model": "gpt-5.4",
                    "messages": [{ "role": "user", "content": "hello" }]
                })
                .to_string(),
            ),
            &[("x-api-key", "sk-dev-admin")],
        )
        .await;
        assert_eq!(x_api_key_response.status(), StatusCode::SERVICE_UNAVAILABLE);
        let x_api_key_payload = json_body(x_api_key_response).await;
        assert_eq!(
            x_api_key_payload["error"]["message"],
            "OpenAI Chat Completions upstream is not configured"
        );

        let google_missing_response = request_on(
            app.clone(),
            "POST",
            "/v1beta/models/gemini-pro:generateContent",
            json!({ "contents": [{ "parts": [{ "text": "hello" }] }] }),
            None,
        )
        .await;
        assert_eq!(google_missing_response.status(), StatusCode::UNAUTHORIZED);
        let google_missing_payload = json_body(google_missing_response).await;
        assert_eq!(
            google_missing_payload["error"]["message"],
            "API key is required"
        );
        assert_eq!(google_missing_payload["error"]["status"], "UNAUTHENTICATED");

        let google_query_key_response = request_on(
            app.clone(),
            "POST",
            "/v1beta/models/gemini-pro:generateContent?key=sk-dev-admin",
            json!({ "contents": [{ "parts": [{ "text": "hello" }] }] }),
            None,
        )
        .await;
        assert_eq!(
            google_query_key_response.status(),
            StatusCode::SERVICE_UNAVAILABLE
        );
        let google_query_key_payload = json_body(google_query_key_response).await;
        assert_eq!(
            google_query_key_payload["error"]["message"],
            "Gemini GenerateContent upstream is not configured"
        );

        let google_api_key_response = request_on(
            app.clone(),
            "POST",
            "/v1beta/models/gemini-pro:generateContent?api_key=sk-dev-admin",
            json!({ "contents": [{ "parts": [{ "text": "hello" }] }] }),
            None,
        )
        .await;
        assert_eq!(google_api_key_response.status(), StatusCode::BAD_REQUEST);
        let google_api_key_payload = json_body(google_api_key_response).await;
        assert_eq!(
            google_api_key_payload["error"]["message"],
            "Query parameter api_key is deprecated. Use Authorization header or key instead."
        );
        assert_eq!(
            google_api_key_payload["error"]["status"],
            "INVALID_ARGUMENT"
        );

        let google_precedence_response = request_with_headers(
            app,
            "POST",
            "/v1beta/models/gemini-pro:generateContent",
            Body::from(json!({ "contents": [{ "parts": [{ "text": "hello" }] }] }).to_string()),
            &[
                ("authorization", "Bearer invalid-key"),
                ("x-goog-api-key", "sk-dev-admin"),
            ],
        )
        .await;
        assert_eq!(
            google_precedence_response.status(),
            StatusCode::SERVICE_UNAVAILABLE
        );
    }

