    #[tokio::test]
    async fn responses_websocket_passthrough_forwards_headers_and_frames() {
        let seen = Arc::new(Mutex::new(Vec::<Value>::new()));
        let seen_for_handler = seen.clone();
        let upstream = Router::new().route(
            "/v1/responses",
            get(move |headers: HeaderMap, ws: WebSocketUpgrade| {
                let seen = seen_for_handler.clone();
                async move {
                    let auth = headers
                        .get("authorization")
                        .and_then(|value| value.to_str().ok())
                        .unwrap_or_default()
                        .to_owned();
                    let beta = headers
                        .get("openai-beta")
                        .and_then(|value| value.to_str().ok())
                        .unwrap_or_default()
                        .to_owned();
                    ws.on_upgrade(move |mut socket| async move {
                        if let Some(Ok(message)) = socket.next().await {
                            let text = message.into_text().unwrap_or_default();
                            seen.lock().unwrap().push(json!({
                                "auth": auth,
                                "beta": beta,
                                "body": serde_json::from_str::<Value>(&text).unwrap()
                            }));
                            let _ = socket
                                .send(AxumWsMessage::Text(
                                    json!({
                                        "type": "response.completed",
                                        "response": { "id": "resp_ws" }
                                    })
                                    .to_string(),
                                ))
                                .await;
                        }
                    })
                }
            }),
        );
        let (upstream_base_url, upstream_shutdown) = spawn_test_ws_server(upstream).await;
        let state = AppState::demo();
        state
            .admin_portal
            .update_collection_item(
                "accounts",
                1,
                json!({
                    "upstream_protocol": "openai_responses",
                    "base_url": upstream_base_url,
                    "api_key": "upstream-secret",
                    "supported_protocols": ["openai_responses"]
                }),
            )
            .unwrap();
        let (gateway_base_url, gateway_shutdown) =
            spawn_test_ws_server(app_with_state(state)).await;
        let url = format!("{gateway_base_url}/v1/responses");
        let mut request = url.into_client_request().unwrap();
        request.headers_mut().insert(
            "authorization",
            HeaderValue::from_static("Bearer sk-dev-admin"),
        );
        let (mut client, _) = tokio_tungstenite::connect_async(request).await.unwrap();

        client
            .send(TungsteniteMessage::Text(
                json!({
                    "type": "response.create",
                    "model": "gpt-5.4",
                    "input": "hello"
                })
                .to_string(),
            ))
            .await
            .unwrap();
        let reply = client.next().await.unwrap().unwrap();

        gateway_shutdown.send(()).ok();
        upstream_shutdown.send(()).ok();

        let reply = reply.into_text().unwrap();
        assert!(reply.contains("response.completed"));
        let seen = seen.lock().unwrap();
        assert_eq!(seen.len(), 1);
        assert_eq!(seen[0]["auth"], "Bearer upstream-secret");
        assert_eq!(seen[0]["beta"], "responses_websockets=2026-02-06");
        assert_eq!(seen[0]["body"]["model"], "gpt-5.4");
    }

