    #[tokio::test]
    async fn anthropic_messages_stream_forwards_upstream_sse() {
        let upstream = Router::new().route(
            "/v1/messages",
            post(|headers: HeaderMap, Json(body): Json<Value>| async move {
                assert_eq!(
                    headers
                        .get("accept")
                        .and_then(|value| value.to_str().ok()),
                    Some("text/event-stream")
                );
                assert_eq!(body["model"], "claude-stream-upstream");
                assert_eq!(body["stream"], true);
                (
                    [(CONTENT_TYPE, HeaderValue::from_static("text/event-stream"))],
                    Body::from(
                        "event: message_start\n\
                         data: {\"type\":\"message_start\",\"message\":{\"id\":\"msg_stream\",\"type\":\"message\",\"role\":\"assistant\",\"content\":[],\"model\":\"claude-stream-upstream\"}}\n\n\
                         event: content_block_delta\n\
                         data: {\"type\":\"content_block_delta\",\"index\":0,\"delta\":{\"type\":\"text_delta\",\"text\":\"anthropic stream\"}}\n\n",
                    ),
                )
            }),
        );
        let (base_url, shutdown) = spawn_test_server(upstream).await;
        let state = AppState::demo();
        state
            .admin_portal
            .update_collection_item(
                "accounts",
                1,
                json!({
                    "provider": "anthropic",
                    "platform": "anthropic",
                    "upstream_protocol": "anthropic_messages",
                    "base_url": base_url,
                    "api_key": "anthropic-secret",
                    "model_mapping": {
                        "claude-sonnet-4-6": "claude-stream-upstream"
                    },
                    "supported_protocols": ["anthropic_messages"]
                }),
            )
            .unwrap();

        let response = request_on(
            app_with_state(state),
            "POST",
            "/v1/messages",
            json!({
                "model": "claude-sonnet-4-6",
                "stream": true,
                "max_tokens": 128,
                "messages": [{ "role": "user", "content": "stream" }]
            }),
            Some("sk-dev-admin"),
        )
        .await;

        shutdown.send(()).ok();
        assert_eq!(response.status(), StatusCode::OK);
        assert_eq!(
            response
                .headers()
                .get(http::header::CONTENT_TYPE)
                .unwrap()
                .to_str()
                .unwrap(),
            "text/event-stream"
        );
        let body = body_text(response).await;
        assert!(body.contains("event: message_start"));
        assert!(body.contains("anthropic stream"));
        assert!(!body.contains("backend_next gateway routed response"));
    }

