    #[tokio::test]
    async fn openai_image_edits_forwards_multipart_body_and_content_type() {
        let upstream = Router::new().route(
            "/v1/images/edits",
            post(|headers: HeaderMap, body: Bytes| async move {
                assert_eq!(
                    headers
                        .get("authorization")
                        .and_then(|value| value.to_str().ok()),
                    Some("Bearer images-secret")
                );
                assert!(headers
                    .get("content-type")
                    .and_then(|value| value.to_str().ok())
                    .unwrap()
                    .starts_with("multipart/form-data; boundary=test-boundary"));
                let body_text = String::from_utf8(body.to_vec()).unwrap();
                assert!(body_text.contains("gpt-image-1"));
                assert!(body_text.contains("fake-image-bytes"));
                Json(json!({
                    "created": 123,
                    "data": [{
                        "b64_json": "ZmFrZS1pbWFnZQ=="
                    }]
                }))
            }),
        );
        let (base_url, shutdown) = spawn_test_server(upstream).await;
        let state = AppState::demo();
        state
            .admin_portal
            .update_collection_item(
                "accounts",
                1,
                json!({
                    "provider": "openai",
                    "platform": "openai",
                    "upstream_protocol": "openai_responses",
                    "base_url": base_url,
                    "api_key": "images-secret",
                    "model_mapping": {
                        "gpt-image-1": "image-upstream"
                    },
                    "supported_protocols": ["openai_images"]
                }),
            )
            .unwrap();

        let multipart_body = "--test-boundary\r\n\
Content-Disposition: form-data; name=\"model\"\r\n\r\n\
gpt-image-1\r\n\
--test-boundary\r\n\
Content-Disposition: form-data; name=\"image\"; filename=\"image.png\"\r\n\
Content-Type: image/png\r\n\r\n\
fake-image-bytes\r\n\
--test-boundary--\r\n";
        let response = request_with_headers(
            app_with_state(state),
            "POST",
            "/v1/images/edits",
            Body::from(multipart_body),
            &[
                ("authorization", "Bearer sk-dev-admin"),
                (
                    "content-type",
                    "multipart/form-data; boundary=test-boundary",
                ),
            ],
        )
        .await;

        shutdown.send(()).ok();
        assert_eq!(response.status(), StatusCode::OK);
        let payload = json_body(response).await;
        assert_eq!(payload["data"][0]["b64_json"], "ZmFrZS1pbWFnZQ==");
    }

