    #[tokio::test]
    async fn antigravity_routes_only_select_antigravity_accounts() {
        let state = AppState::demo();
        state
            .admin_portal
            .update_collection_item(
                "accounts",
                1,
                json!({
                    "provider": "openai",
                    "platform": "openai",
                    "supported_protocols": ["anthropic_messages"]
                }),
            )
            .unwrap();

        let no_antigravity_response = request_on(
            app_with_state(state.clone()),
            "POST",
            "/antigravity/v1/messages",
            json!({
                "model": "claude-sonnet-4-6",
                "messages": [{ "role": "user", "content": "hello" }]
            }),
            Some("sk-dev-admin"),
        )
        .await;
        assert_eq!(
            no_antigravity_response.status(),
            StatusCode::SERVICE_UNAVAILABLE
        );
        let no_antigravity_payload = json_body(no_antigravity_response).await;
        assert_eq!(no_antigravity_payload["type"], "error");

        let upstream = Router::new().route(
            "/v1/messages",
            post(|headers: HeaderMap, Json(body): Json<Value>| async move {
                assert_eq!(
                    headers
                        .get("x-api-key")
                        .and_then(|value| value.to_str().ok()),
                    Some("antigravity-secret")
                );
                assert_eq!(body["model"], "claude-sonnet-4-6");
                Json(json!({
                    "id": "msg_antigravity",
                    "type": "message",
                    "role": "assistant",
                    "model": body["model"],
                    "content": [{ "type": "text", "text": "from antigravity upstream" }],
                    "stop_reason": "end_turn",
                    "usage": { "input_tokens": 5, "output_tokens": 3 }
                }))
            }),
        );
        let (base_url, shutdown) = spawn_test_server(upstream).await;

        state
            .admin_portal
            .update_collection_item(
                "accounts",
                2,
                json!({
                    "name": "Antigravity account",
                    "provider": "antigravity",
                    "platform": "antigravity",
                    "group_id": 1,
                    "status": "active",
                    "supported_protocols": ["anthropic_messages"],
                    "upstream_protocol": "anthropic_messages",
                    "base_url": base_url,
                    "api_key": "antigravity-secret",
                    "priority": 1
                }),
            )
            .unwrap();

        let antigravity_response = request_on(
            app_with_state(state),
            "POST",
            "/antigravity/v1/messages",
            json!({
                "model": "claude-sonnet-4-6",
                "messages": [{ "role": "user", "content": "hello" }]
            }),
            Some("sk-dev-admin"),
        )
        .await;
        shutdown.send(()).ok();
        assert_eq!(antigravity_response.status(), StatusCode::OK);
        let antigravity_payload = json_body(antigravity_response).await;
        assert_eq!(
            antigravity_payload["content"][0]["text"],
            "from antigravity upstream"
        );
    }

