    #[tokio::test]
    async fn gateway_selects_repository_account_bindings_before_admin_portal_fallback() {
        let upstream = Router::new().route(
            "/v1/chat/completions",
            post(|headers: HeaderMap, Json(body): Json<Value>| async move {
                assert_eq!(
                    headers
                        .get("authorization")
                        .and_then(|value| value.to_str().ok()),
                    Some("Bearer repository-secret")
                );
                assert_eq!(body["model"], "deepseek-v4-pro");
                Json(json!({
                    "id": "chatcmpl_repository",
                    "object": "chat.completion",
                    "model": body["model"],
                    "choices": [{
                        "index": 0,
                        "message": {
                            "role": "assistant",
                            "content": "from repository account"
                        },
                        "finish_reason": "stop"
                    }],
                    "usage": {
                        "prompt_tokens": 10,
                        "completion_tokens": 5,
                        "total_tokens": 15
                    }
                }))
            }),
        );
        let (base_url, shutdown) = spawn_test_server(upstream).await;
        let state = AppState::demo();
        state
            .repository
            .upsert_group(Group {
                id: GroupId(1),
                name: "Repository group".to_owned(),
                status: GroupStatus::Active,
            })
            .await
            .unwrap();
        state
            .repository
            .upsert_user(repository::UserRecord {
                id: 88,
                email: "repository-key@example.com".to_owned(),
                username: "repository-key-user".to_owned(),
                role: "user".to_owned(),
                status: "active".to_owned(),
            })
            .await
            .unwrap();
        state
            .repository
            .upsert_api_key(ApiKey {
                id: ApiKeyId(880),
                user_id: 88,
                key: "sk-repository-only".to_owned(),
                name: "repository only key".to_owned(),
                group_id: Some(GroupId(1)),
                status: domain::ApiKeyStatus::Active,
                quota: 1.0,
                rate_limit_5h: 1.0,
                rate_limit_1d: 2.0,
                rate_limit_7d: 3.0,
                ..ApiKey::default()
            })
            .await
            .unwrap();
        state
            .admin_portal
            .update_collection_item(
                "channels",
                1,
                json!({
                    "status": "active",
                    "group_ids": [1],
                    "model_pricing": [{
                        "model": "deepseek-v4-pro",
                        "input_price": 0.01,
                        "output_price": 0.02
                    }]
                }),
            )
            .unwrap();
        let account = Account {
            id: AccountId(501),
            name: "repository-deepseek".to_owned(),
            provider: Provider::DeepSeek,
            default_upstream_protocol: UpstreamProtocol::OpenAiChatCompletions,
            base_url: Some(base_url),
            api_key: Some("repository-secret".to_owned()),
            model_mapping: vec![ModelMappingRule {
                source: "gpt-5.4".to_owned(),
                target: "deepseek-v4-pro".to_owned(),
            }],
            extra: json!({}),
            enabled: true,
        };
        state
            .repository
            .upsert_account(account.clone())
            .await
            .unwrap();
        state
            .repository
            .bind_account_to_group(AccountGroupBinding {
                account,
                group_id: GroupId(1),
                supported_downstream_protocols: vec![
                    protocol::DownstreamProtocol::OpenAiChatCompletions,
                ],
                upstream_protocol_override: Some(UpstreamProtocol::OpenAiChatCompletions),
                priority: 1,
            })
            .await
            .unwrap();

        let response = request_on(
            app_with_state(state.clone()),
            "POST",
            "/v1/chat/completions",
            json!({
                "model": "gpt-5.4",
                "messages": [{ "role": "user", "content": "hello" }]
            }),
            Some("sk-repository-only"),
        )
        .await;

        shutdown.send(()).ok();
        assert_eq!(response.status(), StatusCode::OK);
        let payload = json_body(response).await;
        assert_eq!(payload["id"], "chatcmpl_repository");
        assert_eq!(
            payload["choices"][0]["message"]["content"],
            "from repository account"
        );
        assert!(state
            .auth
            .validate_gateway_api_key("sk-repository-only")
            .is_err());
        let persisted_key = state.repository.get_api_key(ApiKeyId(880)).await.unwrap();
        assert!((persisted_key.quota_used - 0.2).abs() < 0.000_000_1);
        assert!((persisted_key.usage_5h - 0.2).abs() < 0.000_000_1);
        assert!(persisted_key.window_5h_start.is_some());
    }

    #[tokio::test]
    async fn openai_chat_completions_failover_retries_5xx_with_next_account() {
        let failing_calls = Arc::new(AtomicUsize::new(0));
        let failing_call_count = failing_calls.clone();
        let failing_upstream = Router::new().route(
            "/v1/chat/completions",
            post(move || {
                let failing_call_count = failing_call_count.clone();
                async move {
                    failing_call_count.fetch_add(1, Ordering::SeqCst);
                    (
                        StatusCode::BAD_GATEWAY,
                        Json(json!({
                            "error": {
                                "message": "temporary upstream failure"
                            }
                        })),
                    )
                }
            }),
        );
        let successful_calls = Arc::new(AtomicUsize::new(0));
        let successful_call_count = successful_calls.clone();
        let successful_upstream = Router::new().route(
            "/v1/chat/completions",
            post(move |headers: HeaderMap, Json(body): Json<Value>| {
                let successful_call_count = successful_call_count.clone();
                async move {
                    successful_call_count.fetch_add(1, Ordering::SeqCst);
                    assert_eq!(
                        headers
                            .get("authorization")
                            .and_then(|value| value.to_str().ok()),
                        Some("Bearer second-secret")
                    );
                    assert_eq!(body["model"], "deepseek-second");
                    Json(json!({
                        "id": "chatcmpl_failover",
                        "object": "chat.completion",
                        "model": body["model"],
                        "choices": [{
                            "index": 0,
                            "message": {
                                "role": "assistant",
                                "content": "from second account"
                            },
                            "finish_reason": "stop"
                        }]
                    }))
                }
            }),
        );
        let (failing_base_url, failing_shutdown) = spawn_test_server(failing_upstream).await;
        let (successful_base_url, successful_shutdown) =
            spawn_test_server(successful_upstream).await;
        let state = AppState::demo();
        bind_test_account(
            &state,
            601,
            Provider::DeepSeek,
            UpstreamProtocol::OpenAiChatCompletions,
            failing_base_url,
            "first-secret",
            vec![protocol::DownstreamProtocol::OpenAiChatCompletions],
            1,
            vec![ModelMappingRule {
                source: "gpt-5.4".to_owned(),
                target: "deepseek-first".to_owned(),
            }],
        )
        .await;
        bind_test_account(
            &state,
            602,
            Provider::DeepSeek,
            UpstreamProtocol::OpenAiChatCompletions,
            successful_base_url,
            "second-secret",
            vec![protocol::DownstreamProtocol::OpenAiChatCompletions],
            2,
            vec![ModelMappingRule {
                source: "gpt-5.4".to_owned(),
                target: "deepseek-second".to_owned(),
            }],
        )
        .await;

        let response = request_on(
            app_with_state(state),
            "POST",
            "/v1/chat/completions",
            json!({
                "model": "gpt-5.4",
                "messages": [{ "role": "user", "content": "hello" }]
            }),
            Some("sk-dev-admin"),
        )
        .await;

        failing_shutdown.send(()).ok();
        successful_shutdown.send(()).ok();
        assert_eq!(response.status(), StatusCode::OK);
        let payload = json_body(response).await;
        assert_eq!(payload["id"], "chatcmpl_failover");
        assert_eq!(
            payload["choices"][0]["message"]["content"],
            "from second account"
        );
        assert_eq!(failing_calls.load(Ordering::SeqCst), 1);
        assert_eq!(successful_calls.load(Ordering::SeqCst), 1);
    }

