    #[tokio::test]
    async fn openai_responses_chat_bridge_failover_pins_followup_to_successful_account() {
        let failing_calls = Arc::new(AtomicUsize::new(0));
        let failing_call_count = failing_calls.clone();
        let failing_upstream = Router::new().route(
            "/v1/chat/completions",
            post(move || {
                let failing_call_count = failing_call_count.clone();
                async move {
                    failing_call_count.fetch_add(1, Ordering::SeqCst);
                    (
                        StatusCode::SERVICE_UNAVAILABLE,
                        Json(json!({
                            "error": {
                                "message": "first bridge account unavailable"
                            }
                        })),
                    )
                }
            }),
        );
        let successful_calls = Arc::new(AtomicUsize::new(0));
        let successful_call_count = successful_calls.clone();
        let successful_upstream = Router::new().route(
            "/v1/chat/completions",
            post(move |headers: HeaderMap, Json(body): Json<Value>| {
                let successful_call_count = successful_call_count.clone();
                async move {
                    assert_eq!(
                        headers
                            .get("authorization")
                            .and_then(|value| value.to_str().ok()),
                        Some("Bearer bridge-second-secret")
                    );
                    assert_eq!(body["model"], "deepseek-bridge-second");
                    let call_index = successful_call_count.fetch_add(1, Ordering::SeqCst);
                    if call_index == 0 {
                        assert_eq!(body["messages"][0]["content"], "first bridge question");
                        Json(json!({
                            "id": "chatcmpl_bridge_first",
                            "object": "chat.completion",
                            "model": body["model"],
                            "choices": [{
                                "index": 0,
                                "message": {
                                    "role": "assistant",
                                    "content": "first bridge answer"
                                },
                                "finish_reason": "stop"
                            }]
                        }))
                    } else {
                        let messages = body["messages"].as_array().unwrap();
                        assert!(messages.iter().any(|message| {
                            message["role"] == "assistant"
                                && message["content"] == "first bridge answer"
                        }));
                        assert_eq!(
                            messages.last().unwrap()["content"],
                            "second bridge question"
                        );
                        Json(json!({
                            "id": "chatcmpl_bridge_second",
                            "object": "chat.completion",
                            "model": body["model"],
                            "choices": [{
                                "index": 0,
                                "message": {
                                    "role": "assistant",
                                    "content": "second bridge answer"
                                },
                                "finish_reason": "stop"
                            }]
                        }))
                    }
                }
            }),
        );
        let (failing_base_url, failing_shutdown) = spawn_test_server(failing_upstream).await;
        let (successful_base_url, successful_shutdown) =
            spawn_test_server(successful_upstream).await;
        let state = AppState::demo();
        bind_test_account(
            &state,
            701,
            Provider::DeepSeek,
            UpstreamProtocol::OpenAiChatCompletions,
            failing_base_url,
            "bridge-first-secret",
            vec![protocol::DownstreamProtocol::OpenAiResponses],
            1,
            vec![ModelMappingRule {
                source: "gpt-5.4".to_owned(),
                target: "deepseek-bridge-first".to_owned(),
            }],
        )
        .await;
        bind_test_account(
            &state,
            702,
            Provider::DeepSeek,
            UpstreamProtocol::OpenAiChatCompletions,
            successful_base_url,
            "bridge-second-secret",
            vec![protocol::DownstreamProtocol::OpenAiResponses],
            2,
            vec![ModelMappingRule {
                source: "gpt-5.4".to_owned(),
                target: "deepseek-bridge-second".to_owned(),
            }],
        )
        .await;
        let app = app_with_state(state);

        let first_response = request_on(
            app.clone(),
            "POST",
            "/v1/responses",
            json!({
                "model": "gpt-5.4",
                "input": "first bridge question"
            }),
            Some("sk-dev-admin"),
        )
        .await;
        assert_eq!(first_response.status(), StatusCode::OK);
        let first_payload = json_body(first_response).await;
        let previous_response_id = first_payload["id"].as_str().unwrap().to_owned();

        let second_response = request_on(
            app,
            "POST",
            "/v1/responses",
            json!({
                "model": "gpt-5.4",
                "previous_response_id": previous_response_id,
                "input": "second bridge question"
            }),
            Some("sk-dev-admin"),
        )
        .await;

        failing_shutdown.send(()).ok();
        successful_shutdown.send(()).ok();
        assert_eq!(second_response.status(), StatusCode::OK);
        let second_payload = json_body(second_response).await;
        assert_eq!(
            second_payload["output"][0]["content"][0]["text"],
            "second bridge answer"
        );
        assert_eq!(failing_calls.load(Ordering::SeqCst), 1);
        assert_eq!(successful_calls.load(Ordering::SeqCst), 2);
    }

