    #[tokio::test]
    async fn openai_responses_chat_bridge_reuses_previous_response_history() {
        let call_count = Arc::new(AtomicUsize::new(0));
        let upstream_call_count = call_count.clone();
        let upstream = Router::new().route(
            "/v1/chat/completions",
            post(move |Json(body): Json<Value>| {
                let upstream_call_count = upstream_call_count.clone();
                async move {
                    let call_index = upstream_call_count.fetch_add(1, Ordering::SeqCst);
                    assert_eq!(body["model"], "deepseek-state-model");
                    if call_index == 0 {
                        assert_eq!(body["messages"].as_array().unwrap().len(), 1);
                        assert_eq!(body["messages"][0]["role"], "user");
                        assert_eq!(body["messages"][0]["content"], "first question");
                        Json(json!({
                            "id": "chatcmpl_state_first",
                            "object": "chat.completion",
                            "model": body["model"],
                            "choices": [{
                                "index": 0,
                                "message": {
                                    "role": "assistant",
                                    "content": "first answer"
                                },
                                "finish_reason": "stop"
                            }]
                        }))
                    } else {
                        assert_eq!(body["messages"].as_array().unwrap().len(), 3);
                        assert_eq!(body["messages"][0]["role"], "user");
                        assert_eq!(body["messages"][0]["content"], "first question");
                        assert_eq!(body["messages"][1]["role"], "assistant");
                        assert_eq!(body["messages"][1]["content"], "first answer");
                        assert_eq!(body["messages"][2]["role"], "user");
                        assert_eq!(body["messages"][2]["content"], "second question");
                        Json(json!({
                            "id": "chatcmpl_state_second",
                            "object": "chat.completion",
                            "model": body["model"],
                            "choices": [{
                                "index": 0,
                                "message": {
                                    "role": "assistant",
                                    "content": "second answer"
                                },
                                "finish_reason": "stop"
                            }]
                        }))
                    }
                }
            }),
        );
        let (base_url, shutdown) = spawn_test_server(upstream).await;
        let state = AppState::demo();
        state
            .admin_portal
            .update_collection_item(
                "accounts",
                1,
                json!({
                    "provider": "deepseek",
                    "platform": "deepseek",
                    "upstream_protocol": "openai_chat_completions",
                    "base_url": base_url,
                    "api_key": "upstream-secret",
                    "model_mapping": {
                        "gpt-5.4": "deepseek-state-model"
                    },
                    "supported_protocols": ["openai_responses"]
                }),
            )
            .unwrap();
        let app = app_with_state(state);

        let first_response = request_on(
            app.clone(),
            "POST",
            "/v1/responses",
            json!({
                "model": "gpt-5.4",
                "input": "first question"
            }),
            Some("sk-dev-admin"),
        )
        .await;
        assert_eq!(first_response.status(), StatusCode::OK);
        let first_payload = json_body(first_response).await;
        let previous_response_id = first_payload["id"].as_str().unwrap().to_owned();

        let second_response = request_on(
            app,
            "POST",
            "/v1/responses",
            json!({
                "model": "gpt-5.4",
                "previous_response_id": previous_response_id,
                "input": "second question"
            }),
            Some("sk-dev-admin"),
        )
        .await;

        shutdown.send(()).ok();
        assert_eq!(second_response.status(), StatusCode::OK);
        let second_payload = json_body(second_response).await;
        assert_eq!(
            second_payload["output"][0]["content"][0]["text"],
            "second answer"
        );
        assert_eq!(call_count.load(Ordering::SeqCst), 2);
    }

    #[tokio::test]
    async fn openai_responses_chat_bridge_compacts_history_with_llm() {
        let call_count = Arc::new(AtomicUsize::new(0));
        let upstream_call_count = call_count.clone();
        let upstream = Router::new().route(
            "/v1/chat/completions",
            post(move |Json(body): Json<Value>| {
                let upstream_call_count = upstream_call_count.clone();
                async move {
                    let call_index = upstream_call_count.fetch_add(1, Ordering::SeqCst);
                    match call_index {
                        0 => {
                            assert_eq!(body["model"], "deepseek-main");
                            Json(json!({
                                "id": "chatcmpl_long_history",
                                "object": "chat.completion",
                                "model": body["model"],
                                "choices": [{
                                    "index": 0,
                                    "message": {
                                        "role": "assistant",
                                        "content": format!("old assistant answer with very long retained payload {}", "y".repeat(600))
                                    },
                                    "finish_reason": "stop"
                                }]
                            }))
                        }
                        1 => {
                            assert_eq!(body["model"], "deepseek-summary");
                            assert!(
                                body["messages"][1]["content"]
                                    .as_str()
                                    .unwrap()
                                    .contains("old assistant answer with very long retained payload")
                            );
                            Json(json!({
                                "id": "chatcmpl_summary",
                                "object": "chat.completion",
                                "model": body["model"],
                                "choices": [{
                                    "index": 0,
                                    "message": {
                                        "role": "assistant",
                                        "content": "summary of the early long exchange"
                                    },
                                    "finish_reason": "stop"
                                }]
                            }))
                        }
                        _ => {
                            assert_eq!(body["model"], "deepseek-main");
                            let messages = body["messages"].as_array().unwrap();
                            assert_eq!(messages[0]["role"], "system");
                            assert!(messages[0]["content"]
                                .as_str()
                                .unwrap()
                                .contains("summary of the early long exchange"));
                            assert!(
                                !body
                                    .to_string()
                                    .contains("very long first question repeated payload")
                            );
                            assert_eq!(messages.last().unwrap()["content"], "second question");
                            Json(json!({
                                "id": "chatcmpl_after_compaction",
                                "object": "chat.completion",
                                "model": body["model"],
                                "choices": [{
                                    "index": 0,
                                    "message": { "role": "assistant", "content": "answer after compaction" },
                                    "finish_reason": "stop"
                                }]
                            }))
                        }
                    }
                }
            }),
        );
        let (base_url, shutdown) = spawn_test_server(upstream).await;
        let first_input = "first question before compaction";
        let state = AppState::demo();
        state
            .admin_portal
            .update_collection_item(
                "accounts",
                1,
                json!({
                    "provider": "deepseek",
                    "platform": "deepseek",
                    "upstream_protocol": "openai_chat_completions",
                    "base_url": base_url,
                    "api_key": "upstream-secret",
                    "model_mapping": {
                        "gpt-5.4": "deepseek-main"
                    },
                    "supported_protocols": ["openai_responses"],
                    "extra": {
                        "openai_responses_chat_context_window_tokens": 150,
                        "openai_responses_chat_max_output_tokens": 20,
                        "openai_responses_chat_keep_recent_turns": 1,
                        "openai_responses_chat_compaction_model": "deepseek-summary"
                    }
                }),
            )
            .unwrap();
        let app = app_with_state(state);

        let first_response = request_on(
            app.clone(),
            "POST",
            "/v1/responses",
            json!({
                "model": "gpt-5.4",
                "input": first_input
            }),
            Some("sk-dev-admin"),
        )
        .await;
        assert_eq!(first_response.status(), StatusCode::OK);
        let first_payload = json_body(first_response).await;
        let previous_response_id = first_payload["id"].as_str().unwrap().to_owned();

        let second_response = request_on(
            app,
            "POST",
            "/v1/responses",
            json!({
                "model": "gpt-5.4",
                "previous_response_id": previous_response_id,
                "input": "second question"
            }),
            Some("sk-dev-admin"),
        )
        .await;

        shutdown.send(()).ok();
        assert_eq!(second_response.status(), StatusCode::OK);
        let second_payload = json_body(second_response).await;
        assert_eq!(
            second_payload["output"][0]["content"][0]["text"],
            "answer after compaction"
        );
        assert_eq!(call_count.load(Ordering::SeqCst), 3);
    }

    #[tokio::test]
    async fn openai_responses_chat_bridge_errors_when_llm_compaction_fails() {
        let call_count = Arc::new(AtomicUsize::new(0));
        let upstream_call_count = call_count.clone();
        let upstream = Router::new().route(
            "/v1/chat/completions",
            post(move |Json(body): Json<Value>| {
                let upstream_call_count = upstream_call_count.clone();
                async move {
                    let call_index = upstream_call_count.fetch_add(1, Ordering::SeqCst);
                    if call_index == 0 {
                        Json(json!({
                            "id": "chatcmpl_long_history_fail",
                            "object": "chat.completion",
                            "model": body["model"],
                            "choices": [{
                                "index": 0,
                                "message": { "role": "assistant", "content": "old answer" },
                                "finish_reason": "stop"
                            }]
                        }))
                        .into_response()
                    } else {
                        (
                            StatusCode::BAD_GATEWAY,
                            Json(json!({
                                "error": {
                                    "message": "summary failed"
                                }
                            })),
                        )
                            .into_response()
                    }
                }
            }),
        );
        let (base_url, shutdown) = spawn_test_server(upstream).await;
        let state = AppState::demo();
        state
            .admin_portal
            .update_collection_item(
                "accounts",
                1,
                json!({
                    "provider": "deepseek",
                    "platform": "deepseek",
                    "upstream_protocol": "openai_chat_completions",
                    "base_url": base_url,
                    "api_key": "upstream-secret",
                    "supported_protocols": ["openai_responses"],
                    "extra": {
                        "openai_responses_chat_context_window_tokens": 160,
                        "openai_responses_chat_max_output_tokens": 20,
                        "openai_responses_chat_keep_recent_turns": 1,
                        "openai_responses_chat_compaction_model": "deepseek-summary"
                    }
                }),
            )
            .unwrap();
        let app = app_with_state(state);
        let first_response = request_on(
            app.clone(),
            "POST",
            "/v1/responses",
            json!({
                "model": "gpt-5.4",
                "input": format!("very long first question {}", "x".repeat(600))
            }),
            Some("sk-dev-admin"),
        )
        .await;
        assert_eq!(first_response.status(), StatusCode::OK);
        let first_payload = json_body(first_response).await;
        let previous_response_id = first_payload["id"].as_str().unwrap().to_owned();

        let second_response = request_on(
            app,
            "POST",
            "/v1/responses",
            json!({
                "model": "gpt-5.4",
                "previous_response_id": previous_response_id,
                "input": "second question"
            }),
            Some("sk-dev-admin"),
        )
        .await;

        shutdown.send(()).ok();
        assert_eq!(second_response.status(), StatusCode::BAD_GATEWAY);
        let payload = json_body(second_response).await;
        assert!(payload["error"]["message"]
            .as_str()
            .unwrap()
            .contains("LLM compaction upstream returned"));
        assert_eq!(call_count.load(Ordering::SeqCst), 2);
    }

    #[tokio::test]
    async fn openai_responses_stream_converts_chat_sse_to_responses_sse() {
        let upstream = Router::new().route(
            "/v1/chat/completions",
            post(|Json(body): Json<Value>| async move {
                assert_eq!(body["model"], "deepseek-stream-responses");
                assert_eq!(body["stream"], true);
                assert_eq!(body["stream_options"]["include_usage"], true);
                (
                    [(CONTENT_TYPE, HeaderValue::from_static("text/event-stream"))],
                    Body::from(
                        "data: {\"id\":\"chatcmpl_rs\",\"object\":\"chat.completion.chunk\",\"model\":\"deepseek-stream-responses\",\"choices\":[{\"index\":0,\"delta\":{\"content\":\"hello\"},\"finish_reason\":null}]}\n\n\
                         data: {\"id\":\"chatcmpl_rs\",\"object\":\"chat.completion.chunk\",\"model\":\"deepseek-stream-responses\",\"choices\":[{\"index\":0,\"delta\":{\"content\":\" stream\"},\"finish_reason\":\"stop\"}],\"usage\":{\"prompt_tokens\":4,\"completion_tokens\":2,\"total_tokens\":6}}\n\n\
                         data: [DONE]\n\n",
                    ),
                )
            }),
        );
        let (base_url, shutdown) = spawn_test_server(upstream).await;
        let state = AppState::demo();
        state
            .admin_portal
            .update_collection_item(
                "accounts",
                1,
                json!({
                    "provider": "deepseek",
                    "platform": "deepseek",
                    "upstream_protocol": "openai_chat_completions",
                    "base_url": base_url,
                    "api_key": "upstream-secret",
                    "model_mapping": {
                        "gpt-5.4": "deepseek-stream-responses"
                    },
                    "supported_protocols": ["openai_responses"]
                }),
            )
            .unwrap();

        let response = request_on(
            app_with_state(state),
            "POST",
            "/v1/responses",
            json!({
                "model": "gpt-5.4",
                "stream": true,
                "input": "stream please"
            }),
            Some("sk-dev-admin"),
        )
        .await;

        shutdown.send(()).ok();
        assert_eq!(response.status(), StatusCode::OK);
        assert_eq!(
            response
                .headers()
                .get(http::header::CONTENT_TYPE)
                .unwrap()
                .to_str()
                .unwrap(),
            "text/event-stream"
        );
        let body = body_text(response).await;
        assert!(body.contains("event: response.created"));
        assert!(body.contains("event: response.output_text.delta"));
        assert!(body.contains("hello stream"));
        assert!(body.contains("event: response.completed"));
        assert!(body.contains("\"input_tokens\":4"));
        assert!(body.contains("data: [DONE]"));
        assert!(!body.contains("chat.completion.chunk"));
    }

