    #[tokio::test]
    async fn gateway_usage_reports_quota_limited_api_key_state() {
        let app = app();
        let access_token = login_seed_admin(app.clone()).await;
        let create_key_response = request_on(
            app.clone(),
            "POST",
            "/api/v1/keys",
            json!({
                "name": "Quota limited key",
                "custom_key": "sk-test-quota-usage",
                "group_id": 1,
                "quota": 12.5,
                "rate_limit_5h": 100,
                "rate_limit_1d": 200
            }),
            Some(&access_token),
        )
        .await;
        assert_eq!(create_key_response.status(), StatusCode::OK);

        let response = request_with_body(
            app,
            "GET",
            "/v1/usage",
            Body::empty(),
            Some("sk-test-quota-usage"),
        )
        .await;

        assert_eq!(response.status(), StatusCode::OK);
        let payload = json_body(response).await;
        assert_eq!(payload["mode"], "quota_limited");
        assert_eq!(payload["status"], "active");
        assert_eq!(payload["quota"]["limit"], 12.5);
        assert_eq!(payload["quota"]["used"], 0.0);
        assert_eq!(payload["quota"]["remaining"], 12.5);
        assert_eq!(payload["remaining"], 12.5);
        assert_eq!(payload["rate_limits"][0]["window"], "5h");
        assert_close(&payload["rate_limits"][0]["remaining"], 100.0);
        assert_eq!(payload["rate_limits"][1]["window"], "1d");
        assert_eq!(payload["usage"]["today"]["requests"], 0);
        assert!(payload["daily_usage"].as_array().unwrap().is_empty());
        assert!(payload["model_stats"].as_array().unwrap().is_empty());
    }

