    #[tokio::test]
    async fn advanced_auth_and_oauth_routes_match_frontend_contracts() {
        let state = AppState::demo();
        let (smtp_port, smtp_log, smtp_shutdown) = spawn_fake_smtp_server().await;
        configure_smtp_settings(&state, smtp_port).await;
        let app = app_with_state(state.clone());

        let login_response = request_on(
            app.clone(),
            "POST",
            "/api/v1/auth/login",
            json!({ "email": "admin@example.com", "password": "admin123" }),
            None,
        )
        .await;
        assert_eq!(login_response.status(), StatusCode::OK);
        let login_payload = json_body(login_response).await;
        let old_access_token = login_payload["data"]["access_token"]
            .as_str()
            .unwrap()
            .to_owned();
        assert_eq!(login_payload["data"]["user"]["role"], "admin");

        let send_code_response = request_on(
            app.clone(),
            "POST",
            "/api/v1/auth/send-verify-code",
            json!({ "email": "new@example.com" }),
            None,
        )
        .await;
        assert_eq!(send_code_response.status(), StatusCode::OK);
        let send_code_payload = json_body(send_code_response).await;
        assert_eq!(send_code_payload["data"]["countdown"], 60);

        let forgot_response = request_on(
            app.clone(),
            "POST",
            "/api/v1/auth/forgot-password",
            json!({ "email": "admin@example.com" }),
            None,
        )
        .await;
        assert_eq!(forgot_response.status(), StatusCode::OK);
        let forgot_payload = json_body(forgot_response).await;
        assert!(forgot_payload["data"]["message"]
            .as_str()
            .unwrap()
            .contains("password reset"));
        let reset_token = state
            .auth
            .password_reset_token_for_tests("admin@example.com")
            .expect("password reset token generated");
        let smtp_lines = smtp_log.lock().unwrap().clone();
        assert!(smtp_lines
            .iter()
            .any(|line| line.contains("reset-password?email=admin%40example.com")));

        let reset_response = request_on(
            app.clone(),
            "POST",
            "/api/v1/auth/reset-password",
            json!({
                "email": "admin@example.com",
                "token": reset_token,
                "new_password": "new-password"
            }),
            None,
        )
        .await;
        assert_eq!(reset_response.status(), StatusCode::OK);

        let old_password_login = request_on(
            app.clone(),
            "POST",
            "/api/v1/auth/login",
            json!({ "email": "admin@example.com", "password": "admin123" }),
            None,
        )
        .await;
        assert_eq!(old_password_login.status(), StatusCode::UNAUTHORIZED);

        let new_password_login = request_on(
            app.clone(),
            "POST",
            "/api/v1/auth/login",
            json!({ "email": "admin@example.com", "password": "new-password" }),
            None,
        )
        .await;
        assert_eq!(new_password_login.status(), StatusCode::OK);
        let new_password_login_payload = json_body(new_password_login).await;
        let access_token = new_password_login_payload["data"]["access_token"]
            .as_str()
            .unwrap()
            .to_owned();
        let reset_token_reuse_response = request_on(
            app.clone(),
            "POST",
            "/api/v1/auth/reset-password",
            json!({
                "email": "admin@example.com",
                "token": "already-consumed",
                "new_password": "newer-password"
            }),
            None,
        )
        .await;
        assert_eq!(reset_token_reuse_response.status(), StatusCode::BAD_REQUEST);

        let revoked_me_response = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/auth/me",
            Body::empty(),
            Some(&old_access_token),
        )
        .await;
        assert_eq!(revoked_me_response.status(), StatusCode::UNAUTHORIZED);

        let bind_token_response = request_with_body(
            app.clone(),
            "POST",
            "/api/v1/auth/oauth/bind-token",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(bind_token_response.status(), StatusCode::NO_CONTENT);
        let bind_cookie = bind_token_response
            .headers()
            .get(http::header::SET_COOKIE)
            .unwrap()
            .to_str()
            .unwrap();
        assert!(bind_cookie.starts_with("oauth_bind_access_token=bind-"));
        assert!(bind_cookie.contains("Path=/api/v1/auth/oauth"));
        assert!(bind_cookie.contains("HttpOnly"));
        assert!(bind_cookie.contains("SameSite=Lax"));

        for provider in ["linuxdo", "github", "google", "wechat", "oidc", "dingtalk"] {
            let oauth_start_response = request_with_body(
                app.clone(),
                "GET",
                &format!("/api/v1/auth/oauth/{provider}/start?redirect=/dashboard"),
                Body::empty(),
                None,
            )
            .await;
            assert_eq!(oauth_start_response.status(), StatusCode::FOUND);
            let oauth_start_location = oauth_start_response
                .headers()
                .get(http::header::LOCATION)
                .unwrap()
                .to_str()
                .unwrap()
                .to_owned();
            assert!(oauth_start_location
                .starts_with(&format!("/api/v1/auth/oauth/{provider}/callback?")));
            assert!(oauth_start_location.contains("code=demo-"));
            assert!(oauth_start_location.contains("state=demo-state-"));
            let oauth_start_cookies = oauth_start_response
                .headers()
                .get_all(http::header::SET_COOKIE)
                .iter()
                .map(|value| value.to_str().unwrap().to_owned())
                .collect::<Vec<_>>();
            assert!(oauth_start_cookies
                .iter()
                .any(|cookie| cookie.starts_with("oauth_state=demo-state-")));
            assert!(oauth_start_cookies
                .iter()
                .any(|cookie| cookie.starts_with(&format!("oauth_provider={provider}"))));

            let oauth_callback_response = request_with_body(
                app.clone(),
                "GET",
                &format!(
                    "/api/v1/auth/oauth/{provider}/callback?code=demo&state=demo&redirect=/dashboard"
                ),
                Body::empty(),
                None,
            )
            .await;
            assert_eq!(oauth_callback_response.status(), StatusCode::FOUND);
            let oauth_callback_location = oauth_callback_response
                .headers()
                .get(http::header::LOCATION)
                .unwrap()
                .to_str()
                .unwrap();
            if matches!(provider, "github" | "google") {
                assert!(oauth_callback_location.starts_with("/auth/oauth/callback#"));
                assert!(oauth_callback_location.contains("access_token=dev-access-"));
                assert!(oauth_callback_location.contains("refresh_token=dev-refresh-"));
            } else {
                assert!(oauth_callback_location.starts_with(&format!("/auth/{provider}/callback#")));
                assert!(oauth_callback_location.contains("redirect=%2Fdashboard"));
                let oauth_callback_cookies = oauth_callback_response
                    .headers()
                    .get_all(http::header::SET_COOKIE)
                    .iter()
                    .map(|value| value.to_str().unwrap().to_owned())
                    .collect::<Vec<_>>();
                assert!(oauth_callback_cookies
                    .iter()
                    .any(|cookie| cookie.starts_with("oauth_pending_session=pending-")));
            }

            let oauth_error_response = request_with_body(
                app.clone(),
                "GET",
                &format!(
                    "/api/v1/auth/oauth/{provider}/callback?error=access_denied&error_description=nope"
                ),
                Body::empty(),
                None,
            )
            .await;
            assert_eq!(oauth_error_response.status(), StatusCode::FOUND);
            let oauth_error_location = oauth_error_response
                .headers()
                .get(http::header::LOCATION)
                .unwrap()
                .to_str()
                .unwrap();
            assert!(oauth_error_location.contains("#error=provider_error"));
            assert!(oauth_error_location.contains("error_message=access_denied"));

            let complete_response = request_on(
                app.clone(),
                "POST",
                &format!("/api/v1/auth/oauth/{provider}/complete-registration"),
                json!({ "invitation_code": "INVITE" }),
                None,
            )
            .await;
            assert_eq!(complete_response.status(), StatusCode::OK);
            let complete_payload = json_body(complete_response).await;
            assert!(complete_payload["data"]["access_token"].is_string());

            let bind_response = request_on(
                app.clone(),
                "POST",
                &format!("/api/v1/auth/oauth/{provider}/bind-login"),
                json!({ "pending_token": "pending-demo" }),
                None,
            )
            .await;
            assert_eq!(bind_response.status(), StatusCode::NOT_FOUND);

            let create_account_response = request_on(
                app.clone(),
                "POST",
                &format!("/api/v1/auth/oauth/{provider}/create-account"),
                json!({ "invitation_code": "INVITE" }),
                None,
            )
            .await;
            assert_eq!(create_account_response.status(), StatusCode::BAD_REQUEST);
        }

        let wechat_payment_start_response = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/auth/oauth/wechat/payment/start?redirect=/payment",
            Body::empty(),
            None,
        )
        .await;
        assert_eq!(wechat_payment_start_response.status(), StatusCode::FOUND);
        let wechat_payment_start_location = wechat_payment_start_response
            .headers()
            .get(http::header::LOCATION)
            .unwrap()
            .to_str()
            .unwrap();
        assert!(wechat_payment_start_location
            .starts_with("/api/v1/auth/oauth/wechat/payment/callback?"));

        let wechat_payment_callback_response = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/auth/oauth/wechat/payment/callback?code=demo&state=demo&redirect=/purchase",
            Body::empty(),
            None,
        )
        .await;
        assert_eq!(wechat_payment_callback_response.status(), StatusCode::FOUND);
        let wechat_payment_callback_location = wechat_payment_callback_response
            .headers()
            .get(http::header::LOCATION)
            .unwrap()
            .to_str()
            .unwrap();
        assert!(wechat_payment_callback_location.starts_with("/auth/wechat/payment/callback#"));
        assert!(wechat_payment_callback_location.contains("wechat_resume_token=wechat-resume-"));

        let pending_exchange_response = request_on(
            app.clone(),
            "POST",
            "/api/v1/auth/oauth/pending/exchange",
            json!({ "adopt_display_name": true }),
            None,
        )
        .await;
        assert_eq!(pending_exchange_response.status(), StatusCode::BAD_REQUEST);

        let pending_send_code_response = request_on(
            app.clone(),
            "POST",
            "/api/v1/auth/oauth/pending/send-verify-code",
            json!({ "email": "pending@example.com" }),
            None,
        )
        .await;
        assert_eq!(pending_send_code_response.status(), StatusCode::BAD_REQUEST);
        smtp_shutdown.send(()).ok();

        let revoke_response = request_with_body(
            app,
            "POST",
            "/api/v1/auth/revoke-all-sessions",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(revoke_response.status(), StatusCode::OK);
    }

    #[tokio::test]
    async fn oauth_pending_session_create_account_binds_identity_once() {
        let state = AppState::demo();
        let app = app_with_state(state.clone());

        let callback_response = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/auth/oauth/linuxdo/callback?code=demo&state=demo&redirect=/console",
            Body::empty(),
            None,
        )
        .await;
        assert_eq!(callback_response.status(), StatusCode::FOUND);
        let cookie_header = cookie_header_from_response(&callback_response);
        let pending_token = cookie_value_from_header(&cookie_header, "oauth_pending_session");
        let browser_key = cookie_value_from_header(&cookie_header, "oauth_pending_browser_session");
        assert!(pending_token.starts_with("pending-linuxdo-"));
        assert!(browser_key.starts_with("browser-"));

        let preview_response = request_with_headers(
            app.clone(),
            "POST",
            "/api/v1/auth/oauth/pending/exchange",
            Body::from(json!({}).to_string()),
            &[("cookie", &cookie_header)],
        )
        .await;
        assert_eq!(preview_response.status(), StatusCode::OK);
        let preview_payload = json_body(preview_response).await;
        assert_eq!(preview_payload["data"]["auth_result"], "pending_session");
        assert_eq!(preview_payload["data"]["provider"], "linuxdo");
        assert_eq!(preview_payload["data"]["redirect"], "/console");

        let forged_response = request_with_headers(
            app.clone(),
            "POST",
            "/api/v1/auth/oauth/linuxdo/create-account",
            Body::from(
                json!({
                    "pending_token": pending_token,
                    "email": "oauth-created@example.com",
                    "password": "oauth-pass-1"
                })
                .to_string(),
            ),
            &[("cookie", "oauth_pending_browser_session=wrong-browser")],
        )
        .await;
        assert_eq!(forged_response.status(), StatusCode::UNAUTHORIZED);

        let create_response = request_with_headers(
            app.clone(),
            "POST",
            "/api/v1/auth/oauth/linuxdo/create-account",
            Body::from(
                json!({
                    "email": "oauth-created@example.com",
                    "password": "oauth-pass-1"
                })
                .to_string(),
            ),
            &[("cookie", &cookie_header)],
        )
        .await;
        assert_eq!(create_response.status(), StatusCode::OK);
        let create_payload = json_body(create_response).await;
        let user_id = create_payload["data"]["user"]["id"].as_i64().unwrap();
        assert!(create_payload["data"]["access_token"].is_string());
        let identity = state
            .auth
            .oauth_identity_for_user(user_id, "linuxdo")
            .expect("oauth identity bound");
        assert_eq!(identity.email.as_deref(), Some("oauth-created@example.com"));
        let repository_identities = state
            .repository
            .list_oauth_identities_by_user(user_id)
            .await
            .unwrap();
        assert_eq!(repository_identities.len(), 1);
        assert_eq!(repository_identities[0].provider, "linuxdo");
        assert_eq!(
            repository_identities[0].email.as_deref(),
            Some("oauth-created@example.com")
        );
        let repository_credential = state
            .repository
            .get_auth_credential_by_email("oauth-created@example.com")
            .await
            .unwrap();
        assert_eq!(repository_credential.user_id, user_id);
        assert!(verify_repository_password(
            "oauth-pass-1",
            &repository_credential.password_hash
        ));

        let mut recreated_state = AppState::demo();
        recreated_state.repository = state.repository.clone();
        let recreated_app = app_with_state(recreated_state);
        let recreated_login_response = request_on(
            recreated_app,
            "POST",
            "/api/v1/auth/login",
            json!({
                "email": "oauth-created@example.com",
                "password": "oauth-pass-1"
            }),
            None,
        )
        .await;
        assert_eq!(recreated_login_response.status(), StatusCode::OK);

        let reuse_response = request_with_headers(
            app,
            "POST",
            "/api/v1/auth/oauth/linuxdo/create-account",
            Body::from(
                json!({
                    "pending_token": pending_token,
                    "email": "oauth-created-2@example.com",
                    "password": "oauth-pass-2"
                })
                .to_string(),
            ),
            &[("cookie", &cookie_header)],
        )
        .await;
        assert_eq!(reuse_response.status(), StatusCode::UNAUTHORIZED);
    }

    #[tokio::test]
    async fn oauth_callback_uses_configured_provider_token_and_profile_endpoints() {
        let provider_hits = Arc::new(Mutex::new(Vec::new()));
        let token_hits = provider_hits.clone();
        let profile_hits = provider_hits.clone();
        let provider = Router::new()
            .route(
                "/token",
                post(move |headers: HeaderMap, body: Bytes| {
                    let token_hits = token_hits.clone();
                    async move {
                        token_hits.lock().unwrap().push(format!(
                            "token:{}:{}",
                            headers
                                .get(http::header::CONTENT_TYPE)
                                .and_then(|value| value.to_str().ok())
                                .unwrap_or(""),
                            String::from_utf8_lossy(&body)
                        ));
                        Json(json!({ "access_token": "provider-access-token" }))
                    }
                }),
            )
            .route(
                "/userinfo",
                get(move |headers: HeaderMap| {
                    let profile_hits = profile_hits.clone();
                    async move {
                        profile_hits.lock().unwrap().push(format!(
                            "profile:{}",
                            headers
                                .get(http::header::AUTHORIZATION)
                                .and_then(|value| value.to_str().ok())
                                .unwrap_or("")
                        ));
                        Json(json!({
                            "id": "github-user-42",
                            "email": "real-oauth@example.com"
                        }))
                    }
                }),
            );
        let (provider_base_url, provider_shutdown) = spawn_test_server(provider).await;

        let state = AppState::demo();
        state
            .repository
            .upsert_system_setting(repository::SystemSettingRecord {
                namespace: "admin".to_owned(),
                key: "settings".to_owned(),
                value: json!({
                    "oauth": {
                        "github": {
                            "enabled": true,
                            "client_id": "client-id",
                            "client_secret": "client-secret",
                            "token_url": format!("{provider_base_url}/token"),
                            "userinfo_url": format!("{provider_base_url}/userinfo")
                        }
                    }
                }),
                updated_at: "2026-06-16T00:00:00Z".to_owned(),
            })
            .await
            .unwrap();
        let app = app_with_state(state.clone());

        let callback_response = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/auth/oauth/github/callback?code=real-code&state=real-state&redirect=/console&redirect_uri=http%3A%2F%2Flocalhost%2Foauth%2Fgithub",
            Body::empty(),
            None,
        )
        .await;
        provider_shutdown.send(()).ok();
        assert_eq!(callback_response.status(), StatusCode::FOUND);
        let location = callback_response
            .headers()
            .get(http::header::LOCATION)
            .unwrap()
            .to_str()
            .unwrap();
        assert!(location.starts_with("/auth/oauth/callback#"));
        assert!(!location.contains("access_token=dev-access-"));
        let cookie_header = cookie_header_from_response(&callback_response);
        let pending_token = cookie_value_from_header(&cookie_header, "oauth_pending_session");
        assert!(pending_token.starts_with("pending-github-"));

        let create_response = request_with_headers(
            app,
            "POST",
            "/api/v1/auth/oauth/github/create-account",
            Body::from(
                json!({
                    "password": "oauth-pass-1"
                })
                .to_string(),
            ),
            &[("cookie", &cookie_header)],
        )
        .await;
        assert_eq!(create_response.status(), StatusCode::OK);
        let create_payload = json_body(create_response).await;
        let user_id = create_payload["data"]["user"]["id"].as_i64().unwrap();
        assert_eq!(
            create_payload["data"]["user"]["email"],
            "real-oauth@example.com"
        );
        let identity = state
            .auth
            .oauth_identity_for_user(user_id, "github")
            .expect("real oauth identity bound");
        assert_eq!(identity.provider_subject, "github-user-42");
        assert_eq!(identity.email.as_deref(), Some("real-oauth@example.com"));
        let repository_identity = state
            .repository
            .get_oauth_identity("github", "github", "github-user-42")
            .await
            .unwrap();
        assert_eq!(repository_identity.user_id, user_id);
        assert_eq!(
            repository_identity.email.as_deref(),
            Some("real-oauth@example.com")
        );
        let hits = provider_hits.lock().unwrap().clone();
        assert!(hits.iter().any(|hit| hit.contains("code=real-code")));
        assert!(hits
            .iter()
            .any(|hit| hit == "profile:Bearer provider-access-token"));
    }

    #[tokio::test]
    async fn oauth_repository_identity_conflict_survives_app_recreation() {
        let provider = Router::new()
            .route(
                "/token",
                post(|| async { Json(json!({ "access_token": "provider-access-token" })) }),
            )
            .route(
                "/userinfo",
                get(|| async {
                    Json(json!({
                        "id": "github-user-42",
                        "email": "real-oauth@example.com"
                    }))
                }),
            );
        let (provider_base_url, provider_shutdown) = spawn_test_server(provider).await;

        let repository: Arc<dyn repository::AppRepository> =
            Arc::new(repository::InMemoryRepository::new());
        repository
            .upsert_system_setting(repository::SystemSettingRecord {
                namespace: "admin".to_owned(),
                key: "settings".to_owned(),
                value: json!({
                    "oauth": {
                        "github": {
                            "enabled": true,
                            "client_id": "client-id",
                            "client_secret": "client-secret",
                            "token_url": format!("{provider_base_url}/token"),
                            "userinfo_url": format!("{provider_base_url}/userinfo")
                        }
                    }
                }),
                updated_at: "2026-06-16T00:00:00Z".to_owned(),
            })
            .await
            .unwrap();

        let mut first_state = AppState::demo();
        first_state.repository = repository.clone();
        let first_app = app_with_state(first_state.clone());
        let first_callback = request_with_body(
            first_app.clone(),
            "GET",
            "/api/v1/auth/oauth/github/callback?code=real-code&state=real-state",
            Body::empty(),
            None,
        )
        .await;
        assert_eq!(first_callback.status(), StatusCode::FOUND);
        let first_cookies = cookie_header_from_response(&first_callback);
        let first_create = request_with_headers(
            first_app,
            "POST",
            "/api/v1/auth/oauth/github/create-account",
            Body::from(json!({ "password": "oauth-pass-1" }).to_string()),
            &[("cookie", &first_cookies)],
        )
        .await;
        assert_eq!(first_create.status(), StatusCode::OK);
        let first_payload = json_body(first_create).await;
        let created_user_id = first_payload["data"]["user"]["id"].as_i64().unwrap();
        assert_ne!(created_user_id, 1);
        assert_eq!(
            repository
                .get_oauth_identity("github", "github", "github-user-42")
                .await
                .unwrap()
                .user_id,
            created_user_id
        );

        let mut second_state = AppState::demo();
        second_state.repository = repository.clone();
        let second_app = app_with_state(second_state);
        let second_callback = request_with_body(
            second_app.clone(),
            "GET",
            "/api/v1/auth/oauth/github/callback?code=real-code-again&state=real-state",
            Body::empty(),
            None,
        )
        .await;
        assert_eq!(second_callback.status(), StatusCode::FOUND);
        let second_cookies = cookie_header_from_response(&second_callback);
        let conflict_response = request_with_headers(
            second_app,
            "POST",
            "/api/v1/auth/oauth/github/bind-login",
            Body::from(
                json!({
                    "email": "admin@example.com",
                    "password": "admin123"
                })
                .to_string(),
            ),
            &[("cookie", &second_cookies)],
        )
        .await;
        provider_shutdown.send(()).ok();
        assert_eq!(conflict_response.status(), StatusCode::CONFLICT);
        let conflict_payload = json_body(conflict_response).await;
        assert!(conflict_payload["message"]
            .as_str()
            .unwrap_or_default()
            .contains("oauth identity is already bound"));
    }

    #[tokio::test]
    async fn oauth_bind_current_user_uses_bind_cookie_and_consumes_session_once() {
        let state = AppState::demo();
        let app = app_with_state(state.clone());
        let access_token = login_seed_admin(app.clone()).await;

        let bind_token_response = request_with_body(
            app.clone(),
            "POST",
            "/api/v1/auth/oauth/bind-token",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(bind_token_response.status(), StatusCode::NO_CONTENT);
        let bind_cookie = bind_token_response
            .headers()
            .get(http::header::SET_COOKIE)
            .unwrap()
            .to_str()
            .unwrap()
            .split(';')
            .next()
            .unwrap()
            .to_owned();

        let start_response = request_with_headers(
            app.clone(),
            "GET",
            "/api/v1/auth/oauth/linuxdo/bind/start?redirect=/profile",
            Body::empty(),
            &[("cookie", &bind_cookie)],
        )
        .await;
        assert_eq!(start_response.status(), StatusCode::FOUND);
        let start_location = start_response
            .headers()
            .get(http::header::LOCATION)
            .unwrap()
            .to_str()
            .unwrap();
        assert!(start_location.contains("intent=bind_current_user"));
        assert!(start_location.contains("bind_token=bind-"));

        let callback_response =
            request_with_body(app.clone(), "GET", start_location, Body::empty(), None).await;
        assert_eq!(callback_response.status(), StatusCode::FOUND);
        let pending_cookies = cookie_header_from_response(&callback_response);
        let pending_token = cookie_value_from_header(&pending_cookies, "oauth_pending_session");

        let bind_login_response = request_with_headers(
            app.clone(),
            "POST",
            "/api/v1/auth/oauth/linuxdo/bind-login",
            Body::from(
                json!({
                    "email": "admin@example.com",
                    "password": "admin123"
                })
                .to_string(),
            ),
            &[("cookie", &pending_cookies)],
        )
        .await;
        assert_eq!(bind_login_response.status(), StatusCode::OK);
        let bind_login_payload = json_body(bind_login_response).await;
        let user_id = bind_login_payload["data"]["user"]["id"].as_i64().unwrap();
        assert_eq!(user_id, 1);
        assert!(state.auth.oauth_identity_for_user(1, "linuxdo").is_some());
        assert_eq!(
            state
                .repository
                .list_oauth_identities_by_user(1)
                .await
                .unwrap()
                .len(),
            1
        );

        let reuse_response = request_with_headers(
            app,
            "POST",
            "/api/v1/auth/oauth/linuxdo/bind-login",
            Body::from(
                json!({
                    "pending_token": pending_token,
                    "email": "admin@example.com",
                    "password": "admin123"
                })
                .to_string(),
            ),
            &[("cookie", &pending_cookies)],
        )
        .await;
        assert_eq!(reuse_response.status(), StatusCode::UNAUTHORIZED);
    }

    #[tokio::test]
    async fn openai_create_from_oauth_creates_account_and_group_bindings() {
        let state = AppState::demo();
        let app = app_with_state(state.clone());
        let access_token = login_seed_admin(app.clone()).await;

        let auth_url_response = request_on(
            app.clone(),
            "POST",
            "/api/v1/admin/openai/generate-auth-url",
            json!({ "redirect_uri": "http://localhost/oauth/callback" }),
            Some(&access_token),
        )
        .await;
        assert_eq!(auth_url_response.status(), StatusCode::OK);
        let auth_url_payload = json_body(auth_url_response).await;
        let session_id = auth_url_payload["data"]["session_id"].as_str().unwrap();
        let state_token = auth_url_payload["data"]["state"].as_str().unwrap();

        let create_response = request_on(
            app.clone(),
            "POST",
            "/api/v1/admin/openai/create-from-oauth",
            json!({
                "session_id": session_id,
                "code": "oauth-code",
                "state": state_token,
                "name": "OAuth OpenAI",
                "concurrency": 3,
                "priority": 7,
                "group_ids": [1, 2]
            }),
            Some(&access_token),
        )
        .await;
        assert_eq!(create_response.status(), StatusCode::OK);
        let create_payload = json_body(create_response).await;
        let account = &create_payload["data"];
        let account_id = account["id"].as_i64().unwrap();
        assert_eq!(account["name"], "OAuth OpenAI");
        assert_eq!(account["platform"], "openai");
        assert_eq!(account["type"], "oauth");
        assert_eq!(account["account_type"], "oauth");
        assert_eq!(account["concurrency"], 3);
        assert_eq!(account["priority"], 7);
        assert!(account.get("access_token").is_none());
        assert!(account.get("api_key").is_none());
        assert!(account["credentials"].get("access_token").is_none());
        assert!(account["credentials"].get("refresh_token").is_none());
        assert_eq!(
            account["credentials_status"]["has_access_token"],
            Value::Bool(true)
        );
        assert_eq!(
            account["credentials_status"]["has_refresh_token"],
            Value::Bool(true)
        );

        let persisted = state
            .repository
            .get_account(AccountId(account_id))
            .await
            .unwrap();
        assert_eq!(persisted.provider, Provider::OpenAi);
        assert_eq!(persisted.name, "OAuth OpenAI");
        assert!(persisted
            .api_key
            .as_deref()
            .unwrap()
            .starts_with("openai-access-"));
        assert_eq!(persisted.extra["account_type"], "oauth");
        assert!(persisted.extra["credentials"]["access_token"]
            .as_str()
            .unwrap()
            .starts_with("openai-access-"));

        let group_one_bindings = state
            .repository
            .list_bindings_by_group(GroupId(1))
            .await
            .unwrap();
        assert!(group_one_bindings
            .iter()
            .any(|binding| binding.account.id == AccountId(account_id)));
        let group_two_bindings = state
            .repository
            .list_bindings_by_group(GroupId(2))
            .await
            .unwrap();
        let created_group_two = state.repository.get_group(GroupId(2)).await.unwrap();
        assert_eq!(created_group_two.status, GroupStatus::Active);
        assert!(group_two_bindings
            .iter()
            .any(|binding| binding.account.id == AccountId(account_id)));
    }

