    #[tokio::test]
    async fn email_unsubscribe_requires_signed_optional_event_token_and_returns_html() {
        let state = AppState::demo();
        let app = app_with_state(state.clone());

        let missing_response = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/settings/email-unsubscribe",
            Body::empty(),
            None,
        )
        .await;
        assert_eq!(missing_response.status(), StatusCode::BAD_REQUEST);

        let invalid_response = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/settings/email-unsubscribe?token=demo",
            Body::empty(),
            None,
        )
        .await;
        assert_eq!(invalid_response.status(), StatusCode::BAD_REQUEST);

        let token = crate::notification_email::create_unsubscribe_token_for_tests(
            &state.repository,
            "User@Example.com",
            "balance.low",
            Utc::now().timestamp() + 3600,
        )
        .await
        .unwrap();
        let response = request_with_body(
            app.clone(),
            "GET",
            &format!("/api/v1/settings/email-unsubscribe?token={token}"),
            Body::empty(),
            None,
        )
        .await;
        assert_eq!(response.status(), StatusCode::OK);
        assert!(response
            .headers()
            .get(http::header::CONTENT_TYPE)
            .unwrap()
            .to_str()
            .unwrap()
            .starts_with("text/html"));
        let html = body_text(response).await;
        assert!(html.contains("Unsubscribed"));
        assert!(html.contains("User@Example.com"));
        assert!(crate::notification_email::is_unsubscribed(
            &state.repository,
            "user@example.com",
            "balance.low"
        )
        .await
        .unwrap());

        let transactional = crate::notification_email::create_unsubscribe_token_for_tests(
            &state.repository,
            "user@example.com",
            "balance.recharge_success",
            Utc::now().timestamp() + 3600,
        )
        .await
        .unwrap();
        let transactional_response = request_with_body(
            app,
            "GET",
            &format!("/api/v1/settings/email-unsubscribe?token={transactional}"),
            Body::empty(),
            None,
        )
        .await;
        assert_eq!(transactional_response.status(), StatusCode::BAD_REQUEST);
        let transactional_payload = json_body(transactional_response).await;
        assert!(transactional_payload["message"]
            .as_str()
            .unwrap()
            .contains("transactional"));
    }

    #[tokio::test]
    async fn admin_apply_oauth_credentials_updates_repository_and_redacts_response() {
        let state = AppState::demo();
        let app = app_with_state(state.clone());
        let access_token = login_seed_admin(app.clone()).await;

        let create_response = request_on(
            app.clone(),
            "POST",
            "/api/v1/admin/accounts",
            json!({
                "name": "reauth target",
                "platform": "openai",
                "type": "oauth",
                "group_ids": [1],
                "api_key": "old-access-token",
                "credentials": {
                    "access_token": "old-access-token",
                    "refresh_token": "old-refresh-token",
                    "base_url": "https://api.openai.test"
                },
                "extra": {
                    "account_type": "oauth",
                    "privacy_mode": "enabled",
                    "credentials": {
                        "access_token": "old-access-token",
                        "refresh_token": "old-refresh-token"
                    }
                }
            }),
            Some(&access_token),
        )
        .await;
        assert_eq!(create_response.status(), StatusCode::OK);
        let create_payload = json_body(create_response).await;
        let account_id = create_payload["data"]["id"].as_i64().unwrap();

        let apply_response = request_on(
            app.clone(),
            "POST",
            &format!("/api/v1/admin/accounts/{account_id}/apply-oauth-credentials"),
            json!({
                "type": "oauth",
                "credentials": {
                    "access_token": "new-access-token",
                    "refresh_token": "new-refresh-token",
                    "scope": "openid profile",
                    "base_url": "https://api.openai.test"
                },
                "extra": {
                    "reauthorized_at": "2026-06-07T00:00:00Z"
                }
            }),
            Some(&access_token),
        )
        .await;
        assert_eq!(apply_response.status(), StatusCode::OK);
        let apply_payload = json_body(apply_response).await;
        let account = &apply_payload["data"];
        assert_eq!(account["type"], "oauth");
        assert!(account.get("api_key").is_none());
        assert_eq!(account["credentials"]["scope"], "openid profile");
        assert!(account["credentials"].get("access_token").is_none());
        assert!(account["credentials"].get("refresh_token").is_none());
        assert_eq!(
            account["credentials_status"]["has_access_token"],
            Value::Bool(true)
        );
        assert_eq!(
            account["credentials_status"]["has_refresh_token"],
            Value::Bool(true)
        );

        let persisted = state
            .repository
            .get_account(AccountId(account_id))
            .await
            .unwrap();
        assert_eq!(persisted.api_key.as_deref(), Some("new-access-token"));
        assert_eq!(persisted.extra["privacy_mode"], "enabled");
        assert_eq!(persisted.extra["reauthorized_at"], "2026-06-07T00:00:00Z");
        assert_eq!(
            persisted.extra["credentials"]["refresh_token"],
            "new-refresh-token"
        );
    }

