    #[tokio::test]
    async fn admin_routes_require_admin_role() {
        let app = app();
        let protected_admin_routes = [
            ("GET", "/api/v1/admin/dashboard/stats"),
            ("GET", "/api/v1/admin/users"),
            ("GET", "/api/v1/admin/accounts"),
            ("GET", "/api/v1/admin/payment/config"),
            ("GET", "/api/v1/admin/ops/system-logs/health"),
            ("GET", "/api/v1/admin/backups"),
            ("GET", "/api/v1/admin/risk-control/status"),
            ("GET", "/api/v1/admin/affiliates/invites"),
        ];

        for (method, uri) in protected_admin_routes {
            let missing_response =
                request_with_body(app.clone(), method, uri, Body::empty(), None).await;
            assert_eq!(missing_response.status(), StatusCode::UNAUTHORIZED, "{uri}");
        }

        let hardcoded_admin_key_response = request_with_headers(
            app.clone(),
            "GET",
            "/api/v1/admin/dashboard/stats",
            Body::empty(),
            &[("x-api-key", "admin-dev-key")],
        )
        .await;
        assert_eq!(
            hardcoded_admin_key_response.status(),
            StatusCode::UNAUTHORIZED
        );

        let register_response = request_on(
            app.clone(),
            "POST",
            "/api/v1/auth/register",
            json!({
                "email": "regular@example.com",
                "password": "regular123",
                "username": "regular"
            }),
            None,
        )
        .await;
        assert_eq!(register_response.status(), StatusCode::OK);
        let register_payload = json_body(register_response).await;
        let user_token = register_payload["data"]["access_token"].as_str().unwrap();

        let admin_token = login_seed_admin(app.clone()).await;
        let invalid_admin_key_with_bearer_response = request_with_headers(
            app.clone(),
            "GET",
            "/api/v1/admin/dashboard/stats",
            Body::empty(),
            &[
                ("x-api-key", "invalid-admin-key"),
                ("authorization", &format!("Bearer {admin_token}")),
            ],
        )
        .await;
        assert_eq!(
            invalid_admin_key_with_bearer_response.status(),
            StatusCode::UNAUTHORIZED
        );

        for (method, uri) in protected_admin_routes {
            let forbidden_response =
                request_with_body(app.clone(), method, uri, Body::empty(), Some(user_token)).await;
            assert_eq!(forbidden_response.status(), StatusCode::FORBIDDEN, "{uri}");
        }

        let ok_response = request_with_body(
            app,
            "GET",
            "/api/v1/admin/dashboard/stats",
            Body::empty(),
            Some(&admin_token),
        )
        .await;
        assert_eq!(ok_response.status(), StatusCode::OK);
    }

    #[tokio::test]
    async fn external_postgres_and_redis_route_smoke_uses_real_dependencies() {
        if std::env::var("BACKEND_NEXT_EXTERNAL_DEPS").ok().as_deref() != Some("1") {
            return;
        }
        let _guard = crate::config::runtime_env_lock()
            .lock()
            .unwrap_or_else(|poisoned| poisoned.into_inner());
        let original_config_disabled = std::env::var("BACKEND_NEXT_CONFIG_DISABLED").ok();
        let original_state_store = std::env::var("BACKEND_NEXT_RESPONSES_STATE_STORE").ok();
        std::env::remove_var("BACKEND_NEXT_CONFIG_DISABLED");
        std::env::set_var("BACKEND_NEXT_RESPONSES_STATE_STORE", "redis");
        let setup_database_password = std::env::var("BACKEND_NEXT_EXTERNAL_DB_PASSWORD")
            .unwrap_or_else(|_| "123456".to_owned());
        let setup_database_name = std::env::var("BACKEND_NEXT_EXTERNAL_DB_NAME")
            .unwrap_or_else(|_| "sub2api_new".to_owned());
        let setup_redis_password = std::env::var("REDIS_PASSWORD")
            .ok()
            .filter(|value| !value.is_empty());

        let setup_app = app_with_state(AppState::setup_demo());
        let setup_db_response = request_on(
            setup_app.clone(),
            "POST",
            "/setup/test-db",
            json!({
                "host": "127.0.0.1",
                "port": 5432,
                "user": "test",
                "password": setup_database_password,
                "dbname": setup_database_name,
                "sslmode": "disable"
            }),
            None,
        )
        .await;
        assert_eq!(setup_db_response.status(), StatusCode::OK);
        let setup_db_payload = json_body(setup_db_response).await;
        assert_eq!(
            setup_db_payload["data"]["message"],
            "Database connection successful"
        );

        let setup_redis_response = request_on(
            setup_app,
            "POST",
            "/setup/test-redis",
            json!({
                "host": "127.0.0.1",
                "port": 6379,
                "password": setup_redis_password,
                "db": 0,
                "enable_tls": false
            }),
            None,
        )
        .await;
        assert_eq!(setup_redis_response.status(), StatusCode::OK);

        let state = AppState::production().await.unwrap();
        let app = app_with_state(state.clone());
        let access_token = login_seed_admin(app.clone()).await;

        let settings_response = request_on(
            app.clone(),
            "PUT",
            "/api/v1/admin/settings",
            json!({ "site_name": "Sub2API External Smoke" }),
            Some(&access_token),
        )
        .await;
        assert_eq!(settings_response.status(), StatusCode::OK);

        let public_settings_response = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/settings/public",
            Body::empty(),
            None,
        )
        .await;
        assert_eq!(public_settings_response.status(), StatusCode::OK);
        let public_settings_payload = json_body(public_settings_response).await;
        assert_eq!(
            public_settings_payload["data"]["site_name"],
            "Sub2API External Smoke"
        );

        let provider_response = request_on(
            app.clone(),
            "POST",
            "/api/v1/admin/payment/providers",
            json!({
                "name": "External Smoke Provider",
                "provider_key": "airwallex",
                "config": { "currency": "CNY" },
                "supported_types": ["external_smoke_pay"],
                "limits": {
                    "external_smoke_pay": {
                        "currency": "CNY",
                        "dailyLimit": 321.0,
                        "singleMin": 4.0,
                        "singleMax": 99.0,
                        "feeRate": 0.5
                    }
                },
                "enabled": true,
                "sort_order": -999
            }),
            Some(&access_token),
        )
        .await;
        assert_eq!(provider_response.status(), StatusCode::OK);
        let provider_payload = json_body(provider_response).await;
        let provider_id = provider_payload["data"]["id"].as_i64().unwrap();

        let limits_response = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/payment/limits",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(limits_response.status(), StatusCode::OK);
        let limits_payload = json_body(limits_response).await;
        assert_eq!(
            limits_payload["data"]["methods"]["external_smoke_pay"]["provider_instance_id"],
            provider_id
        );
        assert_eq!(
            limits_payload["data"]["methods"]["external_smoke_pay"]["single_min"],
            4.0
        );
        assert_eq!(
            limits_payload["data"]["methods"]["external_smoke_pay"]["single_max"],
            99.0
        );

        let delete_provider_response = request_with_body(
            app,
            "DELETE",
            &format!("/api/v1/admin/payment/providers/{provider_id}"),
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(delete_provider_response.status(), StatusCode::OK);
        assert!(state
            .repository
            .get_payment_provider_instance(provider_id)
            .await
            .is_err());
        let _ = state
            .repository
            .delete_system_setting("admin", "settings")
            .await;

        if let Some(value) = original_config_disabled {
            std::env::set_var("BACKEND_NEXT_CONFIG_DISABLED", value);
        } else {
            std::env::remove_var("BACKEND_NEXT_CONFIG_DISABLED");
        }
        if let Some(value) = original_state_store {
            std::env::set_var("BACKEND_NEXT_RESPONSES_STATE_STORE", value);
        } else {
            std::env::remove_var("BACKEND_NEXT_RESPONSES_STATE_STORE");
        }
    }

