    #[tokio::test]
    async fn admin_backup_data_management_and_risk_control_routes_keep_state() {
        let app = app();
        let access_token = login_seed_admin(app.clone()).await;

        let s3_update_response = request_on(
            app.clone(),
            "PUT",
            "/api/v1/admin/backups/s3-config",
            json!({
                "endpoint": "https://r2.example.com",
                "region": "auto",
                "bucket": "sub2api-backups",
                "access_key_id": "AKIA",
                "secret_access_key": "secret",
                "prefix": "daily/",
                "force_path_style": true
            }),
            Some(&access_token),
        )
        .await;
        assert_eq!(s3_update_response.status(), StatusCode::OK);
        let s3_update_payload = json_body(s3_update_response).await;
        assert_eq!(s3_update_payload["data"]["bucket"], "sub2api-backups");
        assert_eq!(
            s3_update_payload["data"]["secret_access_key_configured"],
            true
        );

        let (s3_base_url, s3_requests, s3_shutdown) = spawn_fake_s3_server(StatusCode::OK).await;
        let s3_test_response = request_on(
            app.clone(),
            "POST",
            "/api/v1/admin/backups/s3-config/test",
            json!({
                "endpoint": s3_base_url,
                "region": "auto",
                "bucket": "sub2api-backups",
                "access_key_id": "AKIA",
                "secret_access_key": "secret",
                "force_path_style": true,
                "use_ssl": false
            }),
            Some(&access_token),
        )
        .await;
        s3_shutdown.send(()).ok();
        assert_eq!(s3_test_response.status(), StatusCode::OK);
        let s3_test_payload = json_body(s3_test_response).await;
        assert_eq!(s3_test_payload["data"]["ok"], true);
        let s3_requests = s3_requests.lock().unwrap().clone();
        assert_eq!(s3_requests[0].method, "HEAD");
        assert_eq!(s3_requests[0].path, "/sub2api-backups");
        assert_eq!(s3_requests[0].has_authorization, true);

        let s3_incomplete_response = request_on(
            app.clone(),
            "POST",
            "/api/v1/admin/backups/s3-config/test",
            json!({
                "endpoint": "http://127.0.0.1:1",
                "bucket": "",
                "access_key_id": "",
                "secret_access_key": ""
            }),
            Some(&access_token),
        )
        .await;
        assert_eq!(s3_incomplete_response.status(), StatusCode::OK);
        let s3_incomplete_payload = json_body(s3_incomplete_response).await;
        assert_eq!(s3_incomplete_payload["data"]["ok"], false);
        assert!(s3_incomplete_payload["data"]["message"]
            .as_str()
            .unwrap()
            .contains("incomplete S3 config"));

        let backup_response = request_on(
            app.clone(),
            "POST",
            "/api/v1/admin/backups",
            json!({ "expire_days": 3 }),
            Some(&access_token),
        )
        .await;
        assert_eq!(backup_response.status(), StatusCode::OK);
        let backup_payload = json_body(backup_response).await;
        let backup_id = backup_payload["data"]["id"].as_str().unwrap().to_owned();
        assert_eq!(backup_payload["data"]["status"], "completed");

        let backup_get_response = request_with_body(
            app.clone(),
            "GET",
            &format!("/api/v1/admin/backups/{backup_id}"),
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(backup_get_response.status(), StatusCode::OK);
        let backup_get_payload = json_body(backup_get_response).await;
        assert_eq!(backup_get_payload["data"]["id"], backup_id);

        let dm_backup_root = std::env::temp_dir().join(format!(
            "backend-next-dm-local-{}",
            uuid::Uuid::new_v4().simple()
        ));
        let dm_config_response = request_on(
            app.clone(),
            "PUT",
            "/api/v1/admin/data-management/config",
            json!({ "backup_root": dm_backup_root.to_string_lossy(), "keep_last": 5 }),
            Some(&access_token),
        )
        .await;
        assert_eq!(dm_config_response.status(), StatusCode::OK);
        let dm_config_payload = json_body(dm_config_response).await;
        assert_eq!(dm_config_payload["data"]["keep_last"], 5);

        let (dm_s3_base_url, dm_s3_requests, dm_s3_shutdown) =
            spawn_fake_s3_server(StatusCode::OK).await;
        let dm_s3_response = request_on(
            app.clone(),
            "POST",
            "/api/v1/admin/data-management/s3/test",
            json!({
                "endpoint": dm_s3_base_url,
                "region": "auto",
                "bucket": "dm-backups",
                "access_key_id": "AKIA",
                "secret_access_key": "secret",
                "force_path_style": true,
                "use_ssl": false
            }),
            Some(&access_token),
        )
        .await;
        dm_s3_shutdown.send(()).ok();
        assert_eq!(dm_s3_response.status(), StatusCode::OK);
        let dm_s3_payload = json_body(dm_s3_response).await;
        assert_eq!(dm_s3_payload["data"]["ok"], true);
        let dm_s3_requests = dm_s3_requests.lock().unwrap().clone();
        assert_eq!(dm_s3_requests[0].method, "HEAD");
        assert_eq!(dm_s3_requests[0].path, "/dm-backups");
        assert_eq!(dm_s3_requests[0].has_authorization, true);

        let (fake_dump_root, fake_pg_dump) =
            create_fake_pg_dump_script("CREATE TABLE dm_full(id int);");
        let profile_response = request_on(
            app.clone(),
            "POST",
            "/api/v1/admin/data-management/sources/postgres/profiles",
            json!({
                "profile_id": "pg-main",
                "name": "Postgres Main",
                "set_active": true,
                "config": {
                    "host": "127.0.0.1",
                    "port": 5432,
                    "user": "sub2api",
                    "password": "secret",
                    "database": "sub2api",
                    "ssl_mode": "disable",
                    "addr": "",
                    "username": "",
                    "db": 0,
                    "container_name": "postgres",
                    "pg_dump_path": fake_pg_dump.to_string_lossy()
                }
            }),
            Some(&access_token),
        )
        .await;
        assert_eq!(profile_response.status(), StatusCode::OK);
        let profile_payload = json_body(profile_response).await;
        assert_eq!(profile_payload["data"]["profile_id"], "pg-main");
        assert_eq!(profile_payload["data"]["is_active"], true);

        let job_response = request_on(
            app.clone(),
            "POST",
            "/api/v1/admin/data-management/backups",
            json!({ "backup_type": "full", "postgres_profile_id": "pg-main" }),
            Some(&access_token),
        )
        .await;
        assert_eq!(job_response.status(), StatusCode::OK);
        let job_payload = json_body(job_response).await;
        let job_id = job_payload["data"]["job_id"].as_str().unwrap().to_owned();
        assert_eq!(job_payload["data"]["status"], "completed");

        let job_get_response = request_with_body(
            app.clone(),
            "GET",
            &format!("/api/v1/admin/data-management/backups/{job_id}"),
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(job_get_response.status(), StatusCode::OK);
        let job_get_payload = json_body(job_get_response).await;
        assert_eq!(job_get_payload["data"]["job_id"], job_id);
        assert_eq!(job_get_payload["data"]["status"], "completed");
        assert_eq!(job_get_payload["data"]["postgres_profile_id"], "pg-main");
        assert_eq!(
            job_get_payload["data"]["execution_plan"]["requires_executor"],
            false
        );
        assert_eq!(
            job_get_payload["data"]["execution_plan"]["executor"],
            "repository-artifact"
        );
        assert!(
            job_get_payload["data"]["artifact"]["size_bytes"]
                .as_u64()
                .unwrap()
                > 0
        );
        assert_eq!(
            job_get_payload["data"]["artifact"]["content_type"],
            "application/gzip"
        );
        assert_eq!(
            job_get_payload["data"]["execution_plan"]["sources"]["postgres"]["profile_id"],
            "pg-main"
        );
        assert_eq!(
            job_get_payload["data"]["execution_plan"]["sources"]["postgres"]["config"]["password"],
            "***"
        );
        assert_eq!(
            job_get_payload["data"]["artifact"]["postgres"]["included"],
            true
        );
        let local_artifact_path = job_get_payload["data"]["artifact"]["local_path"]
            .as_str()
            .unwrap();
        let local_artifact = std::fs::read(local_artifact_path).unwrap();
        assert_eq!(
            local_artifact.len() as u64,
            job_get_payload["data"]["artifact"]["size_bytes"]
                .as_u64()
                .unwrap()
        );
        assert_eq!(
            hex::encode(Sha256::digest(&local_artifact)),
            job_get_payload["data"]["artifact"]["sha256"]
                .as_str()
                .unwrap()
        );

        let jobs_page_response = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/admin/data-management/backups?backup_type=full&status=completed&page_size=1",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(jobs_page_response.status(), StatusCode::OK);
        let jobs_page_payload = json_body(jobs_page_response).await;
        assert_eq!(
            jobs_page_payload["data"]["items"].as_array().unwrap().len(),
            1
        );
        assert_eq!(jobs_page_payload["data"]["items"][0]["job_id"], job_id);
        assert_eq!(jobs_page_payload["data"]["total"], 1);

        let jobs_empty_response = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/admin/data-management/backups?backup_type=redis",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(jobs_empty_response.status(), StatusCode::OK);
        let jobs_empty_payload = json_body(jobs_empty_response).await;
        assert_eq!(
            jobs_empty_payload["data"]["items"]
                .as_array()
                .unwrap()
                .len(),
            0
        );

        let risk_update_response = request_on(
            app.clone(),
            "PUT",
            "/api/v1/admin/risk-control/config",
            json!({
                "enabled": true,
                "mode": "observe",
                "model": "omni-moderation-latest",
                "worker_count": 2,
                "queue_size": 200
            }),
            Some(&access_token),
        )
        .await;
        assert_eq!(risk_update_response.status(), StatusCode::OK);
        let risk_update_payload = json_body(risk_update_response).await;
        assert_eq!(risk_update_payload["data"]["enabled"], true);

        let risk_status_response = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/admin/risk-control/status",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(risk_status_response.status(), StatusCode::OK);
        let risk_status_payload = json_body(risk_status_response).await;
        assert_eq!(risk_status_payload["data"]["enabled"], true);
        std::fs::remove_dir_all(fake_dump_root).ok();
        std::fs::remove_dir_all(dm_backup_root).ok();
        assert_eq!(risk_status_payload["data"]["worker_count"], 2);

        let moderation_calls = Arc::new(AtomicUsize::new(0));
        let moderation_call_count = moderation_calls.clone();
        let moderation_api = Router::new().route(
            "/v1/moderations",
            post(move |headers: HeaderMap, Json(body): Json<Value>| {
                let moderation_call_count = moderation_call_count.clone();
                async move {
                    moderation_call_count.fetch_add(1, Ordering::SeqCst);
                    assert_eq!(
                        headers
                            .get("authorization")
                            .and_then(|value| value.to_str().ok()),
                        Some("Bearer sk-demo")
                    );
                    assert_eq!(body["model"], "omni-moderation-latest");
                    Json(json!({
                        "results": [{
                            "flagged": false,
                            "category_scores": {
                                "violence": 0.1,
                                "hate": 0.05
                            }
                        }]
                    }))
                }
            }),
        );
        let (moderation_base_url, moderation_shutdown) = spawn_test_server(moderation_api).await;
        let risk_test_response = request_on(
            app,
            "POST",
            "/api/v1/admin/risk-control/api-keys/test",
            json!({
                "api_keys": ["sk-demo"],
                "base_url": moderation_base_url,
                "prompt": "hello"
            }),
            Some(&access_token),
        )
        .await;
        moderation_shutdown.send(()).ok();
        assert_eq!(risk_test_response.status(), StatusCode::OK);
        let risk_test_payload = json_body(risk_test_response).await;
        assert_eq!(moderation_calls.load(Ordering::SeqCst), 1);
        assert_eq!(risk_test_payload["data"]["items"][0]["status"], "ok");
        assert_eq!(
            risk_test_payload["data"]["items"][0]["last_http_status"],
            200
        );
        assert_eq!(risk_test_payload["data"]["audit_result"]["flagged"], false);
    }

    #[tokio::test]
    async fn admin_account_and_proxy_data_import_export_keep_state() {
        let app = app();
        let access_token = login_seed_admin(app.clone()).await;

        let initial_accounts_export = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/admin/accounts/data",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(initial_accounts_export.status(), StatusCode::OK);
        let initial_accounts_payload = json_body(initial_accounts_export).await;
        assert_eq!(initial_accounts_payload["data"]["type"], "sub2api-data");
        assert!(initial_accounts_payload["data"]["accounts"].is_array());
        assert!(initial_accounts_payload["data"]["proxies"].is_array());

        let import_payload = json!({
            "data": {
                "type": "sub2api-data",
                "version": 1,
                "exported_at": "2026-06-06T00:00:00Z",
                "proxies": [{
                    "proxy_key": "http|127.0.0.1|7890||",
                    "name": "Local HTTP",
                    "protocol": "http",
                    "host": "127.0.0.1",
                    "port": 7890,
                    "status": "active"
                }],
                "accounts": [{
                    "name": "Imported OpenAI",
                    "platform": "openai",
                    "type": "api-key",
                    "credentials": {
                        "api_key": "sk-imported",
                        "base_url": "https://api.example.com"
                    },
                    "proxy_key": "http|127.0.0.1|7890||",
                    "concurrency": 2,
                    "priority": 5
                }]
            }
        });

        let import_accounts_response = request_on(
            app.clone(),
            "POST",
            "/api/v1/admin/accounts/data",
            import_payload.clone(),
            Some(&access_token),
        )
        .await;
        assert_eq!(import_accounts_response.status(), StatusCode::OK);
        let import_accounts_body = json_body(import_accounts_response).await;
        assert_eq!(import_accounts_body["data"]["proxy_created"], 1);
        assert_eq!(import_accounts_body["data"]["account_created"], 1);
        assert_eq!(import_accounts_body["data"]["account_failed"], 0);

        let exported_accounts_response = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/admin/accounts/data",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(exported_accounts_response.status(), StatusCode::OK);
        let exported_accounts_body = json_body(exported_accounts_response).await;
        let exported_accounts = exported_accounts_body["data"]["accounts"]
            .as_array()
            .unwrap();
        assert!(exported_accounts
            .iter()
            .any(|item| item["name"] == "Imported OpenAI"));
        let exported_proxies = exported_accounts_body["data"]["proxies"]
            .as_array()
            .unwrap();
        assert!(exported_proxies
            .iter()
            .any(|item| item["proxy_key"] == "http|127.0.0.1|7890||"));

        let import_proxies_response = request_on(
            app.clone(),
            "POST",
            "/api/v1/admin/proxies/data",
            import_payload,
            Some(&access_token),
        )
        .await;
        assert_eq!(import_proxies_response.status(), StatusCode::OK);
        let import_proxies_body = json_body(import_proxies_response).await;
        assert_eq!(import_proxies_body["data"]["proxy_reused"], 1);
        assert_eq!(import_proxies_body["data"]["account_created"], 0);

        let proxies_export = request_with_body(
            app,
            "GET",
            "/api/v1/admin/proxies/data",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(proxies_export.status(), StatusCode::OK);
        let proxies_export_body = json_body(proxies_export).await;
        assert_eq!(
            proxies_export_body["data"]["accounts"]
                .as_array()
                .unwrap()
                .len(),
            0
        );
        assert!(proxies_export_body["data"]["proxies"]
            .as_array()
            .unwrap()
            .iter()
            .any(|item| item["name"] == "Local HTTP"));
    }

    #[tokio::test]
    async fn admin_api_key_auth_uses_repository_state_after_app_recreation() {
        let state = AppState::demo();
        let app = app_with_state(state.clone());
        let access_token = login_seed_admin(app.clone()).await;

        let regenerate_response = request_with_body(
            app,
            "POST",
            "/api/v1/admin/settings/admin-api-key/regenerate",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(regenerate_response.status(), StatusCode::OK);
        let admin_api_key = json_body(regenerate_response).await["data"]["key"]
            .as_str()
            .unwrap()
            .to_owned();

        let mut recreated_state = AppState::demo();
        recreated_state.repository = state.repository.clone();
        let recreated_app = app_with_state(recreated_state);

        let persisted_key_auth_response = request_with_headers(
            recreated_app.clone(),
            "GET",
            "/api/v1/admin/dashboard/stats",
            Body::empty(),
            &[("x-api-key", admin_api_key.as_str())],
        )
        .await;
        assert_eq!(persisted_key_auth_response.status(), StatusCode::OK);

        let status_response = request_with_headers(
            recreated_app.clone(),
            "GET",
            "/api/v1/admin/settings/admin-api-key",
            Body::empty(),
            &[("x-api-key", admin_api_key.as_str())],
        )
        .await;
        assert_eq!(status_response.status(), StatusCode::OK);
        let status_payload = json_body(status_response).await;
        assert_eq!(status_payload["data"]["exists"], true);
        assert!(status_payload["data"]["masked_key"]
            .as_str()
            .unwrap()
            .starts_with("admin-"));

        let delete_response = request_with_headers(
            recreated_app.clone(),
            "DELETE",
            "/api/v1/admin/settings/admin-api-key",
            Body::empty(),
            &[("x-api-key", admin_api_key.as_str())],
        )
        .await;
        assert_eq!(delete_response.status(), StatusCode::OK);

        let deleted_key_auth_response = request_with_headers(
            recreated_app,
            "GET",
            "/api/v1/admin/dashboard/stats",
            Body::empty(),
            &[("x-api-key", admin_api_key.as_str())],
        )
        .await;
        assert_eq!(deleted_key_auth_response.status(), StatusCode::UNAUTHORIZED);
    }

