    #[tokio::test]
    async fn admin_backup_postgres_s3_executor_dumps_gzips_and_uploads() {
        let state = AppState::demo();
        let app = app_with_state(state.clone());
        let access_token = login_seed_admin(app.clone()).await;
        let (s3_base_url, s3_requests, s3_shutdown) = spawn_fake_s3_server(StatusCode::OK).await;
        let (fake_dump_root, fake_pg_dump) =
            create_fake_pg_dump_script("CREATE TABLE backup_test(id int);");
        let (fake_psql_root, fake_psql, restored_sql) = create_fake_psql_script();

        let s3_update_response = request_on(
            app.clone(),
            "PUT",
            "/api/v1/admin/backups/s3-config",
            json!({
                "endpoint": s3_base_url,
                "region": "auto",
                "bucket": "postgres-backups",
                "access_key_id": "AKIA",
                "secret_access_key": "secret",
                "prefix": "pg/",
                "force_path_style": true,
                "use_ssl": false
            }),
            Some(&access_token),
        )
        .await;
        assert_eq!(s3_update_response.status(), StatusCode::OK);

        let backup_response = request_on(
            app.clone(),
            "POST",
            "/api/v1/admin/backups",
            json!({
                "executor": "postgres_s3",
                "database": {
                    "host": "127.0.0.1",
                    "port": 5432,
                    "user": "test",
                    "password": "123456",
                    "dbname": "sub2api_new",
                    "sslmode": "disable",
                    "pg_dump_path": fake_pg_dump.to_string_lossy()
                }
            }),
            Some(&access_token),
        )
        .await;

        assert_eq!(backup_response.status(), StatusCode::OK);
        let backup_payload = json_body(backup_response).await;
        let backup = &backup_payload["data"];
        let backup_id = backup["id"].as_str().unwrap().to_owned();
        assert_eq!(backup["status"], "completed");
        assert_eq!(backup["backup_type"], "postgres");
        assert_eq!(backup["executor"], "postgres_s3");
        assert_eq!(backup["artifact_kind"], "postgres_sql_gzip");
        assert_eq!(backup["content_type"], "application/gzip");
        assert_eq!(backup["manifest_version"], 1);
        assert!(backup["size_bytes"].as_u64().unwrap() > 0);
        assert!(backup["s3_key"].as_str().unwrap().starts_with("pg/"));

        let s3_requests_snapshot = s3_requests.lock().unwrap().clone();
        let put_request = s3_requests_snapshot
            .iter()
            .find(|request| request.method == "PUT")
            .expect("postgres backup should upload one S3 object");
        assert!(put_request.path.starts_with("/postgres-backups/pg/"));
        assert_eq!(put_request.has_authorization, true);
        assert_eq!(
            put_request.content_type.as_deref(),
            Some("application/gzip")
        );
        let mut decoder = GzDecoder::new(put_request.body.as_slice());
        let mut sql = String::new();
        decoder.read_to_string(&mut sql).unwrap();
        assert!(sql.contains("CREATE TABLE backup_test"));

        let download_url_response = request_with_body(
            app.clone(),
            "GET",
            &format!("/api/v1/admin/backups/{backup_id}/download-url"),
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(download_url_response.status(), StatusCode::OK);
        let download_url_payload = json_body(download_url_response).await;
        let download_url = download_url_payload["data"]["url"].as_str().unwrap();
        let download_response =
            request_with_body(app.clone(), "GET", download_url, Body::empty(), None).await;
        assert_eq!(download_response.status(), StatusCode::OK);
        assert_eq!(
            download_response
                .headers()
                .get(CONTENT_TYPE)
                .and_then(|value| value.to_str().ok()),
            Some("application/gzip")
        );
        let downloaded_gzip = body_bytes(download_response).await;
        let mut downloaded_decoder = GzDecoder::new(downloaded_gzip.as_slice());
        let mut downloaded_sql = String::new();
        downloaded_decoder
            .read_to_string(&mut downloaded_sql)
            .unwrap();
        assert!(downloaded_sql.contains("CREATE TABLE backup_test"));

        let restore_response = request_on(
            app.clone(),
            "POST",
            &format!("/api/v1/admin/backups/{backup_id}/restore"),
            json!({
                "password": "admin123",
                "database": {
                    "host": "127.0.0.1",
                    "port": 5432,
                    "user": "test",
                    "password": "123456",
                    "dbname": "sub2api_new",
                    "sslmode": "disable",
                    "psql_path": fake_psql.to_string_lossy()
                }
            }),
            Some(&access_token),
        )
        .await;
        assert_eq!(restore_response.status(), StatusCode::OK);
        let restore_payload = json_body(restore_response).await;
        assert_eq!(restore_payload["data"]["restore_status"], "completed");
        let restored_sql_text = std::fs::read_to_string(&restored_sql).unwrap();
        assert!(restored_sql_text.contains("CREATE TABLE backup_test"));

        let get_response = request_with_body(
            app.clone(),
            "GET",
            &format!("/api/v1/admin/backups/{backup_id}"),
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(get_response.status(), StatusCode::OK);
        let get_payload = json_body(get_response).await;
        assert_eq!(get_payload["data"]["executor"], "postgres_s3");
        assert_eq!(get_payload["data"]["restore_status"], "completed");

        let delete_response = request_with_body(
            app,
            "DELETE",
            &format!("/api/v1/admin/backups/{backup_id}"),
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(delete_response.status(), StatusCode::OK);
        let s3_requests_after_delete = s3_requests.lock().unwrap().clone();
        assert!(s3_requests_after_delete
            .iter()
            .any(|request| request.method == "DELETE"
                && request.path.starts_with("/postgres-backups/pg/")));

        s3_shutdown.send(()).ok();
        let _ = std::fs::remove_dir_all(fake_dump_root);
        let _ = std::fs::remove_dir_all(fake_psql_root);
    }

