    #[tokio::test]
    async fn admin_ops_records_real_gateway_success_and_upstream_errors() {
        let upstream = Router::new().route(
            "/v1/chat/completions",
            post(|Json(body): Json<Value>| async move {
                if body["messages"][0]["content"] == "fail" {
                    return (
                        StatusCode::BAD_GATEWAY,
                        Json(json!({
                            "error": {
                                "message": "upstream unavailable"
                            }
                        })),
                    );
                }
                (
                    StatusCode::OK,
                    Json(json!({
                        "id": "chatcmpl_ops",
                        "object": "chat.completion",
                        "model": body["model"],
                        "usage": {
                            "prompt_tokens": 3,
                            "completion_tokens": 4,
                            "total_tokens": 7
                        },
                        "choices": [{
                            "index": 0,
                            "message": {
                                "role": "assistant",
                                "content": "ops ok"
                            },
                            "finish_reason": "stop"
                        }]
                    })),
                )
            }),
        );
        let (base_url, shutdown) = spawn_test_server(upstream).await;
        let state = AppState::demo();
        let app = app_with_state(state.clone());
        let access_token = login_seed_admin(app.clone()).await;
        let gateway_group_id = GroupId(701);
        let gateway_account_id = AccountId(702);
        let gateway_api_key = "sk-ops-deepseek";
        state
            .repository
            .upsert_group(Group {
                id: gateway_group_id,
                name: "ops deepseek group".to_owned(),
                status: GroupStatus::Active,
            })
            .await
            .expect("gateway group can be stored for route selection");
        state
            .repository
            .upsert_api_key(ApiKey {
                id: ApiKeyId(703),
                user_id: 1,
                key: gateway_api_key.to_owned(),
                name: "ops deepseek key".to_owned(),
                group_id: Some(gateway_group_id),
                status: ApiKeyStatus::Active,
                ..ApiKey::default()
            })
            .await
            .expect("gateway API key can be stored for route selection");
        let account = Account {
            id: gateway_account_id,
            name: "ops deepseek".to_owned(),
            provider: Provider::DeepSeek,
            default_upstream_protocol: UpstreamProtocol::OpenAiChatCompletions,
            base_url: Some(base_url),
            api_key: Some("ops-upstream-secret".to_owned()),
            model_mapping: vec![ModelMappingRule {
                source: "gpt-5.4".to_owned(),
                target: "deepseek-v4-pro".to_owned(),
            }],
            extra: json!({}),
            enabled: true,
        };
        state
            .repository
            .upsert_account(account.clone())
            .await
            .expect("gateway account can be stored for route selection");
        state
            .repository
            .bind_account_to_group(AccountGroupBinding {
                group_id: gateway_group_id,
                account,
                supported_downstream_protocols: vec![
                    protocol::DownstreamProtocol::OpenAiChatCompletions,
                ],
                upstream_protocol_override: Some(UpstreamProtocol::OpenAiChatCompletions),
                priority: 1,
            })
            .await
            .expect("gateway account can be bound for route selection");
        let account_id = gateway_account_id.0;

        let success_response = request_on(
            app.clone(),
            "POST",
            "/v1/chat/completions",
            json!({
                "model": "gpt-5.4",
                "messages": [{ "role": "user", "content": "hello" }]
            }),
            Some(gateway_api_key),
        )
        .await;
        assert_eq!(success_response.status(), StatusCode::OK);

        let requests_response = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/admin/ops/requests?page_size=100",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(requests_response.status(), StatusCode::OK);
        let requests_payload = json_body(requests_response).await;
        let success_item = requests_payload["data"]["items"]
            .as_array()
            .unwrap()
            .iter()
            .find(|item| {
                item["path"] == "/v1/chat/completions"
                    && item["status_code"] == 200
                    && item["account_id"] == account_id
            })
            .expect("gateway success should be visible in ops requests");
        assert_eq!(success_item["platform"], "deepseek");
        assert_eq!(success_item["account_id"], account_id);
        assert_eq!(success_item["account_name"], "ops deepseek");
        assert_eq!(success_item["model"], "gpt-5.4");
        assert_eq!(success_item["upstream_model"], "deepseek-v4-pro");
        assert_eq!(success_item["total_tokens"], 7);

        let realtime_response = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/admin/ops/realtime-traffic?window=1m&platform=deepseek&group_id=701",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(realtime_response.status(), StatusCode::OK);
        let realtime_payload = json_body(realtime_response).await;
        assert_eq!(realtime_payload["data"]["summary"]["window"], "1min");
        assert_eq!(realtime_payload["data"]["summary"]["platform"], "deepseek");
        assert_eq!(realtime_payload["data"]["summary"]["group_id"], 701);
        assert!(
            realtime_payload["data"]["summary"]["qps"]["current"]
                .as_f64()
                .unwrap()
                > 0.0
        );
        assert!(
            realtime_payload["data"]["summary"]["tps"]["current"]
                .as_f64()
                .unwrap()
                > 0.0
        );

        let token_stats_response = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/admin/ops/dashboard/openai-token-stats?platform=deepseek&group_id=701&top_n=1",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(token_stats_response.status(), StatusCode::OK);
        let token_stats_payload = json_body(token_stats_response).await;
        assert_eq!(token_stats_payload["data"]["total"], 1);
        assert_eq!(token_stats_payload["data"]["top_n"], 1);
        assert_eq!(token_stats_payload["data"]["items"][0]["model"], "gpt-5.4");
        assert_eq!(
            token_stats_payload["data"]["items"][0]["total_output_tokens"],
            4
        );
        assert_eq!(token_stats_payload["data"]["items"][0]["request_count"], 1);

        let availability_response = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/admin/ops/account-availability?platform=deepseek&group_id=701",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(availability_response.status(), StatusCode::OK);
        let availability_payload = json_body(availability_response).await;
        assert_eq!(
            availability_payload["data"]["account"][account_id.to_string()]["account_name"],
            "ops deepseek"
        );
        assert_eq!(
            availability_payload["data"]["account"][account_id.to_string()]["is_available"],
            true
        );
        assert_eq!(
            availability_payload["data"]["platform"]["deepseek"]["available_count"],
            1
        );

        let error_response = request_on(
            app.clone(),
            "POST",
            "/v1/chat/completions",
            json!({
                "model": "gpt-5.4",
                "messages": [{ "role": "user", "content": "fail" }]
            }),
            Some(gateway_api_key),
        )
        .await;
        shutdown.send(()).ok();
        assert_eq!(error_response.status(), StatusCode::BAD_GATEWAY);

        let upstream_errors_response = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/admin/ops/upstream-errors?page_size=100",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(upstream_errors_response.status(), StatusCode::OK);
        let upstream_errors_payload = json_body(upstream_errors_response).await;
        let error_item = upstream_errors_payload["data"]["items"]
            .as_array()
            .unwrap()
            .iter()
            .find(|item| {
                item["path"] == "/v1/chat/completions"
                    && item["status_code"] == 502
                    && item["account_id"] == account_id
            })
            .expect("gateway upstream error should be visible in ops upstream errors");
        assert_eq!(error_item["platform"], "deepseek");
        assert_eq!(error_item["account_id"], account_id);
        assert_eq!(error_item["model"], "gpt-5.4");

        let availability_after_error_response = request_with_body(
            app,
            "GET",
            "/api/v1/admin/ops/account-availability?platform=deepseek&group_id=701",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(availability_after_error_response.status(), StatusCode::OK);
        let availability_after_error_payload = json_body(availability_after_error_response).await;
        assert_eq!(
            availability_after_error_payload["data"]["account"][account_id.to_string()]
                ["has_error"],
            true
        );
        assert_eq!(
            availability_after_error_payload["data"]["platform"]["deepseek"]["error_count"],
            1
        );
    }

    #[tokio::test]
    async fn admin_ops_reflects_live_gateway_scheduler_state() {
        let release_primary = Arc::new(tokio::sync::Notify::new());
        let primary_started = Arc::new(AtomicUsize::new(0));
        let release_primary_for_upstream = release_primary.clone();
        let primary_started_for_upstream = primary_started.clone();
        let upstream = Router::new().route(
            "/v1/chat/completions",
            post(move |Json(body): Json<Value>| {
                let release_primary = release_primary_for_upstream.clone();
                let primary_started = primary_started_for_upstream.clone();
                async move {
                    primary_started.fetch_add(1, Ordering::SeqCst);
                    release_primary.notified().await;
                    Json(json!({
                        "id": "chatcmpl_live_ops",
                        "object": "chat.completion",
                        "model": body["model"],
                        "choices": [{
                            "index": 0,
                            "message": {
                                "role": "assistant",
                                "content": "released"
                            },
                            "finish_reason": "stop"
                        }]
                    }))
                }
            }),
        );
        let (base_url, shutdown) = spawn_test_server(upstream).await;
        let state = AppState::demo();
        bind_test_account_with_extra(
            &state,
            711,
            Provider::DeepSeek,
            UpstreamProtocol::OpenAiChatCompletions,
            base_url,
            "upstream-secret",
            vec![protocol::DownstreamProtocol::OpenAiChatCompletions],
            1,
            Vec::new(),
            json!({ "gateway_max_concurrent": 2 }),
        )
        .await;
        let app = app_with_state(state);
        let access_token = login_seed_admin(app.clone()).await;
        let first_app = app.clone();
        let first_request = tokio::spawn(async move {
            request_on(
                first_app,
                "POST",
                "/v1/chat/completions",
                json!({
                    "model": "gpt-5.4",
                    "messages": [{ "role": "user", "content": "hold" }]
                }),
                Some("sk-dev-admin"),
            )
            .await
        });
        tokio::time::timeout(std::time::Duration::from_secs(5), async {
            while primary_started.load(Ordering::SeqCst) == 0 {
                tokio::time::sleep(std::time::Duration::from_millis(10)).await;
            }
        })
        .await
        .unwrap();

        let concurrency_response = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/admin/ops/concurrency?platform=deepseek&group_id=1",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(concurrency_response.status(), StatusCode::OK);
        let concurrency_payload = json_body(concurrency_response).await;
        assert_eq!(
            concurrency_payload["data"]["account"]["711"]["current_in_use"],
            1
        );
        assert_eq!(
            concurrency_payload["data"]["account"]["711"]["max_capacity"],
            2
        );
        assert_eq!(
            concurrency_payload["data"]["account"]["711"]["load_percentage"],
            50
        );
        assert_eq!(
            concurrency_payload["data"]["platform"]["deepseek"]["current_in_use"],
            1
        );
        assert_eq!(
            concurrency_payload["data"]["platform"]["deepseek"]["max_capacity"],
            2
        );

        release_primary.notify_waiters();
        let first_response = first_request.await.unwrap();
        shutdown.send(()).ok();
        assert_eq!(first_response.status(), StatusCode::OK);

        let released_response = request_with_body(
            app,
            "GET",
            "/api/v1/admin/ops/concurrency?platform=deepseek&group_id=1",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(released_response.status(), StatusCode::OK);
        let released_payload = json_body(released_response).await;
        assert_eq!(
            released_payload["data"]["account"]["711"]["current_in_use"],
            0
        );
        assert_eq!(
            released_payload["data"]["account"]["711"]["max_capacity"],
            2
        );
    }

    #[tokio::test]
    async fn admin_ops_keeps_streaming_gateway_concurrency_until_body_is_drained() {
        let release_stream = Arc::new(tokio::sync::Notify::new());
        let stream_started = Arc::new(AtomicUsize::new(0));
        let release_stream_for_upstream = release_stream.clone();
        let stream_started_for_upstream = stream_started.clone();
        let upstream = Router::new().route(
            "/v1/chat/completions",
            post(move || {
                let release_stream = release_stream_for_upstream.clone();
                let stream_started = stream_started_for_upstream.clone();
                async move {
                    stream_started.fetch_add(1, Ordering::SeqCst);
                    let body_stream = stream::unfold(
                        (0_u8, release_stream),
                        |(step, release_stream)| async move {
                            match step {
                                0 => Some((
                                    Ok::<_, std::convert::Infallible>(Bytes::from_static(
                                        b"data: {\"choices\":[{\"delta\":{\"content\":\"hello\"}}]}\n\n",
                                    )),
                                    (1, release_stream),
                                )),
                                1 => {
                                    release_stream.notified().await;
                                    Some((
                                        Ok::<_, std::convert::Infallible>(Bytes::from_static(
                                            b"data: [DONE]\n\n",
                                        )),
                                        (2, release_stream),
                                    ))
                                }
                                _ => None,
                            }
                        },
                    );
                    (
                        StatusCode::OK,
                        [(CONTENT_TYPE, HeaderValue::from_static("text/event-stream"))],
                        Body::from_stream(body_stream),
                    )
                }
            }),
        );
        let (base_url, shutdown) = spawn_test_server(upstream).await;
        let state = AppState::demo();
        bind_test_account_with_extra(
            &state,
            713,
            Provider::DeepSeek,
            UpstreamProtocol::OpenAiChatCompletions,
            base_url,
            "upstream-secret",
            vec![protocol::DownstreamProtocol::OpenAiChatCompletions],
            1,
            Vec::new(),
            json!({ "gateway_max_concurrent": 1 }),
        )
        .await;
        let app = app_with_state(state);
        let access_token = login_seed_admin(app.clone()).await;

        let stream_response = request_on(
            app.clone(),
            "POST",
            "/v1/chat/completions",
            json!({
                "model": "gpt-5.4",
                "stream": true,
                "messages": [{ "role": "user", "content": "stream" }]
            }),
            Some("sk-dev-admin"),
        )
        .await;
        assert_eq!(stream_response.status(), StatusCode::OK);
        tokio::time::timeout(std::time::Duration::from_secs(5), async {
            while stream_started.load(Ordering::SeqCst) == 0 {
                tokio::time::sleep(std::time::Duration::from_millis(10)).await;
            }
        })
        .await
        .unwrap();

        let concurrency_response = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/admin/ops/concurrency?platform=deepseek&group_id=1",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(concurrency_response.status(), StatusCode::OK);
        let concurrency_payload = json_body(concurrency_response).await;
        assert_eq!(
            concurrency_payload["data"]["account"]["713"]["current_in_use"],
            1
        );
        assert_eq!(
            concurrency_payload["data"]["account"]["713"]["load_percentage"],
            100
        );

        release_stream.notify_waiters();
        let stream_text = body_text(stream_response).await;
        assert!(stream_text.contains("[DONE]"));

        let released_response = request_with_body(
            app,
            "GET",
            "/api/v1/admin/ops/concurrency?platform=deepseek&group_id=1",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        shutdown.send(()).ok();
        assert_eq!(released_response.status(), StatusCode::OK);
        let released_payload = json_body(released_response).await;
        assert_eq!(
            released_payload["data"]["account"]["713"]["current_in_use"],
            0
        );
    }

    #[tokio::test]
    async fn admin_ops_reflects_gateway_scheduler_cooldown_state() {
        let upstream = Router::new().route(
            "/v1/chat/completions",
            post(|| async {
                (
                    StatusCode::BAD_GATEWAY,
                    Json(json!({
                        "error": {
                            "message": "provider temporarily unavailable"
                        }
                    })),
                )
            }),
        );
        let (base_url, shutdown) = spawn_test_server(upstream).await;
        let state = AppState::demo();
        bind_test_account_with_extra(
            &state,
            712,
            Provider::DeepSeek,
            UpstreamProtocol::OpenAiChatCompletions,
            base_url,
            "upstream-secret",
            vec![protocol::DownstreamProtocol::OpenAiChatCompletions],
            1,
            Vec::new(),
            json!({
                "gateway_failure_cooldown_seconds": 60,
                "gateway_max_failure_cooldown_seconds": 60
            }),
        )
        .await;
        let app = app_with_state(state);
        let access_token = login_seed_admin(app.clone()).await;

        let error_response = request_on(
            app.clone(),
            "POST",
            "/v1/chat/completions",
            json!({
                "model": "gpt-5.4",
                "messages": [{ "role": "user", "content": "fail" }]
            }),
            Some("sk-dev-admin"),
        )
        .await;
        shutdown.send(()).ok();
        assert_eq!(error_response.status(), StatusCode::BAD_GATEWAY);

        let availability_response = request_with_body(
            app,
            "GET",
            "/api/v1/admin/ops/account-availability?platform=deepseek&group_id=1",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(availability_response.status(), StatusCode::OK);
        let availability_payload = json_body(availability_response).await;
        let account = &availability_payload["data"]["account"]["712"];
        assert_eq!(account["status"], "overloaded");
        assert_eq!(account["is_available"], false);
        assert_eq!(account["is_overloaded"], true);
        assert_eq!(account["has_error"], true);
        assert!(account["overload_remaining_sec"].as_i64().unwrap() > 0);
        assert!(account["error_message"]
            .as_str()
            .unwrap()
            .contains("upstream returned"));
        assert_eq!(
            availability_payload["data"]["platform"]["deepseek"]["error_count"],
            1
        );
    }

    #[tokio::test]
    async fn admin_ops_alert_rules_trigger_from_gateway_metrics_with_filters_and_cooldown() {
        let upstream = Router::new().route(
            "/v1/chat/completions",
            post(|| async {
                (
                    StatusCode::BAD_GATEWAY,
                    Json(json!({
                        "error": {
                            "message": "provider temporarily unavailable"
                        }
                    })),
                )
            }),
        );
        let (base_url, shutdown) = spawn_test_server(upstream).await;
        let state = AppState::demo();
        bind_test_account_with_extra(
            &state,
            714,
            Provider::DeepSeek,
            UpstreamProtocol::OpenAiChatCompletions,
            base_url,
            "upstream-secret",
            vec![protocol::DownstreamProtocol::OpenAiChatCompletions],
            1,
            Vec::new(),
            json!({ "gateway_failure_cooldown_seconds": 1 }),
        )
        .await;
        let app = app_with_state(state);
        let access_token = login_seed_admin(app.clone()).await;

        let created_rule_response = request_on(
            app.clone(),
            "POST",
            "/api/v1/admin/ops/alert-rules",
            json!({
                "name": "DeepSeek upstream failures",
                "enabled": true,
                "metric_type": "upstream_error_rate",
                "operator": ">=",
                "threshold": 100,
                "severity": "P1",
                "cooldown_minutes": 10,
                "filters": {
                    "platform": "deepseek",
                    "group_id": 1,
                    "account_id": 714
                }
            }),
            Some(&access_token),
        )
        .await;
        assert_eq!(created_rule_response.status(), StatusCode::OK);
        let created_rule_payload = json_body(created_rule_response).await;
        let rule_id = created_rule_payload["data"]["id"].as_i64().unwrap();

        let gateway_error_response = request_on(
            app.clone(),
            "POST",
            "/v1/chat/completions",
            json!({
                "model": "gpt-5.4",
                "messages": [{ "role": "user", "content": "fail" }]
            }),
            Some("sk-dev-admin"),
        )
        .await;
        assert_eq!(gateway_error_response.status(), StatusCode::BAD_GATEWAY);

        let events_response = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/admin/ops/alert-events",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(events_response.status(), StatusCode::OK);
        let events_payload = json_body(events_response).await;
        let events = events_payload["data"].as_array().unwrap();
        let event = events
            .iter()
            .find(|item| {
                item["rule_id"] == rule_id
                    && item["metric_type"] == "upstream_error_rate"
                    && item["severity"] == "P1"
            })
            .expect("alert event should be created from gateway metric");
        assert_eq!(event["status"], "firing");
        assert_eq!(event["metric_value"], 100.0);
        assert_eq!(event["threshold_value"], 100.0);
        assert_eq!(event["dimensions"]["account_id"], 714);

        let second_gateway_response = request_on(
            app.clone(),
            "POST",
            "/v1/chat/completions",
            json!({
                "model": "gpt-5.4",
                "messages": [{ "role": "user", "content": "fail again" }]
            }),
            Some("sk-dev-admin"),
        )
        .await;
        shutdown.send(()).ok();
        assert_eq!(
            second_gateway_response.status(),
            StatusCode::SERVICE_UNAVAILABLE
        );

        let events_after_cooldown_response = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/admin/ops/alert-events?severity=P1&status=firing&email_sent=false&platform=deepseek&group_id=1&limit=1",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(events_after_cooldown_response.status(), StatusCode::OK);
        let events_after_cooldown_payload = json_body(events_after_cooldown_response).await;
        let filtered_events = events_after_cooldown_payload["data"].as_array().unwrap();
        assert_eq!(filtered_events.len(), 1);
        assert_eq!(filtered_events[0]["rule_id"], rule_id);

        let cursor_response = request_with_body(
            app,
            "GET",
            &format!(
                "/api/v1/admin/ops/alert-events?before_fired_at={}&before_id={}",
                filtered_events[0]["fired_at"].as_str().unwrap(),
                filtered_events[0]["id"].as_i64().unwrap()
            ),
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(cursor_response.status(), StatusCode::OK);
        let cursor_payload = json_body(cursor_response).await;
        assert!(!cursor_payload["data"]
            .as_array()
            .unwrap()
            .iter()
            .any(|item| item["rule_id"] == rule_id));
    }

