    #[tokio::test]
    async fn webhook_and_event_logging_compatibility_routes_are_acknowledged() {
        let state = AppState::demo();
        let app = app_with_state(state.clone());
        let access_token = login_seed_admin(app.clone()).await;

        let event_response = request_on(
            app.clone(),
            "POST",
            "/api/event_logging/batch",
            json!({ "events": [{ "type": "frontend_error" }, { "type": "click" }] }),
            None,
        )
        .await;
        assert_eq!(event_response.status(), StatusCode::OK);
        let event_payload = json_body(event_response).await;
        assert_eq!(event_payload["data"]["accepted"], true);
        assert_eq!(event_payload["data"]["count"], 2);
        assert_eq!(state.payment_portal.event_log_count(), 1);

        let create_order_response = request_on(
            app.clone(),
            "POST",
            "/api/v1/payment/orders",
            json!({ "amount": 12.5, "payment_type": "stripe" }),
            Some(&access_token),
        )
        .await;
        assert_eq!(create_order_response.status(), StatusCode::OK);
        let create_order_payload = json_body(create_order_response).await;
        let out_trade_no = create_order_payload["data"]["out_trade_no"]
            .as_str()
            .unwrap()
            .to_owned();

        let webhook_response = request_on(
            app.clone(),
            "POST",
            "/api/v1/payment/webhook/stripe",
            json!({
                "out_trade_no": out_trade_no,
                "event": "payment.succeeded",
                "amount": 12.5,
                "mock_signature": "valid"
            }),
            None,
        )
        .await;
        assert_eq!(webhook_response.status(), StatusCode::OK);
        assert!(body_text(webhook_response).await.is_empty());

        let order_response = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/payment/orders/1",
            Body::empty(),
            Some(&access_token),
        )
        .await;
        assert_eq!(order_response.status(), StatusCode::OK);
        let order_payload = json_body(order_response).await;
        assert_eq!(order_payload["data"]["status"], "COMPLETED");

        let unknown_webhook_response = request_with_body(
            app.clone(),
            "GET",
            "/api/v1/payment/webhook/easypay?out_trade_no=missing-order&amount=12.5&mock_signature=valid",
            Body::empty(),
            None,
        )
        .await;
        assert_eq!(unknown_webhook_response.status(), StatusCode::OK);
        assert_eq!(body_text(unknown_webhook_response).await, "success");

        let wxpay_webhook_response = request_on(
            app,
            "POST",
            "/api/v1/payment/webhook/wxpay",
            json!({
                "out_trade_no": "missing-wxpay-order",
                "amount": 12.5,
                "mock_signature": "valid"
            }),
            None,
        )
        .await;
        assert_eq!(wxpay_webhook_response.status(), StatusCode::OK);
        let wxpay_payload = json_body(wxpay_webhook_response).await;
        assert_eq!(wxpay_payload["code"], "SUCCESS");
        assert_eq!(wxpay_payload["message"], "\u{6210}\u{529f}");
        assert_eq!(state.payment_portal.webhook_records()["total"], 3);
    }
